# Type aliases for gear measurement data structures
# These define the standard data format used throughout the application
ToothData = Dict[int, List[float]]  # {tooth_id: [measurement_values]}
SideData = Dict[str, ToothData]  # {'left': ToothData, 'right': ToothData}
GearMeasurementData = SideData  # Alias for clarity in function signatures


def create_gear_data_structure() -> GearMeasurementData:
    """Create empty gear measurement data structure.
    
    This is the standard structure used for profile_data, flank_data, etc.
    Each side ('left', 'right') contains a dictionary mapping tooth IDs to measurement arrays.
    
    Returns:
        Dict with 'left' and 'right' keys, each containing empty dict for tooth data
        
    Example:
        >>> data = create_gear_data_structure()
        >>> data['left'][1] = [0.1, 0.2, 0.3, ...]  # Store measurements for tooth 1, left side
    """
    return {'left': {}, 'right': {}}


def remove_outliers(data: np.ndarray, method: str = 'iqr', threshold: float = 1.5) -> np.ndarray:
    """剔除异常值
    
    Args:
        data: 输入数据数组
        method: 异常值检测方法，'iqr' 或 'zscore'
        threshold: 异常值阈值
    
    Returns:
        剔除异常值后的数据数组
    """
    if len(data) == 0:
        return data
    
    data = np.array(data, dtype=float)
    
    if method == 'iqr':
        # 使用IQR方法
        q1 = np.percentile(data, 25)
        q3 = np.percentile(data, 75)
        iqr = q3 - q1
        lower_bound = q1 - threshold * iqr
        upper_bound = q3 + threshold * iqr
    elif method == 'zscore':
        # 使用Z-score方法
        mean = np.mean(data)
        std = np.std(data)
        lower_bound = mean - threshold * std
        upper_bound = mean + threshold * std
    else:
        return data
    
    # 剔除异常值
    filtered_data = data[(data >= lower_bound) & (data <= upper_bound)]
    
    return filtered_data


def remove_outliers_from_gear_data(gear_data: GearMeasurementData) -> GearMeasurementData:
    """从齿轮测量数据中剔除异常值
    
    Args:
        gear_data: 齿轮测量数据结构
    
    Returns:
        剔除异常值后的齿轮测量数据
    """
    cleaned_data = {'left': {}, 'right': {}}
    
    for side in ['left', 'right']:
        side_data = gear_data.get(side, {})
        for tooth_id, values in side_data.items():
            if values:
                cleaned_values = remove_outliers(values)
                cleaned_data[side][tooth_id] = cleaned_values.tolist()
    
    return cleaned_data


def remove_crowning_and_slope(data: np.ndarray) -> np.ndarray:
    """去除鼓形和倾斜（二次曲线拟合）
    
    Args:
        data: 输入数据数组
    
    Returns:
        去除鼓形和倾斜后的数据数组
    """
    if len(data) < 3:
        return data
    
    data = np.array(data, dtype=float)
    x = np.arange(len(data), dtype=float)
    
    # 拟合二次曲线
    coefficients = np.polyfit(x, data, 2)
    fitted_curve = np.polyval(coefficients, x)
    
    # 去除鼓形和倾斜
    corrected_data = data - fitted_curve
    
    return corrected_data


def remove_crowning_and_slope_from_gear_data(gear_data: GearMeasurementData) -> GearMeasurementData:
    """从齿轮测量数据中去除鼓形和倾斜
    
    Args:
        gear_data: 齿轮测量数据结构
    
    Returns:
        去除鼓形和倾斜后的齿轮测量数据
    """
    corrected_data = {'left': {}, 'right': {}}
    
    for side in ['left', 'right']:
        side_data = gear_data.get(side, {})
        for tooth_id, values in side_data.items():
            if values:
                corrected_values = remove_crowning_and_slope(values)
                corrected_data[side][tooth_id] = corrected_values.tolist()
    
    return corrected_data


def calculate_rotation_angles(data_length: int, teeth_count: int) -> np.ndarray:
    """计算旋转角度
    
    Args:
        data_length: 数据长度
        teeth_count: 齿数
    
    Returns:
        旋转角度数组（度）
    """
    if data_length == 0 or teeth_count <= 0:
        return np.array([])
    
    angles = np.linspace(0, (360.0 / teeth_count), data_length)
    return angles


def style_table(table, fontsize: int = 9, header_color: str = '#1E3A5F', 
                alternate_rows: bool = True, bold_cols: list = None):
    """统一设置表格样式
    
    Args:
        table: matplotlib表格对象
        fontsize: 字体大小
        header_color: 表头颜色
        alternate_rows: 是否交替行颜色
        bold_cols: 需要加粗的列索引列表
    """
    if bold_cols is None:
        bold_cols = []
    
    table.auto_set_font_size(False)
    table.set_fontsize(fontsize)
    
    n_rows, n_cols = table.get_celld().keys()
    n_rows = max(key[0] for key in table.get_celld().keys()) + 1
    n_cols = max(key[1] for key in table.get_celld().keys()) + 1
    
    for key, cell in table.get_celld().items():
        row, col = key
        if row == 0:
            cell.set_facecolor(header_color)
            cell.set_text_props(weight='bold', color='white')
        else:
            if alternate_rows and row % 2 == 0:
                cell.set_facecolor('#F8FAFC')
            else:
                cell.set_facecolor('white')
            
            if col in bold_cols:
                cell.set_text_props(weight='bold')
        
        cell.set_edgecolor('#E2E8F0')
        cell.set_linewidth(0.3)
        cell.set_text_props(ha='center', va='center', fontsize=fontsize)


