def calculate_rotation_angles_for_gear_data(gear_data: GearMeasurementData, teeth_count: int) -> Dict[str, Dict[int, np.ndarray]]:
    """计算齿轮数据的旋转角度
    
    Args:
        gear_data: 齿轮测量数据结构
        teeth_count: 齿数
    
    Returns:
        旋转角度数据结构
    """
    angle_data = {'left': {}, 'right': {}}
    
    for side in ['left', 'right']:
        side_data = gear_data.get(side, {})
        for tooth_id, values in side_data.items():
            if values:
                angles = calculate_rotation_angles(len(values), teeth_count)
                angle_data[side][tooth_id] = angles
    
    return angle_data


def extract_evaluation_range(data: np.ndarray, start_percent: float = 0.2, end_percent: float = 0.8) -> np.ndarray:
    """提取评价范围内的数据点
    
    Args:
        data: 输入数据数组
        start_percent: 评价范围起始百分比
        end_percent: 评价范围结束百分比
    
    Returns:
        评价范围内的数据数组
    """
    if len(data) == 0:
        return data
    
    data = np.array(data, dtype=float)
    data_length = len(data)
    
    # 计算评价范围的起始和结束索引
    start_idx = int(data_length * start_percent)
    end_idx = int(data_length * end_percent)
    
    # 确保索引有效
    start_idx = max(0, start_idx)
    end_idx = min(data_length, end_idx)
    
    # 提取评价范围内的数据
    evaluation_data = data[start_idx:end_idx]
    
    return evaluation_data


def extract_evaluation_range_from_gear_data(gear_data: GearMeasurementData) -> GearMeasurementData:
    """从齿轮测量数据中提取评价范围
    
    Args:
        gear_data: 齿轮测量数据结构
    
    Returns:
        评价范围内的齿轮测量数据
    """
    eval_data = {'left': {}, 'right': {}}
    
    for side in ['left', 'right']:
        side_data = gear_data.get(side, {})
        for tooth_id, values in side_data.items():
            if values:
                eval_values = extract_evaluation_range(values)
                eval_data[side][tooth_id] = eval_values.tolist()
    
    return eval_data


def sort_and_deduplicate_angles(angles: np.ndarray) -> np.ndarray:
    """排序并去除重复角度值
    
    Args:
        angles: 角度数组
    
    Returns:
        排序并去重后的角度数组
    """
    if len(angles) == 0:
        return angles
    
    angles = np.array(angles, dtype=float)
    
    # 排序
    sorted_angles = np.sort(angles)
    
    # 去除重复值
    if len(sorted_angles) > 1:
        # 计算相邻角度的差值
        diffs = np.diff(sorted_angles)
        # 保留差值大于0.001的角度
        mask = np.concatenate([[True], diffs > 0.001])
        deduplicated_angles = sorted_angles[mask]
    else:
        deduplicated_angles = sorted_angles
    
    return deduplicated_angles


def sort_and_deduplicate_angles_for_gear_data(angle_data: Dict[str, Dict[int, np.ndarray]]) -> Dict[str, Dict[int, np.ndarray]]:
    """对齿轮数据的角度进行排序和去重
    
    Args:
        angle_data: 角度数据结构
    
    Returns:
        排序和去重后的角度数据
    """
    processed_data = {'left': {}, 'right': {}}
    
    for side in ['left', 'right']:
        side_data = angle_data.get(side, {})
        for tooth_id, angles in side_data.items():
            if angles.size > 0:
                processed_angles = sort_and_deduplicate_angles(angles)
                processed_data[side][tooth_id] = processed_angles
    
    return processed_data


def ensure_angle_range_0_360(angles: np.ndarray) -> np.ndarray:
    """确保角度在0-360范围内
    
    Args:
        angles: 角度数组
    
    Returns:
        调整到0-360范围内的角度数组
    """
    if len(angles) == 0:
        return angles
    
    angles = np.array(angles, dtype=float)
    
    # 调整角度到0-360范围
    normalized_angles = angles % 360.0
    # 处理负数角度
    normalized_angles[normalized_angles < 0] += 360.0
    
    return normalized_angles


def ensure_angle_range_for_gear_data(angle_data: Dict[str, Dict[int, np.ndarray]]) -> Dict[str, Dict[int, np.ndarray]]:
    """确保齿轮数据的角度在0-360范围内
    
    Args:
        angle_data: 角度数据结构
    
    Returns:
        调整到0-360范围内的角度数据
    """
    processed_data = {'left': {}, 'right': {}}
    
    for side in ['left', 'right']:
        side_data = angle_data.get(side, {})
        for tooth_id, angles in side_data.items():
            if angles.size > 0:
                processed_angles = ensure_angle_range_0_360(angles)
                processed_data[side][tooth_id] = processed_angles
    
    return processed_data


def process_gear_data(gear_data: GearMeasurementData, teeth_count: int) -> Dict:
    """完整的齿轮数据处理流程
    
    处理流程：
    1. 读取MKA文件数据
    2. 应用异常值剔除
    3. 去除鼓形和倾斜（二次曲线拟合）
    4. 计算旋转角度
    5. 提取评价范围内的数据点
    6. 排序并去除重复角度值
    7. 确保角度在0-360范围内
    
    Args:
        gear_data: 齿轮测量数据结构
        teeth_count: 齿数
    
    Returns:
        处理后的齿轮数据和角度数据
    """
    # 1. 应用异常值剔除
    cleaned_data = remove_outliers_from_gear_data(gear_data)
    
    # 2. 去除鼓形和倾斜
    corrected_data = remove_crowning_and_slope_from_gear_data(cleaned_data)
    
    # 3. 提取评价范围
    eval_data = extract_evaluation_range_from_gear_data(corrected_data)
    
    # 4. 计算旋转角度
    angle_data = calculate_rotation_angles_for_gear_data(eval_data, teeth_count)
    
    # 5. 对角度进行排序和去重
    sorted_angle_data = sort_and_deduplicate_angles_for_gear_data(angle_data)
    
    # 6. 确保角度在0-360范围内
    final_angle_data = ensure_angle_range_for_gear_data(sorted_angle_data)
    
    return {
        'processed_data': eval_data,
        'angle_data': final_angle_data
    }


def calculate_involute_polar_angle(radius: float, base_radius: float) -> float:
    """计算渐开线上某点的极角（压力角函数）
    
    渐开线极角公式: θ = tan(α) - α = inv(α)
    其中 α 为该点的压力角，由 cos(α) = rb/r 求得
    
    Args:
        radius: 当前点的半径 (mm)
        base_radius: 基圆半径 (mm)
    
    Returns:
        极角（弧度），从基圆开始计算
    """
    if radius <= base_radius or base_radius <= 0:
        return 0.0
    
    cos_alpha = base_radius / radius
    if cos_alpha > 1.0:
        cos_alpha = 1.0
    if cos_alpha < -1.0:
        cos_alpha = -1.0
    
    alpha = np.arccos(cos_alpha)
    inv_alpha = np.tan(alpha) - alpha
    
    return inv_alpha


def calculate_involute_polar_angle_array(radii: np.ndarray, base_radius: float) -> np.ndarray:
    """计算渐开线上多个点的极角数组
    
    Args:
        radii: 半径数组 (mm)
        base_radius: 基圆半径 (mm)
    
    Returns:
        极角数组（弧度）
    """
    radii = np.array(radii, dtype=float)
    polar_angles = np.zeros_like(radii)
    
    valid_mask = radii > base_radius
    if base_radius > 0:
        cos_alpha = np.zeros_like(radii)
        cos_alpha[valid_mask] = base_radius / radii[valid_mask]
        cos_alpha = np.clip(cos_alpha, -1.0, 1.0)
        
        alpha = np.zeros_like(radii)
        alpha[valid_mask] = np.arccos(cos_alpha[valid_mask])
        
        polar_angles[valid_mask] = np.tan(alpha[valid_mask]) - alpha[valid_mask]
    
    return polar_angles


def remove_slope_and_crowning_for_undulation(data: np.ndarray, x: np.ndarray = None) -> tuple:
    """去除斜率偏差和鼓形
    
    分两步处理：
    1. 先用二元二次多项式（抛物线）去除鼓形
    2. 再用一元一次多项式（线性）去除斜率偏差
    """
    if len(data) < 3:
        return data, (None, None)
    
    data = np.array(data, dtype=float)
    n = len(data)
    
    if x is None:
        x = np.arange(n, dtype=float)
    else:
        x = np.array(x, dtype=float)
    
    x_norm = (x - np.mean(x)) / (np.std(x) + 1e-10)
    
    crowning_coeffs = np.polyfit(x_norm, data, 2)
    crowning_curve = np.polyval(crowning_coeffs, x_norm)
    data_after_crowning = data - crowning_curve
    
    slope_coeffs = np.polyfit(x_norm, data_after_crowning, 1)
    slope_curve = np.polyval(slope_coeffs, x_norm)
    corrected_data = data_after_crowning - slope_curve
    
    return corrected_data, (crowning_coeffs, slope_coeffs)


def fit_sine_wave_least_squares(angles: np.ndarray, values: np.ndarray, order: int) -> dict:
    """使用最小二乘法拟合指定阶次的正弦波
    
    拟合模型: y = A * sin(order * θ + φ)
    """
    angles = np.array(angles, dtype=float)
    values = np.array(values, dtype=float)
    
    cos_term = np.cos(order * angles)
    sin_term = np.sin(order * angles)
    
    A = np.column_stack([cos_term, sin_term])
    coeffs, residuals, rank, s = np.linalg.lstsq(A, values, rcond=None)
    
    a, b = coeffs[0], coeffs[1]
    amplitude = np.sqrt(a**2 + b**2)
    phase = np.arctan2(a, b)
    
    fitted = a * cos_term + b * sin_term
    residual = values - fitted
    
    return {
        'amplitude': amplitude,
        'phase': phase,
        'fitted': fitted,
        'residual': residual,
        'coefficients': (a, b)
    }


def find_max_amplitude_order(angles: np.ndarray, values: np.ndarray, 
                              max_order: int = 50, min_order: int = 1,
                              excluded_orders: set = None) -> dict:
    """寻找振幅最大的阶次"""
    if excluded_orders is None:
        excluded_orders = set()
    
    best_order = min_order
    best_amplitude = 0
    best_result = None
    
    for order in range(min_order, max_order + 1):
        if order in excluded_orders:
            continue
        result = fit_sine_wave_least_squares(angles, values, order)
        if result['amplitude'] > best_amplitude:
            best_amplitude = result['amplitude']
            best_order = order
            best_result = result
    
    return {
        'order': best_order,
        'amplitude': best_amplitude,
        'fit_result': best_result
    }


def iterative_sine_decomposition(angles: np.ndarray, values: np.ndarray, 
                                  num_components: int = 10, max_order: int = 50) -> dict:
    """迭代正弦波分解算法
    
    通过最小二乘法分解阶次最大的正弦波，从原始信号中移除已提取的最大阶次正弦波，
    对剩余信号重复上述过程，直到提取出第十个较大的阶次。
    """
    angles = np.array(angles, dtype=float)
    residual = np.array(values, dtype=float)
    
    orders = []
    amplitudes = []
    phases = []
    components = []
    extracted_orders = set()
    
    for i in range(num_components):
        result = find_max_amplitude_order(angles, residual, max_order, min_order=1,
                                          excluded_orders=extracted_orders)
        
        order = result['order']
        extracted_orders.add(order)
        
        fit_result = fit_sine_wave_least_squares(angles, residual, order)
        
        orders.append(order)
        amplitudes.append(fit_result['amplitude'])
        phases.append(fit_result['phase'])
        components.append(fit_result['fitted'])
        
        residual = fit_result['residual']
    
    reconstructed = np.zeros_like(values)
    for comp in components:
        reconstructed += comp
    
    return {
        'orders': np.array(orders),
        'amplitudes': np.array(amplitudes),
        'phases': np.array(phases),
        'components': components,
        'residual': residual,
        'original': np.array(values),
        'reconstructed': reconstructed
    }


def calculate_high_order_undulation(spectrum_result: dict, ze: int) -> dict:
    """计算高阶波纹度（波数≥ZE的分量）
    
    高阶波纹度评价方式：筛选出波数≥ZE的所有分量，计算其合成振幅
    """
    orders = spectrum_result['orders']
    amplitudes = spectrum_result['amplitudes']
    phases = spectrum_result['phases']
    components = spectrum_result['components']
    
    high_order_mask = orders >= ze
    
    high_order_indices = np.where(high_order_mask)[0]
    high_order_waves = orders[high_order_mask]
    high_order_amplitudes = amplitudes[high_order_mask]
    high_order_phases = phases[high_order_mask]
    
    high_order_reconstructed = np.zeros_like(spectrum_result['original'])
    for idx in high_order_indices:
        if idx < len(components):
            high_order_reconstructed += components[idx]
    
    total_amplitude = np.sum(high_order_amplitudes)
    rms = np.sqrt(np.mean(high_order_reconstructed ** 2))
    
    return {
        'high_order_indices': high_order_indices,
        'high_order_waves': high_order_waves,
        'high_order_amplitudes': high_order_amplitudes,
        'high_order_phases': high_order_phases,
        'total_high_order_amplitude': total_amplitude,
        'high_order_rms': rms,
        'high_order_reconstructed': high_order_reconstructed,
        'ze': ze
    }


def analyze_undulation_spectrum(angles_deg: np.ndarray, values: np.ndarray, 
                                 teeth_count: int, num_components: int = 10) -> dict:
    """分析波纹度频谱
    
    Args:
        angles_deg: 角度数组（度），范围0-360
        values: 测量值数组
        teeth_count: 齿数（ZE）
        num_components: 要提取的分量数量
    
    Returns:
        dict: 分解结果和频谱信息
    """
    unique_angles, unique_indices = np.unique(np.round(angles_deg, 3), return_index=True)
    unique_values = values[unique_indices]
    
    max_order = 5 * teeth_count
    num_interp_points = max(360, 2 * max_order + 10)
    interp_angles = np.linspace(0, 360, num_interp_points)
    interp_values = np.interp(interp_angles, unique_angles, unique_values, period=360)
    
    angles_rad = np.radians(interp_angles)
    
    spectrum = iterative_sine_decomposition(angles_rad, interp_values, 
                                            num_components=num_components, max_order=max_order)
    
    high_order = calculate_high_order_undulation(spectrum, teeth_count)
    
    return {
        'spectrum': spectrum,
        'high_order': high_order,
        'interp_angles': interp_angles,
        'interp_values': interp_values
    }


def calculate_full_rotation_curve(
    gear_data: GearMeasurementData,
    teeth_count: int,
    module: float,
    pressure_angle: float,
    eval_start_diameter: float = None,
    side: str = 'left'
) -> dict:
    """计算完整旋转角度曲线（0-360度）
    
    将多个齿的测量数据按照渐开线极角排列，组成0到360度的完整曲线。
    
    算法说明:
    1. 计算基圆半径: rb = m * z * cos(α) / 2
    2. 计算节距角: pitch_angle = 360° / z
    3. 对每个齿:
       - 计算每个测量点对应的半径
       - 根据渐开线理论计算每个点的极角
       - 找出起评点，确定起始极角
       - 将齿序号*节距角与测量点极角组合
    4. 合并所有齿的数据，按角度排序
    5. 归一化到0-360度范围
    
    Args:
        gear_data: 齿轮测量数据结构 {'left': {tooth_id: [values]}, 'right': {...}}
        teeth_count: 齿数
        module: 模数 (mm)
        pressure_angle: 压力角 (度)
        eval_start_diameter: 起评点直径 (mm)，如果为None则使用数据的20%位置
        side: 齿面 ('left' 或 'right')
    
    Returns:
        dict: {
            'angles': 角度数组 (度, 0-360),
            'values': 测量值数组,
            'tooth_indices': 每个点对应的齿号,
            'point_indices': 每个点在齿内的索引
        }
    """
    if side not in gear_data:
        return {'angles': np.array([]), 'values': np.array([]), 
                'tooth_indices': np.array([]), 'point_indices': np.array([])}
    
    side_data = gear_data[side]
    if not side_data:
        return {'angles': np.array([]), 'values': np.array([]),
                'tooth_indices': np.array([]), 'point_indices': np.array([])}
    
    pitch_radius = module * teeth_count / 2.0
    base_radius = pitch_radius * np.cos(np.radians(pressure_angle))
    pitch_angle_deg = 360.0 / teeth_count
    
    all_angles = []
    all_values = []
    all_tooth_indices = []
    all_point_indices = []
    
    sorted_teeth = sorted(side_data.keys())
    
    for tooth_id in sorted_teeth:
        tooth_values = side_data[tooth_id]
        if not tooth_values or len(tooth_values) == 0:
            continue
        
        tooth_values = np.array(tooth_values)
        num_points = len(tooth_values)
        
        tooth_index = int(tooth_id) - 1 if isinstance(tooth_id, (int, str)) and str(tooth_id).isdigit() else 0
        if tooth_index < 0:
            tooth_index = 0
        if tooth_index >= teeth_count:
            tooth_index = teeth_count - 1
        
        tooth_base_angle = tooth_index * pitch_angle_deg
        
        radii = np.linspace(base_radius * 1.05, pitch_radius * 1.15, num_points)
        
        if eval_start_diameter and eval_start_diameter > 0:
            eval_start_radius = eval_start_diameter / 2.0
            start_polar_angle = calculate_involute_polar_angle(eval_start_radius, base_radius)
        else:
            start_idx = int(num_points * 0.2)
            start_radius = radii[start_idx] if start_idx < num_points else radii[0]
            start_polar_angle = calculate_involute_polar_angle(start_radius, base_radius)
        
        point_polar_angles = calculate_involute_polar_angle_array(radii, base_radius)
        point_polar_angles_deg = np.degrees(point_polar_angles - start_polar_angle)
        
        final_angles = tooth_base_angle + point_polar_angles_deg
        
        all_angles.extend(final_angles.tolist())
        all_values.extend(tooth_values.tolist())
        all_tooth_indices.extend([tooth_id] * num_points)
        all_point_indices.extend(list(range(num_points)))
    
    if not all_angles:
        return {'angles': np.array([]), 'values': np.array([]),
                'tooth_indices': np.array([]), 'point_indices': np.array([])}
    
    all_angles = np.array(all_angles)
    all_values = np.array(all_values)
    all_tooth_indices = np.array(all_tooth_indices)
    all_point_indices = np.array(all_point_indices)
    
    all_angles = all_angles % 360.0
    all_angles[all_angles < 0] += 360.0
    
    sort_indices = np.argsort(all_angles)
    all_angles = all_angles[sort_indices]
    all_values = all_values[sort_indices]
    all_tooth_indices = all_tooth_indices[sort_indices]
    all_point_indices = all_point_indices[sort_indices]
    
    return {
        'angles': all_angles,
        'values': all_values,
        'tooth_indices': all_tooth_indices,
        'point_indices': all_point_indices
    }


def calculate_full_rotation_curve_from_profile_data(
    profile_data: dict,
    teeth_count: int,
    module: float,
    pressure_angle: float,
    eval_start_spread: float = None,
    side: str = 'left',
    base_diameter: float = None
) -> dict:
    """从齿形数据计算完整旋转角度曲线
    
    齿形数据是按展长测量的，需要先转换为半径，再计算极角。
    
    Args:
        profile_data: 齿形数据 {'left': {tooth_id: [values]}, 'right': {...}}
        teeth_count: 齿数
        module: 模数 (mm)
        pressure_angle: 压力角 (度)
        eval_start_spread: 起评点展长 (mm)
        side: 齿面 ('left' 或 'right')
        base_diameter: 基圆直径 (mm)
    
    Returns:
        dict: {
            'angles': 角度数组 (度, 0-360),
            'values': 测量值数组,
            'tooth_indices': 每个点对应的齿号,
            'point_indices': 每个点在齿内的索引,
            'spread_lengths': 展长数组
        }
    """
    if side not in profile_data:
        return {'angles': np.array([]), 'values': np.array([]),
                'tooth_indices': np.array([]), 'point_indices': np.array([])}
    
    side_data = profile_data[side]
    if not side_data:
        return {'angles': np.array([]), 'values': np.array([]),
                'tooth_indices': np.array([]), 'point_indices': np.array([])}
    
    pitch_radius = module * teeth_count / 2.0
    if base_diameter and base_diameter > 0:
        base_radius = base_diameter / 2.0
    else:
        base_radius = pitch_radius * np.cos(np.radians(pressure_angle))
    
    pitch_angle_deg = 360.0 / teeth_count
    
    all_angles = []
    all_values = []
    all_tooth_indices = []
    all_point_indices = []
    all_spreads = []
    
    sorted_teeth = sorted(side_data.keys())
    
    for tooth_id in sorted_teeth:
        tooth_values = side_data[tooth_id]
        if not tooth_values or len(tooth_values) == 0:
            continue
        
        tooth_values = np.array(tooth_values)
        num_points = len(tooth_values)
        
        tooth_index = int(tooth_id) - 1 if isinstance(tooth_id, (int, str)) and str(tooth_id).isdigit() else 0
        if tooth_index < 0:
            tooth_index = 0
        if tooth_index >= teeth_count:
            tooth_index = teeth_count - 1
        
        tooth_base_angle = tooth_index * pitch_angle_deg
        
        spread_lengths = np.linspace(0, module * 2.0, num_points)
        
        radii = np.sqrt(spread_lengths ** 2 + base_radius ** 2)
        
        if eval_start_spread and eval_start_spread > 0:
            start_polar_angle = calculate_involute_polar_angle(
                np.sqrt(eval_start_spread ** 2 + base_radius ** 2), base_radius
            )
        else:
            start_idx = int(num_points * 0.2)
            start_radius = radii[start_idx] if start_idx < num_points else radii[0]
            start_polar_angle = calculate_involute_polar_angle(start_radius, base_radius)
        
        point_polar_angles = calculate_involute_polar_angle_array(radii, base_radius)
        point_polar_angles_deg = np.degrees(point_polar_angles - start_polar_angle)
        
        final_angles = tooth_base_angle + point_polar_angles_deg
        
        all_angles.extend(final_angles.tolist())
        all_values.extend(tooth_values.tolist())
        all_tooth_indices.extend([tooth_id] * num_points)
        all_point_indices.extend(list(range(num_points)))
        all_spreads.extend(spread_lengths.tolist())
    
    if not all_angles:
        return {'angles': np.array([]), 'values': np.array([]),
                'tooth_indices': np.array([]), 'point_indices': np.array([]),
                'spread_lengths': np.array([])}
    
    all_angles = np.array(all_angles)
    all_values = np.array(all_values)
    all_tooth_indices = np.array(all_tooth_indices)
    all_point_indices = np.array(all_point_indices)
    all_spreads = np.array(all_spreads)
    
    all_angles = all_angles % 360.0
    all_angles[all_angles < 0] += 360.0
    
    sort_indices = np.argsort(all_angles)
    all_angles = all_angles[sort_indices]
    all_values = all_values[sort_indices]
    all_tooth_indices = all_tooth_indices[sort_indices]
    all_point_indices = all_point_indices[sort_indices]
    all_spreads = all_spreads[sort_indices]
    
    return {
        'angles': all_angles,
        'values': all_values,
        'tooth_indices': all_tooth_indices,
        'point_indices': all_point_indices,
        'spread_lengths': all_spreads
    }


