class ChartMarkerHelper:
    """Unified chart marker helper for consistent visual indication of measurement ranges.
    
    Provides standardized methods for marking:
    - Start points (起测点) - Green markers
    - End points (终测点) - Red markers
    - Evaluation ranges (评定范围) - Blue shaded regions
    """
    
    # Marker style constants - 宋式美学配色
    MARKER_STYLES = {
        'start': {
            'color': '#7A9E7E',      # 石绿色 - 起测点
            'marker': 'o',
            'size': 8,
            'label': '起测点',
            'zorder': 5
        },
        'end': {
            'color': '#A0522D',      # 赭石色 - 终测点
            'marker': 's',
            'size': 8,
            'label': '终测点',
            'zorder': 5
        },
        'range': {
            'color': '#D9CFC1',      # 浅灰色 - 评定范围
            'alpha': 0.25,
            'label': '评定范围',
            'zorder': 1
        }
    }
    
    @staticmethod
    def plot_start_point(ax, x_value: float, y_value: float, show_label: bool = True):
        """Plot start point marker on chart.
        
        Args:
            ax: Matplotlib axes object
            x_value: X coordinate of start point
            y_value: Y coordinate of start point
            show_label: Whether to show label in legend
        """
        style = ChartMarkerHelper.MARKER_STYLES['start']
        ax.plot(x_value, y_value, 
                marker=style['marker'],
                color=style['color'],
                markersize=style['size'],
                label=style['label'] if show_label else None,
                zorder=style['zorder'],
                markeredgecolor='white',
                markeredgewidth=1.5)
    
    @staticmethod
    def plot_end_point(ax, x_value: float, y_value: float, show_label: bool = True):
        """Plot end point marker on chart.
        
        Args:
            ax: Matplotlib axes object
            x_value: X coordinate of end point
            y_value: Y coordinate of end point
            show_label: Whether to show label in legend
        """
        style = ChartMarkerHelper.MARKER_STYLES['end']
        ax.plot(x_value, y_value,
                marker=style['marker'],
                color=style['color'],
                markersize=style['size'],
                label=style['label'] if show_label else None,
                zorder=style['zorder'],
                markeredgecolor='white',
                markeredgewidth=1.5)
    
    @staticmethod
    def plot_evaluation_range(ax, x_start: float, x_end: float, show_label: bool = True):
        """Plot evaluation range as shaded region.
        
        Args:
            ax: Matplotlib axes object
            x_start: Start of evaluation range
            x_end: End of evaluation range
            show_label: Whether to show label in legend
        """
        style = ChartMarkerHelper.MARKER_STYLES['range']
        ax.axvspan(x_start, x_end,
                   color=style['color'],
                   alpha=style['alpha'],
                   label=style['label'] if show_label else None,
                   zorder=style['zorder'])
    
    @staticmethod
    def plot_all_markers(ax, x_data: List[float], y_data: List[float], 
                        start_idx: int, end_idx: int, show_labels: bool = True):
        """Plot all markers (start, end, and range) on chart.
        
        Args:
            ax: Matplotlib axes object
            x_data: X-axis data array
            y_data: Y-axis data array
            start_idx: Index of start point
            end_idx: Index of end point
            show_labels: Whether to show labels in legend
        """
        # Validate indices
        if start_idx < 0 or end_idx >= len(x_data) or start_idx >= end_idx:
            return
        
        # Plot evaluation range first (background)
        ChartMarkerHelper.plot_evaluation_range(
            ax, x_data[start_idx], x_data[end_idx], show_labels
        )
        
        # Plot start and end points (foreground)
        ChartMarkerHelper.plot_start_point(
            ax, x_data[start_idx], y_data[start_idx], show_labels
        )
        ChartMarkerHelper.plot_end_point(
            ax, x_data[end_idx], y_data[end_idx], show_labels
        )



