class FileProcessingThread(QThread):
    """文件处理线程，用于在后台加载和解析MKA文件"""
    finished = pyqtSignal(dict, dict, dict, dict, dict, str)  # gear_data, flank_data, profile_data, pitch_data, topography_data, file_path
    error = pyqtSignal(str)
    progress = pyqtSignal(str)

    def __init__(self, file_path, parent=None):
        super().__init__(parent)
        self.file_path = file_path
        self.gear_data = None
        self.flank_data = {}
        self.profile_data = {}
        self.pitch_data = {'left': {}, 'right': {}}
        self.topography_data = {}
        self._is_cancelled = False

    def cancel(self):
        """请求取消处理"""
        self._is_cancelled = True

    def run(self):
        try:
            if self._is_cancelled:
                return

            logger.info(f"开始处理文件: {self.file_path}")
            self.progress.emit("正在读取文件内容...")
            
            # Windows系统不支持SIGALRM，移除超时保护
            # 在Windows上使用其他方式处理超时

            # 添加文件大小检查
            file_size = os.path.getsize(self.file_path)
            if file_size > 50 * 1024 * 1024:  # 大于50MB
                self.error.emit("文件过大，请选择小于50MB的文件")
                return

            # 使用更安全的方式读取文件
            content = ""
            with open(self.file_path, 'r', encoding='utf-8', errors='replace') as f:
                # 分块读取避免内存问题
                while True:
                    if self._is_cancelled:
                        return
                    chunk = f.read(1024 * 1024)  # 每次读取1MB
                    if not chunk:
                        break
                    content += chunk

            if self._is_cancelled:
                return

            # 添加内容长度检查
            if len(content) > 100 * 1024 * 1024:  # 大于100MB
                self.error.emit("文件内容过大")
                return

            self.progress.emit("正在解析基本数据...")
            self.gear_data = self.extract_gear_basic_data(content)
            
            # 在提取测量数据后，如果齿数仍为0，尝试从测量数据推断
            # 注意：这里的推断会在后续提取测量数据后进行

            if self._is_cancelled:
                return

            self.progress.emit("正在解析齿向数据...")
            self.flank_data = self.extract_measurement_data(content, "Flankenlinie")

            if self._is_cancelled:
                return

            self.progress.emit("正在解析齿形数据...")
            self.profile_data = self.extract_measurement_data(content, "Profil")

            if self._is_cancelled:
                return

            self.progress.emit("正在解析周节数据...")
            try:
                logger.info("开始提取周节数据...")
                self.pitch_data = self.extract_pitch_data(content)
                logger.info(f"周节数据提取完成: 左齿面 {len(self.pitch_data.get('left', {}))} 个齿, 右齿面 {len(self.pitch_data.get('right', {}))} 个齿")
            except Exception as e:
                logger.error(f"周节数据提取失败: {str(e)}")
                self.pitch_data = {'left': {}, 'right': {}}
            
            # 计算实际测量齿数（从齿形和齿向测量数据中统计）
            # 测量齿数 = 实际测量了齿形和/或齿向的齿的数量
            # 需要合并齿形和齿向数据中的齿号，并去重
            measured_teeth_set = set()
            
            # 从齿形数据统计（合并左右两侧的齿号）
            if self.profile_data and isinstance(self.profile_data, dict):
                for side in ['left', 'right']:
                    side_data = self.profile_data.get(side, {})
                    if side_data and isinstance(side_data, dict):
                        measured_teeth_set.update(side_data.keys())
                        logger.debug(f"齿形数据 {side} 侧: {len(side_data)} 个齿")
            
            # 从齿向数据统计（合并左右两侧的齿号）
            if self.flank_data and isinstance(self.flank_data, dict):
                for side in ['left', 'right']:
                    side_data = self.flank_data.get(side, {})
                    if side_data and isinstance(side_data, dict):
                        measured_teeth_set.update(side_data.keys())
                        logger.debug(f"齿向数据 {side} 侧: {len(side_data)} 个齿")
            
            # 计算测量齿数（齿形和齿向数据的并集，去重后的总数）
            measured_teeth_count = len(measured_teeth_set) if measured_teeth_set else 0
            
            # 如果测量齿数为0，尝试从单侧数据统计（作为备选方案）
            if measured_teeth_count == 0:
                # 从齿形数据统计（取左右两侧的最大值）
                if self.profile_data and isinstance(self.profile_data, dict):
                    for side in ['left', 'right']:
                        side_data = self.profile_data.get(side, {})
                        if side_data and isinstance(side_data, dict):
                            measured_teeth_count = max(measured_teeth_count, len(side_data))
                # 从齿向数据统计（取左右两侧的最大值）
                if self.flank_data and isinstance(self.flank_data, dict):
                    for side in ['left', 'right']:
                        side_data = self.flank_data.get(side, {})
                        if side_data and isinstance(side_data, dict):
                            measured_teeth_count = max(measured_teeth_count, len(side_data))
            
            # 更新测量齿数（优先使用从实际测量数据统计的值）
            if measured_teeth_count > 0:
                self.gear_data['测量齿数'] = measured_teeth_count
                self.gear_data['measured_teeth'] = measured_teeth_count
                logger.info(f"从测量数据统计测量齿数: {measured_teeth_count} (齿形+齿向数据合并去重后，共测量了 {len(measured_teeth_set)} 个不同的齿)")
            elif self.gear_data.get('measured_teeth', 0) > 0:
                # 如果无法从数据统计，但MKA文件中有值，保留原值但记录警告
                logger.warning(f"无法从测量数据统计测量齿数，使用MKA文件中的值: {self.gear_data.get('measured_teeth', 0)}")
            
            # 如果齿数为0，尝试从测量数据推断
            if self.gear_data.get('齿数', 0) <= 0:
                inferred_teeth = 0
                # 从周节数据推断（最准确）
                if self.pitch_data:
                    for side in ['left', 'right']:
                        side_data = self.pitch_data.get(side, {})
                        if side_data and isinstance(side_data, dict) and side_data:
                            max_tooth = max(side_data.keys())
                            inferred_teeth = max(inferred_teeth, max_tooth)
                # 从齿形数据推断
                if inferred_teeth <= 0 and self.profile_data and isinstance(self.profile_data, dict):
                    for side in ['left', 'right']:
                        side_data = self.profile_data.get(side, {})
                        if side_data and isinstance(side_data, dict):
                            inferred_teeth = max(inferred_teeth, len(side_data))
                # 从齿向数据推断
                if inferred_teeth <= 0 and self.flank_data and isinstance(self.flank_data, dict):
                    for side in ['left', 'right']:
                        side_data = self.flank_data.get(side, {})
                        if side_data and isinstance(side_data, dict):
                            inferred_teeth = max(inferred_teeth, len(side_data))
                
                if inferred_teeth > 0:
                    self.gear_data['齿数'] = inferred_teeth
                    self.gear_data['teeth'] = inferred_teeth
                    logger.info(f"从测量数据推断齿数: {inferred_teeth}")

            self.progress.emit("正在解析形貌数据...")
            try:
                self.topography_data = self.extract_topography_data(content)
                logger.info(f"Topography data extraction complete: {len(self.topography_data)} teeth processed")
                if self.topography_data:
                    # 调试：显示提取的数据结构
                    first_tooth = sorted(self.topography_data.keys())[0]
                    first_tooth_data = self.topography_data[first_tooth]
                    logger.info(f"Sample topography data - Tooth {first_tooth}:")
                    logger.info(f"  Left: profiles={len(first_tooth_data.get('left', {}).get('profiles', {}))}, "
                               f"flank_lines={len(first_tooth_data.get('left', {}).get('flank_lines', {}))}")
                    logger.info(f"  Right: profiles={len(first_tooth_data.get('right', {}).get('profiles', {}))}, "
                               f"flank_lines={len(first_tooth_data.get('right', {}).get('flank_lines', {}))}")
                else:
                    logger.warning("No topography data extracted from file")
            except Exception as e:
                logger.error(f"Failed to extract topography data: {e}")
                import traceback
                logger.error(traceback.format_exc())
                self.topography_data = {}

            if not self._is_cancelled:
                self.finished.emit(self.gear_data, self.flank_data, self.profile_data, self.pitch_data, self.topography_data, self.file_path)
                logger.info(f"文件处理完成: {self.file_path}")
        except MemoryError:
            self.error.emit("内存不足，无法处理此文件")
        except Exception as e:
            if not self._is_cancelled:
                logger.exception(f"文件处理错误: {str(e)}")
                self.error.emit(f"文件处理错误: {str(e)}")

    def extract_gear_basic_data(self, content):
        """从MKA文件内容中提取齿轮基本数据"""
        gear_data = {}
        lines = content.split('\n')

        patterns = [
            # 基本信息（文本字段）
            ('program', r'^\s*1\s*:Protokolldaten.*?Zahnrad.*?\((.+?)\)', 'str', 1),
            ('date', r'^\s*2\s*:Datum[^:]*:\s*(.+)', 'str', 1),
            ('start_time', r'^\s*3\s*:Zeit[^:]*:\s*([\d:]+)\s*/\s*([\d:]*)', 'str', 1),
            ('end_time', r'^\s*3\s*:Zeit[^:]*:\s*[\d:]+\s*/\s*([\d:]+)', 'str', 1),
            ('operator', r'^\s*4\s*:Operator[^:]*:\s*(.+)', 'str', 1),
            ('location', r'^\s*5\s*:Location of check[^:]*:\s*(.+)', 'str', 1),
            ('drawing_no', r'^\s*6\s*:Drawing No[^:]*:\s*(.+)', 'str', 1),
            ('order_no', r'^\s*7\s*:Order No[^:]*:\s*(.+)', 'str', 1),
            ('order_no', r'^\s*7\s*:.*?Serial.*?:\s*(.+)', 'str', 1),
            ('order_no', r'^\s*7\s*:.*?Serien.*?:\s*(.+)', 'str', 1),
            ('order_no', r'^\s*\d+\s*:.*?Serial.*?:\s*(.+)', 'str', 1),
            ('order_no', r'^\s*\d+\s*:.*?Serien.*?:\s*(.+)', 'str', 1),
            ('type', r'^\s*8\s*:Type[^:]*:\s*(.+)', 'str', 1),
            ('customer', r'^\s*9\s*:Custom/Mach[^:]*:\s*(.+)', 'str', 1),
            ('condition', r'^\s*10\s*:Condition[^:]*:\s*(.+)', 'str', 1),
            ('spindle_no', r'^\s*1007\s*:Spindelnummer[^:]*:\s*(.+)', 'str', 1),
            ('purpose', r'^\s*1015\s*:Untersuchungszweck[^:]*:\s*(.+)', 'str', 1),
            ('accuracy_grade', r'^\s*1016\s*:.*?:\s*(\d+)', 'int', 1),  # 添加精度等级

            # 齿轮参数 - 单值（改进正则表达式以匹配实际格式）
            ('module', r'^\s*21\s*:.*?Normalmodul[^:]*:\s*([\d.]+)', 'float', 1),
            ('module', r'^\s*21\s*:.*?:\s*([\d.]+)', 'float', 1),  # 备用模式
            ('teeth', r'^\s*22\s*:.*?Zähnezahl[^:]*:\s*(-?\d+)', 'int', 1),
            ('teeth', r'^\s*22\s*:.*?Z.*?hnezahl[^:]*:\s*(-?\d+)', 'int', 1),  # 处理编码问题
            ('teeth', r'^\s*22\s*:.*?No\. of teeth[^:]*:\s*(-?\d+)', 'int', 1),  # 英文版
            ('teeth', r'^\s*22\s*:.*?Number of teeth[^:]*:\s*(-?\d+)', 'int', 1),  # 英文版
            ('teeth', r'^\s*22\s*:.*?:\s*(-?\d+)$', 'int', 1),  # 简化模式（作为最后备选）
            ('helix_angle', r'^\s*23\s*:.*?Schrägungswinkel[^:]*:\s*(-?[\d.]+)', 'float', 1),
            ('helix_angle', r'^\s*23\s*:.*?:\s*(-?[\d.]+)', 'float', 1),  # 兼容编码异常/英文缺失
            ('pressure_angle', r'^\s*24\s*:.*?Eingriffswinkel[^:]*:\s*([\d.]+)', 'float', 1),
            ('pressure_angle', r'^\s*24\s*:.*?:\s*([\d.]+)', 'float', 1),  # 兼容编码异常/英文缺失
            ('modification_coeff', r'^\s*25\s*:.*?Profilverschiebungsfaktor[^:]*:\s*([\d.-]+)', 'float', 1),
            ('width', r'^\s*26\s*:.*?Zahnbreite[^:]*:\s*([\d.]+)', 'float', 1),
            ('tip_diameter', r'^\s*27\s*:.*?Kopfkreisdurchmesser[^:]*:\s*([\d.]+)', 'float', 1),
            ('root_diameter', r'^\s*272\s*:.*?Fußkreisdurchmesser[^:]*:\s*([\d.]+)', 'float', 1),
            ('ball_diameter', r'^\s*28\s*:.*?Kugeldurchmesser[^:]*:\s*([\d.]+)', 'float', 1),
            ('measured_teeth', r'^\s*281\s*:.*?(?:Messzähnezahl|Messlückenz\.|Messzzwnezahl)[^=]*[=:][^:]*:\s*(-?\d+)', 'int', 1),
            ('measured_teeth', r'^\s*106\s*:.*?gemessene.*?Zähne[^:]*:\s*(-?\d+)', 'int', 1),  # 测量齿数字段106
            ('measured_teeth', r'^\s*106\s*:.*?Measured.*?Teeth[^:]*:\s*(-?\d+)', 'int', 1),  # 英文测量齿数
            ('measured_teeth', r'^\s*106\s*:.*?:\s*(-?\d+)$', 'int', 1),  # 简化模式
            ('start_meas_position', r'^\s*66\s*:.*?:\s*([\d.]+)', 'float', 1),
            ('width_reduction', r'^\s*67\s*:[^%]*?([\d.]+)\s*%', 'float', 1),
            ('mdk', r'^\s*111\s*:.*?:\s*([\d.]+)', 'float', 1),
            ('wkt', r'^\s*115\s*:.*?:\s*([\d.]+)', 'float', 1),

            # 齿轮参数 - 左右齿面值（改进正则表达式）
            ('da', r'^\s*41\s*:.*?Start Messbereich[^:]*:\s*([\d.]+)\s+([\d.]+)', 'float', (1, 2)),
            ('d1', r'^\s*42\s*:.*?Start der Auswertestrecke[^:]*:\s*([\d.]+)\s+([\d.]+)', 'float', (1, 2)),
            ('d2', r'^\s*43\s*:.*?Ende der Auswertestrecke[^:]*:\s*([\d.]+)\s+([\d.]+)', 'float', (1, 2)),
            ('de', r'^\s*44\s*:.*?Ende der Messstrecke[^:]*:\s*([\d.]+)\s+([\d.]+)', 'float', (1, 2)),
            ('la', r'^\s*45\s*:.*?Länge der Auswertestrecke[^:]*:\s*([\d.]+)\s+([\d.]+)', 'float', (1, 2)),
            ('v_circle', r'^\s*46\s*:.*?Flankenlinienmesskreis[^:]*:\s*([\d.]+)\s+([\d.]+)', 'float', (1, 2)),
            ('pitch_circle', r'^\s*47\s*:.*?Teilungsmesskreis[^:]*:\s*([\d.]+)(?:\s+([\d.]+))?', 'float', (1, 2)),
            ('inner_circle', r'^\s*48\s*:.*?Flankenlinienmesskreis.*innen[^:]*:\s*([\d.]+)\s+([\d.]+)', 'float', (1, 2)),
            ('outer_circle', r'^\s*49\s*:.*?Flankenlinienmesskreis.*außen[^:]*:\s*([\d.]+)\s+([\d.]+)', 'float', (1, 2)),
            ('ba', r'^\s*61\s*:.*?Messanfang.*unten[^:]*:\s*([\d.-]+)\s+([\d.-]+)', 'float', (1, 2)),
            ('b1', r'^\s*62\s*:.*?Auswerteanfang[^:]*:\s*([\d.]+)\s+([\d.]+)', 'float', (1, 2)),
            ('b2', r'^\s*63\s*:.*?Auswerteende[^:]*:\s*([\d.]+)\s+([\d.]+)', 'float', (1, 2)),
            ('be', r'^\s*64\s*:.*?Messende.*oben[^:]*:\s*([\d.]+)\s+([\d.]+)', 'float', (1, 2)),
            ('profile_position', r'^\s*65\s*:.*?:\s*([\d.]+)\s+([\d.]+)', 'float', (1, 2)),
            ('lower_position', r'^\s*68\s*:.*?:\s*([\d.]+)\s+([\d.]+)', 'float', (1, 2)),
            ('upper_position', r'^\s*69\s*:.*?:\s*([\d.]+)\s+([\d.]+)', 'float', (1, 2)),
        ]

        for line in lines:
            if self._is_cancelled:
                return {}

            for key, pattern, data_type, index in patterns:
                # 如果已经提取到该字段且值有效，跳过后续模式（避免被更宽松的模式覆盖）
                if key in gear_data:
                    if isinstance(gear_data[key], (int, float)) and gear_data[key] != 0:
                        continue
                    elif isinstance(gear_data[key], str) and gear_data[key]:
                        continue
                
                match = re.search(pattern, line)
                if match:
                    try:
                        if data_type == 'str':
                            value = match.group(index).strip()
                            if value:
                                gear_data[key] = value
                        else:
                            if isinstance(index, tuple):
                                left_val = match.group(index[0]).strip() if match.group(index[0]) else '0'
                                right_val = match.group(index[1]).strip() if match.group(index[1]) else left_val

                                left = float(left_val) if left_val else 0.0
                                right = float(right_val) if right_val else 0.0
                                gear_data[key] = {'left': left, 'right': right}
                            else:
                                value = match.group(index).strip()
                                if value:
                                    if data_type == 'int':
                                        val = int(value)
                                        # 对于齿数，如果值为负数或0，尝试绝对值或跳过
                                        if key == 'teeth' and val <= 0:
                                            # 如果是负数，尝试使用绝对值
                                            if val < 0:
                                                val = abs(val)
                                                logger.info(f"齿数为负数 {value}，使用绝对值 {val}")
                                            else:
                                                continue  # 跳过0值，尝试下一个模式
                                        gear_data[key] = val
                                    else:
                                        gear_data[key] = float(value)
                                else:
                                    gear_data[key] = 0.0 if data_type == 'float' else 0
                    except (ValueError, IndexError) as e:
                        logger.warning(f"解析错误 '{key}' - {line.strip()} - {str(e)}")
                    break

        # 如果齿数为0或负数，尝试从测量齿数获取或使用绝对值
        teeth = gear_data.get('teeth', 0)
        if teeth <= 0:
            measured_teeth = gear_data.get('measured_teeth', 0)
            if measured_teeth > 0:
                teeth = measured_teeth
                gear_data['teeth'] = teeth
                logger.info(f"使用测量齿数作为齿数: {teeth}")
            elif teeth < 0:
                # 如果是负数，使用绝对值
                teeth = abs(teeth)
                gear_data['teeth'] = teeth
                logger.info(f"齿数为负数，使用绝对值: {teeth}")
        
        # 计算ISO1328公差值
        module = gear_data.get('module', 0.0)
        width = gear_data.get('width', 0)
        accuracy_grade = gear_data.get('accuracy_grade', 5)

        # 计算分度圆直径
        pitch_diameter = module * teeth

        # 精度等级系数
        grade_factors = {5: 1.0, 6: 1.6, 7: 2.5, 8: 4.0, 9: 6.0}
        k = grade_factors.get(accuracy_grade, 1.0)  # 默认5级精度

        # 1. 计算齿形公差 F_alpha
        if pitch_diameter > 0:
            F_alpha_5 = 0.1 * module + 0.45 * math.sqrt(pitch_diameter) + 5
        else:
            F_alpha_5 = 0
        F_alpha = k * F_alpha_5

        # 2. 计算齿形斜率公差 fH_alpha (通常为F_alpha的70%)
        fH_alpha = F_alpha * 0.7

        # 3. 计算齿形形状公差 ff_alpha (通常为F_alpha的40%)
        ff_alpha = F_alpha * 0.4

        # 4. 计算齿向公差 F_beta
        if width > 0 and pitch_diameter > 0:
            d_b_ratio = pitch_diameter / width
            F_beta_5 = 0.1 * math.sqrt(d_b_ratio) * width + 0.45 * math.sqrt(width) + 5
        else:
            F_beta_5 = 0
        F_beta = k * F_beta_5

        # 5. 计算齿向斜率公差 fH_beta (通常为F_beta的70%)
        fH_beta = F_beta * 0.7

        # 6. 计算齿向形状公差 ff_beta (通常为F_beta的40%)
        ff_beta = F_beta * 0.4

        # 将公差值存入gear_data (单位: 微米)
        gear_data['F_alpha'] = F_alpha
        gear_data['fH_alpha'] = fH_alpha
        gear_data['ff_alpha'] = ff_alpha
        gear_data['F_beta'] = F_beta
        gear_data['fH_beta'] = fH_beta
        gear_data['ff_beta'] = ff_beta

        return {
            # 基本信息
            '程序名': gear_data.get('program', ''),
            '日期': gear_data.get('date', ''),
            '开始测量时间': gear_data.get('start_time', ''),
            '结束测量时间': gear_data.get('end_time', ''),
            '操作员': gear_data.get('operator', ''),
            '检查地点': gear_data.get('location', ''),
            '图号': gear_data.get('drawing_no', ''),
            '序号': gear_data.get('order_no', ''),
            '类型': gear_data.get('type', ''),
            '客户': gear_data.get('customer', ''),
            '状况': gear_data.get('condition', ''),
            '轴号': gear_data.get('spindle_no', ''),
            '研究目的': gear_data.get('purpose', ''),
            '精度等级': gear_data.get('accuracy_grade', 5),  # 默认为5级精度

            # 齿轮参数
            '模数': gear_data.get('module', 0.0),
            '齿数': teeth,  # 使用处理后的齿数值
            '螺旋角': gear_data.get('helix_angle', 0.0),
            '压力角': gear_data.get('pressure_angle', 0.0),
            '变位系数': gear_data.get('modification_coeff', 0.0),
            '齿宽': gear_data.get('width', 0),
            '齿顶圆直径': gear_data.get('tip_diameter', 0.0),
            '齿根圆直径': gear_data.get('root_diameter', 0.0),
            '球径': gear_data.get('ball_diameter', 0),
            '测量齿数': gear_data.get('measured_teeth', 0),
            '齿向起测点位置': gear_data.get('start_meas_position', 0.0),
            '齿向测量缩减百分比': gear_data.get('width_reduction', 0.0),
            '跨棒距名义值': gear_data.get('mdk', 0.0),
            '公法线名义值': gear_data.get('wkt', 0.0),

            # 公差值 (微米)
            '齿形公差': F_alpha,
            '齿形斜率公差': fH_alpha,
            '齿形形状公差': ff_alpha,
            '齿向公差': F_beta,
            '齿向斜率公差': fH_beta,
            '齿向形状公差': ff_beta,

            # 左右齿面参数
            '齿形起测点直径': gear_data.get('da', {'left': 0.0, 'right': 0.0}),
            '齿形起评点直径': gear_data.get('d1', {'left': 0.0, 'right': 0.0}),
            '齿形终评点直径': gear_data.get('d2', {'left': 0.0, 'right': 0.0}),
            '齿形终测点直径': gear_data.get('de', {'left': 0.0, 'right': 0.0}),
            '齿轮展长': gear_data.get('la', {'left': 0.0, 'right': 0.0}),
            '齿向测量位置': gear_data.get('v_circle', {'left': 0.0, 'right': 0.0}),
            '分度圆直径': gear_data.get('pitch_circle', {'left': 0.0, 'right': 0.0}),
            '内部测量圆直径': gear_data.get('inner_circle', {'left': 0.0, 'right': 0.0}),
            '外部测量圆直径': gear_data.get('outer_circle', {'left': 0.0, 'right': 0.0}),
            '齿向起测点': gear_data.get('ba', {'left': 0.0, 'right': 0.0}),
            '齿向起评点': gear_data.get('b1', {'left': 0.0, 'right': 0.0}),
            '齿向终评点': gear_data.get('b2', {'left': 0.0, 'right': 0.0}),
            '齿向终测点': gear_data.get('be', {'left': 0.0, 'right': 0.0}),
            '齿形测量位置': gear_data.get('profile_position', {'left': 0.0, 'right': 0.0}),
            '齿形下方测量位置': gear_data.get('lower_position', {'left': 0.0, 'right': 0.0}),
            '齿形上方测量位置': gear_data.get('upper_position', {'left': 0.0, 'right': 0.0}),
        }

    def extract_measurement_data(self, content, data_type):
        """从MKA文件内容中提取测量数据（齿向或齿形）"""
        if self._is_cancelled:
            return {}

        measurement_data = {'left': {}, 'right': {}}
        max_teeth = 200  # 增加最大齿数限制，确保提取所有齿的数据

        # 根据数据类型确定匹配模式和点数
        if data_type == "Flankenlinie":
            pattern_char = r'd'  # 齿向数据匹配 d=
            expected_points = 915  # 齿向数据有915个点
        elif data_type == "Profil":
            pattern_char = r'z'  # 齿形数据匹配 z=
            expected_points = 480  # 齿形数据有480个点
        else:
            logger.warning(f"未知的数据类型: {data_type}")
            return measurement_data

        # 查找数据块的起始位置 - 改进匹配模式
        start_patterns = [
            data_type + ": ",
            data_type + ":",
            "TOPOGRAFIE:.*?" + data_type + ":"
        ]
        
        start_index = -1
        for pattern in start_patterns:
            start_index = content.find(pattern)
            if start_index != -1:
                break
                
        if start_index == -1:
            logger.warning(f"未找到{data_type}数据块")
            return measurement_data

        # 提取数据块内容
        data_block = content[start_index:]

        # 兼容不同格式的正则表达式
        tooth_patterns = [
            # 250210427.mka格式: Flankenlinie: Zahn-Nr.: 1 rechts / 915 Werte / d= 47.82
            re.compile(rf'Zahn-Nr\.:\s*(\d+)\s*(links|rechts)\s*/\s*(\d+)\s*Werte\s*/?\s*{pattern_char}=\s*([-\d.]+)', re.IGNORECASE),
            # 202305021044.mka格式: Zahn-Nr.: 17 links / 480 Werte d= 104.661
            re.compile(rf'Zahn-Nr\.:\s*(\d+)\s*(links|rechts)\s*/\s*(\d+)\s*Werte\s*{pattern_char}=\s*([-\d.]+)', re.IGNORECASE),
            # 简化格式: Zahn-Nr.: 1 rechts
            re.compile(rf'Zahn-Nr\.:\s*(\d+)\s*(links|rechts)', re.IGNORECASE),
        ]

        # 查找所有齿号行
        tooth_matches = []
        actual_points = expected_points
        
        for pattern in tooth_patterns:
            tooth_matches = list(pattern.finditer(data_block))
            if tooth_matches:
                # 如果是完整格式，获取实际点数
                if len(tooth_matches[0].groups()) >= 3:
                    try:
                        reported_points = int(tooth_matches[0].group(3))
                        # 使用报告的点数，但确保不超过预期
                        actual_points = min(reported_points, expected_points)
                        logger.info(f"{data_type}: 报告点数{reported_points}，实际使用{actual_points}点")
                    except (ValueError, IndexError):
                        actual_points = expected_points
                break
            
        if not tooth_matches:
            logger.warning(f"在{data_type}数据块中未找到任何齿数据")
            return measurement_data

        # 处理所有匹配的齿
        for i, match in enumerate(tooth_matches):
            if self._is_cancelled:
                return {}

            tooth_id = int(match.group(1))
            flank = match.group(2).lower()
            start_pos = match.end()

            # 确定下一个齿的起始位置（如果有）
            end_pos = tooth_matches[i + 1].start() if i + 1 < len(tooth_matches) else len(data_block)

            # 提取数据点部分
            data_section = data_block[start_pos:end_pos]

            # 提取数值 - 使用统一的提取方法
            values = self.extract_numerical_values_unified(data_section, actual_points)

            # 存储数据
            if flank == 'links':
                measurement_data['left'][tooth_id] = values
            else:
                measurement_data['right'][tooth_id] = values

        logger.info(f"提取{data_type}数据: 左齿面 {len(measurement_data['left'])} 个齿, 右齿面 {len(measurement_data['right'])} 个齿")
        return measurement_data


    def extract_numerical_values_unified(self, data_section, expected_points):
        """统一的数值提取方法 - 支持915个和480个数据点"""
        values = []
        
        # 使用更精确的数字提取模式
        number_pattern = re.compile(r'[-+]?\d*\.?\d+')
        numbers = number_pattern.findall(data_section)
        
        # 转换为浮点数
        for num in numbers:
            try:
                # 处理前导点的情况
                if num.startswith('.') or num.startswith('-.'):
                    num = num.replace('.', '0.', 1) if num.startswith('.') else num.replace('-.', '-0.')
                values.append(float(num))
            except ValueError:
                continue
            
            # 如果已经收集到足够的点，停止提取
            if len(values) >= expected_points:
                values = values[:expected_points]
                break
        
        # 确保有足够的点
        if len(values) < expected_points:
            # 用0填充不足的点
            values.extend([0.0] * (expected_points - len(values)))
            logger.warning(f"数据点不足: {len(values)} < {expected_points}，用0填充")
        elif len(values) > expected_points:
            values = values[:expected_points]
            logger.info(f"数据点过多: {len(values)} > {expected_points}，截取前{expected_points}个点")
        
        return values

    def extract_pitch_data(self, content):
        """从MKA文件内容中提取周节数据"""
        pitch_data = {'left': {}, 'right': {}}
        
        try:
            # 方法1: 查找 "linke Zahnflanke" 和 "rechte Zahnflanke" 格式的数据
            left_pattern = r'linke Zahnflanke\s*\n\s*Zahn-Nr\.\s+fp\s+Fp\s+Fr\s*\n((?:\s*\d+\s+[-\d.]+\s+[-\d.]+\s+[-\d.]+\s*\n?)+)'
            right_pattern = r'rechte Zahnflanke\s*\n\s*Zahn-Nr\.\s+fp\s+Fp\s+Fr\s*\n((?:\s*\d+\s+[-\d.]+\s+[-\d.]+\s+[-\d.]+\s*\n?)+)'
            
            # 提取左侧周节数据
            left_match = re.search(left_pattern, content, re.IGNORECASE)
            if left_match:
                left_data_text = left_match.group(1)
                left_data_lines = left_data_text.strip().split('\n')
                
                for line in left_data_lines:
                    line = line.strip()
                    if line and re.match(r'^\d+', line):
                        parts = line.split()
                        if len(parts) >= 4:
                            tooth_num = int(parts[0])
                            fp = float(parts[1])
                            Fp = float(parts[2])
                            Fr = float(parts[3])
                            
                            pitch_data['left'][tooth_num] = {
                                'fp': fp,
                                'Fp': Fp,
                                'Fr': Fr
                            }
            
            # 提取右侧周节数据
            right_match = re.search(right_pattern, content, re.IGNORECASE)
            if right_match:
                right_data_text = right_match.group(1)
                right_data_lines = right_data_text.strip().split('\n')
                
                for line in right_data_lines:
                    line = line.strip()
                    if line and re.match(r'^\d+', line):
                        parts = line.split()
                        if len(parts) >= 4:
                            tooth_num = int(parts[0])
                            fp = float(parts[1])
                            Fp = float(parts[2])
                            Fr = float(parts[3])
                            
                            pitch_data['right'][tooth_num] = {
                                'fp': fp,
                                'Fp': Fp,
                                'Fr': Fr
                            }
            
            # 方法2: 查找 "Teilung:" 格式的数据（包含坐标信息）
            teilung_pattern = r'Teilung:\s*\nZ-Nr\.\s+Seite\s+PHI\s+X\s+Y\s+Z\s*\n((?:\s*\d+\s+[LR]\s+[-\d.]+\s+[-\d.]+\s+[-\d.]+\s+[-\d.]+\s*\n?)+)'
            teilung_match = re.search(teilung_pattern, content, re.IGNORECASE)
            
            if teilung_match:
                teilung_text = teilung_match.group(1)
                teilung_lines = teilung_text.strip().split('\n')
                
                for line in teilung_lines:
                    line = line.strip()
                    if line and re.match(r'^\d+', line):
                        parts = line.split()
                        if len(parts) >= 6:
                            tooth_num = int(parts[0])
                            side = parts[1]  # L 或 R
                            phi = float(parts[2])
                            x = float(parts[3])
                            y = float(parts[4])
                            z = float(parts[5])
                            
                            side_key = 'left' if side == 'L' else 'right'
                            if tooth_num not in pitch_data[side_key]:
                                pitch_data[side_key][tooth_num] = {}
                            
                            pitch_data[side_key][tooth_num].update({
                                'phi': phi,
                                'x': x,
                                'y': y,
                                'z': z
                            })
            
            # 方法3: 查找其他可能的周节数据格式
            # 查找包含 "fp", "Fp", "Fr" 的数据行
            pitch_lines = re.findall(r'^\s*(\d+)\s+([-\d.]+)\s+([-\d.]+)\s+([-\d.]+)\s*$', content, re.MULTILINE)
            
            if pitch_lines and not pitch_data['left'] and not pitch_data['right']:
                # 如果没有找到标准格式，尝试从数据行推断
                for line_match in pitch_lines:
                    tooth_num = int(line_match[0])
                    fp = float(line_match[1])
                    Fp = float(line_match[2])
                    Fr = float(line_match[3])
                    
                    # 根据齿号判断左右齿面（假设偶数齿为右面，奇数齿为左面）
                    side_key = 'left' if tooth_num % 2 == 1 else 'right'
                    pitch_data[side_key][tooth_num] = {
                        'fp': fp,
                        'Fp': Fp,
                        'Fr': Fr
                    }
            
            logger.info(f"提取周节数据: 左齿面 {len(pitch_data['left'])} 个齿, 右齿面 {len(pitch_data['right'])} 个齿")
            
        except Exception as e:
            logger.error(f"周节数据提取错误: {str(e)}")
        
        return pitch_data

    def extract_topography_data(self, content):
        """
        提取3D形貌数据
        同时解析Profil（z值，齿面高度）和Flankenlinie（d值，齿面直径）数据
        支持两种格式：
        1. TOPOGRAFIE: Zahn-Nr.: 23 /Profil:1 rechts / 480 Werte  / z= 4.75
        2. Profil:  Zahn-Nr.: 1a rechts / 480 Werte  / z= 2.1
        """
        topography_data = {}
        
        # 格式1: 带 TOPOGRAFIE 前缀
        # TOPOGRAFIE: Zahn-Nr.: 23 /Profil:1 rechts / 480 Werte  / z= 4.75
        pattern_profil1 = re.compile(
            r'TOPOGRAFIE:\s*Zahn-Nr\.:\s*(\d+)\s*/Profil:(\d+)\s*(links|rechts)\s*/\s*(\d+)\s*Werte\s*/?\s*z=\s*([-\d.]+)', 
            re.IGNORECASE
        )
        pattern_flank1 = re.compile(
            r'TOPOGRAFIE:\s*Zahn-Nr\.:\s*(\d+)\s*/Flankenlinie:(\d+)\s*(links|rechts)\s*/\s*(\d+)\s*Werte\s*/?\s*d=\s*([-\d.]+)', 
            re.IGNORECASE
        )
        
        # 格式2: 不带 TOPOGRAFIE 前缀
        # Profil:  Zahn-Nr.: 1a rechts / 480 Werte  / z= 2.1
        # Flankenlinie:  Zahn-Nr.: 1a rechts / 480 Werte  / d= 174.822
        pattern_profil2 = re.compile(
            r'Profil:\s*Zahn-Nr\.:\s*(\d+[a-z]?)\s*(links|rechts)\s*/\s*(\d+)\s*Werte\s*/\s*z=\s*([-\d.]+)', 
            re.IGNORECASE
        )
        pattern_flank2 = re.compile(
            r'Flankenlinie:\s*Zahn-Nr\.:\s*(\d+[a-z]?)\s*(links|rechts)\s*/\s*(\d+)\s*Werte\s*/\s*d=\s*([-\d.]+)', 
            re.IGNORECASE
        )
        
        # 收集所有匹配
        all_matches = []
        for match in pattern_profil1.finditer(content):
            all_matches.append(('profil', 1, match))
        for match in pattern_profil2.finditer(content):
            all_matches.append(('profil', 2, match))
        for match in pattern_flank1.finditer(content):
            all_matches.append(('flank', 1, match))
        for match in pattern_flank2.finditer(content):
            all_matches.append(('flank', 2, match))
        
        # 按位置排序
        all_matches.sort(key=lambda x: x[2].start())
        
        if not all_matches:
            logger.info("未找到形貌数据")
            return topography_data
        
        profil_count = sum(1 for x in all_matches if x[0] == 'profil')
        flank_count = sum(1 for x in all_matches if x[0] == 'flank')
        logger.info(f"找到 {profil_count} 个Profil数据块, {flank_count} 个Flankenlinie数据块")
        
        for i, (data_type, format_type, match) in enumerate(all_matches):
            if self._is_cancelled:
                return {}
                
            try:
                if format_type == 1:
                    # 格式1: TOPOGRAFIE: Zahn-Nr.: 23 /Profil:1 rechts / 480 Werte  / z= 4.75
                    tooth_num_str = match.group(1)
                    idx = int(match.group(2))
                    side_str = match.group(3).lower()
                    expected_points = int(match.group(4))
                    if data_type == 'profil':
                        z_val = float(match.group(5))
                    else:
                        d_val = float(match.group(5))
                else:
                    # 格式2: Profil:  Zahn-Nr.: 1a rechts / 480 Werte  / z= 2.1
                    tooth_num_str = match.group(1)
                    side_str = match.group(2).lower()
                    expected_points = int(match.group(3))
                    if data_type == 'profil':
                        z_val = float(match.group(4))
                        # 根据字母后缀确定索引：a=1(底部), b=2(中间), c=3(顶部)
                        if 'a' in tooth_num_str.lower():
                            idx = 1
                        elif 'b' in tooth_num_str.lower():
                            idx = 2
                        elif 'c' in tooth_num_str.lower():
                            idx = 3
                        else:
                            idx = 2  # 默认中间位置
                    else:
                        d_val = float(match.group(4))
                        # 根据字母后缀确定索引
                        if 'a' in tooth_num_str.lower():
                            idx = 1
                        elif 'b' in tooth_num_str.lower():
                            idx = 2
                        elif 'c' in tooth_num_str.lower():
                            idx = 3
                        else:
                            idx = 2
                
                # 提取齿号（去除字母后缀）
                tooth_num_match = re.match(r'(\d+)', tooth_num_str)
                if tooth_num_match:
                    tooth_num = int(tooth_num_match.group(1))
                else:
                    tooth_num = 1
                
                side = 'left' if side_str == 'links' else 'right'
                
                # 确定数据范围
                start_pos = match.end()
                end_pos = all_matches[i+1][2].start() if i + 1 < len(all_matches) else len(content)
                
                data_section = content[start_pos:end_pos]
                
                # 提取数值
                values = self.extract_numerical_values_unified(data_section, expected_points)
                
                # 存储数据 - 使用新格式
                if tooth_num not in topography_data:
                    topography_data[tooth_num] = {
                        'left': {'profiles': {}, 'flank_lines': {}},
                        'right': {'profiles': {}, 'flank_lines': {}}
                    }
                
                if data_type == 'profil':
                    topography_data[tooth_num][side]['profiles'][idx] = {
                        'z': z_val,
                        'values': values
                    }
                else:  # flank
                    topography_data[tooth_num][side]['flank_lines'][idx] = {
                        'd': d_val,
                        'values': values
                    }
                
            except Exception as e:
                logger.warning(f"解析形貌数据块失败: {e}")
                continue
                
        return topography_data







class UndulationAnalysisThread(QThread):
    """波纹度分析线程"""
    finished = pyqtSignal(dict)  # undulation_results
    progress = pyqtSignal(str)

    def __init__(self, profile_data, flank_data, gear_data, parent=None):
        super().__init__(parent)
        self.profile_data = profile_data
        self.flank_data = flank_data
        self.gear_data = gear_data
        self._is_cancelled = False

    def cancel(self):
        """请求取消处理"""
        self._is_cancelled = True

    def process_profile_data(self, side: str) -> dict:
        """处理齿形数据，计算完整旋转曲线（使用评价范围内数据）
        
        根据标准公式:
        φ = -ξ + τ
        
        其中:
        - φ: 旋转角度
        - ξ (xi): 滚动角 = 渐开线极角 inv(α) = tan(α) - α
        - τ (tau): 节距角 = 齿序号 × 360° / 齿数
        
        只使用起评点到终评点范围内的数据
        """
        if side not in self.profile_data or not self.profile_data[side]:
            return None
        
        module = self.gear_data.get('module', self.gear_data.get('模数', 0))
        teeth_count = self.gear_data.get('teeth', self.gear_data.get('齿数', 0))
        pressure_angle = self.gear_data.get('pressure_angle', self.gear_data.get('压力角', 20))
        base_diameter = self.gear_data.get('base_diameter', self.gear_data.get('基圆直径', 0))
        
        # 获取起评点和终评点展长（使用英文键名）
        start_eval_spread = self.gear_data.get('profile_eval_start', None)
        end_eval_spread = self.gear_data.get('profile_eval_end', None)
        
        if teeth_count <= 0:
            logger.warning(f"齿数无效: {teeth_count}，无法进行波纹度分析")
            return None
        
        pitch_radius = module * teeth_count / 2.0
        if base_diameter and base_diameter > 0:
            base_radius = base_diameter / 2.0
        else:
            base_radius = pitch_radius * np.cos(np.radians(pressure_angle))
        
        pitch_angle_deg = 360.0 / teeth_count
        
        side_data = self.profile_data[side]
        sorted_teeth = sorted(side_data.keys())
        
        all_angles = []
        all_values = []
        all_tooth_indices = []
        
        for tooth_id in sorted_teeth:
            tooth_values = side_data[tooth_id]
            if tooth_values is None or len(tooth_values) == 0:
                continue
            
            tooth_values = np.array(tooth_values)
            actual_points = len(tooth_values)
            
            # 确定评价范围内的数据点
            # 使用实际的起评点和终评点展长来计算索引
            if start_eval_spread is not None and end_eval_spread is not None:
                # 获取起测点和终测点展长（使用英文键名）
                start_meas_spread = self.gear_data.get('profile_meas_start', 0.0)
                end_meas_spread = self.gear_data.get('profile_meas_end', 20.0)
                
                if end_meas_spread > start_meas_spread:
                    # 计算评价范围在测量范围内的比例
                    eval_start_ratio = (start_eval_spread - start_meas_spread) / (end_meas_spread - start_meas_spread)
                    eval_end_ratio = (end_eval_spread - start_meas_spread) / (end_meas_spread - start_meas_spread)
                    
                    start_idx = int(actual_points * max(0.0, min(1.0, eval_start_ratio)))
                    end_idx = int(actual_points * max(0.0, min(1.0, eval_end_ratio)))
                else:
                    start_idx = int(actual_points * 0.2)
                    end_idx = int(actual_points * 0.8)
            else:
                start_idx = 0
                end_idx = actual_points
            
            # 只使用评价范围内的数据
            eval_values = tooth_values[start_idx:end_idx]
            eval_points = len(eval_values)
            
            if eval_points < 3:
                continue
            
            corrected_values, _ = remove_slope_and_crowning_for_undulation(eval_values)
            
            # 计算滚动角 ξ (渐开线极角)
            # 在评价范围内线性分布
            xi_angles_deg = np.linspace(0, 1.0, eval_points)
            
            tooth_index = int(tooth_id) - 1 if isinstance(tooth_id, (int, str)) and str(tooth_id).isdigit() else 0
            if tooth_index < 0:
                tooth_index = 0
            if tooth_index >= teeth_count:
                tooth_index = teeth_count - 1
            
            # 节距角 τ
            tau_angle = tooth_index * pitch_angle_deg
            
            # 旋转角度 φ = -ξ + τ (左齿形用负号)
            final_angles = tau_angle - xi_angles_deg
            
            all_angles.extend(final_angles.tolist())
            all_values.extend(corrected_values.tolist())
            all_tooth_indices.extend([tooth_id] * eval_points)
        
        if not all_angles:
            return None
        
        all_angles = np.array(all_angles)
        all_values = np.array(all_values)
        all_tooth_indices = np.array(all_tooth_indices)
        
        # 归一化到0-360度
        all_angles = all_angles % 360.0
        all_angles[all_angles < 0] += 360.0
        
        # 按角度排序
        sort_indices = np.argsort(all_angles)
        all_angles = all_angles[sort_indices]
        all_values = all_values[sort_indices]
        all_tooth_indices = all_tooth_indices[sort_indices]
        
        return {
            'angles': all_angles,
            'values': all_values,
            'tooth_indices': all_tooth_indices,
            'side': side,
            'type': 'profile'
        }

    def process_helix_data(self, side: str) -> dict:
        """处理齿向数据，计算完整旋转曲线（使用评价范围内数据）
        
        根据标准公式:
        φ = -Δφ + τ
        
        其中:
        - φ: 旋转角度
        - Δφ (delta_phi): 轴向位置产生的旋转 = 2 × L × tan(β) / d
        - τ (tau): 节距角 = 齿序号 × 360° / 齿数
        
        只使用起评点到终评点范围内的数据
        """
        if side not in self.flank_data or not self.flank_data[side]:
            return None
        
        module = self.gear_data.get('module', self.gear_data.get('模数', 0))
        teeth_count = self.gear_data.get('teeth', self.gear_data.get('齿数', 0))
        helix_angle = self.gear_data.get('helix_angle', self.gear_data.get('螺旋角', 0))
        pitch_diameter = module * teeth_count
        
        # 获取起评点和终评点（使用英文键名）
        start_eval = self.gear_data.get('helix_eval_start', None)
        end_eval = self.gear_data.get('helix_eval_end', None)
        
        if teeth_count <= 0:
            logger.warning(f"齿数无效: {teeth_count}，无法进行波纹度分析")
            return None
        
        pitch_angle_deg = 360.0 / teeth_count
        
        side_data = self.flank_data[side]
        sorted_teeth = sorted(side_data.keys())
        
        all_angles = []
        all_values = []
        all_tooth_indices = []
        
        for tooth_id in sorted_teeth:
            tooth_values = side_data[tooth_id]
            if tooth_values is None or len(tooth_values) == 0:
                continue
            
            tooth_values = np.array(tooth_values)
            actual_points = len(tooth_values)
            
            # 确定评价范围内的数据点
            # 使用实际的起评点和终评点来计算索引
            if start_eval is not None and end_eval is not None:
                # 获取起测点和终测点（使用英文键名）
                start_meas = self.gear_data.get('helix_meas_start', 0.0)
                end_meas = self.gear_data.get('helix_meas_end', 42.0)
                
                if end_meas > start_meas:
                    # 计算评价范围在测量范围内的比例
                    eval_start_ratio = (start_eval - start_meas) / (end_meas - start_meas)
                    eval_end_ratio = (end_eval - start_meas) / (end_meas - start_meas)
                    
                    start_idx = int(actual_points * max(0.0, min(1.0, eval_start_ratio)))
                    end_idx = int(actual_points * max(0.0, min(1.0, eval_end_ratio)))
                else:
                    start_idx = int(actual_points * 0.05)  # 从5%开始
                    end_idx = int(actual_points * 0.95)    # 到95%结束
            else:
                start_idx = 0
                end_idx = actual_points
            
            # 只使用评价范围内的数据
            eval_values = tooth_values[start_idx:end_idx]
            eval_points = len(eval_values)
            
            if eval_points < 3:
                continue
            
            corrected_values, _ = remove_slope_and_crowning_for_undulation(eval_values)
            
            # 计算相对轴向距离（从起评点开始的距离）
            # 根据公式: Δφ = 2 × Δz × tan(β) / D₀
            delta_L = end_eval - start_eval  # 评价范围内的轴向距离
            relative_positions = np.linspace(0, delta_L, eval_points)
            
            # 计算轴向位置产生的旋转 Δφ
            if abs(helix_angle) > 0.01:
                delta_phi_angles = 2 * relative_positions * np.tan(np.radians(helix_angle)) / pitch_diameter
                delta_phi_angles = np.degrees(delta_phi_angles)
            else:
                delta_phi_angles = np.linspace(0, 1, eval_points)
            
            tooth_index = int(tooth_id) - 1 if isinstance(tooth_id, (int, str)) and str(tooth_id).isdigit() else 0
            if tooth_index < 0:
                tooth_index = 0
            if tooth_index >= teeth_count:
                tooth_index = teeth_count - 1
            
            # 节距角 τ
            tau_angle = tooth_index * pitch_angle_deg
            
            # 根据左右齿向确定符号
            # 左齿向: φ = τ - Δφ (向左倾斜)
            # 右齿向: φ = τ + Δφ (向右倾斜)
            if side == 'left':
                final_angles = tau_angle - delta_phi_angles
            else:
                final_angles = tau_angle + delta_phi_angles
            
            all_angles.extend(final_angles.tolist())
            all_values.extend(corrected_values.tolist())
            all_tooth_indices.extend([tooth_id] * eval_points)
        
        if not all_angles:
            return None
        
        all_angles = np.array(all_angles)
        all_values = np.array(all_values)
        all_tooth_indices = np.array(all_tooth_indices)
        
        all_angles = all_angles % 360.0
        all_angles[all_angles < 0] += 360.0
        
        sort_indices = np.argsort(all_angles)
        all_angles = all_angles[sort_indices]
        all_values = all_values[sort_indices]
        all_tooth_indices = all_tooth_indices[sort_indices]
        
        return {
            'angles': all_angles,
            'values': all_values,
            'tooth_indices': all_tooth_indices,
            'side': side,
            'type': 'helix'
        }

    def run(self):
        """运行波纹度分析"""
        try:
            if self._is_cancelled:
                return

            self.progress.emit("开始波纹度分析...")
            
            results = {
                'profile': {},
                'flank': {},
                'stats': {
                    'profile': {'total': 0, 'passed': 0, 'failed': 0, 'avg_w': 0.0, 'avg_rms': 0.0},
                    'flank': {'total': 0, 'passed': 0, 'failed': 0, 'avg_w': 0.0, 'avg_rms': 0.0}
                },
                'spectrum_data': {}
            }
            
            teeth_count = self.gear_data.get('teeth', self.gear_data.get('齿数', 0))
            
            self.progress.emit("处理齿形数据...")
            
            for side in ['left', 'right']:
                curve_data = self.process_profile_data(side)
                if curve_data:
                    spectrum_result = analyze_undulation_spectrum(
                        curve_data['angles'], curve_data['values'], teeth_count
                    )
                    
                    high_order = spectrum_result['high_order']
                    w_value = high_order['total_high_order_amplitude']
                    rms_value = high_order['high_order_rms']
                    
                    tolerance = 2.0
                    status = "合格" if w_value <= tolerance else "超差"
                    
                    key = f"{'L' if side == 'left' else 'R'}_profile"
                    
                    result = {
                        'tooth': '全部',
                        'side': side,
                        'data_type': 'profile',
                        'w_value': w_value,
                        'rms_value': rms_value,
                        'tolerance': tolerance,
                        'status': status,
                        'num_features': len(high_order['high_order_waves']),
                        'point_spacing': 0.01,
                        'start_eval_index': 0,
                        'end_eval_index': len(curve_data['values']) - 1,
                        'values': curve_data['values'],
                        'angles': curve_data['angles'],
                        'spectrum': spectrum_result['spectrum'],
                        'high_order': high_order,
                        'orders': spectrum_result['spectrum']['orders'].tolist(),
                        'amplitudes': spectrum_result['spectrum']['amplitudes'].tolist()
                    }
                    
                    results['profile'][key] = result
                    results['spectrum_data'][key] = spectrum_result
                    
                    results['stats']['profile']['total'] += 1
                    if status == "合格":
                        results['stats']['profile']['passed'] += 1
                    else:
                        results['stats']['profile']['failed'] += 1
                    results['stats']['profile']['avg_w'] += w_value
                    results['stats']['profile']['avg_rms'] += rms_value
            
            self.progress.emit("处理齿向数据...")
            
            for side in ['left', 'right']:
                curve_data = self.process_helix_data(side)
                if curve_data:
                    spectrum_result = analyze_undulation_spectrum(
                        curve_data['angles'], curve_data['values'], teeth_count
                    )
                    
                    high_order = spectrum_result['high_order']
                    w_value = high_order['total_high_order_amplitude']
                    rms_value = high_order['high_order_rms']
                    
                    tolerance = 2.0
                    status = "合格" if w_value <= tolerance else "超差"
                    
                    key = f"{'L' if side == 'left' else 'R'}_helix"
                    
                    result = {
                        'tooth': '全部',
                        'side': side,
                        'data_type': 'flank',
                        'w_value': w_value,
                        'rms_value': rms_value,
                        'tolerance': tolerance,
                        'status': status,
                        'num_features': len(high_order['high_order_waves']),
                        'point_spacing': 0.01,
                        'start_eval_index': 0,
                        'end_eval_index': len(curve_data['values']) - 1,
                        'values': curve_data['values'],
                        'angles': curve_data['angles'],
                        'spectrum': spectrum_result['spectrum'],
                        'high_order': high_order,
                        'orders': spectrum_result['spectrum']['orders'].tolist(),
                        'amplitudes': spectrum_result['spectrum']['amplitudes'].tolist()
                    }
                    
                    results['flank'][key] = result
                    results['spectrum_data'][key] = spectrum_result
                    
                    results['stats']['flank']['total'] += 1
                    if status == "合格":
                        results['stats']['flank']['passed'] += 1
                    else:
                        results['stats']['flank']['failed'] += 1
                    results['stats']['flank']['avg_w'] += w_value
                    results['stats']['flank']['avg_rms'] += rms_value
            
            if results['stats']['profile']['total'] > 0:
                results['stats']['profile']['avg_w'] /= results['stats']['profile']['total']
                results['stats']['profile']['avg_rms'] /= results['stats']['profile']['total']
            if results['stats']['flank']['total'] > 0:
                results['stats']['flank']['avg_w'] /= results['stats']['flank']['total']
                results['stats']['flank']['avg_rms'] /= results['stats']['flank']['total']
            
            if not self._is_cancelled:
                self.finished.emit(results)
                
        except Exception as e:
            logger.exception("波纹度分析失败")
            self.progress.emit(f"波纹度分析失败: {str(e)}")


class PitchAnalysisThread(QThread):
    """周节偏差分析线程"""
    finished = pyqtSignal(dict)  # pitch_results
    progress = pyqtSignal(str)
    error = pyqtSignal(str)

    def __init__(self, pitch_data, gear_data, parent=None):
        super().__init__(parent)
        self.pitch_data = pitch_data
        self.gear_data = gear_data
        self._is_cancelled = False

    def cancel(self):
        """请求取消处理"""
        self._is_cancelled = True

    def run(self):
        """运行周节偏差分析"""
        try:
            if self._is_cancelled:
                return

            self.progress.emit("开始周节偏差分析...")
            
            results = {'left': {}, 'right': {}}
            
            # 分析左侧周节数据
            if 'left' in self.pitch_data and self.pitch_data['left']:
                self.progress.emit("分析左侧周节偏差...")
                left_results = self.analyze_pitch_side(self.pitch_data['left'], 'left')
                results['left'] = left_results
            
            # 分析右侧周节数据
            if 'right' in self.pitch_data and self.pitch_data['right']:
                self.progress.emit("分析右侧周节偏差...")
                right_results = self.analyze_pitch_side(self.pitch_data['right'], 'right')
                results['right'] = right_results
            
            if not self._is_cancelled:
                self.finished.emit(results)
                
        except Exception as e:
            logger.exception("周节偏差分析失败")
            self.error.emit(f"周节偏差分析失败: {str(e)}")

    def analyze_pitch_side(self, pitch_data, side):
        """分析单侧周节偏差"""
        try:
            # 提取周节数据 - 处理字典格式的数据
            teeth = []
            fp_values = []
            
            for tooth, data in pitch_data.items():
                if isinstance(data, dict):
                    # 提取fp值
                    teeth.append(tooth)
                    fp_values.append(float(data.get('fp', 0)))
                else:
                    # 跳过无效数据
                    continue
            
            if not teeth or not fp_values:
                return {}
            
            # 正确计算累积周节偏差 Fp
            # Fp = Σ(fp) 从第一个齿到当前齿的累积和
            Fp_values = []
            cumulative_sum = 0
            for fp in fp_values:
                cumulative_sum += fp
                Fp_values.append(cumulative_sum)
            
            # 计算径向跳动 Fr (峰峰值)
            Fr = max(Fp_values) - min(Fp_values) if Fp_values else 0
            
            # 计算统计信息
            fp_max = max(fp_values) if fp_values else 0
            fp_min = min(fp_values) if fp_values else 0
            fp_avg = sum(fp_values) / len(fp_values) if fp_values else 0
            
            Fp_max = max(Fp_values) if Fp_values else 0
            Fp_min = min(Fp_values) if Fp_values else 0
            Fp_avg = sum(Fp_values) / len(Fp_values) if Fp_values else 0
            
            return {
                'teeth': teeth,
                'fp': fp_values,
                'Fp': Fp_values,
                'Fr': Fr,
                'fp_max': fp_max,
                'fp_min': fp_min,
                'fp_avg': fp_avg,
                'Fp_max': Fp_max,
                'Fp_min': Fp_min,
                'Fp_avg': Fp_avg,
                'side': side
            }
            
        except Exception as e:
            logger.error(f"周节偏差分析错误 ({side}): {str(e)}")
            return {}


class DeviationAnalysisThread(QThread):
    """ISO1328齿形和齿向偏差分析线程"""
    finished = pyqtSignal(dict)  # deviation_results
    progress = pyqtSignal(str)
    
    def __init__(self, profile_data, flank_data, pitch_data, gear_data, analysis_settings=None, parent=None):
        super().__init__(parent)
        self.profile_data = profile_data
        self.flank_data = flank_data
        self.pitch_data = pitch_data
        self.gear_data = gear_data
        self.analysis_settings = analysis_settings or {}
        self.cancelled = False
    
    def cancel(self):
        """取消分析"""
        self.cancelled = True
    
    def run(self):
        """执行偏差分析"""
        try:
            # 实现实际的偏差分析逻辑
            results = {
                'profile': {},
                'flank': {},
                'spacing': {},
                'stats': {
                    'profile': {'avg_F_alpha': 0, 'avg_fH_alpha': 0, 'avg_ff_alpha': 0, 'max_F_alpha': 0, 'max_fH_alpha': 0, 'max_ff_alpha': 0, 'passed': 0, 'total': 0},
                    'flank': {'avg_F_beta': 0, 'avg_fH_beta': 0, 'avg_ff_beta': 0, 'max_F_beta': 0, 'max_fH_beta': 0, 'max_ff_beta': 0, 'passed': 0, 'total': 0},
                    'spacing': {'avg_fp': 0, 'avg_Fp': 0, 'avg_Fr': 0, 'max_fp': 0, 'max_Fp': 0, 'max_Fr': 0, 'passed': 0, 'total': 0}
                }
            }
            
            # 分析齿形数据
            if self.profile_data:
                for side in ['left', 'right']:
                    if side in self.profile_data:
                        for tooth_key, tooth_data in self.profile_data[side].items():
                            # 实际计算齿形偏差
                            F_alpha, fH_alpha, ff_alpha = self.calculate_profile_deviations(tooth_data, side)
                            
                            # 使用ISO1328标准计算公差
                            tolerance_F_alpha, tolerance_fH_alpha, tolerance_ff_alpha = self.calculate_tolerances('profile', side)
                            
                            status = "合格" if (F_alpha <= tolerance_F_alpha and abs(fH_alpha) <= tolerance_fH_alpha and ff_alpha <= tolerance_ff_alpha) else "超差"
                            
                            result = {
                                'tooth': tooth_key,
                                'side': side,
                                'data_type': 'profile',
                                'F_alpha': F_alpha,
                                'fH_alpha': fH_alpha,
                                'ff_alpha': ff_alpha,
                                'F_alpha_tolerance': tolerance_F_alpha,
                                'fH_alpha_tolerance': tolerance_fH_alpha,
                                'ff_alpha_tolerance': tolerance_ff_alpha,
                                'F_alpha_status': "合格" if F_alpha <= tolerance_F_alpha else "超差",
                                'fH_alpha_status': "合格" if abs(fH_alpha) <= tolerance_fH_alpha else "超差",
                                'ff_alpha_status': "合格" if ff_alpha <= tolerance_ff_alpha else "超差",
                                'status': status,
                                'values': tooth_data
                            }
                            
                            key = f"{'L' if side == 'left' else 'R'}{tooth_key}"
                            results['profile'][key] = result
                            
                            # 更新统计
                            results['stats']['profile']['total'] += 1
                            if status == "合格":
                                results['stats']['profile']['passed'] += 1
                            results['stats']['profile']['avg_F_alpha'] += F_alpha
                            results['stats']['profile']['avg_fH_alpha'] += fH_alpha
                            results['stats']['profile']['avg_ff_alpha'] += ff_alpha
                            results['stats']['profile']['max_F_alpha'] = max(results['stats']['profile']['max_F_alpha'], F_alpha)
                            results['stats']['profile']['max_fH_alpha'] = max(results['stats']['profile']['max_fH_alpha'], fH_alpha)
                            results['stats']['profile']['max_ff_alpha'] = max(results['stats']['profile']['max_ff_alpha'], ff_alpha)
            
            # 分析齿向数据
            if self.flank_data:
                for side in ['left', 'right']:
                    if side in self.flank_data:
                        for tooth_key, tooth_data in self.flank_data[side].items():
                            # 实际计算齿向偏差
                            F_beta, fH_beta, ff_beta = self.calculate_flank_deviations(tooth_data, side)
                            
                            # 使用ISO1328标准计算公差
                            tolerance_F_beta, tolerance_fH_beta, tolerance_ff_beta = self.calculate_tolerances('flank', side)
                            
                            status = "合格" if (F_beta <= tolerance_F_beta and abs(fH_beta) <= tolerance_fH_beta and ff_beta <= tolerance_ff_beta) else "超差"
                            
                            result = {
                                'tooth': tooth_key,
                                'side': side,
                                'data_type': 'flank',
                                'F_beta': F_beta,
                                'fH_beta': fH_beta,
                                'ff_beta': ff_beta,
                                'F_beta_tolerance': tolerance_F_beta,
                                'fH_beta_tolerance': tolerance_fH_beta,
                                'ff_beta_tolerance': tolerance_ff_beta,
                                'F_beta_status': "合格" if F_beta <= tolerance_F_beta else "超差",
                                'fH_beta_status': "合格" if abs(fH_beta) <= tolerance_fH_beta else "超差",
                                'ff_beta_status': "合格" if ff_beta <= tolerance_ff_beta else "超差",
                                'status': status,
                                'values': tooth_data
                            }
                            
                            key = f"{'L' if side == 'left' else 'R'}{tooth_key}"
                            results['flank'][key] = result
                            
                            # 更新统计
                            results['stats']['flank']['total'] += 1
                            if status == "合格":
                                results['stats']['flank']['passed'] += 1
                            results['stats']['flank']['avg_F_beta'] += F_beta
                            results['stats']['flank']['avg_fH_beta'] += fH_beta
                            results['stats']['flank']['avg_ff_beta'] += ff_beta
                            results['stats']['flank']['max_F_beta'] = max(results['stats']['flank']['max_F_beta'], F_beta)
                            results['stats']['flank']['max_fH_beta'] = max(results['stats']['flank']['max_fH_beta'], fH_beta)
                            results['stats']['flank']['max_ff_beta'] = max(results['stats']['flank']['max_ff_beta'], ff_beta)
            
            # 分析周节数据
            if self.pitch_data:
                for side in ['left', 'right']:
                    if side in self.pitch_data:
                        for tooth_key, tooth_data in self.pitch_data[side].items():
                            # 获取周节偏差值
                            fp = tooth_data.get('fp', 0.0)
                            Fp = tooth_data.get('Fp', 0.0)
                            Fr = tooth_data.get('Fr', 0.0)
                            
                            # 使用ISO1328标准计算公差
                            tolerance_fp, tolerance_Fp, tolerance_Fr = self.calculate_tolerances('spacing', side)
                            
                            status = "合格" if (abs(fp) <= tolerance_fp and abs(Fp) <= tolerance_Fp and abs(Fr) <= tolerance_Fr) else "超差"
                            
                            result = {
                                'tooth': tooth_key,
                                'side': side,
                                'data_type': 'spacing',
                                'fp': fp,
                                'Fp': Fp,
                                'Fr': Fr,
                                'fp_tolerance': tolerance_fp,
                                'Fp_tolerance': tolerance_Fp,
                                'Fr_tolerance': tolerance_Fr,
                                'fp_status': "合格" if abs(fp) <= tolerance_fp else "超差",
                                'Fp_status': "合格" if abs(Fp) <= tolerance_Fp else "超差",
                                'Fr_status': "合格" if abs(Fr) <= tolerance_Fr else "超差",
                                'status': status
                            }
                            
                            key = f"{'L' if side == 'left' else 'R'}{tooth_key}"
                            results['spacing'][key] = result
                            
                            # 更新统计
                            results['stats']['spacing']['total'] += 1
                            if status == "合格":
                                results['stats']['spacing']['passed'] += 1
                            results['stats']['spacing']['avg_fp'] += abs(fp)
                            results['stats']['spacing']['avg_Fp'] += abs(Fp)
                            results['stats']['spacing']['avg_Fr'] += abs(Fr)
                            results['stats']['spacing']['max_fp'] = max(results['stats']['spacing']['max_fp'], abs(fp))
                            results['stats']['spacing']['max_Fp'] = max(results['stats']['spacing']['max_Fp'], abs(Fp))
                            results['stats']['spacing']['max_Fr'] = max(results['stats']['spacing']['max_Fr'], abs(Fr))
            
            # 计算平均值
            if results['stats']['profile']['total'] > 0:
                results['stats']['profile']['avg_F_alpha'] /= results['stats']['profile']['total']
                results['stats']['profile']['avg_fH_alpha'] /= results['stats']['profile']['total']
                results['stats']['profile']['avg_ff_alpha'] /= results['stats']['profile']['total']
            if results['stats']['flank']['total'] > 0:
                results['stats']['flank']['avg_F_beta'] /= results['stats']['flank']['total']
                results['stats']['flank']['avg_fH_beta'] /= results['stats']['flank']['total']
                results['stats']['flank']['avg_ff_beta'] /= results['stats']['flank']['total']
            if results['stats']['spacing']['total'] > 0:
                results['stats']['spacing']['avg_fp'] /= results['stats']['spacing']['total']
                results['stats']['spacing']['avg_Fp'] /= results['stats']['spacing']['total']
                results['stats']['spacing']['avg_Fr'] /= results['stats']['spacing']['total']
            
            self.progress.emit("偏差分析完成")
            self.finished.emit(results)
        except Exception as e:
            logger.error(f"偏差分析错误: {e}")

    def calculate_tolerances(self, data_type, side):
        """根据ISO1328标准计算公差值 - 线程版本"""
        try:
            if not self.gear_data:
                # 默认5级精度公差值
                if data_type == 'spacing':
                    return 12.0, 36.0, 28.0  # fp, Fp, Fr
                return 8.0, 5.6, 3.2  # F, fH, ff
            
            # 获取齿轮参数
            module = self.gear_data.get('module', 2.0)
            teeth = self.gear_data.get('teeth', 20)
            width = self.gear_data.get('width', 20)
            
            # 使用分析设置中的公差模式
            tolerance_mode = self.analysis_settings.get('tolerance_mode', '使用MKA文件默认值')
            iso_grade = self.analysis_settings.get('iso_grade', 5)  # 默认5级精度
            custom_tolerances = self.analysis_settings.get('custom_tolerances', {})
            
            # 如果使用自定义公差
            if tolerance_mode == "自定义自由公差":
                if data_type == 'profile':
                    return (custom_tolerances.get('F_alpha', 8.0), 
                           custom_tolerances.get('fH_alpha', 5.6), 
                           custom_tolerances.get('ff_alpha', 3.2))
                elif data_type == 'spacing':
                    return (custom_tolerances.get('fp', 12.0), 
                           custom_tolerances.get('Fp', 36.0), 
                           custom_tolerances.get('Fr', 28.0))
                else:
                    return (custom_tolerances.get('F_beta', 8.0), 
                           custom_tolerances.get('fH_beta', 5.6), 
                           custom_tolerances.get('ff_beta', 3.2))
            
            # 使用ISO 1328标准或MKA文件默认值
            accuracy_grade = iso_grade if tolerance_mode == "ISO 1328 标准公差" else self.gear_data.get('accuracy_grade', 5)
            
            # 使用固定公差查找表（DIN 3962标准）
            if data_type == 'profile':
                # 齿形公差查找表 (Fa, fHa, ffa)
                profile_tolerance_table = {
                    1: (3.0, 4.0, 5.0),
                    2: (4.0, 6.0, 7.0),
                    3: (5.5, 8.0, 10.0),
                    4: (8.0, 12.0, 14.0),
                    5: (11.0, 16.0, 20.0),
                    6: (16.0, 22.0, 28.0),
                    7: (22.0, 32.0, 40.0),
                    8: (28.0, 45.0, 56.0),
                    9: (40.0, 63.0, 80.0),
                    10: (63.0, 100.0, 125.0),
                    11: (100.0, 160.0, 200.0),
                    12: (160.0, 250.0, 315.0)
                }
                
                if accuracy_grade in profile_tolerance_table:
                    fH_alpha, ff_alpha, F_alpha = profile_tolerance_table[accuracy_grade]
                else:
                    # 默认5级
                    fH_alpha, ff_alpha, F_alpha = profile_tolerance_table[5]
                
                logger.info(f"线程齿形公差（查表） - 精度等级: {accuracy_grade}, F_alpha: {F_alpha:.1f}, fH_alpha: {fH_alpha:.1f}, ff_alpha: {ff_alpha:.1f}")
                
                return F_alpha, fH_alpha, ff_alpha
                
            elif data_type == 'spacing':
                # 周节公差查找表 (fp, Fp, Fr)
                spacing_tolerance_table = {
                    1: (3.0, 9.0, 7.0),
                    2: (4.5, 14.0, 10.0),
                    3: (6.0, 18.0, 14.0),
                    4: (8.0, 25.0, 20.0),
                    5: (12.0, 36.0, 28.0),
                    6: (16.0, 45.0, 40.0),
                    7: (22.0, 71.0, 56.0),
                    8: (32.0, 90.0, 80.0),
                    9: (45.0, 125.0, 110.0),
                    10: (71.0, 200.0, 160.0),
                    11: (110.0, 320.0, 220.0),
                    12: (180.0, 560.0, 320.0)
                }
                
                if accuracy_grade in spacing_tolerance_table:
                    fp, Fp, Fr = spacing_tolerance_table[accuracy_grade]
                else:
                    # 默认5级
                    fp, Fp, Fr = spacing_tolerance_table[5]
                
                logger.info(f"线程周节公差（查表） - 精度等级: {accuracy_grade}, fp: {fp:.1f}, Fp: {Fp:.1f}, Fr: {Fr:.1f}")
                
                return fp, Fp, Fr
                
            else:
                # 齿向公差查找表 (Fb, fHb, ffb)
                lead_tolerance_table = {
                    1: (4.0, 5.0, 6.0),
                    2: (6.0, 7.0, 9.0),
                    3: (8.0, 10.0, 12.0),
                    4: (12.0, 14.0, 18.0),
                    5: (17.0, 20.0, 25.0),
                    6: (24.0, 28.0, 36.0),
                    7: (34.0, 40.0, 50.0),
                    8: (48.0, 56.0, 71.0),
                    9: (68.0, 80.0, 100.0),
                    10: (96.0, 112.0, 140.0),
                    11: (135.0, 160.0, 200.0),
                    12: (190.0, 224.0, 280.0)
                }
                
                if accuracy_grade in lead_tolerance_table:
                    fH_beta, ff_beta, F_beta = lead_tolerance_table[accuracy_grade]
                else:
                    # 默认5级
                    fH_beta, ff_beta, F_beta = lead_tolerance_table[5]
                
                logger.info(f"线程齿向公差（查表） - 精度等级: {accuracy_grade}, F_beta: {F_beta:.1f}, fH_beta: {fH_beta:.1f}, ff_beta: {ff_beta:.1f}")
                
                return F_beta, fH_beta, ff_beta
                
        except Exception as e:
            logger.error(f"线程公差计算错误: {e}")
            # 返回默认5级精度公差值
            if data_type == 'spacing':
                return 12.0, 36.0, 28.0  # fp, Fp, Fr
            return 8.0, 5.6, 3.2

    def calculate_profile_deviations(self, profile_data, side='left'):
        """计算齿形偏差 F_alpha, fH_alpha, ff_alpha - 使用评价区间"""
        try:
            # 提取测量数据
            if isinstance(profile_data, dict):
                if 'values' in profile_data:
                    data = np.array(profile_data['values'])
                else:
                    # 如果没有values字段，尝试其他字段
                    data = np.array(list(profile_data.values()))
            elif isinstance(profile_data, (list, np.ndarray)):
                data = np.array(profile_data)
            else:
                logger.error(f"不支持的profile_data类型: {type(profile_data)}")
                return 0.0, 0.0, 0.0
            
            if len(data) == 0:
                return 0.0, 0.0, 0.0
            
            # 获取评价区间参数
            start_spread = self.gear_data.get('齿形起测点展长', {}).get(side, 0.0)
            start_eval_spread = self.gear_data.get('齿形起评点展长', {}).get(side, 0.0)
            end_eval_spread = self.gear_data.get('齿形终评点展长', {}).get(side, 0.0)
            end_spread = self.gear_data.get('齿形终测点展长', {}).get(side, 0.0)
            
            # 打印参数值用于调试
            logger.debug(f'齿形起测点展长: {start_spread}, 齿形终测点展长: {end_spread}')
            logger.debug(f'总范围: {end_spread - start_spread}')
            
            # 计算点间距
            point_spacing = (end_spread - start_spread) / 479.0
            
            # 打印点间距
            logger.debug(f'点间距={point_spacing:.6f}mm')
            
            # 计算评价区间索引
            start_eval_index = max(0, int((start_eval_spread - start_spread) / point_spacing))
            end_eval_index = min(len(data) - 1, int((end_eval_spread - start_spread) / point_spacing))
            
            # 确保评价区间有效
            if end_eval_index <= start_eval_index:
                start_eval_index = 0
                end_eval_index = len(data) - 1
            
            # 提取评价区间数据
            eval_data = data[start_eval_index:end_eval_index + 1]
            
            if len(eval_data) == 0:
                return 0.0, 0.0, 0.0
            
            # 计算总偏差 F_alpha（峰峰值）
            F_alpha = np.max(eval_data) - np.min(eval_data)
            
            # 计算斜率偏差 fH_alpha
            # 根据 ISO 1328 标准：fHα 是评价范围两端平均齿廓迹线的差值
            # 平均齿廓迹线用最小二乘法拟合
            x = np.arange(len(eval_data))
            coeffs = np.polyfit(x, eval_data, 1)
            trend_line = coeffs[0] * x + coeffs[1]
            # fH_alpha = 趋势线终点值 - 趋势线起点值（可正可负）
            fH_alpha = trend_line[-1] - trend_line[0]
            
            # 计算形状偏差 ff_alpha（去除趋势后的残余分量峰峰值）
            residuals = eval_data - trend_line
            ff_alpha = np.max(residuals) - np.min(residuals)
            
            return F_alpha, fH_alpha, ff_alpha
            
        except Exception as e:
            logger.error(f"齿形偏差计算错误: {e}")
            return 0.0, 0.0, 0.0

    def calculate_flank_deviations(self, flank_data, side='left'):
        """计算齿向偏差 F_beta, fH_beta, ff_beta - 使用评价区间"""
        try:
            # 提取测量数据
            if isinstance(flank_data, dict):
                if 'values' in flank_data:
                    data = np.array(flank_data['values'])
                else:
                    # 如果没有values字段，尝试其他字段
                    data = np.array(list(flank_data.values()))
            elif isinstance(flank_data, (list, np.ndarray)):
                data = np.array(flank_data)
            else:
                logger.error(f"不支持的flank_data类型: {type(flank_data)}")
                return 0.0, 0.0, 0.0
            
            if len(data) == 0:
                return 0.0, 0.0, 0.0
            
            # 获取评价区间参数
            start_point = self.gear_data.get('齿向起测点', {}).get(side, 0.0)
            start_eval_point = self.gear_data.get('齿向起评点', {}).get(side, 0.0)
            end_eval_point = self.gear_data.get('齿向终评点', {}).get(side, 0.0)
            end_point = self.gear_data.get('齿向终测点', {}).get(side, 0.0)
            
            # 打印参数值用于调试
            logger.debug(f'齿向起测点: {start_point}, 齿向终测点: {end_point}')
            logger.debug(f'总范围: {end_point - start_point}')
            
            # 计算点间距
            point_spacing = (end_point - start_point) / 479.0
            
            # 打印点间距
            logger.debug(f'点间距={point_spacing:.6f}mm')
            
            # 计算评价区间索引
            start_eval_index = max(0, int((start_eval_point - start_point) / point_spacing))
            end_eval_index = min(len(data) - 1, int((end_eval_point - start_point) / point_spacing))
            
            # 确保评价区间有效
            if end_eval_index <= start_eval_index:
                start_eval_index = 0
                end_eval_index = len(data) - 1
            
            # 提取评价区间数据
            eval_data = data[start_eval_index:end_eval_index + 1]
            
            if len(eval_data) == 0:
                return 0.0, 0.0, 0.0
            
            # 计算总偏差 F_beta（峰峰值）
            F_beta = np.max(eval_data) - np.min(eval_data)
            
            # 计算斜率偏差 fH_beta
            # 根据 ISO 1328 标准：fHβ 是评价范围两端平均螺旋线迹线的差值
            # 平均螺旋线迹线用最小二乘法拟合
            x = np.arange(len(eval_data))
            coeffs = np.polyfit(x, eval_data, 1)
            trend_line = coeffs[0] * x + coeffs[1]
            # fH_beta = 趋势线终点值 - 趋势线起点值（可正可负）
            fH_beta = trend_line[-1] - trend_line[0]
            
            # 计算形状偏差 ff_beta（去除趋势后的残余分量峰峰值）
            residuals = eval_data - trend_line
            ff_beta = np.max(residuals) - np.min(residuals)
            
            return F_beta, fH_beta, ff_beta
            
        except Exception as e:
            logger.error(f"齿向偏差计算错误: {e}")
            return 0.0, 0.0, 0.0

    def calculate_tolerances(self, data_type, side):
        """根据ISO1328标准计算公差值"""
        try:
            if not self.gear_data:
                # 默认5级精度公差值
                if data_type == 'spacing':
                    return 12.0, 36.0, 28.0  # fp, Fp, Fr
                return 8.0, 5.6, 3.2  # F, fH, ff
            
            # 获取齿轮参数
            module = self.gear_data.get('module', 2.0)
            teeth = self.gear_data.get('teeth', 20)
            width = self.gear_data.get('width', 20)
            
            # 使用分析设置中的公差模式
            tolerance_mode = getattr(self, 'analysis_settings', {}).get('tolerance_mode', '使用MKA文件默认值')
            iso_grade = getattr(self, 'analysis_settings', {}).get('iso_grade', 5)  # 默认5级精度
            custom_tolerances = getattr(self, 'analysis_settings', {}).get('custom_tolerances', {})
            
            # 如果使用自定义公差
            if tolerance_mode == "自定义自由公差":
                if data_type == 'profile':
                    return (custom_tolerances.get('F_alpha', 8.0), 
                           custom_tolerances.get('fH_alpha', 5.6), 
                           custom_tolerances.get('ff_alpha', 3.2))
                elif data_type == 'spacing':
                    return (custom_tolerances.get('fp', 12.0), 
                           custom_tolerances.get('Fp', 36.0), 
                           custom_tolerances.get('Fr', 28.0))
                else:
                    return (custom_tolerances.get('F_beta', 8.0), 
                           custom_tolerances.get('fH_beta', 5.6), 
                           custom_tolerances.get('ff_beta', 3.2))
            
            # 使用ISO 1328标准或MKA文件默认值
            accuracy_grade = iso_grade if tolerance_mode == "ISO 1328 标准公差" else self.gear_data.get('accuracy_grade', 5)
            
            # 计算分度圆直径
            pitch_diameter = module * teeth
            
            # 精度等级系数 (扩展到4-12级)
            grade_factors = {4: 0.63, 5: 1.0, 6: 1.6, 7: 2.5, 8: 4.0, 9: 6.0, 10: 10.0, 11: 16.0, 12: 25.0}
            k = grade_factors.get(accuracy_grade, 1.0)
            
            if data_type == 'profile':
                # 齿形公差计算
                F_alpha_5 = 0.1 * module + 0.45 * math.sqrt(pitch_diameter) + 5
                F_alpha = k * F_alpha_5
                fH_alpha = F_alpha * 0.7  # 通常为F_alpha的70%
                ff_alpha = F_alpha * 0.4   # 通常为F_alpha的40%
                
                # 添加调试信息
                logger.info(f"齿形公差计算 - 模式: {tolerance_mode}, 精度等级: {accuracy_grade}, k系数: {k}")
                logger.info(f"F_alpha_5: {F_alpha_5:.2f}, F_alpha: {F_alpha:.2f}, fH_alpha: {fH_alpha:.2f}, ff_alpha: {ff_alpha:.2f}")
                
                return F_alpha, fH_alpha, ff_alpha
            elif data_type == 'spacing':
                # 周节公差计算 (基于ISO 1328-1:2013)
                # fp: 单个周节偏差公差
                # Fp: 周节总偏差公差  
                # Fr: 径向跳动公差
                fp_5 = 0.6 * math.sqrt(pitch_diameter) + 6.0  # 5级基准
                Fp_5 = 1.8 * math.sqrt(pitch_diameter) + 18.0  # 5级基准
                Fr_5 = 1.4 * math.sqrt(pitch_diameter) + 14.0  # 5级基准
                
                fp = k * fp_5
                Fp = k * Fp_5
                Fr = k * Fr_5
                
                # 添加调试信息
                logger.info(f"周节公差计算 - 模式: {tolerance_mode}, 精度等级: {accuracy_grade}, k系数: {k}")
                logger.info(f"fp_5: {fp_5:.2f}, fp: {fp:.2f}, Fp: {Fp:.2f}, Fr: {Fr:.2f}")
                
                return fp, Fp, Fr
            else:
                # 齿向公差计算
                d_b_ratio = pitch_diameter / width if width > 0 else 1
                F_beta_5 = 0.1 * math.sqrt(d_b_ratio) * width + 0.45 * math.sqrt(width) + 5
                F_beta = k * F_beta_5
                fH_beta = F_beta * 0.7  # 通常为F_beta的70%
                ff_beta = F_beta * 0.4   # 通常为F_beta的40%
                
                # 添加调试信息
                logger.info(f"齿向公差计算 - 模式: {tolerance_mode}, 精度等级: {accuracy_grade}, k系数: {k}")
                logger.info(f"F_beta_5: {F_beta_5:.2f}, F_beta: {F_beta:.2f}, fH_beta: {fH_beta:.2f}, ff_beta: {ff_beta:.2f}")
                
                return F_beta, fH_beta, ff_beta
                
        except Exception as e:
            logger.error(f"公差计算错误: {e}")
            # 返回默认5级精度公差值
            if data_type == 'spacing':
                return 12.0, 36.0, 28.0  # fp, Fp, Fr
            return 8.0, 5.6, 3.2


class RippleAnalysisThread(QThread):
    """波纹度分析线程"""
    finished = pyqtSignal(dict)  # ripple_results
    progress = pyqtSignal(str)
    error = pyqtSignal(str)
    
   
    def __init__(self, profile_data, flank_data, gear_data, ripple_settings=None, parent=None):
        super().__init__(parent)
        self.profile_data = profile_data
        self.flank_data = flank_data
        self.gear_data = gear_data
        self.ripple_settings = ripple_settings or self.get_default_settings()
        self._is_cancelled = False
    
    def cancel(self):
        """取消分析"""
        self._is_cancelled = True
    
    def run(self):
        """执行Ripple分析"""
        try:
            if self._is_cancelled:
                return

            self.progress.emit("开始Ripple分析...")
            
            # 初始化结果结构
            results = {
                'profile': {},
                'flank': {},
                'order_analysis': {},
                'stats': {
                    'profile': {
                        'left_analyzed': False,
                        'right_analyzed': False,
                        'left_ripple': 0.0,
                        'right_ripple': 0.0,
                        'avg_ripple': 0.0,
                        'max_ripple': 0.0,
                        'avg_rms': 0.0,
                        'overall_quality': '未知',
                        'left_consistency': '',
                        'right_consistency': ''
                    },
                    'flank': {
                        'left_analyzed': False,
                        'right_analyzed': False,
                        'left_ripple': 0.0,
                        'right_ripple': 0.0,
                        'avg_ripple': 0.0,
                        'max_ripple': 0.0,
                        'avg_rms': 0.0,
                        'overall_quality': '未知',
                        'left_consistency': '',
                        'right_consistency': ''
                    }
                }
            }

            # 分析齿形数据
            if self.profile_data:
                self.progress.emit("分析齿形Ripple...")
                profile_results = self.analyze_profile_ripple()
                results['profile'] = profile_results
                
                # 更新统计信息
                if profile_results.get('left_analyzed'):
                    results['stats']['profile']['left_analyzed'] = True
                    results['stats']['profile']['left_ripple'] = profile_results.get('left_ripple', 0.0)
                    results['stats']['profile']['left_consistency'] = profile_results.get('left_consistency', '')
                
                if profile_results.get('right_analyzed'):
                    results['stats']['profile']['right_analyzed'] = True
                    results['stats']['profile']['right_ripple'] = profile_results.get('right_ripple', 0.0)
                    results['stats']['profile']['right_consistency'] = profile_results.get('right_consistency', '')

            # 分析齿向数据
            if self.flank_data:
                self.progress.emit("分析齿向Ripple...")
                flank_results = self.analyze_flank_ripple()
                results['flank'] = flank_results
                
                # 更新统计信息
                if flank_results.get('left_analyzed'):
                    results['stats']['flank']['left_analyzed'] = True
                    results['stats']['flank']['left_ripple'] = flank_results.get('left_ripple', 0.0)
                    results['stats']['flank']['left_consistency'] = flank_results.get('left_consistency', '')
                
                if flank_results.get('right_analyzed'):
                    results['stats']['flank']['right_analyzed'] = True
                    results['stats']['flank']['right_ripple'] = flank_results.get('right_ripple', 0.0)
                    results['stats']['flank']['right_consistency'] = flank_results.get('right_consistency', '')

            # 计算平均值和最大值
            self.calculate_average_stats(results['stats'])

            # 生成阶次分析数据
            self.progress.emit("生成阶次分析...")
            order_analysis = self.generate_order_analysis()
            results['order_analysis'] = order_analysis

            if not self._is_cancelled:
                self.finished.emit(results)
                logger.info("Ripple分析完成")

        except Exception as e:
            logger.error(f"Ripple分析错误: {e}")
            self.error.emit(str(e))

    def analyze_profile_ripple(self):
        """分析齿形Ripple"""
        results = {
            'left_analyzed': False,
            'right_analyzed': False,
            'left_ripple': 0.0,
            'right_ripple': 0.0,
            'left_consistency': '',
            'right_consistency': ''
        }
        
        # 分析左齿面
        if 'left' in self.profile_data and self.profile_data['left']:
            left_ripple = self.calculate_ripple_value(self.profile_data['left'], 'profile')
            results['left_analyzed'] = True
            results['left_ripple'] = left_ripple['Wt']  # 使用Wt作为主要波纹度值
            results['left_rms'] = left_ripple['Wq']
            results['left_avg'] = left_ripple['Wa']
            results['left_consistency'] = self.evaluate_consistency(left_ripple['Wt'])
        
        # 分析右齿面
        if 'right' in self.profile_data and self.profile_data['right']:
            right_ripple = self.calculate_ripple_value(self.profile_data['right'], 'profile')
            results['right_analyzed'] = True
            results['right_ripple'] = right_ripple['Wt']  # 使用Wt作为主要波纹度值
            results['right_rms'] = right_ripple['Wq']
            results['right_avg'] = right_ripple['Wa']
            results['right_consistency'] = self.evaluate_consistency(right_ripple['Wt'])
        
        return results

    def analyze_flank_ripple(self):
        """分析齿向Ripple"""
        results = {
            'left_analyzed': False,
            'right_analyzed': False,
            'left_ripple': 0.0,
            'right_ripple': 0.0,
            'left_consistency': '',
            'right_consistency': ''
        }
        
        # 分析左齿面
        if 'left' in self.flank_data and self.flank_data['left']:
            left_ripple = self.calculate_ripple_value(self.flank_data['left'], 'flank')
            results['left_analyzed'] = True
            results['left_ripple'] = left_ripple['Wt']  # 使用Wt作为主要波纹度值
            results['left_rms'] = left_ripple['Wq']
            results['left_avg'] = left_ripple['Wa']
            results['left_consistency'] = self.evaluate_consistency(left_ripple['Wt'])
        
        # 分析右齿面
        if 'right' in self.flank_data and self.flank_data['right']:
            right_ripple = self.calculate_ripple_value(self.flank_data['right'], 'flank')
            results['right_analyzed'] = True
            results['right_ripple'] = right_ripple['Wt']  # 使用Wt作为主要波纹度值
            results['right_rms'] = right_ripple['Wq']
            results['right_avg'] = right_ripple['Wa']
            results['right_consistency'] = self.evaluate_consistency(right_ripple['Wt'])
        
        return results

    def calculate_ripple_value(self, data_dict, data_type='profile'):
        """计算波纹度值 Wt, Wq, Wa"""
        if not data_dict:
            return {'Wt': 0.0, 'Wq': 0.0, 'Wa': 0.0}
        
        # 计算所有齿的波纹度值
        all_wt_values = []
        all_wq_values = []
        all_wa_values = []
        
        for tooth_id, data in data_dict.items():
            if isinstance(data, (list, np.ndarray)) and len(data) > 0:
                # 转换为numpy数组
                data = np.array(data)
                
                # 直接使用原始数据，不进行评价区间裁剪
                eval_data = data
                
                # 确保数据不为零
                if np.all(eval_data == 0):
                    logger.warning(f"齿{tooth_id}数据全为零，跳过")
                    continue
                
                # 去除线性趋势
                x = np.arange(len(eval_data))
                try:
                    coeffs = np.polyfit(x, eval_data, 1)
                    trend = coeffs[0] * x + coeffs[1]
                    detrended_data = eval_data - trend
                except np.RankWarning:
                    # 如果拟合失败，使用原始数据
                    detrended_data = eval_data
                except Exception as e:
                    logger.warning(f"趋势去除失败: {e}")
                    detrended_data = eval_data
                
                # 确保去趋势后数据不为零
                if np.all(detrended_data == 0):
                    detrended_data = eval_data  # 使用原始数据
                
                # 应用截止波长滤波（高斯滤波）
                try:
                   # 获取截止波长设置
                   cutoff_wavelength = self.ripple_settings.get('cutoff_wavelength', 0.8)
    
                   # 计算点间距
                   if data_type == 'profile':
                       # 齿形数据：使用展长范围计算点间距
                       # 确定左右齿面
                       side = 'left' if 'left' in str(data) else 'right'
                       
                       # 获取齿轮测量参数
                       start_spread = self.gear_data.get('齿形起测点展长', {}).get(side, 0.0)
                       end_spread = self.gear_data.get('齿形终测点展长', {}).get(side, 0.0)
                       
                       # 获取齿轮测量特定参数
                       ep = self.gear_data.get('ep', {}).get(side, 0.0)
                       lo = self.gear_data.get('lo', {}).get(side, 0.0)
                       lu = self.gear_data.get('lu', {}).get(side, 0.0)
                       
                       # 优先使用评价范围参数
                       if ep > 0:
                           eval_length = ep
                       elif lo > 0 and lu > 0:
                           eval_length = abs(lu - lo)
                       elif end_spread > start_spread:
                           eval_length = end_spread - start_spread
                       else:
                           eval_length = 10.0  # 默认10mm
                       
                       point_spacing = eval_length / max(1, len(data) - 1)
                   else:
                       # 齿向数据：使用长度范围计算点间距
                       side = 'left' if 'left' in str(data) else 'right'
                       
                       # 获取齿轮测量参数
                       start_point = self.gear_data.get('齿向起测点', {}).get(side, 0.0)
                       end_point = self.gear_data.get('齿向终测点', {}).get(side, 0.0)
                       
                       # 获取齿轮测量特定参数
                       el = self.gear_data.get('el', {}).get(side, 0.0)
                       zc = self.gear_data.get('zc', {}).get(side, 0.0)
                       zu = self.gear_data.get('zu', {}).get(side, 0.0)
                       
                       # 优先使用评价范围参数
                       if el > 0:
                           eval_length = el
                       elif zc > 0 and zu > 0:
                           eval_length = abs(zu - zc)
                       elif end_point > start_point:
                           eval_length = end_point - start_point
                       else:
                           eval_length = 20.0  # 默认20mm
                       
                       point_spacing = eval_length / max(1, len(data) - 1)
                   
                   # 打印点间距
                   logger.debug(f'点间距={point_spacing:.6f}mm')
    
                   # 计算高斯滤波的sigma参数
                   sigma = cutoff_wavelength / (2 * np.sqrt(2 * np.log(2))) / point_spacing
    
                   # 确保sigma在合理范围内
                   sigma = max(0.1, min(sigma, len(detrended_data) / 4))
    
                   # 应用高斯滤波
                   from scipy.ndimage import gaussian_filter1d
                   filtered_data = gaussian_filter1d(detrended_data, sigma)
    
                   logger.debug(f"截止波长滤波: λc={cutoff_wavelength}mm, σ={sigma:.3f}, 点间距={point_spacing}mm")
    
                except Exception as e:
                   logger.warning(f"截止波长滤波失败: {e}，使用去趋势数据")
                   filtered_data = detrended_data

                # 暂时使用原始数据计算波纹度参数
                # 计算波纹度参数（使用原始数据）
                raw_data = eval_data
                Wt = np.max(raw_data) - np.min(raw_data)  # 峰峰值
                Wq = np.sqrt(np.mean(raw_data**2))  # RMS值
                Wa = np.mean(np.abs(raw_data))  # 算术平均值
                
                # 检查数据有效性并记录调试信息
                logger.info(f"齿{tooth_id} 使用原始数据进行分析，未进行去趋势和滤波处理")
                logger.debug(f"齿{tooth_id} 原始数据统计: 最大值={np.max(raw_data):.3f}, 最小值={np.min(raw_data):.3f}, 标准差={np.std(raw_data):.3f}")
                logger.debug(f"齿{tooth_id} 计算结果: Wt={Wt:.3f}, Wq={Wq:.3f}, Wa={Wa:.3f}")
                

                
                # 确保计算结果合理
                if Wt > 0.001 and Wq > 0.001 and Wa > 0.001:
                    all_wt_values.append(Wt)
                    all_wq_values.append(Wq)
                    all_wa_values.append(Wa)
                    logger.debug(f"齿{tooth_id} 最终结果: Wt={Wt:.3f}, Wq={Wq:.3f}, Wa={Wa:.3f}")
                else:
                    logger.warning(f"齿{tooth_id} 计算结果不合理，跳过该齿")
        
        # 返回平均值
        if all_wt_values:
            return {
                'Wt': np.mean(all_wt_values),
                'Wq': np.mean(all_wq_values),
                'Wa': np.mean(all_wa_values)
            }
        else:
            # 如果没有有效数据，返回None表示无数据
            logger.warning(f"没有有效的{data_type}波纹度数据")
            return None
    
    def evaluate_consistency(self, ripple_value):
        """评估一致性"""
        if ripple_value < 2.0:
            return "优秀"
        elif ripple_value < 5.0:
            return "良好"
        elif ripple_value < 10.0:
            return "一般"
        else:
            return "较差"

    def get_evaluation_range_data(self, data, data_type):
        """获取评价区间数据 - 优化版"""
        try:
            # 优化：统一左右齿面判断逻辑
            side = 'left' if 'left' in str(data) else 'right'
            
            if data_type == 'profile':
                # 齿形评价区间
                start_eval_spread = self.gear_data.get('齿形起评点展长', {}).get(side, 0)
                end_eval_spread = self.gear_data.get('齿形终评点展长', {}).get(side, 0)
                start_spread = self.gear_data.get('齿形起测点展长', {}).get(side, 0)
                end_spread = self.gear_data.get('齿形终测点展长', {}).get(side, 0)
                
                # 获取齿轮测量特定参数
                ep = self.gear_data.get('ep', {}).get(side, 0.0)
                lo = self.gear_data.get('lo', {}).get(side, 0.0)
                lu = self.gear_data.get('lu', {}).get(side, 0.0)
                
                # 优先使用评价范围参数
                if ep > 0:
                    eval_length = ep
                elif lo > 0 and lu > 0:
                    eval_length = abs(lu - lo)
                elif end_spread > start_spread:
                    eval_length = end_spread - start_spread
                else:
                    eval_length = 10.0  # 默认10mm
                
                point_spacing = eval_length / max(1, len(data) - 1)
            else:
                # 齿向评价区间
                start_eval_spread = self.gear_data.get('齿向起评点', {}).get(side, 0)
                end_eval_spread = self.gear_data.get('齿向终评点', {}).get(side, 0)
                start_point = self.gear_data.get('齿向起测点', {}).get(side, 0)
                end_point = self.gear_data.get('齿向终测点', {}).get(side, 0)
                
                # 获取齿轮测量特定参数
                el = self.gear_data.get('el', {}).get(side, 0.0)
                zc = self.gear_data.get('zc', {}).get(side, 0.0)
                zu = self.gear_data.get('zu', {}).get(side, 0.0)
                
                # 优先使用评价范围参数
                if el > 0:
                    eval_length = el
                elif zc > 0 and zu > 0:
                    eval_length = abs(zu - zc)
                elif end_point > start_point:
                    eval_length = end_point - start_point
                else:
                    eval_length = 20.0  # 默认20mm
                
                point_spacing = eval_length / max(1, len(data) - 1)
                
                # 为齿向数据定义start_spread和end_spread
                start_spread = start_point
                end_spread = end_point

            # 计算评价区间索引 - 性能优化版
            if point_spacing > 0:
                # 避免重复计算，使用预先计算的值
                start_offset = start_eval_spread - start_spread
                end_offset = end_eval_spread - start_spread
                start_eval_index = max(0, int(start_offset / point_spacing))
                end_eval_index = min(len(data), int(end_offset / point_spacing))
            else:
                # 如果没有点间距信息，使用默认评价区间（中间80%）
                data_len = len(data)
                start_eval_index = int(0.1 * data_len)
                end_eval_index = int(0.9 * data_len)
            
            # 确保索引有效
            start_eval_index = max(0, min(start_eval_index, len(data)-1))
            end_eval_index = max(start_eval_index+1, min(end_eval_index, len(data)))
            
            return data[start_eval_index:end_eval_index]
            
        except Exception as e:
            logger.error(f"获取评价区间数据错误: {e}")
            # 返回中间80%的数据作为默认
            start_idx = int(0.1 * len(data))
            end_idx = int(0.9 * len(data))
            return data[start_idx:end_idx]

    def calculate_average_stats(self, stats):
        """计算平均统计信息 - 性能优化版"""
        # 齿形统计 - 避免重复访问字典键
        profile_stats = stats['profile']
        if profile_stats['left_analyzed'] and profile_stats['right_analyzed']:
            profile_stats['avg_ripple'] = (profile_stats['left_ripple'] + profile_stats['right_ripple']) / 2
            profile_stats['max_ripple'] = max(profile_stats['left_ripple'], profile_stats['right_ripple'])
        elif profile_stats['left_analyzed']:
            profile_stats['avg_ripple'] = profile_stats['left_ripple']
            profile_stats['max_ripple'] = profile_stats['left_ripple']
        elif profile_stats['right_analyzed']:
            profile_stats['avg_ripple'] = profile_stats['right_ripple']
            profile_stats['max_ripple'] = profile_stats['right_ripple']
        
        # 齿向统计 - 避免重复访问字典键
        flank_stats = stats['flank']
        if flank_stats['left_analyzed'] and flank_stats['right_analyzed']:
            flank_stats['avg_ripple'] = (flank_stats['left_ripple'] + flank_stats['right_ripple']) / 2
            flank_stats['max_ripple'] = max(flank_stats['left_ripple'], flank_stats['right_ripple'])
        elif flank_stats['left_analyzed']:
            flank_stats['avg_ripple'] = flank_stats['left_ripple']
            flank_stats['max_ripple'] = flank_stats['left_ripple']
        elif flank_stats['right_analyzed']:
            flank_stats['avg_ripple'] = flank_stats['right_ripple']
            flank_stats['max_ripple'] = flank_stats['right_ripple']

    def generate_order_analysis(self):
        """生成阶次分析数据 - 性能优化版"""
        order_analysis = {}
        
        # 为齿形和齿向生成真实的阶次分析数据
        # 避免重复进行数据类型比较
        if self.profile_data:
            order_analysis['profile'] = self.create_real_order_analysis(self.profile_data, 'profile')
        if self.flank_data:
            order_analysis['flank'] = self.create_real_order_analysis(self.flank_data, 'flank')
        
        return order_analysis

    def create_real_order_analysis(self, data_dict, data_type):
        """基于真实数据创建阶次分析数据 - 使用klingelnberg_ripple_spectrum.py中的方法"""
        try:
            # 直接使用klingelnberg_ripple_spectrum.py中的方法进行频谱分析
            from gear_analysis_refactored.reports.klingelnberg_ripple_spectrum import KlingelnbergRippleSpectrumReport, RippleSpectrumSettings, SpectrumParams
            
            # 创建设置对象
            settings = RippleSpectrumSettings()
            # 禁用去趋势和滤波，使用原始数据
            settings.profile_helix_settings['detrend_settings']['enabled'] = False
            settings.profile_helix_settings['filter_params']['enabled'] = False
            
            # 创建报告对象
            report = KlingelnbergRippleSpectrumReport(settings)
            
            # 获取齿数
            teeth_count = self.gear_data.get('齿数', 0) if hasattr(self, 'gear_data') else 0
            if teeth_count <= 0:
                # 尝试从数据中推断齿数
                inferred_teeth = 0
                for side in ['left', 'right']:
                    side_data = data_dict.get(side, {})
                    if side_data:
                        inferred_teeth = max(inferred_teeth, len(side_data))
                teeth_count = inferred_teeth if inferred_teeth > 0 else 20  # 默认值
            
            # 准备参数
            params = SpectrumParams(
                data_dict=data_dict,
                teeth_count=teeth_count,
                eval_markers=None,
                max_order=200,
                eval_length=None,
                base_diameter=None,
                max_components=50,
                side='left',
                data_type=data_type,
                info=None
            )
            
            # 计算频谱
            # 直接传递params对象给_calculate_spectrum方法
            orders, amplitudes, rms_value = report._calculate_spectrum(params)
            
            if not orders:
                logger.warning(f"{data_type}频谱分析失败，没有有效数据")
                return self.create_default_order_analysis()
            
            # 扩展到200个阶次
            max_orders = 200
            full_orders = list(range(1, max_orders + 1))
            full_amplitudes = [0.0] * max_orders
            
            # 填充振幅数据
            for order, amp in zip(orders, amplitudes):
                if 1 <= order <= max_orders:
                    full_amplitudes[order - 1] = amp
            
            # 找到主要阶次
            mean_amplitude = np.mean(full_amplitudes)
            threshold = mean_amplitude * 1.2
            dominant_indices = [i for i, amp in enumerate(full_amplitudes) if amp > threshold]
            dominant_orders = [i + 1 for i in dominant_indices]  # 转换为1-based索引
            
            return {
                'orders': full_orders,
                'amplitudes': full_amplitudes,
                'dominant_orders': dominant_orders[:5],  # 最多5个主要阶次
                'total_ripple': float(sum(full_amplitudes)),
                'peak_amplitude': float(max(full_amplitudes)) if full_amplitudes else 0.0,
                'data_type': data_type
            }
            
        except Exception as e:
            logger.error(f"阶次分析数据生成错误: {e}")
            return self.create_default_order_analysis()
    
    def _get_evaluation_indices(self, data, eval_range, data_type):
        """获取评价区间的索引 - 性能优化版"""
        try:
            data_len = len(data)
            if data_len == 0:
                return 0, 0
            
            # 获取评价范围参数
            start_eval, end_eval = eval_range
            
            # 如果评价范围为0，使用完整数据
            if start_eval == 0.0 and end_eval == 0.0:
                return 0, data_len
            
            # 根据数据类型获取正确的测量和评价参数
            # 预确定参数前缀，避免重复判断数据类型
            prefix = '齿形' if data_type == 'profile' else '齿向'
            start_key = f'{prefix}起测点展长' if data_type == 'profile' else f'{prefix}起测点'
            end_key = f'{prefix}终测点展长' if data_type == 'profile' else f'{prefix}终测点'
            start_eval_key = f'{prefix}起评点展长' if data_type == 'profile' else f'{prefix}起评点'
            end_eval_key = f'{prefix}终评点展长' if data_type == 'profile' else f'{prefix}终评点'
            
            # 避免重复访问gear_data字典
            gear_data = self.gear_data
            
            # 齿形/齿向数据：获取参数（单位：毫米，转换为微米）
            start_measure = gear_data.get(start_key, {}).get('left', 0.0) * 1000.0  # 毫米转微米
            start_eval_point = gear_data.get(start_eval_key, {}).get('left', 0.0) * 1000.0
            end_eval_point = gear_data.get(end_eval_key, {}).get('left', 0.0) * 1000.0
            end_measure = gear_data.get(end_key, {}).get('left', 0.0) * 1000.0
            
            # 如果用户设置了自定义评价范围，使用用户设置（单位：毫米，转换为微米）
            if start_eval != 0.0 or end_eval != 0.0:
                start_eval_point = start_eval * 1000.0  # 毫米转微米
                end_eval_point = end_eval * 1000.0
            
            # 计算点间距（微米/点）
            if end_measure > start_measure and data_len > 1:
                point_spacing = (end_measure - start_measure) / (data_len - 1)
            else:
                point_spacing = 1000.0  # 默认1mm = 1000μm
            
            # 计算评价区间索引
            start_idx = max(0, int((start_eval_point - start_measure) / point_spacing))
            end_idx = min(data_len, int((end_eval_point - start_measure) / point_spacing))
            
            # 确保索引有效
            if end_idx <= start_idx:
                start_idx = 0
                end_idx = data_len
            return start_idx, end_idx
            
        except Exception as e:
            logger.error(f"计算评价区间索引失败: {e}")
            return 0, len(data)

    # _sine_fit_spectrum_analysis 方法已移除，使用 klingelnberg_ripple_spectrum.py 中的实现
    # _candidate_orders_near_ze_multiples 方法已移除，使用 klingelnberg_ripple_spectrum.py 中的实现
    
    def create_simulated_order_analysis(self, data_type):
        """创建模拟阶次分析数据（当真实数据不可用时）"""
        orders = list(range(1, 201))  # 1-200阶次
        
        # 根据数据类型生成不同的模拟数据
        if data_type == 'profile':
            # 齿形数据：主要阶次在1, 5, 6，扩展到200个阶次
            base_amplitudes = [0.5, 0.372, 0.343, 0.353, 0.376, 0.391, 0.356, 0.357, 
                              0.358, 0.351, 0.344, 0.341, 0.328, 0.336, 0.328]
            # 扩展到200个阶次，后面的阶次逐渐衰减
            amplitudes = base_amplitudes + [0.1 * np.exp(-i/50) for i in range(16, 201)]
        else:
            # 齿向数据：主要阶次在1, 5, 6，扩展到200个阶次
            base_amplitudes = [0.4, 0.297, 0.275, 0.283, 0.301, 0.313, 0.285, 0.286, 
                              0.287, 0.281, 0.275, 0.273, 0.263, 0.269, 0.269]
            # 扩展到200个阶次，后面的阶次逐渐衰减
            amplitudes = base_amplitudes + [0.08 * np.exp(-i/50) for i in range(16, 201)]
        
        # 找到主要阶次
        mean_amplitude = np.mean(amplitudes)
        dominant_orders = [i+1 for i, amp in enumerate(amplitudes) if amp > mean_amplitude * 1.2]
        
        return {
            'orders': orders,
            'amplitudes': amplitudes,
            'dominant_orders': dominant_orders[:10],
            'total_ripple': np.sum(amplitudes),
            'peak_amplitude': np.max(amplitudes),
            'data_type': data_type
        }

    def create_default_order_analysis(self):
        """创建默认阶次分析数据"""
        orders = np.arange(1, 51)
        amplitudes = np.zeros(50)  # 全零数据
        
        return {
            'orders': orders.tolist(),
            'amplitudes': amplitudes.tolist(),
            'dominant_orders': [],
            'total_ripple': 0.0,
            'peak_amplitude': 0.0,
            'data_type': 'unknown'
        }


class RippleAnalysisDialog(QDialog):
    """波纹度分析对话框"""
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setWindowTitle("波纹度分析参数设置")
        self.setGeometry(300, 300, 500, 600)
        
        layout = QVBoxLayout()
        self.setLayout(layout)
        
        # 添加设置控件
        self.setup_ui(layout)
    
    def setup_ui(self, layout):
        """设置UI控件"""
        # 截止波长设置组
        cutoff_group = QGroupBox("截止波长设置 (λc)")
        cutoff_layout = QFormLayout()
        
        # 截止波长设置
        self.cutoff_wavelength = QLineEdit("0.8")
        self.cutoff_wavelength.setValidator(QDoubleValidator(0.1, 10.0, 2))
        cutoff_layout.addRow("截止波长 λc (mm):", self.cutoff_wavelength)
        
        # 截止波长说明
        cutoff_note = QLabel("说明：截止波长用于分离波纹度和粗糙度。\n• 0.8mm：标准设置，适用于大多数齿轮\n• 2.5mm：ISO1328标准，适用于精密齿轮\n• 自定义：根据具体需求调整")
        cutoff_note.setStyleSheet("color: #666; font-size: 10px;")
        cutoff_note.setWordWrap(True)
        cutoff_layout.addRow("", cutoff_note)
        
        cutoff_group.setLayout(cutoff_layout)
        layout.addWidget(cutoff_group)
        
        # 滤波器设置组
        filter_group = QGroupBox("滤波器设置")
        filter_layout = QFormLayout()
        
        # 高通截止频率
        self.highpass_cutoff = QLineEdit("0.01")
        self.highpass_cutoff.setValidator(QDoubleValidator(0.001, 2.0, 3))
        filter_layout.addRow("高通截止频率(周期/mm):", self.highpass_cutoff)
        
        # 低通截止频率
        self.lowpass_cutoff = QLineEdit("1.0")
        self.lowpass_cutoff.setValidator(QDoubleValidator(0.1, 20.0, 2))
        filter_layout.addRow("低通截止频率(周期/mm):", self.lowpass_cutoff)
        
        # 滤波器类型
        self.filter_type = QComboBox()
        self.filter_type.addItems(["Butterworth", "Chebyshev", "Elliptic", "Bessel"])
        self.filter_type.setCurrentText("Butterworth")
        filter_layout.addRow("滤波器类型:", self.filter_type)
        
        # 滤波器阶数
        self.filter_order = QComboBox()
        self.filter_order.addItems(["2", "4", "6", "8", "10"])
        self.filter_order.setCurrentIndex(1)  # 默认4阶
        filter_layout.addRow("滤波器阶数:", self.filter_order)
        
        filter_group.setLayout(filter_layout)
        layout.addWidget(filter_group)
        
        # 阶次分析参数组
        order_group = QGroupBox("阶次分析")
        order_layout = QFormLayout()
        
        # 阶次分析范围
        self.order_range = QLineEdit("1,200")
        order_layout.addRow("阶次分析范围:", self.order_range)
        
        # 关键阶次阈值
        self.threshold = QLineEdit("0.5")
        self.threshold.setValidator(QDoubleValidator(0.1, 10.0, 2))
        order_layout.addRow("关键阶次阈值(%):", self.threshold)
        
        # 基频计算方法
        self.fundamental_method = QComboBox()
        self.fundamental_method.addItems(["基于齿数", "基于周长", "基于转速", "自动检测"])
        self.fundamental_method.setCurrentText("基于齿数")
        order_layout.addRow("基频计算方法:", self.fundamental_method)
        
        # 谐波分析深度
        self.harmonic_depth = QSpinBox()
        self.harmonic_depth.setRange(3, 20)
        self.harmonic_depth.setValue(10)
        order_layout.addRow("谐波分析深度:", self.harmonic_depth)
        
        order_group.setLayout(order_layout)
        layout.addWidget(order_group)
        
        # 高级设置组
        advanced_group = QGroupBox("高级设置")
        advanced_layout = QFormLayout()
        
        # 窗口类型
        self.window_type = QComboBox()
        self.window_type.addItems(["矩形窗", "汉宁窗", "汉明窗", "布莱克曼窗"])
        self.window_type.setCurrentText("汉宁窗")
        advanced_layout.addRow("窗口类型:", self.window_type)
        
        # 重叠率
        self.overlap_ratio = QLineEdit("50")
        self.overlap_ratio.setValidator(QDoubleValidator(0, 100, 1))
        advanced_layout.addRow("重叠率(%):", self.overlap_ratio)
        
        # 零填充
        self.zero_padding = QSpinBox()
        self.zero_padding.setRange(0, 10)
        self.zero_padding.setValue(2)
        advanced_layout.addRow("零填充倍数:", self.zero_padding)
        
        # 启用诊断
        self.enable_diagnosis = QCheckBox("启用详细诊断")
        self.enable_diagnosis.setChecked(True)
        advanced_layout.addRow("", self.enable_diagnosis)
        
        # 诊断深度
        self.diagnosis_depth = QComboBox()
        self.diagnosis_depth.addItems(["基本", "详细", "完整"])
        self.diagnosis_depth.setCurrentText("详细")
        advanced_layout.addRow("诊断深度:", self.diagnosis_depth)
        
        advanced_group.setLayout(advanced_layout)
        layout.addWidget(advanced_group)
        
        # 按钮
        button_box = QDialogButtonBox(QDialogButtonBox.Ok | QDialogButtonBox.Cancel)
        button_box.accepted.connect(self.accept)
        button_box.rejected.connect(self.reject)
        layout.addWidget(button_box)
        
        # 连接截止波长变化事件
        self.cutoff_wavelength.textChanged.connect(self.on_cutoff_wavelength_changed)
    
    def on_cutoff_wavelength_changed(self):
        """截止波长变化时的处理"""
        try:
            cutoff = float(self.cutoff_wavelength.text())
            # 根据截止波长自动调整滤波器参数
            if cutoff <= 0.8:
                self.highpass_cutoff.setText("0.01")
                self.lowpass_cutoff.setText("1.0")
            elif cutoff <= 2.5:
                self.highpass_cutoff.setText("0.005")
                self.lowpass_cutoff.setText("0.5")
            else:
                self.highpass_cutoff.setText("0.002")
                self.lowpass_cutoff.setText("0.2")
        except ValueError:
            pass



    def get_settings(self):
        """获取分析参数"""
        try:
            cutoff_wavelength = float(self.cutoff_wavelength.text())
            highpass = float(self.highpass_cutoff.text())
            lowpass = float(self.lowpass_cutoff.text())
            order = int(self.filter_order.currentText())
            min_order, max_order = map(int, self.order_range.text().split(','))
            threshold = float(self.threshold.text()) / 100  # 转换为小数
            overlap = float(self.overlap_ratio.text())
            
            return {
                # 截止波长设置
                'cutoff_wavelength': cutoff_wavelength,
                
                # 滤波器设置
                'highpass_cutoff': highpass,
                'lowpass_cutoff': lowpass,
                'filter_type': self.filter_type.currentText(),
                'filter_order': order,
                
                # 阶次分析
                'min_order': min_order,
                'max_order': max_order,
                'threshold': threshold,
                'fundamental_method': self.fundamental_method.currentText(),
                'harmonic_depth': self.harmonic_depth.value(),
                
                # 高级设置
                'window_type': self.window_type.currentText(),
                'overlap_ratio': overlap,
                'zero_padding': self.zero_padding.value(),
                'enable_diagnosis': self.enable_diagnosis.isChecked(),
                'diagnosis_depth': self.diagnosis_depth.currentText()
            }
        except ValueError as e:
            QMessageBox.warning(self, "参数错误", f"参数格式错误: {str(e)}")
            return None


