    def _get_3d_view_html(self):
        html = "<h2>3D 齿面形貌图</h2>"
        plot_path = self.plots.get('3d_surface')
        if plot_path:
            side, tooth = self.get_first_available_tooth_for_3d()
            if side and tooth:
                html += f"<p>下图展示了齿号 <b>{tooth} ({'左' if side=='left' else '右'}齿面)</b> 的三维表面偏差分布。</p>"
                html += '<div class="chart-container" style="text-align:center;">'
                html += f'<img src="{os.path.relpath(plot_path, os.path.dirname(self.report_path))}" alt="3D齿面图" style="max-width: 80%;">'
                html += "</div>"
            else:
                html += "<p>无法找到同时拥有齿形和齿向数据的齿。</p>"
        else:
            html += "<p>无可用数据生成3D视图。</p>"
        return html

    def get_first_available_tooth_for_3d(self):
        """为3D报告获取第一个同时拥有齿形和齿向数据的齿"""
        # 检查profile_data和flank_data是否存在且不为None
        if hasattr(self, 'profile_data') and self.profile_data and hasattr(self, 'flank_data') and self.flank_data:
            # 检查左侧数据
            if self.profile_data.get('left') and self.flank_data.get('left'):
                left_profile_teeth = set(self.profile_data['left'].keys())
                left_flank_teeth = set(self.flank_data['left'].keys())
                common_left = sorted(list(left_profile_teeth.intersection(left_flank_teeth)))
                if common_left:
                    return 'left', common_left[0]
            
            # 检查右侧数据
            if self.profile_data.get('right') and self.flank_data.get('right'):
                right_profile_teeth = set(self.profile_data['right'].keys())
                right_flank_teeth = set(self.flank_data['right'].keys())
                common_right = sorted(list(right_profile_teeth.intersection(right_flank_teeth)))
                if common_right:
                    return 'right', common_right[0]
        return None, None

    def _create_deviation_plot(self, data_type):
        """为偏差数据创建并保存图表"""
        results_group = self.deviation_results.get(data_type, {})
        if not results_group: 
            return None

        fig, ax = plt.subplots(figsize=(12, 8))
        all_values = []
        
        # 设置中文字体
        plt.rcParams['font.sans-serif'] = ['SimHei', 'Microsoft YaHei']
        plt.rcParams['axes.unicode_minus'] = False
        
        for key, result in results_group.items():
            side = result.get('side', 'N/A')
            tooth = result.get('tooth', 'N/A')
            
            # 安全地获取原始数据
            raw_data = None
            if data_type == 'profile' and hasattr(self, 'profile_data') and self.profile_data:
                raw_data = self.profile_data.get(side, {}).get(tooth)
            elif data_type == 'flank' and hasattr(self, 'flank_data') and self.flank_data:
                raw_data = self.flank_data.get(side, {}).get(tooth)
            
            if raw_data is not None and len(raw_data) > 0:
                eval_start = result.get('start_eval_index', 0)
                eval_end = result.get('end_eval_index', len(raw_data)-1)
                
                # 确保索引在有效范围内
                eval_start = max(0, min(eval_start, len(raw_data)-1))
                eval_end = max(eval_start, min(eval_end, len(raw_data)-1))
                
                y_values = raw_data[eval_start:eval_end+1]
                if len(y_values) > 0:
                    x_values = np.linspace(0, 100, len(y_values))
                    ax.plot(x_values, y_values, alpha=0.4, linewidth=1)
                    all_values.append(y_values)
        
        if all_values:
            try:
                max_len = max(len(v) for v in all_values)
                padded_values = [np.pad(v, (0, max_len - len(v)), 'mean') for v in all_values]
                avg_values = np.mean(padded_values, axis=0)
                x_values = np.linspace(0, 100, len(avg_values))
                ax.plot(x_values, avg_values, 'r-', linewidth=3, label='平均曲线')
            except Exception as e: 
                logger.error(f"计算平均曲线失败: {e}")

        ax.set_title(f"{'齿形' if data_type == 'profile' else '齿向'}偏差曲线", fontsize=16, fontweight='bold')
        ax.set_xlabel("评价长度 (%)", fontsize=12)
        ax.set_ylabel("偏差 (μm)", fontsize=12)
        ax.grid(True, linestyle='--', alpha=0.6)
        ax.legend(fontsize=10)
        
        # 确保图片目录存在
        os.makedirs(self.img_dir, exist_ok=True)
        
        plot_path = os.path.join(self.img_dir, f"deviation_{data_type}.png")
        fig.savefig(plot_path)
        plt.close(fig)
        
        logger.info(f"已生成{data_type}偏差图表: {plot_path}")
        return plot_path


    def _get_pitch_html(self):
        """生成周节偏差分析部分的HTML，参照窗体格式"""
        if not self.pitch_results or not (self.pitch_results.get('left') or self.pitch_results.get('right')):
            return "<h2>周节偏差分析</h2><p>未执行周节偏差分析。</p>"

        left_data = self.pitch_results.get('left', {})
        right_data = self.pitch_results.get('right', {})
        
        # 提取周节数据
        left_teeth = left_data.get('teeth', [])
        left_fp_values = left_data.get('fp', [])
        left_Fp_values = left_data.get('Fp', [])
        left_Fr_value = left_data.get('Fr', 0)
        
        right_teeth = right_data.get('teeth', [])
