        filter_type_layout.addRow("滤波类型:", self.filter_type_combo)
        
        # 滤波说明
        filter_note = QLabel("说明：\n• 无滤波：直接使用原始数据\n• 低通滤波：去除高频噪声\n• 高通滤波：去除低频趋势\n• 带通滤波：保留特定频率范围\n• 截止波长滤波：去除特定波长以下的成分\n• 自定义滤波：使用自定义滤波器")
        filter_note.setStyleSheet("color: #666; font-size: 10px;")
