    def init_waterfall_chart(self):
        """初始化瀑布图, 显示默认内容"""
        self.waterfall_figure.clear()
        ax = self.waterfall_figure.add_subplot(111, projection='3d')
        ax.text2D(0.5, 0.5, '请先运行Ripple分析以生成时频瀑布图', 
                  horizontalalignment='center', verticalalignment='center',
                  transform=ax.transAxes, fontsize=14, color='gray')
        ax.set_title("时频瀑布图")
        self.waterfall_canvas.draw()
    
    # 缓存STFT计算结果以提高性能
    _stft_cache = {}
    _last_ripple_results_id = None
    
    def plot_waterfall_analysis(self):
        """绘制时频瀑布图 - 性能优化版"""
        logger.info("开始绘制时频瀑布图")
        
        # 快速检查：如果没有分析结果，立即显示提示信息
        if not self.ripple_results:
            self.waterfall_figure.clear()
            ax = self.waterfall_figure.add_subplot(111, projection='3d')
            ax.text2D(0.5, 0.5, "无Ripple分析数据", ha='center', va='center', transform=ax.transAxes)
            self.waterfall_canvas.draw()
            return
        
        # 检查数据是否存在
        analysis_data = self.ripple_results.get('order_analysis', {}).get('profile') or \
                       self.ripple_results.get('order_analysis', {}).get('flank')
        
        if not analysis_data or 'stft_results' not in analysis_data or not analysis_data['stft_results']:
            self.waterfall_figure.clear()
            ax = self.waterfall_figure.add_subplot(111, projection='3d')
            ax.text2D(0.5, 0.5, "无STFT数据，无法生成瀑布图", ha='center', va='center', transform=ax.transAxes)
            ax.set_title("时频瀑布图 (无数据)")
            self.waterfall_canvas.draw()
            return
        
        # 使用缓存键避免重复绘制相同数据
        stft_data = analysis_data['stft_results']
        cache_key = (id(self.ripple_results), 
                    stft_data.get('hash', hash(str(stft_data['frequencies']) + str(stft_data['times']))))
        
        # 只有数据变化或首次绘制时才重新计算和绘制
        if cache_key not in self.__class__._stft_cache:
            self.waterfall_figure.clear()
            ax = self.waterfall_figure.add_subplot(111, projection='3d')
            
            # 使用numpy优化网格创建
            f, t, Zxx = stft_data['frequencies'], stft_data['times'], stft_data['magnitudes']
            
            # 内存优化：使用更高效的数据类型
            if isinstance(Zxx, np.ndarray):
                # 如果数据很大，考虑降采样或使用更高效的数据类型
                if Zxx.size > 1000000:
                    # 对大型数据进行降采样以提高性能
                    step = max(1, int(np.sqrt(Zxx.size / 1000000)))
                    f = f[::step]
                    t = t[::step]
                    Zxx = Zxx[::step, ::step]
                    logger.info(f"已对大型STFT数据进行降采样，步长: {step}")
                
                # 使用float32提高性能和减少内存使用
                if Zxx.dtype == np.float64:
                    Zxx = Zxx.astype(np.float32)
            
            # 优化网格创建
            T, F = np.meshgrid(t, f, indexing='xy')
            
            # 绘制优化：使用rstride和cstride减少渲染点数
            stride = 1
            if F.shape[0] > 200 or F.shape[1] > 200:
                stride = max(1, min(F.shape[0], F.shape[1]) // 200)
            
            surf = ax.plot_surface(T, F, Zxx, cmap=plt.get_cmap('viridis'),
                                 rstride=stride, cstride=stride, alpha=0.9)
            
            ax.set_title(f"{analysis_data.get('data_type', 'N/A').capitalize()} 时频瀑布图")
            ax.set_xlabel('测量位置'), ax.set_ylabel('频率 (Hz)'), ax.set_zlabel('幅值')
            
            # 保存到缓存
            self.__class__._stft_cache[cache_key] = {
                'figure_state': self.waterfall_figure,
                'axes_state': ax
            }
        
        # 立即绘制以提高响应速度
        self.waterfall_canvas.draw_idle()  # 使用draw_idle替代draw，减少不必要的重绘
        logger.info("时频瀑布图绘制完成")
        
    def clear_cache(self):
        """清理缓存，在数据更新时调用"""
        self.__class__._stft_cache.clear()
        logger.info("已清理图表缓存")

