    def _delayed_create_pages(self):
        """延迟创建页面组件，避免启动时卡顿"""
        try:
            logger.info("开始延迟创建页面组件")
            self.create_pages()
            
            # 设置默认选中项（基本信息）
            for i in range(self.nav_tree_widget.topLevelItemCount()):
                root_item = self.nav_tree_widget.topLevelItem(i)
                if root_item.text(0) == "功能导航":
                    for j in range(root_item.childCount()):
                        child_item = root_item.child(j)
                        if child_item.text(0) == "基本信息":
                            self.nav_tree_widget.setCurrentItem(child_item)
                            break
                break

            # 设置默认页面为报表页面
            self.stacked_widget.setCurrentIndex(10)

            # 主布局已经在初始化时设置，不需要再次添加

            # 按钮引用已经在初始化时创建，不需要再次赋值
            
            # 恢复导航栏状态
            self.restore_nav_state()
            
            # 启用自动隐藏功能
            self.enable_nav_autohide()
        except Exception as e:
            logger.error(f"延迟创建页面组件时出错: {str(e)}")
            import traceback
            logger.error(traceback.format_exc())

    def create_floating_navigation(self):
        """创建浮动导航栏"""
        from PyQt5.QtWidgets import QDockWidget, QPushButton, QHBoxLayout
        
        # 创建停靠窗口作为导航栏
        self.nav_dock = QDockWidget("导航菜单", self)
        self.nav_dock.setObjectName("navigation_dock_widget")  # 设置objectName
        self.nav_dock.setAllowedAreas(Qt.LeftDockWidgetArea | Qt.RightDockWidgetArea | Qt.TopDockWidgetArea | Qt.BottomDockWidgetArea)
        self.nav_dock.setFeatures(QDockWidget.DockWidgetMovable | QDockWidget.DockWidgetFloatable | QDockWidget.DockWidgetClosable)
        
        # 创建导航栏内容
        nav_widget = QWidget()
        nav_layout = QVBoxLayout(nav_widget)
        
        # 导航栏标题和控制按钮
        title_layout = QHBoxLayout()
        nav_title = QLabel("功能导航")
        nav_title.setFont(QFont("Arial", 12, QFont.Bold))
        nav_title.setAlignment(Qt.AlignCenter)
        nav_title.setStyleSheet("background-color: #F9F6F0; color: #333333; padding: 8px; border-radius: 4px; border: 1px solid #D9CFC1;")
        title_layout.addWidget(nav_title)
        
        # 添加控制按钮
        pin_btn = QPushButton("📌")
        pin_btn.setToolTip("固定/浮动导航栏")
        pin_btn.setStyleSheet("""
            QPushButton {
                background-color: #F9F6F0;
                color: #333333;
                border: 1px solid #7A9E7E;
                border-radius: 4px;
                padding: 4px;
                font-size: 14px;
            }
            QPushButton:hover {
                background-color: #D9CFC1;
            }
        """)
        pin_btn.clicked.connect(self.toggle_nav_pin)
        title_layout.addWidget(pin_btn)
        
        nav_layout.addLayout(title_layout)
        
        # 创建树形控件
        self.nav_tree_widget = QTreeWidget()
        self.nav_tree_widget.setHeaderHidden(True)
        self.nav_tree_widget.setStyleSheet("""
            QTreeWidget {
                background-color: #F9F6F0;
                font-size: 12px;
                border: 1px solid #D9CFC1;
                border-radius: 4px;
            }
            QTreeWidget::item {
                height: 30px;
                padding-left: 10px;
                border-radius: 2px;
                margin: 1px;
            }
            QTreeWidget::item:selected {
                background-color: #7A9E7E;
                color: #F9F6F0;
            }
            QTreeWidget::item:hover {
                background-color: #D9CFC1;
            }
        """)
        
        # 添加树形节点
        root = QTreeWidgetItem(self.nav_tree_widget, ["功能导航"])
        
        # 第一级节点 - 只保留文件操作、基础信息、报表工具和设置
        file_item = QTreeWidgetItem(root, ["📁 文件操作"])
        basic_item = QTreeWidgetItem(root, ["📊 基础信息"])
        report_item = QTreeWidgetItem(root, ["📄 报表工具"])
        settings_item = QTreeWidgetItem(root, ["⚙️ 设置"])
        
        # 第二级节点 (文件操作)
        QTreeWidgetItem(file_item, ["📂 打开文件"])
        QTreeWidgetItem(file_item, ["📂 批量处理"])
        
        # 第二级节点 (基础信息)
        QTreeWidgetItem(basic_item, ["ℹ️ 基本信息"])
        QTreeWidgetItem(basic_item, ["⚙️ 齿轮参数"])
        QTreeWidgetItem(basic_item, ["🔄 左右齿面"])
        
        # 第二级节点 (报表工具)
        QTreeWidgetItem(report_item, ["📄 齿轮综合分析报表"])
        QTreeWidgetItem(report_item, ["📄 生成PDF报告"])
        
        # 第二级节点 (设置)
        QTreeWidgetItem(settings_item, ["📊 波纹度公差设置"])
        
        # 展开所有节点
        self.nav_tree_widget.expandAll()
        
        nav_layout.addWidget(self.nav_tree_widget)
        nav_layout.setContentsMargins(5, 5, 5, 5)
        
        # 设置停靠窗口内容
        self.nav_dock.setWidget(nav_widget)
        
        # 设置停靠窗口初始大小和位置
        self.nav_dock.setMinimumWidth(250)
        self.nav_dock.setMaximumWidth(350)
        
        # 添加到主窗口
        self.addDockWidget(Qt.LeftDockWidgetArea, self.nav_dock)
        
        # 连接关闭事件，防止导航栏被完全关闭
        self.nav_dock.visibilityChanged.connect(self.on_nav_visibility_changed)
        
        # 启用右键菜单
        self.nav_tree_widget.setContextMenuPolicy(Qt.CustomContextMenu)
        self.nav_tree_widget.customContextMenuRequested.connect(self.show_nav_context_menu)
        
        # 保存按钮引用
        self.pin_btn = pin_btn
        self.nav_is_pinned = False
        
        # 初始化自动隐藏定时器
        self._nav_auto_hide_timer = QTimer(self)
        self._nav_auto_hide_timer.setSingleShot(True)
        self._nav_auto_hide_timer.timeout.connect(self._hide_nav_dock)
        
        # 启用自动嵌入功能
        self.enable_auto_dock()

    def toggle_nav_pin(self):
        """切换导航栏固定状态"""
        from PyQt5.QtWidgets import QDockWidget
        
        if self.nav_is_pinned:
            # 取消固定，允许浮动
            self.nav_dock.setFeatures(QDockWidget.DockWidgetMovable | QDockWidget.DockWidgetFloatable | QDockWidget.DockWidgetClosable)
            self.pin_btn.setText("📌")
            self.pin_btn.setToolTip("固定导航栏")
            self.nav_is_pinned = False
        else:
            # 固定导航栏
            self.nav_dock.setFeatures(QDockWidget.DockWidgetClosable)
            self.pin_btn.setText("🔓")
            self.pin_btn.setToolTip("取消固定")
            self.nav_is_pinned = True

    def on_nav_visibility_changed(self, visible):
        """导航栏可见性改变时的处理"""
        if not visible:
            # 如果导航栏被关闭，重新显示它
            self.nav_dock.show()

    def show_nav_context_menu(self, position):
        """显示导航栏右键菜单"""
        from PyQt5.QtWidgets import QMenu
        
        item = self.nav_tree_widget.itemAt(position)
        if not item:
            return
            
        menu = QMenu(self.nav_tree_widget)
        
        # 添加菜单项
        expand_action = menu.addAction("展开所有")
        collapse_action = menu.addAction("折叠所有")
        menu.addSeparator()
        
        # 根据选中项添加特定操作
        item_text = item.text(0)
        if "文件操作" in item_text:
            menu.addAction("快速打开文件", self.open_mka_file)
        elif "基本信息" in item_text:
            menu.addAction("刷新数据", self.refresh_basic_info)
        elif "Ripple分析" in item_text:
            menu.addAction("开始Ripple分析", lambda: self.start_ripple_analysis())
        elif "ISO1328偏差" in item_text:
            menu.addAction("开始偏差分析", lambda: self.analyze_deviation())
        
        # 连接信号
        expand_action.triggered.connect(self.nav_tree_widget.expandAll)
        collapse_action.triggered.connect(self.nav_tree_widget.collapseAll)
        
        # 显示菜单
        menu.exec_(self.nav_tree_widget.mapToGlobal(position))

    def save_nav_state(self):
        """保存导航栏状态"""
        from PyQt5.QtCore import QSettings
        
        settings = QSettings("GearAnalysis", "Navigation")
        settings.setValue("nav_dock_geometry", self.nav_dock.saveGeometry())
        settings.setValue("nav_dock_state", self.saveState())
        settings.setValue("nav_dock_floating", self.nav_dock.isFloating())
        settings.setValue("nav_is_pinned", self.nav_is_pinned)
        settings.setValue("nav_auto_hide_enabled", self._nav_auto_hide_enabled)

    def restore_nav_state(self):
        """恢复导航栏状态"""
        from PyQt5.QtCore import QSettings
        
        settings = QSettings("GearAnalysis", "Navigation")
        if settings.contains("nav_dock_geometry"):
            self.nav_dock.restoreGeometry(settings.value("nav_dock_geometry"))
        if settings.contains("nav_dock_state"):
            self.restoreState(settings.value("nav_dock_state"))
        if settings.contains("nav_dock_floating"):
            self.nav_dock.setFloating(settings.value("nav_dock_floating", type=bool))
        if settings.contains("nav_is_pinned"):
            self.nav_is_pinned = settings.value("nav_is_pinned", type=bool)
            if self.nav_is_pinned:
                self.pin_btn.setText("🔓")
                self.pin_btn.setToolTip("取消固定")
        if settings.contains("nav_auto_hide_enabled"):
            self._nav_auto_hide_enabled = settings.value("nav_auto_hide_enabled", type=bool)

    def enable_nav_autohide(self):
        """启用导航栏自动隐藏功能"""
        if hasattr(self, 'nav_dock') and self.nav_dock:
            self.nav_dock.installEventFilter(self)

    def eventFilter(self, obj, event):
        """事件过滤器，处理导航栏自动隐藏和自动嵌入"""
        # 添加递归保护
        if hasattr(self, '_event_filter_recursion_depth'):
            self._event_filter_recursion_depth += 1
            if self._event_filter_recursion_depth > 10:  # 防止无限递归
                return super().eventFilter(obj, event)
        else:
            self._event_filter_recursion_depth = 1
        
        try:
            if obj == self.nav_dock:
                # 处理自动隐藏
                if hasattr(self, '_nav_auto_hide_enabled') and self._nav_auto_hide_enabled:
                    if event.type() == QEvent.Enter:
                        self._show_nav_dock()
                        if self._nav_auto_hide_timer and self._nav_auto_hide_timer.isActive():
                            self._nav_auto_hide_timer.stop()
                    elif event.type() == QEvent.Leave:
                        if self._nav_auto_hide_timer:
                            self._nav_auto_hide_timer.start(800)  # 800ms后收起
                
                # 处理自动嵌入
                if hasattr(self, '_auto_dock_enabled') and self._auto_dock_enabled:
                    if event.type() == QEvent.Move:
                        # 检查是否需要自动嵌入
                        self.check_auto_dock()
                    elif event.type() == QEvent.MouseButtonRelease:
                        # 鼠标释放时也检查一次
                        self.check_auto_dock()
            
            return super().eventFilter(obj, event)
        finally:
            # 减少递归深度
            if hasattr(self, '_event_filter_recursion_depth'):
                self._event_filter_recursion_depth -= 1

    def _show_nav_dock(self):
        """展开导航栏"""
        if hasattr(self, 'nav_dock') and self.nav_dock and not self.nav_dock.isFloating():
            self.nav_dock.setMaximumWidth(self._nav_expanded_width)

    def _hide_nav_dock(self):
        """收起导航栏"""
        if hasattr(self, 'nav_dock') and self.nav_dock and not self.nav_dock.isFloating():
            self.nav_dock.setMaximumWidth(self._nav_collapsed_width)

    def enable_auto_dock(self):
        """启用自动嵌入功能"""
        if hasattr(self, 'nav_dock') and self.nav_dock:
            # 安装事件过滤器到导航栏
            self.nav_dock.installEventFilter(self)
            # 初始化自动嵌入相关变量
            self._auto_dock_enabled = True
            self._dock_threshold = 50  # 距离左边界的阈值（像素）
            self._last_dock_check_time = 0
            self._dock_check_interval = 100  # 检查间隔（毫秒）

    def check_auto_dock(self):
        """检查是否需要自动嵌入"""
        if not hasattr(self, '_auto_dock_enabled') or not self._auto_dock_enabled:
            return
            
        if not self.nav_dock or not self.nav_dock.isFloating():
            return
            
        # 获取导航栏的位置
        dock_pos = self.nav_dock.mapToParent(self.nav_dock.rect().topLeft())
        dock_x = dock_pos.x()
        
        # 如果导航栏靠近左边界，自动嵌入
        if dock_x <= self._dock_threshold:
            self.auto_dock_to_left()

    def auto_dock_to_left(self):
        """自动嵌入到左边"""
        if self.nav_dock and self.nav_dock.isFloating():
            # 停止浮动状态
            self.nav_dock.setFloating(False)
            # 重新添加到左边停靠区域
            self.addDockWidget(Qt.LeftDockWidgetArea, self.nav_dock)
            # 显示状态消息（安全检查）
            if hasattr(self, 'status_bar') and self.status_bar:
                self.status_bar.showMessage("导航栏已自动嵌入到左边", 2000)

