    def create_pages(self):
        """创建页面管理系统 - 实现页面的延迟加载以提高启动性能"""
        logger.info("初始化页面管理系统")
        
        # 页面定义和初始化状态管理
        self._page_config = {
            'basic': {'init_func': self.init_basic_tab, 'loaded': False},
            'params': {'init_func': self.init_params_tab, 'loaded': False},
            'sides': {'init_func': self.init_sides_tab, 'loaded': False},
            'flank': {'init_func': lambda layout: self.init_flank_tab(layout, "齿向数据", "Flankenlinie"), 'loaded': False},
            'profile': {'init_func': lambda layout: self.init_flank_tab(layout, "齿形数据", "Profil"), 'loaded': False},
            'curve': {'init_func': self.init_curve_tab, 'loaded': False},
            'undulation': {'init_func': self.init_undulation_tab, 'loaded': False},
            'deviation': {'init_func': self.init_deviation_tab, 'loaded': False},
            'ripple': {'init_func': self.init_ripple_tab, 'loaded': False},
            'pitch': {'init_func': self.init_pitch_tab, 'loaded': False},
            'report': {'init_func': self.init_report_tab, 'loaded': False},
            'batch': {'init_func': self.init_batch_tab, 'loaded': False}
        }
        
        # 存储页面控件引用
        self._pages = {}
        
        # 预加载最重要的页面（基本信息、参数和齿面参数）
        priority_pages = ['basic', 'params', 'sides']
        
        # 为所有页面创建占位符，但只初始化优先级页面
        for page_name, config in self._page_config.items():
            page_widget = QWidget()
            page_layout = QVBoxLayout(page_widget)
            page_layout.setContentsMargins(0, 0, 0, 0)
            
            # 对于非优先级页面，添加加载占位符
            if page_name not in priority_pages:
                placeholder = QLabel(f"页面 '{page_name}' 正在加载...")
                placeholder.setAlignment(Qt.AlignCenter)
                placeholder.setObjectName(f"{page_name}_placeholder")
                page_layout.addWidget(placeholder)
                
            # 存储页面信息
            self._pages[page_name] = {
                'widget': page_widget,
                'layout': page_layout
            }
            
            # 添加到堆叠窗口
            self.stacked_widget.addWidget(page_widget)
            
            # 初始化优先级页面
            if page_name in priority_pages:
                self._load_page(page_name)
        
        # 连接页面切换信号以实现按需加载
        self.nav_tree_widget.currentItemChanged.connect(self._handle_page_switch)
        
        logger.info("页面管理系统初始化完成，已预加载核心页面")
    
    def _load_page(self, page_name):
        """加载指定的页面"""
        if page_name not in self._page_config or self._page_config[page_name]['loaded']:
            return
        
        logger.info(f"开始加载页面: {page_name}")
        
        try:
            page_info = self._pages[page_name]
            page_layout = page_info['layout']
            
            # 移除占位符（如果存在）
            placeholder = page_info['widget'].findChild(QLabel, f"{page_name}_placeholder")
            if placeholder:
                placeholder.deleteLater()
            else:
                # 清空布局中的所有项目
                while page_layout.count() > 0:
                    item = page_layout.takeAt(0)
                    if item.widget():
                        item.widget().deleteLater()
            
            # 调用初始化函数
            init_func = self._page_config[page_name]['init_func']
            result = init_func(page_layout)
            
            # 处理特殊返回值（如flank和profile页面）
            if page_name == 'flank' and isinstance(result, tuple):
                self.flank_text_area, self.flank_status_label = result
            elif page_name == 'profile' and isinstance(result, tuple):
                self.profile_text_area, self.profile_status_label = result
            
            # 标记为已加载
            self._page_config[page_name]['loaded'] = True
            logger.info(f"页面加载完成: {page_name}")
            
        except Exception as e:
            logger.error(f"页面加载失败 {page_name}: {str(e)}")
            # 添加错误信息标签
            error_label = QLabel(f"页面加载失败: {str(e)}")
            error_label.setStyleSheet("color: red; font-weight: bold;")
            error_label.setAlignment(Qt.AlignCenter)
            page_info['layout'].addWidget(error_label)
    
    def _handle_page_switch(self, current, previous):
        """处理页面切换事件，实现按需加载"""
        if not current:
            return
        
        # 根据选择的菜单项确定要加载的页面
        page_name = self._get_page_name_from_item(current)
        if page_name and page_name in self._page_config:
            # 使用QTimer延迟加载，避免阻塞UI
            QTimer.singleShot(50, lambda: self._load_page(page_name))
    
    def _get_page_name_from_item(self, tree_item):
        """根据树节点获取对应的页面名称"""
        # 这里需要根据实际的树形菜单结构进行映射
        # 返回与菜单项目对应的页面标识符
        item_text = tree_item.text(0)
        
        # 页面名称映射字典
        page_mapping = {
            '基本信息': 'basic',
            '齿轮参数': 'params', 
            '左右齿面参数': 'sides',
            '齿向数据': 'flank',
            '齿形数据': 'profile',
            '曲线分析': 'curve',
            '波纹度分析': 'undulation',
            'ISO1328偏差分析': 'deviation',
            'Ripple分析': 'ripple',
            '周节偏差分析': 'pitch',
            '📄 报表工具': 'report',
            '📄 齿轮综合分析报表': 'report',
            '📄 生成PDF报告': 'report',
            '批量处理': 'batch',
            '📂 批量处理': 'batch'  # 修复：添加带emoji的映射
        }
        
        return page_mapping.get(item_text)
    
    def _preload_page(self, page_name):
        """预加载指定页面（可在后台线程或空闲时调用）"""
        if page_name in self._page_config and not self._page_config[page_name]['loaded']:
            QTimer.singleShot(0, lambda: self._load_page(page_name))
    
    def preload_common_pages(self):
        """预加载常用页面，优化用户体验"""
        common_pages = ['flank', 'profile', 'curve']
        for page_name in common_pages:
            QTimer.singleShot(1000, lambda name=page_name: self._preload_page(name))

