        self.curve_mdi_area.setTabsClosable(True)
        self.curve_mdi_area.setTabsMovable(True)
        
        # 添加空提示标签
        self.curve_empty_label = QLabel("请选择曲线类型和齿号，然后点击刷新按钮")
        self.curve_empty_label.setAlignment(Qt.AlignCenter)
        self.curve_empty_label.setStyleSheet("color: #999; font-style: italic; font-size: 14px;")
