    def generate_topography_report(self):
        """生成Topography分析报告"""
        try:
            # 动态导入以避免启动时的依赖问题
            import sys
            import os
            # 确保gear_analysis_refactored在路径中
            current_dir = os.path.dirname(os.path.abspath(__file__))
            if current_dir not in sys.path:
                sys.path.append(current_dir)
                
            from gear_analysis_refactored.models.gear_data import GearMeasurementData, TopographyData, GearBasicInfo
            from gear_analysis_refactored.reports.klingelnberg_topography import KlingelnbergTopographyReport
            from matplotlib.backends.backend_pdf import PdfPages
            
            if not self.gear_data:
                QMessageBox.warning(self, "无数据", "请先打开一个MKA文件并运行分析。")
                return

            # 检查是否有形貌数据
            if not self.topography_data:
                logger.info("无形貌数据，跳过Topography报告生成")
                return
            
            # 构建TopographyData对象并检查数据有效性
            topo_data_obj = TopographyData()
            topo_data_obj.data = self.topography_data
            
            # 使用has_data()方法严格检查数据是否有效
            if not topo_data_obj.has_data():
                logger.info("形貌数据为空或无效，跳过Topography报告生成")
                return
            
            # 进一步检查数据是否包含实际测量值（不仅仅是空字典）
            has_valid_measurements = False
            for tooth_num, tooth_data in topo_data_obj.data.items():
                if not isinstance(tooth_data, dict):
                    continue
                for side in ['left', 'right']:
                    side_data = tooth_data.get(side, {})
                    if not side_data:
                        continue
                    # 检查新格式：profiles或flank_lines
                    if 'profiles' in side_data:
                        profiles = side_data['profiles']
                        if isinstance(profiles, dict) and profiles:
                            for profile_data in profiles.values():
                                values = profile_data.get('values', [])
                                if values and len(values) > 0:
                                    has_valid_measurements = True
                                    break
                    if 'flank_lines' in side_data:
                        flank_lines = side_data['flank_lines']
                        if isinstance(flank_lines, dict) and flank_lines:
                            for flank_data in flank_lines.values():
                                values = flank_data.get('values', [])
                                if values and len(values) > 0:
                                    has_valid_measurements = True
                                    break
                    # 检查旧格式：直接是索引到数组的字典
                    if not ('profiles' in side_data or 'flank_lines' in side_data):
                        for v in side_data.values():
                            if v and (isinstance(v, (list, tuple)) and len(v) > 0):
                                has_valid_measurements = True
                                break
                    if has_valid_measurements:
                        break
                if has_valid_measurements:
                    break
            
            if not has_valid_measurements:
                logger.info("形貌数据中没有有效的测量值，跳过Topography报告生成")
                return
            
            # 构建GearBasicInfo
            basic_info = GearBasicInfo()
            # 映射基本信息
            basic_info.program = self.gear_data.get('program', '')
            basic_info.date = self.gear_data.get('date', '')
            basic_info.order_no = self.gear_data.get('order_no', '')
            basic_info.operator = self.gear_data.get('operator', '')
            basic_info.module = float(self.gear_data.get('module', 0.0))
            basic_info.teeth = int(self.gear_data.get('teeth', 0))
            basic_info.helix_angle = float(self.gear_data.get('helix_angle', 0.0))
            basic_info.pressure_angle = float(self.gear_data.get('pressure_angle', 0.0))
            basic_info.width = float(self.gear_data.get('width', 0.0))
            
            # 构建GearMeasurementData
            meas_data = GearMeasurementData(
                basic_info=basic_info,
                topography_data=topo_data_obj,
                flank_data=self.flank_data,
                profile_data=self.profile_data
            )
            
            # 调试：检查数据
            logger.info(f"Topography data check: has_data={topo_data_obj.has_data()}, "
                       f"data keys={list(topo_data_obj.data.keys()) if topo_data_obj.data else 'None'}")
            if topo_data_obj.data:
                first_tooth = sorted(topo_data_obj.data.keys())[0] if topo_data_obj.data else None
                if first_tooth:
                    first_tooth_data = topo_data_obj.data[first_tooth]
                    logger.info(f"First tooth ({first_tooth}) data: left={first_tooth_data.get('left', {})}, "
                               f"right={first_tooth_data.get('right', {})}")
            
            # 选择保存路径
            file_name_base = os.path.splitext(os.path.basename(self.current_file))[0]
            default_name = f"{file_name_base}_Topography.pdf"
            save_path, _ = QFileDialog.getSaveFileName(
                self, "保存Topography报告", default_name, "PDF Files (*.pdf)"
            )
            
            if not save_path:
                return
                
            # 生成报告 - 使用 KlingelnbergTopographyReport
            report = KlingelnbergTopographyReport()
            
            # 使用 PdfPages 生成 PDF
            with PdfPages(save_path) as pdf:
                report.create_page(pdf, meas_data)
            
            QMessageBox.information(self, "成功", f"Topography报告已保存:\n{save_path}")
            
            # 尝试打开PDF
            try:
                os.startfile(save_path)
            except Exception:
                pass
                
        except Exception as e:
            logger.exception("生成Topography报告失败")
            QMessageBox.critical(self, "生成失败", f"生成报告时出错:\n{str(e)}")

    def on_prev_page(self):
        """处理上一页按钮点击事件"""
        if not hasattr(self, 'pdf_current_page'):
            self.pdf_current_page = 0
            
        if self.pdf_current_page > 0:
            self.pdf_current_page -= 1
            self._render_pdf_page()
            logger.info(f"切换到第 {self.pdf_current_page + 1} 页")

    def on_next_page(self):
        """处理下一页按钮点击事件"""
        if not hasattr(self, 'pdf_current_page'):
            self.pdf_current_page = 0
        if not hasattr(self, 'pdf_total_pages'):
            self.pdf_total_pages = 0
            
        # 检查是否可以翻页（如果总页数为0，允许翻页，因为可能还没获取到总页数）
        if self.pdf_total_pages == 0 or self.pdf_current_page < self.pdf_total_pages - 1:
            self.pdf_current_page += 1
            self._render_pdf_page()
            logger.info(f"切换到第 {self.pdf_current_page + 1} 页")
        else:
            logger.info("已经是最后一页")

    def update_page_info(self):
        """更新页面信息显示"""
        if hasattr(self, 'pdf_current_page') and hasattr(self, 'pdf_total_pages') and hasattr(self, 'page_info'):
            page_text = f"页面: {self.pdf_current_page + 1} / {self.pdf_total_pages if self.pdf_total_pages > 0 else '?'}"
            self.page_info.setText(page_text)
            logger.debug(f"更新页面信息: {page_text}")
    
    def sync_pdf_page_info(self):
        """从PDF查看器同步当前页数"""
        js_code = """
        (function() {
            // 方法1: 尝试从URL hash获取（格式: #page=1 或 #page=1/9）
            var urlMatch = window.location.href.match(/#page=(\\d+)(?:\\/(\\d+))?/);
            if (urlMatch) {
                var current = parseInt(urlMatch[1]);
                var total = urlMatch[2] ? parseInt(urlMatch[2]) : 0;
                return {current: current, total: total};
            }
            
            // 方法2: 尝试从页面标题获取（格式: "filename.pdf (1/9)"）
            var titleMatch = document.title.match(/\\((\\d+)\\/(\\d+)\\)/);
            if (titleMatch) {
                return {
                    current: parseInt(titleMatch[1]),
                    total: parseInt(titleMatch[2])
                };
            }
            
            // 方法3: 尝试使用PDFViewerApplication API
            if (typeof PDFViewerApplication !== 'undefined' && PDFViewerApplication.page !== undefined) {
                var current = PDFViewerApplication.page;
                var total = PDFViewerApplication.pagesCount || 
                           (PDFViewerApplication.pdfDocument ? PDFViewerApplication.pdfDocument.numPages : 0);
                return {current: current, total: total};
            }
            
            return null;
        })();
        """
        
        def on_sync_result(result):
            if result and isinstance(result, dict):
                current = result.get('current', 0)
                total = result.get('total', 0)
                if current > 0:
                    self.pdf_current_page = current - 1  # 转换为0-based
                if total > 0 and total != self.pdf_total_pages:
                    self.pdf_total_pages = total
                self.update_page_info()
                logger.debug(f"同步页面信息: 当前页={current}, 总页数={total}")
            else:
                # 如果无法同步，至少更新显示
                self.update_page_info()
        
        self.report_webview.page().runJavaScript(js_code, on_sync_result)
    
    def on_pdf_loaded(self, success):
        """PDF加载完成事件处理"""
        if success:
            logger.info("PDF文件加载完成")
            # 初始化页面信息
            if not hasattr(self, 'pdf_current_page'):
                self.pdf_current_page = 0
            if not hasattr(self, 'pdf_total_pages'):
                self.pdf_total_pages = 0
            
            # 延迟获取总页数和设置页面监听，确保PDF已完全渲染
            from PyQt5.QtCore import QTimer
            # 重置重试计数
            self._pdf_page_retry_count = 0
            QTimer.singleShot(1000, self.get_pdf_total_pages)
            QTimer.singleShot(1500, self.setup_pdf_page_listener)
            QTimer.singleShot(2000, self.sync_pdf_page_info)  # 同步一次页面信息
        else:
            logger.error("PDF文件加载失败")
            # 尝试获取页面标题和URL
            logger.error(f"当前页面标题: {self.report_webview.title()}")
            logger.error(f"当前页面URL: {self.report_webview.url().toString()}")
    
    def setup_pdf_page_listener(self):
        """设置PDF页面变化监听"""
        js_code = """
        (function() {
            if (typeof PDFViewerApplication !== 'undefined' && PDFViewerApplication.eventBus) {
                // 监听页面变化事件
                PDFViewerApplication.eventBus.on('pagechanging', function(e) {
                    console.log('页面变化:', e.page);
                });
                return true;
            }
            return false;
        })();
        """
        self.report_webview.page().runJavaScript(js_code)
        # 同步一次页面信息
        self.sync_pdf_page_info()
    
    def get_pdf_total_pages(self):
        """获取PDF总页数 - 使用PyPDF2直接读取文件"""
        logger.info("开始获取PDF总页数")
        
        # 方法1: 尝试使用PyPDF2直接读取PDF文件
        try:
            if hasattr(self, 'current_pdf_path') and self.current_pdf_path:
                import PyPDF2
                with open(self.current_pdf_path, 'rb') as pdf_file:
                    pdf_reader = PyPDF2.PdfReader(pdf_file)
                    total_pages = len(pdf_reader.pages)
                    if total_pages > 0:
                        self.pdf_total_pages = total_pages
                        self.pdf_current_page = 0  # 重置为第一页
                        self.update_page_info()
                        logger.info(f"使用PyPDF2获取到PDF总页数: {self.pdf_total_pages}")
                        return
        except ImportError:
            logger.warning("PyPDF2未安装，尝试使用JavaScript方法")
        except Exception as e:
            logger.warning(f"使用PyPDF2读取PDF失败: {e}，尝试使用JavaScript方法")
        
        # 方法2: 如果PyPDF2失败，尝试从URL获取（浏览器可能显示在标题栏）
        try:
            if hasattr(self, 'current_pdf_path') and self.current_pdf_path:
                # 从PDF查看器的标题栏获取页数（如果浏览器显示了）
                js_code = """
                (function() {
                    // 尝试从页面标题获取（格式可能是 "filename.pdf (1/9)"）
                    var title = document.title;
                    var match = title.match(/\((\d+)\/(\d+)\)/);
                    if (match && match[2]) {
                        return parseInt(match[2]);
                    }
                    
                    // 尝试从URL hash获取
                    var hashMatch = window.location.href.match(/#page=\d+\/(\d+)/);
                    if (hashMatch && hashMatch[1]) {
                        return parseInt(hashMatch[1]);
                    }
                    
                    return 0;
                })();
                """
                self.report_webview.page().runJavaScript(js_code, lambda num_pages: self.on_get_total_pages_callback(num_pages))
                logger.info("已请求通过JavaScript获取PDF总页数")
        except Exception as e:
            logger.error(f"获取PDF总页数失败: {e}")
            self.pdf_total_pages = 0
            self.update_page_info()
    
    def on_webview_load_started(self):
        """PDF开始加载事件处理"""
        logger.info("PDF文件开始加载")
    
    def on_webview_load_progress(self, progress):
        """PDF加载进度事件处理"""
        logger.info(f"PDF文件加载进度: {progress}%")
    
    def on_get_total_pages_callback(self, total_pages):
        """获取总页数的回调函数"""
        if total_pages is not None and total_pages > 0:
            self.pdf_total_pages = int(total_pages)
            # 同时同步当前页数
            self.sync_pdf_page_info()
            logger.info(f"通过JavaScript获取到PDF总页数: {self.pdf_total_pages}")
        else:
            # 不再无限重试，避免日志刷屏
            if not hasattr(self, '_pdf_page_retry_count'):
                self._pdf_page_retry_count = 0
            
            self._pdf_page_retry_count += 1
            if self._pdf_page_retry_count < 3:  # 最多重试3次
                logger.warning(f"无法获取PDF总页数，将重试 ({self._pdf_page_retry_count}/3)")
                from PyQt5.QtCore import QTimer
                QTimer.singleShot(2000, self.get_pdf_total_pages)
            else:
                logger.warning("无法获取PDF总页数，停止重试")
                self.pdf_total_pages = 0
            self.update_page_info()

