    def on_tree_item_clicked(self, item, column):
        """树形菜单项点击事件"""
        if not item or item.parent() is None:
            return
        
        item_text = item.text(0)
        parent_text = item.parent().text(0)
        grandparent = item.parent().parent()
        grandparent_text = grandparent.text(0) if grandparent else ""
        
        # 调试信息
        logger.info(f"点击菜单项: grandparent='{grandparent_text}', parent='{parent_text}', item='{item_text}'")
        
        # 特殊处理批量处理的子目录项（双击打开PDF）
        if grandparent_text == "📁 文件操作" and parent_text == "📂 批量处理":
            from PyQt5.QtCore import Qt
            # 获取PDF路径
            pdf_path = item.data(0, Qt.UserRole)
            if pdf_path:
                logger.info(f"打开PDF文件: {pdf_path}")
                # 切换到报表页面
                self._handle_page_switch(item, None)
                # 在子窗体中显示PDF
                self.load_pdf_in_subwindow(pdf_path)
            return
            
        # 特殊处理设置
        if parent_text == "⚙️ 设置":
            if item_text == "📊 波纹度公差设置":
                logger.info("调用 show_ripple_tolerance_settings()")
                try:
                    self.show_ripple_tolerance_settings()
                except Exception as e:
                    logger.exception(f"调用 show_ripple_tolerance_settings 失败: {e}")
                    from PyQt5.QtWidgets import QMessageBox
                    QMessageBox.critical(self, "错误", f"打开设置窗口失败：\n{str(e)}")
                return
    
    def find_tree_item(self, item_text, parent_text=None):
        """查找指定文本的树形菜单项
        
        Args:
            item_text: 菜单项文本
            parent_text: 父菜单项文本（可选）
            
        Returns:
            QTreeWidgetItem: 找到的菜单项，未找到返回None
        """
        for i in range(self.nav_tree_widget.topLevelItemCount()):
            root_item = self.nav_tree_widget.topLevelItem(i)
            if parent_text and root_item.text(0) != parent_text:
                continue
                
            if not parent_text:
                # 搜索顶层节点
                if root_item.text(0) == item_text:
                    return root_item
            
            # 搜索子节点
            for j in range(root_item.childCount()):
                child_item = root_item.child(j)
                if child_item.text(0) == item_text:
                    return child_item
        
        return None
    
    def update_batch_tree_items(self, mka_files):
        """更新批量处理菜单项的子目录
        
        Args:
            mka_files: 包含(MKA文件名, PDF路径)的列表
        """
        from PyQt5.QtCore import Qt
        
        # 查找批量处理菜单项
        batch_item = self.find_tree_item("📂 批量处理", "📁 文件操作")
        if not batch_item:
            logger.error("未找到批量处理菜单项")
            return
        
        # 清空现有子节点
        while batch_item.childCount() > 0:
            batch_item.takeChild(0)
        
        # 添加新子节点
        for mka_name, pdf_path in mka_files:
            child = QTreeWidgetItem([mka_name])
            # 存储PDF路径，用于双击打开
            child.setData(0, Qt.UserRole, pdf_path)
            batch_item.addChild(child)
        
        # 展开批量处理节点
        batch_item.setExpanded(True)
        logger.info(f"已更新批量处理子目录，共添加 {len(mka_files)} 个文件")
    
    def view_spectrum_chart(self):
        """单独打开频谱图，只显示一张，并支持单独刷新数据
        
        该方法会创建一个只包含频谱图的新窗口，而不是打开整个PDF报告，
        并支持单独刷新频谱数据，避免重新生成所有PDF文件。
        """
        try:
            import os
            import sys
            import matplotlib.pyplot as plt
            import matplotlib.gridspec as gridspec
            import numpy as np
            from PyQt5.QtWidgets import QMdiSubWindow, QWidget, QVBoxLayout, QHBoxLayout, QPushButton, QLabel, QComboBox
            from PyQt5.QtCore import Qt
            from types import SimpleNamespace
            
            # 检查是否有当前打开的文件
            if not hasattr(self, 'current_file') or not self.current_file:
                logger.error("没有当前打开的文件")
                QMessageBox.warning(self, "无数据", "请先打开一个MKA文件。")
                return
            
            # 检查是否有必要的数据
            if not hasattr(self, 'gear_data') or not self.gear_data:
                logger.error("没有齿轮数据")
                QMessageBox.warning(self, "无数据", "请先打开一个MKA文件并完成分析。")
                return
            
            # 导入频谱分析模块
            sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))
            from gear_analysis_refactored.reports.klingelnberg_ripple_spectrum import KlingelnbergRippleSpectrumReport, RippleSpectrumSettings
            
            # 创建测量数据对象
            class MeasurementData:
                def __init__(self, gear_data, profile_data, flank_data):
                    self.basic_info = SimpleNamespace(
                        module=float(gear_data.get('模数', 0.0)),
                        teeth=int(gear_data.get('齿数', 0)),
                        pressure_angle=float(gear_data.get('压力角', 20.0)),
                        helix_angle=float(gear_data.get('螺旋角', 0.0)),
                        order_no=gear_data.get('序号', ''),
                        drawing_no=gear_data.get('图号', ''),
                        date=gear_data.get('日期', ''),
                        time=gear_data.get('开始测量时间', ''),
                        program=gear_data.get('程序名', '')
                    )
                    self.profile_left = profile_data.get('left', {})
                    self.profile_right = profile_data.get('right', {})
                    self.helix_left = flank_data.get('left', {})
                    self.helix_right = flank_data.get('right', {})
            
            # 获取齿形和齿向数据
            profile_data = getattr(self, 'profile_data', {'left': {}, 'right': {}})
            flank_data = getattr(self, 'flank_data', {'left': {}, 'right': {}})
            
            # 创建测量数据对象
            measurement_data = MeasurementData(self.gear_data, profile_data, flank_data)
            
            # 创建频谱分析报告对象
            settings = RippleSpectrumSettings()
            report = KlingelnbergRippleSpectrumReport(settings)
            
            # 创建Mdi子窗口
            sub_window = QMdiSubWindow()
            sub_window.setWindowTitle("频谱图")
            # QMdiSubWindow没有setWidgetResizable方法，移除该调用
            
            # 创建主容器
            container = QWidget()
            main_layout = QVBoxLayout(container)
            
            # 创建图表容器
            self.chart_container = QWidget()
            chart_layout = QVBoxLayout(self.chart_container)
            
            # 添加到主布局
            main_layout.addWidget(self.chart_container)
            
            # 存储当前的图表和画布
            self.current_spectrum_fig = None
            self.current_spectrum_canvas = None
            
            # 绘制初始频谱图
            self._draw_spectrum_chart(measurement_data, report)
            
            # 设置子窗口
            sub_window.setWidget(container)
            self.mdi_area.addSubWindow(sub_window)
            sub_window.show()
            
        except Exception as e:
            logger.error(f"查看频谱图失败: {e}")
            QMessageBox.critical(self, "错误", f"查看频谱图失败:\n{str(e)}")
    
