    def view_spectrum_pdf(self):
        """直接打开频谱PDF在MDI窗体中，避免重新计算所有PDF
        
        该方法会查找与当前MKA文件对应的频谱PDF文件，并直接在MDI窗口中打开它，
        而不需要重新生成所有PDF文件，节省时间和计算资源。
        """

        try:
            import os
            import re
            import difflib
            
            # 检查是否有当前打开的文件
            if not hasattr(self, 'current_file') or not self.current_file:
                logger.error("没有当前打开的文件")
                QMessageBox.warning(self, "无数据", "请先打开一个MKA文件。")
                return
            
            # 生成对应的PDF文件路径
            pdf_path = os.path.splitext(self.current_file)[0] + ".pdf"
            
            # 如果PDF文件存在，直接在MDI中显示
            if os.path.exists(pdf_path):
                logger.info(f"在MDI中显示频谱PDF: {pdf_path}")
                self.load_pdf_in_subwindow(pdf_path)
                return
            
            # 如果找不到同名PDF，尝试查找匹配的PDF文件
            logger.info("PDF文件不存在，尝试查找匹配的PDF文件")
            
            # 使用当前打开的MKA文件名称构建PDF文件路径
            # 获取当前文件的基本名称（不含扩展名）
            current_file_base = os.path.splitext(os.path.basename(self.current_file))[0]
            current_file_name = os.path.basename(self.current_file)
            logger.info(f"当前打开的文件: {current_file_name}")
            
            base_dir = os.path.dirname(os.path.abspath(self.current_file))
            
            # 构建预期的PDF文件名
            expected_pdf_name = f"{current_file_base}.pdf"
            expected_pdf_path = os.path.join(base_dir, expected_pdf_name)
            logger.info(f"预期的PDF文件名: {expected_pdf_name}")
            
            # 优先查找完全匹配的PDF文件
            if os.path.exists(expected_pdf_path):
                pdf_file_path = expected_pdf_path
                logger.info(f"找到完全匹配的PDF文件: {expected_pdf_name}")
            else:
                # 如果没有完全匹配的PDF文件，查找所有PDF文件
                pdf_files = [f for f in os.listdir(base_dir) if f.endswith('.pdf')]
                pdf_file_path = None
                
                # 如果找到PDF文件，尝试匹配
                if pdf_files:
                    # 从当前文件名中提取订单号（处理不同格式）
                    order_no_match = re.search(r'(\d+-\d+)', current_file_base)
                    order_no = order_no_match.group(1) if order_no_match else None
                    logger.info(f"从当前文件名提取的订单号: {order_no}")
                    
                    # 首先尝试完全匹配当前文件名的PDF文件
                    exact_matches = [f for f in pdf_files if current_file_base in f]
                    if exact_matches:
                        # 如果有完全匹配的，按修改时间排序，取最新的
                        exact_matches.sort(key=lambda f: os.path.getmtime(os.path.join(base_dir, f)), reverse=True)
                        best_match = exact_matches[0]
                        pdf_file_path = os.path.join(base_dir, best_match)
                        logger.info(f"找到完全匹配的PDF文件: {best_match}")
                    else:
                        # 如果没有完全匹配，尝试使用订单号匹配
                        order_matches = []
                        if order_no:
                            order_matches = [f for f in pdf_files if order_no in f]
                            logger.info(f"找到{len(order_matches)}个包含订单号{order_no}的PDF文件")
                        
                        if order_matches:
                            # 在订单号匹配的文件中，使用相似度计算找到最匹配的
                            best_match = None
                            highest_similarity = 0
                            
                            for pdf_file in order_matches:
                                # 获取PDF文件名的基本名称（不含扩展名）
                                pdf_base_name = os.path.splitext(pdf_file)[0]
                                
                                # 使用SequenceMatcher计算相似度
                                similarity = difflib.SequenceMatcher(None, current_file_base.lower(), pdf_base_name.lower()).ratio()
                                
                                if similarity > highest_similarity:
                                    highest_similarity = similarity
                                    best_match = pdf_file
                                elif similarity == highest_similarity and best_match:
                                    # 如果相似度相同，选择最新修改的文件
                                    current_time = os.path.getmtime(os.path.join(base_dir, pdf_file))
                                    best_time = os.path.getmtime(os.path.join(base_dir, best_match))
                                    if current_time > best_time:
                                        best_match = pdf_file
                            
                            if best_match:
                                pdf_file_path = os.path.join(base_dir, best_match)
                                logger.info(f"找到最匹配的PDF文件: {best_match} (相似度: {highest_similarity:.2f})")
                        else:
                            # 如果没有订单号匹配，尝试使用文件名相似度匹配
                            best_match = None
                            highest_similarity = 0
                            
                            for pdf_file in pdf_files:
                                pdf_base_name = os.path.splitext(pdf_file)[0]
                                similarity = difflib.SequenceMatcher(None, current_file_base.lower(), pdf_base_name.lower()).ratio()
                                
                                if similarity > highest_similarity:
                                    highest_similarity = similarity
                                    best_match = pdf_file
                                elif similarity == highest_similarity and best_match:
                                    current_time = os.path.getmtime(os.path.join(base_dir, pdf_file))
                                    best_time = os.path.getmtime(os.path.join(base_dir, best_match))
                                    if current_time > best_time:
                                        best_match = pdf_file
                            
                            if best_match and highest_similarity > 0.3:
                                pdf_file_path = os.path.join(base_dir, best_match)
                                logger.info(f"找到相似的PDF文件: {best_match} (相似度: {highest_similarity:.2f})")
                
            # 如果找到匹配的PDF文件，在MDI中显示
            if pdf_file_path and os.path.exists(pdf_file_path):
                logger.info(f"在MDI中显示找到的PDF: {pdf_file_path}")
                self.load_pdf_in_subwindow(pdf_file_path)
            else:
                # 如果找不到PDF文件，提示用户
                logger.error("未找到匹配的PDF文件")
                QMessageBox.warning(self, "PDF文件不存在", "未找到与当前MKA文件对应的PDF频谱文件。\n请先生成克林贝格报告以创建频谱PDF文件。")
                
        except Exception as e:
            logger.error(f"查看频谱PDF失败: {e}")
            QMessageBox.critical(self, "错误", f"查看频谱PDF失败:\n{str(e)}")
    
    def load_pdf_in_subwindow(self, pdf_path):
        """在子窗体中加载并显示PDF文件，带缩放功能和鼠标滚轮翻页
        
        Args:
            pdf_path: PDF文件的完整路径
        """
        try:
            from PyQt5.QtWidgets import (
                QMdiSubWindow, QWidget, QVBoxLayout, QHBoxLayout, 
                QPushButton, QLabel, QScrollArea, QFrame
            )
            from PyQt5.QtCore import Qt, QObject, QEvent
            from PyQt5.QtGui import QImage, QPixmap
            import os
            
            if not os.path.exists(pdf_path):
                logger.error(f"PDF文件不存在: {pdf_path}")
                return
            
            # 尝试动态导入 PyMuPDF
            global fitz, PYMUPDF_AVAILABLE
            try:
                import fitz
                PYMUPDF_AVAILABLE = True
            except ImportError:
                PYMUPDF_AVAILABLE = False
                fitz = None
            
            # 检查 PyMuPDF 是否可用
            if PYTHON_VERSION_TOO_OLD:
                QMessageBox.critical(self, "Python版本过低", 
                    f"当前Python版本: {sys.version_info.major}.{sys.version_info.minor}\n\n"
                    "PyMuPDF需要Python 3.7或更高版本。")
                return
            elif not PYMUPDF_AVAILABLE or fitz is None:
                QMessageBox.warning(self, "缺少依赖", 
                    "需要安装PyMuPDF库才能显示PDF。\n\n"
                    "请运行: pip install PyMuPDF")
                return
            
            # 创建容器Widget，包含工具栏和PDF查看器
            container_widget = QWidget()
            container_layout = QVBoxLayout(container_widget)
            container_layout.setContentsMargins(0, 0, 0, 0)
            container_layout.setSpacing(0)
            
            # 创建工具栏
            toolbar = QWidget()
            toolbar.setStyleSheet("background-color: #f0f0f0; padding: 5px;")
            toolbar_layout = QHBoxLayout(toolbar)
            toolbar_layout.setContentsMargins(5, 5, 5, 5)
            toolbar_layout.setSpacing(10)
            
            # 页面导航按钮
            prev_page_btn = QPushButton("上一页")
            prev_page_btn.setMinimumWidth(80)
            prev_page_btn.setToolTip("上一页 (或鼠标滚轮向上)")
            
            next_page_btn = QPushButton("下一页")
            next_page_btn.setMinimumWidth(80)
            next_page_btn.setToolTip("下一页 (或鼠标滚轮向下)")
            
            # 页面信息标签
            page_info_label = QLabel("页面: 1 / ?")
            page_info_label.setAlignment(Qt.AlignCenter)
            page_info_label.setStyleSheet("font-weight: bold; margin: 0 10px; min-width: 100px;")
            
            # 缩放按钮
            zoom_out_btn = QPushButton("缩小 (-)")
            zoom_out_btn.setToolTip("缩小PDF视图")
            
            zoom_in_btn = QPushButton("放大 (+)")
            zoom_in_btn.setToolTip("放大PDF视图")
            
            reset_zoom_btn = QPushButton("重置 (100%)")
            reset_zoom_btn.setToolTip("重置缩放为100%")
            
            fit_width_btn = QPushButton("适应宽度")
            fit_width_btn.setToolTip("适应窗口宽度")
            
            fit_page_btn = QPushButton("适应页面")
            fit_page_btn.setToolTip("适应整个页面")
            
            # 缩放比例显示标签
            zoom_label = QLabel("100%")
            zoom_label.setMinimumWidth(60)
            zoom_label.setAlignment(Qt.AlignCenter)
            zoom_label.setStyleSheet("background-color: white; padding: 2px 8px; border: 1px solid #ccc;")
            
            # 添加到工具栏
            toolbar_layout.addWidget(prev_page_btn)
            toolbar_layout.addWidget(page_info_label)
            toolbar_layout.addWidget(next_page_btn)
            
            # 添加分隔符
            separator = QFrame()
            separator.setFrameShape(QFrame.VLine)
            separator.setFrameShadow(QFrame.Sunken)
            toolbar_layout.addWidget(separator)
            
            toolbar_layout.addWidget(zoom_out_btn)
            toolbar_layout.addWidget(zoom_in_btn)
            toolbar_layout.addWidget(reset_zoom_btn)
            toolbar_layout.addWidget(fit_width_btn)
            toolbar_layout.addWidget(fit_page_btn)
            toolbar_layout.addStretch()
            toolbar_layout.addWidget(QLabel("缩放:"))
            toolbar_layout.addWidget(zoom_label)
            
            # 创建滚动区域（用于居中显示）
            scroll_area = QScrollArea()
            scroll_area.setWidgetResizable(True)
            scroll_area.setAlignment(Qt.AlignCenter)
            scroll_area.setStyleSheet("background-color: #525252;")  # 深灰色背景，类似PDF阅读器
            # 禁用滚动条的滚轮事件，使用自定义翻页功能
            scroll_area.setVerticalScrollBarPolicy(Qt.ScrollBarAsNeeded)
            scroll_area.setHorizontalScrollBarPolicy(Qt.ScrollBarAsNeeded)
            
            # 创建PDF图像标签
            pdf_image_label = QLabel()
            pdf_image_label.setAlignment(Qt.AlignCenter)
            pdf_image_label.setStyleSheet("background-color: white;")
            pdf_image_label.setScaledContents(False)
            scroll_area.setWidget(pdf_image_label)
            
            # 将工具栏和PDF查看器添加到容器
            container_layout.addWidget(toolbar)
            container_layout.addWidget(scroll_area)
            
            # 打开PDF文档
            pdf_doc = fitz.open(pdf_path)
            pdf_total_pages = len(pdf_doc)
            pdf_current_page = 0
            pdf_zoom_factor = 1.0
            
            # 渲染PDF页面的函数
            def render_pdf_page(page_num, zoom=1.0):
                nonlocal pdf_current_page
                if 0 <= page_num < pdf_total_pages:
                    pdf_current_page = page_num
                    page = pdf_doc[page_num]
                    
                    # 计算缩放矩阵
                    zoom_dpi = zoom * 2.0  # 基础DPI为72，乘以2得到144 DPI
                    mat = fitz.Matrix(zoom_dpi, zoom_dpi)
                    
                    # 渲染页面为图像
                    pix = page.get_pixmap(matrix=mat, alpha=False)
                    
                    # 转换为QPixmap
                    img_data = pix.samples
                    img = QImage(img_data, pix.width, pix.height, pix.stride, QImage.Format_RGB888)
                    pixmap = QPixmap.fromImage(img)
                    
                    # 设置图像
                    pdf_image_label.setPixmap(pixmap)
                    pdf_image_label.resize(pixmap.size())
                    
                    # 更新页面信息
                    page_info_label.setText(f"页面: {page_num + 1} / {pdf_total_pages}")
                    zoom_label.setText(f"{int(zoom * 100)}%")
                    
                    # 重置滚动条到顶部（新页面从顶部开始显示）
                    # 使用QApplication.processEvents()确保UI更新完成
                    QApplication.processEvents()
                    scroll_area.verticalScrollBar().setValue(scroll_area.verticalScrollBar().minimum())
                    scroll_area.horizontalScrollBar().setValue(scroll_area.horizontalScrollBar().minimum())
                    
                    # 确保图像标签可见并居中显示
                    scroll_area.ensureWidgetVisible(pdf_image_label)
                    
                    # 再次处理事件，确保滚动条重置生效
                    QApplication.processEvents()
            
            # 上一页
            def on_prev_page():
                if pdf_current_page > 0:
                    render_pdf_page(pdf_current_page - 1, pdf_zoom_factor)
            
            # 下一页
            def on_next_page():
                if pdf_current_page < pdf_total_pages - 1:
                    render_pdf_page(pdf_current_page + 1, pdf_zoom_factor)
            
            # 缩放函数
            def on_zoom(delta, reset=False):
                nonlocal pdf_zoom_factor
                if reset:
                    pdf_zoom_factor = 1.0
                else:
                    pdf_zoom_factor = max(0.25, min(5.0, pdf_zoom_factor + delta))
                render_pdf_page(pdf_current_page, pdf_zoom_factor)
            
            # 适应宽度
            def on_fit_width():
                nonlocal pdf_zoom_factor
                if pdf_current_page < pdf_total_pages:
                    page = pdf_doc[pdf_current_page]
                    page_width = page.rect.width
                    viewer_width = scroll_area.viewport().width()
                    pdf_zoom_factor = (viewer_width / page_width) * (72 / 144)  # 调整DPI比例
                    render_pdf_page(pdf_current_page, pdf_zoom_factor)
            
            # 适应页面
            def on_fit_page():
                nonlocal pdf_zoom_factor
                if pdf_current_page < pdf_total_pages:
                    page = pdf_doc[pdf_current_page]
                    page_width = page.rect.width
                    page_height = page.rect.height
                    viewer_width = scroll_area.viewport().width()
                    viewer_height = scroll_area.viewport().height()
                    
                    zoom_w = (viewer_width / page_width) * (72 / 144)
                    zoom_h = (viewer_height / page_height) * (72 / 144)
                    pdf_zoom_factor = min(zoom_w, zoom_h)
                    render_pdf_page(pdf_current_page, pdf_zoom_factor)
            
            # 重写滚动区域的滚轮事件处理：先滚动页面，到底部/顶部时再翻页
            def scroll_area_wheel_event(event):
                angle_delta = event.angleDelta().y()
                vertical_scrollbar = scroll_area.verticalScrollBar()
                
                # 获取滚动条的范围和当前值
                scroll_min = vertical_scrollbar.minimum()
                scroll_max = vertical_scrollbar.maximum()
                scroll_value = vertical_scrollbar.value()
                
                # 使用小容差判断是否在顶部或底部（考虑浮点误差）
                tolerance = 5  # 5像素的容差
                is_at_top = scroll_value <= scroll_min + tolerance
                is_at_bottom = scroll_value >= scroll_max - tolerance
                
                if angle_delta > 0:  # 向上滚动
                    if is_at_top:
                        # 已经在顶部，向上滚动时翻到上一页
                        on_prev_page()
                        event.accept()
                    else:
                        # 不在顶部，先执行默认滚动行为
                        # 使用QScrollArea的默认wheelEvent处理滚动
                        QScrollArea.wheelEvent(scroll_area, event)
                elif angle_delta < 0:  # 向下滚动
                    if is_at_bottom:
                        # 已经在底部，向下滚动时翻到下一页
                        on_next_page()
                        event.accept()
                    else:
                        # 不在底部，先执行默认滚动行为
                        # 使用QScrollArea的默认wheelEvent处理滚动
                        QScrollArea.wheelEvent(scroll_area, event)
                else:
                    event.ignore()
            
            scroll_area.wheelEvent = scroll_area_wheel_event
            
            # 重写图像标签的滚轮事件处理：先滚动页面，到底部/顶部时再翻页
            def pdf_image_label_wheel_event(event):
                angle_delta = event.angleDelta().y()
                vertical_scrollbar = scroll_area.verticalScrollBar()
                
                # 获取滚动条的范围和当前值
                scroll_min = vertical_scrollbar.minimum()
                scroll_max = vertical_scrollbar.maximum()
                scroll_value = vertical_scrollbar.value()
                
                # 使用小容差判断是否在顶部或底部（考虑浮点误差）
                tolerance = 5  # 5像素的容差
                is_at_top = scroll_value <= scroll_min + tolerance
                is_at_bottom = scroll_value >= scroll_max - tolerance
                
                if angle_delta > 0:  # 向上滚动
                    if is_at_top:
                        # 已经在顶部，向上滚动时翻到上一页
                        on_prev_page()
                        event.accept()
                    else:
                        # 不在顶部，将事件传递给滚动区域处理
                        scroll_area.wheelEvent(event)
                elif angle_delta < 0:  # 向下滚动
                    if is_at_bottom:
                        # 已经在底部，向下滚动时翻到下一页
                        on_next_page()
                        event.accept()
                    else:
                        # 不在底部，将事件传递给滚动区域处理
                        scroll_area.wheelEvent(event)
                else:
                    event.ignore()
            
            pdf_image_label.wheelEvent = pdf_image_label_wheel_event
            
            # 连接按钮信号
            prev_page_btn.clicked.connect(on_prev_page)
            next_page_btn.clicked.connect(on_next_page)
            zoom_out_btn.clicked.connect(lambda: on_zoom(-0.1))
            zoom_in_btn.clicked.connect(lambda: on_zoom(0.1))
            reset_zoom_btn.clicked.connect(lambda: on_zoom(0, reset=True))
            fit_width_btn.clicked.connect(on_fit_width)
            fit_page_btn.clicked.connect(on_fit_page)
            
            # 初始渲染第一页
            render_pdf_page(0, pdf_zoom_factor)
            
            # 创建子窗口
            sub_window = QMdiSubWindow()
            sub_window.setWidget(container_widget)
            sub_window.setWindowTitle(f"PDF查看器 - {os.path.basename(pdf_path)}")
            sub_window.setGeometry(100, 100, 1000, 700)
            
            # 设置窗口属性，确保可以正确关闭
            sub_window.setAttribute(Qt.WA_DeleteOnClose, True)
            
            # 保存PDF文档引用，以便在窗口关闭时清理
            sub_window.pdf_doc = pdf_doc
            sub_window.pdf_path = pdf_path  # 保存路径用于日志
            
            # 重写closeEvent方法以正确处理关闭
            def custom_close_event(event):
                """自定义关闭事件处理"""
                try:
                    # 关闭PDF文档
                    if hasattr(sub_window, 'pdf_doc') and sub_window.pdf_doc:
                        sub_window.pdf_doc.close()
                        logger.info(f"已关闭PDF文档: {sub_window.pdf_path}")
                except Exception as e:
                    logger.error(f"关闭PDF文档时出错: {e}")
                
                # 接受关闭事件，允许窗口关闭
                event.accept()
                
                # 确保窗口被正确隐藏和移除
                sub_window.hide()
                
                # 如果窗口在MDI区域中，显式移除
                if hasattr(self, 'mdi_area') and self.mdi_area:
                    try:
                        self.mdi_area.removeSubWindow(sub_window)
                        logger.info(f"已从MDI区域移除PDF子窗口: {sub_window.pdf_path}")
                    except Exception as e:
                        logger.warning(f"从MDI区域移除子窗口时出错: {e}")
            
            sub_window.closeEvent = custom_close_event
            
            # 检查是否有MDI区域
            if hasattr(self, 'mdi_area') and self.mdi_area:
                self.mdi_area.addSubWindow(sub_window)
                sub_window.show()
                logger.info(f"成功在子窗体中打开PDF: {pdf_path}")
            else:
                # 如果没有MDI区域，使用独立窗口
                sub_window.show()
                logger.info(f"成功在独立窗口中打开PDF: {pdf_path}")
                
        except Exception as e:
            logger.error(f"打开PDF文件失败: {str(e)}")
            import traceback
            traceback.print_exc()
            QMessageBox.critical(self, "错误", f"打开PDF文件失败:\n{str(e)}")
    
    def _handle_pdf_subwindow_close(self, event, sub_window, pdf_path):
        """处理PDF子窗口关闭事件"""
        try:
            # 关闭PDF文档
            if hasattr(sub_window, 'pdf_doc') and sub_window.pdf_doc:
                sub_window.pdf_doc.close()
                logger.info(f"已关闭PDF文档: {pdf_path}")
        except Exception as e:
            logger.error(f"关闭PDF文档时出错: {e}")
        
        # 接受关闭事件，允许窗口关闭
        event.accept()
    
