    def show_3d_gear_view(self):
        """显示3D齿轮视图"""
        if not self.gear_data:
            QMessageBox.warning(self, "无数据", "请先打开一个MKA文件。")
            return
        
        viewer = Gear3DViewer(self.gear_data, self)
        viewer.exec_()

    def show_gear_ripple_analysis_chart(self):
        """显示齿轮波纹度分析图表"""
        try:
            # 导入齿轮波纹度分析图表模块
            from gear_ripple_analysis_chart import create_detailed_gear_chart
            
            # 获取齿轮参数
            z = 23
            if self.gear_data and isinstance(self.gear_data, dict):
                z = self.gear_data.get('齿数', self.gear_data.get('teeth', 23))
            
            # 创建图表 - 传递真实数据
            fig = create_detailed_gear_chart(
                flank_data=self.flank_data,
                profile_data=self.profile_data,
                gear_data=self.gear_data
            )
            
            # 显示图表窗口
            from matplotlib.backends.backend_qt5agg import FigureCanvasQTAgg as FigureCanvas
            
            dialog = QDialog(self)
            dialog.setWindowTitle(f"齿轮波纹度分析图表 (z={z})")
            dialog.setMinimumSize(1200, 900)
            
            layout = QVBoxLayout(dialog)
            canvas = FigureCanvas(fig)
            layout.addWidget(canvas)
            
            # 添加按钮区域
            button_layout = QHBoxLayout()
            
            save_btn = QPushButton("保存图片")
            save_btn.clicked.connect(lambda: self.save_gear_ripple_chart(fig))
            button_layout.addWidget(save_btn)
            
            close_btn = QPushButton("关闭")
            close_btn.clicked.connect(dialog.close)
            button_layout.addWidget(close_btn)
            
            layout.addLayout(button_layout)
            
            dialog.exec_()
            
        except Exception as e:
            QMessageBox.critical(self, "错误", f"显示齿轮波纹度分析图表失败:\n{str(e)}")
            import logging
            logging.error(f"显示齿轮波纹度分析图表失败: {e}")

    def save_gear_ripple_chart(self, fig):
        """保存齿轮波纹度分析图表"""
