    def open_tolerance_calculator(self):
        """打开ISO1328公差计算器"""
        # 使用 ToleranceSettingsDialog 替换原有的 ImageViewerDialog
        try:
            from ui.tolerance_dialog import ToleranceSettingsDialog
            
            # Ensure gear_data is initialized
            if self.gear_data is None:
                self.gear_data = {}
                
            # Sync data from UI tables to gear_data
            if hasattr(self, 'basic_table') and self.basic_table and self.basic_table.rowCount() > 0:
                try:
                    basic_keys = [
                        'program', 'date', 'start_time', 'end_time',
                        'operator', 'location', 'drawing_no', 'order_no', 'type',
                        'customer', 'condition', 'spindle_no', 'purpose', 'accuracy_grade'
                    ]
                    for i, key in enumerate(basic_keys):
                        if i < self.basic_table.rowCount():
                            item = self.basic_table.item(i, 1)
                            if item:
                                self.gear_data[key] = item.text()
                except Exception as e:
                    logger.warning(f"Error syncing params table: {e}")

            dialog = ToleranceSettingsDialog(self.gear_data, self)
            
            # 确保对话框完成初始化
            if hasattr(dialog, 'init_ui'):
                try:
                    dialog.init_ui()
                except Exception as e:
                    logger.warning(f"调用init_ui失败: {e}")
            
            # 隐藏左侧树形菜单以简化操作 - 多种方法确保隐藏
            if hasattr(dialog, 'tree_widget'):
                dialog.tree_widget.setVisible(False)
                dialog.tree_widget.hide()
                dialog.tree_widget.setMaximumWidth(0)
                logger.info("树形菜单已隐藏（open_tolerance_calculator）")
            
            # 强制更新对话框布局
            dialog.updateGeometry()
            if dialog.layout():
                dialog.layout().update()
                dialog.layout().activate()
            
            dialog.tolerances_updated.connect(self.update_tolerances)
            
            # 使用QTimer延迟刷新布局和隐藏树形菜单
            from PyQt5.QtCore import QTimer
            def refresh_layout():
                try:
                    if dialog.isVisible():
                        # 再次确保树形菜单隐藏
                        if hasattr(dialog, 'tree_widget'):
                            dialog.tree_widget.setVisible(False)
                            dialog.tree_widget.hide()
                            dialog.tree_widget.setMaximumWidth(0)
                        dialog.updateGeometry()
                        if dialog.layout():
                            dialog.layout().update()
                except Exception as e:
                    logger.debug(f"刷新布局失败: {e}")
            
            QTimer.singleShot(100, refresh_layout)
            
            dialog.exec_()
        except ImportError as e:
            QMessageBox.warning(self, "Error", f"Could not import ToleranceSettingsDialog: {e}")
        except Exception as e:
            logger.exception("Error opening tolerance calculator")
            QMessageBox.warning(self, "Error", f"Error opening tolerance calculator: {e}")
    
    def open_tolerance_settings(self, standard_name="DIN 3962", tolerance_type="Spacing"):
        """打开公差设置对话框（隐藏树形菜单）"""
        try:
            from ui.tolerance_dialog import ToleranceSettingsDialog
            from PyQt5.QtWidgets import QVBoxLayout, QWidget, QDialog
            
            # 确保gear_data已初始化
            if self.gear_data is None:
                self.gear_data = {}
            
            # 创建ToleranceSettingsDialog
            dialog = ToleranceSettingsDialog(self.gear_data, self)
            
            # 页面索引映射
            base_page_mapping = {
                "DIN 3962": 0,
                "AGMA": 3,
                "ISO 1328:1997": 6,
                "ISO 1328:2013": 9,
                "ANSI B92.1": 12,
                "DIN 5480": 15
            }
            
            # 类型偏移
            type_offset = {
                "Profile": 0,
                "Lead": 1,
                "Spacing": 2
            }
            
            # 设置目标页面
            if hasattr(dialog, 'content_stack') and standard_name in base_page_mapping:
                base_index = base_page_mapping[standard_name]
                offset = type_offset.get(tolerance_type, 2)
                page_index = base_index + offset
                dialog.content_stack.setCurrentIndex(page_index)
                logger.info(f"设置content_stack索引为: {page_index}")
            
            # 设置current_page_id，确保calculate_tolerances能正确识别页面类型
            # 页面ID格式需要与tolerance_dialog.py中的判断一致
            if standard_name == "AGMA":
                if tolerance_type == "Profile":
                    page_id = "AGMA_Profile"
                elif tolerance_type == "Lead":
                    page_id = "AGMA_Lead / Line of action"
                elif tolerance_type == "Spacing":
                    page_id = "AGMA_Spacing"
                else:
                    page_id = f"AGMA_{tolerance_type}"
            elif standard_name == "ISO 1328:1997":
                if tolerance_type == "Profile":
                    page_id = "ISO 1328 : 1997_Profile"
                elif tolerance_type == "Lead":
                    page_id = "ISO 1328 : 1997_Lead / Line of action"
                elif tolerance_type == "Spacing":
                    page_id = "ISO 1328 : 1997_Spacing"
                else:
                    page_id = f"ISO 1328 : 1997_{tolerance_type}"
            elif standard_name == "ISO 1328:2013":
                if tolerance_type == "Profile":
                    page_id = "ISO 1328 : 2013_Profile"
                elif tolerance_type == "Lead":
                    page_id = "ISO 1328 : 2013_Lead / Line of action"
                elif tolerance_type == "Spacing":
                    page_id = "ISO 1328 : 2013_Spacing"
                else:
                    page_id = f"ISO 1328 : 2013_{tolerance_type}"
            else:
                page_id = f"{standard_name}_{tolerance_type}"
            dialog.current_page_id = page_id
            logger.info(f"========== 打开公差设置对话框 ==========")
            logger.info(f"设置current_page_id为: {page_id}")
            logger.info(f"standard_name={standard_name}, tolerance_type={tolerance_type}")
            logger.info(f"=========================================")
            
            # 隐藏树形菜单
            if hasattr(dialog, 'tree_widget'):
                dialog.tree_widget.setVisible(False)
                dialog.tree_widget.hide()
                dialog.tree_widget.setMaximumWidth(0)
                logger.info("已隐藏树形菜单")
            
            # 设置窗口标题
            dialog.setWindowTitle(f"Tolerances acc.to {standard_name} {tolerance_type}")
            
            # 连接信号
            dialog.tolerances_updated.connect(self.update_tolerances)
            
            # 显示对话框
            result = dialog.exec_()
            logger.info(f"公差设置对话框已关闭 (结果: {result})")
                
        except ImportError as e:
            logger.error(f"无法导入ToleranceSettingsDialog: {e}")
            QMessageBox.warning(self, "错误", f"无法加载公差设置对话框:\n{str(e)}\n\n请确保ui/tolerance_dialog.py文件存在")
        except Exception as e:
            logger.exception("打开公差设置对话框失败")
            QMessageBox.critical(self, "错误", f"打开公差设置对话框时发生错误:\n{str(e)}")
    
    def _call_calculate_tolerances(self, tolerance_dialog, tolerance_type, content_widget):
        """辅助方法：调用calculate_tolerances并确保传递正确的content_widget"""
        try:
            logger.info(f"========== _call_calculate_tolerances被调用 ==========")
            logger.info(f"tolerance_type={tolerance_type}")
            logger.info(f"tolerance_dialog.current_page_id={getattr(tolerance_dialog, 'current_page_id', 'N/A')}")
                
            # 确保content_widget被设置为当前widget
            if hasattr(tolerance_dialog, 'content_stack'):
                # 找到content_widget在content_stack中的索引
                for i in range(tolerance_dialog.content_stack.count()):
                    widget = tolerance_dialog.content_stack.widget(i)
                    if widget == content_widget or (hasattr(widget, 'findChild') and widget.findChild(type(content_widget))):
                        tolerance_dialog.content_stack.setCurrentIndex(i)
                        logger.info(f"设置content_stack当前索引为: {i}")
                        break
            
            # 确保content_widget的引用正确传递
            if content_widget and not hasattr(content_widget, 'tolerance_dialog'):
                content_widget.tolerance_dialog = tolerance_dialog
            
            # 调用calculate_tolerances
            logger.info("开始调用calculate_tolerances")
            tolerance_dialog.calculate_tolerances(tolerance_type)
            logger.info("calculate_tolerances调用完成")
            logger.info("=" * 50)
        except Exception as e:
            logger.error(f"调用calculate_tolerances失败: {e}")
            import traceback
            traceback.print_exc()
            QMessageBox.warning(None, "错误", f"更新公差值失败: {str(e)}")
    
    def _handle_tolerance_apply(self, tolerance_dialog, simple_dialog, close_dialog=False):
        """处理公差设置的应用"""
        try:
            logger.info("处理公差应用")
            
            # 调用tolerance_dialog的apply或ok方法来触发信号
            if hasattr(tolerance_dialog, 'on_apply_clicked'):
                tolerance_dialog.on_apply_clicked()
            elif hasattr(tolerance_dialog, 'on_ok_clicked'):
                tolerance_dialog.on_ok_clicked()
            else:
                # 手动触发tolerances_updated信号
                logger.info("手动触发tolerances_updated信号")
                if hasattr(tolerance_dialog, 'collect_tolerance_data'):
                    try:
                        tolerance_data = tolerance_dialog.collect_tolerance_data()
                        if hasattr(tolerance_dialog, 'tolerances_updated'):
                            tolerance_dialog.tolerances_updated.emit(tolerance_data)
                    except Exception as e:
                        logger.error(f"收集公差数据失败: {e}")
            
            # 如果是Ok按钮，关闭对话框
            if close_dialog:
                simple_dialog.accept()
            
            logger.info("公差应用处理完成")
            
        except Exception as e:
            logger.error(f"处理公差应用失败: {e}")
            QMessageBox.warning(self, "警告", f"应用公差设置时出错:\n{str(e)}")
    
    def show_ripple_tolerance_settings(self):
        """显示波纹度公差设置对话框（在子窗口中）"""
        from PyQt5.QtWidgets import (QWidget, QVBoxLayout, QHBoxLayout, QLabel, 
                                     QDoubleSpinBox, QPushButton, QCheckBox, QGroupBox, 
                                     QGridLayout, QMessageBox, QMdiSubWindow)
        
        try:
            logger.info("开始执行 show_ripple_tolerance_settings")
            
            # 检查是否已有设置子窗口打开，如果有则先关闭
            if hasattr(self, 'ripple_tolerance_subwindow') and self.ripple_tolerance_subwindow:
                old_subwindow = self.ripple_tolerance_subwindow
                # 检查子窗口是否还在MDI区域中
                found_in_mdi = False
                if hasattr(self, 'curve_mdi_area') and self.curve_mdi_area:
                    if old_subwindow in self.curve_mdi_area.subWindowList():
                        logger.info("关闭已存在的设置子窗口（curve_mdi_area）")
                        self.curve_mdi_area.removeSubWindow(old_subwindow)
                        found_in_mdi = True
                elif hasattr(self, 'mdi_area') and self.mdi_area:
                    if old_subwindow in self.mdi_area.subWindowList():
                        logger.info("关闭已存在的设置子窗口（mdi_area）")
                        self.mdi_area.removeSubWindow(old_subwindow)
                        found_in_mdi = True
                elif hasattr(self, 'settings_mdi_area') and self.settings_mdi_area:
                    if old_subwindow in self.settings_mdi_area.subWindowList():
                        logger.info("关闭已存在的设置子窗口（settings_mdi_area）")
                        self.settings_mdi_area.removeSubWindow(old_subwindow)
                        found_in_mdi = True
                
                # 关闭并清理旧窗口
                try:
                    old_subwindow.close()
                    old_subwindow.deleteLater()
                except:
                    pass
                
                # 清理引用
                self.ripple_tolerance_subwindow = None
                
                # 如果找到了旧窗口，等待一下再创建新的（避免UI冲突）
                if found_in_mdi:
                    from PyQt5.QtCore import QTimer
                    QTimer.singleShot(100, lambda: self._create_ripple_tolerance_window())
                    return
            
            # 创建新窗口
            self._create_ripple_tolerance_window()
            
        except Exception as e:
            logger.exception(f"显示波纹度公差设置对话框失败: {e}")
            QMessageBox.critical(self, "错误", f"打开设置对话框失败：\n{str(e)}")
    
    def _create_ripple_tolerance_window(self):
        """创建波纹度公差设置子窗口（内部方法）"""
        from PyQt5.QtWidgets import QMdiSubWindow, QMessageBox, QPushButton, QScrollArea
        from gear_analysis_refactored.ui.ripple_tolerance_dialog import RippleToleranceDialog
        from gear_analysis_refactored.models.gear_data import GearMeasurementData, ToleranceData, GearBasicInfo
        
        try:
            logger.info("创建新的设置子窗口")
            
            # 创建或获取measurement_data对象
            measurement_data = None
            if hasattr(self, 'measurement_data') and self.measurement_data:
                measurement_data = self.measurement_data
            else:
                # 从gear_data创建measurement_data
                measurement_data = GearMeasurementData()
                
                # 设置基本信息
                if hasattr(self, 'gear_data') and self.gear_data:
                    basic_info = GearBasicInfo(
                        drawing_no=self.gear_data.get('drawing_no', ''),
                        customer=self.gear_data.get('customer', ''),
                        order_no=self.gear_data.get('order_no', ''),
                        type_=self.gear_data.get('type', 'gear'),
                        program=self.gear_data.get('program', ''),
                        date=self.gear_data.get('date', ''),
                        teeth=self.gear_data.get('teeth', 0)
                    )
                    measurement_data.basic_info = basic_info
                
                # 设置公差数据
                tolerance = ToleranceData()
                if hasattr(self, 'gear_data') and self.gear_data:
                    tolerance.ripple_tolerance_R = self.gear_data.get('ripple_tolerance_R', 2.0)
                    tolerance.ripple_tolerance_N0 = self.gear_data.get('ripple_tolerance_N0', 1.0)
                    tolerance.ripple_tolerance_K = self.gear_data.get('ripple_tolerance_K', 0.0)
                    tolerance.ripple_tolerance_enabled = self.gear_data.get('ripple_tolerance_enabled', True)
                measurement_data.tolerance = tolerance
                
                # 保存引用
                self.measurement_data = measurement_data
            
            # 创建子窗口
            subwindow = QMdiSubWindow()
            subwindow.setWindowTitle("波纹度公差设置")
            subwindow.setMinimumSize(900, 700)
            # 允许关闭
            subwindow.setAttribute(Qt.WA_DeleteOnClose, True)
            
            # 创建RippleToleranceDialog
            # 注意：将parent设为None，以便嵌入到子窗口中
            dialog = RippleToleranceDialog(measurement_data=measurement_data, parent=None)
            
            # 修改对话框的窗口标志，使其可以作为widget嵌入
            dialog.setWindowFlags(Qt.Widget)
            
            # 连接设置更新信号
            def on_settings_updated(settings):
                """处理设置更新并刷新图表"""
                try:
                    # 保存到gear_data
                    if not hasattr(self, 'gear_data') or self.gear_data is None:
                        self.gear_data = {}
                    
                    self.gear_data['ripple_tolerance_R'] = settings.get('R', 2.0)
                    self.gear_data['ripple_tolerance_N0'] = settings.get('N0', 1.0)
                    self.gear_data['ripple_tolerance_K'] = settings.get('K', 0.0)
                    self.gear_data['ripple_tolerance_enabled'] = settings.get('enabled', True)
                    
                    # 同时更新measurement_data
                    if hasattr(self, 'measurement_data') and self.measurement_data:
                        if hasattr(self.measurement_data, 'tolerance'):
                            self.measurement_data.tolerance.ripple_tolerance_R = settings.get('R', 2.0)
                            self.measurement_data.tolerance.ripple_tolerance_N0 = settings.get('N0', 1.0)
                            self.measurement_data.tolerance.ripple_tolerance_K = settings.get('K', 0.0)
                            self.measurement_data.tolerance.ripple_tolerance_enabled = settings.get('enabled', True)
                    
                    logger.info("波纹度公差设置已保存")
                    
                    # 刷新图表（如果存在波纹度分析结果）
                    self.refresh_ripple_charts_with_tolerance()
                    
                except Exception as e:
                    logger.exception(f"保存设置失败: {e}")
            
            dialog.settings_updated.connect(on_settings_updated)
            
            # 修改对话框的按钮行为
            # 找到所有按钮
            for btn in dialog.findChildren(QPushButton):
                if btn.text() == "应用":
                    # 应用按钮：保存设置并刷新图表，但不关闭对话框
                    btn.clicked.disconnect()
                    def on_apply_clicked():
                        dialog.apply_settings()  # 调用apply_settings方法
                        on_settings_updated(dialog.get_settings())  # 触发图表刷新
                    btn.clicked.connect(on_apply_clicked)
                elif btn.text() == "确定":
                    # 确定按钮：保存设置并关闭对话框
                    btn.clicked.disconnect()
                    def on_ok_clicked():
                        on_settings_updated(dialog.get_settings())
                        subwindow.close()  # 关闭子窗口
                    btn.clicked.connect(on_ok_clicked)
                elif btn.text() == "取消":
                    # 取消按钮关闭子窗口
                    btn.clicked.disconnect()
                    def on_cancel_clicked():
                        subwindow.close()
                    btn.clicked.connect(on_cancel_clicked)
            
            # 直接设置对话框为子窗口内容（对话框内部已经有滚动区域）
            # 设置对话框的大小策略，使其可以适应子窗口大小
            dialog.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)
            
            # 设置子窗口内容为对话框
            subwindow.setWidget(dialog)
            
            # 添加到MDI区域
            mdi_added = False
            if hasattr(self, 'curve_mdi_area') and self.curve_mdi_area:
                logger.info("添加到 curve_mdi_area")
                self.curve_mdi_area.addSubWindow(subwindow)
                self.curve_mdi_area.setActiveSubWindow(subwindow)
                mdi_added = True
            elif hasattr(self, 'mdi_area') and self.mdi_area:
                logger.info("添加到 mdi_area")
                self.mdi_area.addSubWindow(subwindow)
                self.mdi_area.setActiveSubWindow(subwindow)
                mdi_added = True
            
            if not mdi_added:
                # 如果没有MDI区域，尝试使用主窗口的中央区域或创建一个新的
                logger.warning("未找到MDI区域，尝试创建新的或使用主窗口")
                # 尝试找到主窗口的中央widget
                central_widget = self.centralWidget()
                if central_widget:
                    # 如果中央widget是QMdiArea，使用它
                    from PyQt5.QtWidgets import QMdiArea
                    if isinstance(central_widget, QMdiArea):
                        logger.info("使用中央widget作为MDI区域")
                        central_widget.addSubWindow(subwindow)
                        central_widget.setActiveSubWindow(subwindow)
                        mdi_added = True
                    else:
                        # 创建一个新的MDI区域并替换中央widget
                        logger.info("创建新的MDI区域")
                        from PyQt5.QtWidgets import QMdiArea
                        # 保存原来的中央widget
                        if not hasattr(self, '_original_central_widget'):
                            self._original_central_widget = central_widget
                            logger.info("保存原始中央widget")
                        
                        self.settings_mdi_area = QMdiArea()
                        self.settings_mdi_area.setViewMode(QMdiArea.TabbedView)
                        self.settings_mdi_area.setTabsClosable(True)
                        # 将新MDI区域添加到中央widget（如果中央widget是容器）
                        if hasattr(central_widget, 'layout') and central_widget.layout():
                            central_widget.layout().addWidget(self.settings_mdi_area)
                        else:
                            self.setCentralWidget(self.settings_mdi_area)
                        self.settings_mdi_area.addSubWindow(subwindow)
                        self.settings_mdi_area.setActiveSubWindow(subwindow)
                        mdi_added = True
                
                # 如果还是没有MDI区域，直接显示为独立窗口
                if not mdi_added:
                    logger.info("未找到MDI区域，显示为独立窗口")
                    subwindow.setWindowFlags(subwindow.windowFlags() | Qt.Window)
                    subwindow.setParent(None)  # 移除父窗口
                    mdi_added = True
            
            # 保存子窗口引用
            self.ripple_tolerance_subwindow = subwindow
            
            # 连接关闭事件，确保清理引用和恢复窗体
            def on_subwindow_destroyed():
                """子窗口销毁时的回调"""
                if hasattr(self, 'ripple_tolerance_subwindow') and self.ripple_tolerance_subwindow == subwindow:
                    self.ripple_tolerance_subwindow = None
                    logger.info("子窗口引用已清理")
                
                # 如果使用了settings_mdi_area且已为空，恢复原始中央widget
                if hasattr(self, 'settings_mdi_area') and self.settings_mdi_area:
                    if not self.settings_mdi_area.subWindowList():
                        if hasattr(self, '_original_central_widget') and self._original_central_widget:
                            try:
                                logger.info("窗口销毁时恢复原始中央widget")
                                # 从布局中移除settings_mdi_area
                                if hasattr(self.settings_mdi_area, 'parent') and self.settings_mdi_area.parent():
                                    parent = self.settings_mdi_area.parent()
                                    if hasattr(parent, 'layout') and parent.layout():
                                        parent.layout().removeWidget(self.settings_mdi_area)
                                
                                # 恢复原始中央widget
                                self.setCentralWidget(self._original_central_widget)
                                
                                # 清理settings_mdi_area
                                self.settings_mdi_area.deleteLater()
                                self.settings_mdi_area = None
                                
                                # 清理保存的引用
                                delattr(self, '_original_central_widget')
                                
                                logger.info("已恢复原始中央widget")
                            except Exception as restore_error:
                                logger.exception(f"恢复原始中央widget失败: {restore_error}")
            
            subwindow.destroyed.connect(on_subwindow_destroyed)
            
            # 显示子窗口
            logger.info("显示子窗口")
            subwindow.show()
            subwindow.raise_()  # 确保窗口在最前面
            logger.info("设置子窗口已显示")
            
        except Exception as e:
            logger.exception(f"创建波纹度公差设置窗口失败: {e}")
            from PyQt5.QtWidgets import QMessageBox
            QMessageBox.critical(self, "错误", f"创建设置窗口失败：\n{str(e)}")
    
    def refresh_ripple_charts_with_tolerance(self):
        """刷新波纹度图表，应用新的公差设置"""
        try:
            logger.info("开始刷新波纹度图表，应用新的公差设置")
            
            # 检查是否有数据可以生成报表
            if not hasattr(self, 'gear_data') or not self.gear_data:
                logger.warning("没有齿轮数据，无法生成报表")
                from PyQt5.QtWidgets import QMessageBox
                QMessageBox.information(self, "提示", "公差设置已保存！\n\n请先加载MKA文件并运行分析，然后生成报表以查看更新后的公差曲线。")
                return
            
            if not hasattr(self, 'current_file') or not self.current_file:
                logger.warning("没有当前文件，无法生成报表")
                from PyQt5.QtWidgets import QMessageBox
                QMessageBox.information(self, "提示", "公差设置已保存！\n\n请先打开MKA文件，然后生成报表以查看更新后的公差曲线。")
                return
            
            # 自动重新生成报表
            logger.info("开始重新生成报表以应用新的公差设置")
            try:
                # 显示进度提示
                from PyQt5.QtWidgets import QMessageBox, QApplication
                from PyQt5.QtCore import QTimer
                
                # 重新生成报表
                self.generate_klingelnberg_pdf_report(auto_generate=True)
                logger.info("报表已重新生成，公差设置已应用到图表")
                
                # 如果当前在报表页面，自动刷新PDF显示
                if hasattr(self, 'current_tab') and self.current_tab == 2:  # 报表页面
                    logger.info("当前在报表页面，自动刷新PDF显示")
                    try:
                        # 使用QTimer延迟刷新，确保PDF文件已完全生成
                        QTimer.singleShot(500, self.show_klingelnberg_pdf_in_webview)
                        logger.info("已安排PDF显示刷新")
                        from PyQt5.QtWidgets import QMessageBox
                        QMessageBox.information(self, "成功", "报表已重新生成！\n\n公差设置已应用到图表，报表正在自动刷新...")
                    except Exception as e:
                        logger.exception(f"刷新PDF显示失败: {e}")
                        from PyQt5.QtWidgets import QMessageBox
                        QMessageBox.information(self, "成功", "报表已重新生成！\n\n公差设置已应用到图表。\n\n如果报表未自动刷新，请手动切换到报表页面查看。")
                else:
                    from PyQt5.QtWidgets import QMessageBox
                    QMessageBox.information(self, "成功", "报表已重新生成！\n\n公差设置已应用到图表。\n\n请切换到报表页面查看更新后的报表。")
                    
            except Exception as e:
                logger.exception(f"重新生成报表失败: {e}")
                from PyQt5.QtWidgets import QMessageBox
                QMessageBox.warning(self, "提示", f"公差设置已保存，但重新生成报表时出错：\n{str(e)}\n\n请手动重新生成报表以查看更新后的公差曲线。")
                
        except Exception as e:
            logger.exception(f"刷新波纹度图表失败: {e}")
            from PyQt5.QtWidgets import QMessageBox
            QMessageBox.warning(self, "错误", f"刷新图表时发生错误：\n{str(e)}")
    
    def update_tolerances(self, settings):
        """Update tolerance settings from dialog"""
        self.tolerance_settings = settings
        
        # 更新gear_data中的公差值（包括profile、lead和spacing）
        if self.gear_data and settings:
            # 从settings中提取公差值并更新到gear_data
            for standard_key, standard_data in settings.items():
                if isinstance(standard_data, dict) and 'data' in standard_data:
                    tolerance_data = standard_data['data']
                    
                    # Profile公差 (齿形)
                    if 'Profile' in standard_key:
                        if 'Fa' in tolerance_data:
                            self.gear_data['F_alpha_tolerance'] = tolerance_data['Fa'].get('left', {}).get('upp', 0)
                        if 'fHa' in tolerance_data:
                            self.gear_data['fH_alpha_tolerance'] = tolerance_data['fHa'].get('left', {}).get('upp', 0)
                        if 'ffa' in tolerance_data:
                            self.gear_data['ff_alpha_tolerance'] = tolerance_data['ffa'].get('left', {}).get('upp', 0)
                    
                    # Lead公差 (齿向)
                    elif 'Lead' in standard_key:
                        if 'Fb' in tolerance_data:
                            self.gear_data['F_beta_tolerance'] = tolerance_data['Fb'].get('left', {}).get('upp', 0)
                        if 'fHb' in tolerance_data:
                            self.gear_data['fH_beta_tolerance'] = tolerance_data['fHb'].get('left', {}).get('upp', 0)
                        if 'ffb' in tolerance_data:
                            self.gear_data['ff_beta_tolerance'] = tolerance_data['ffb'].get('left', {}).get('upp', 0)
                    
                    # Spacing公差 (周节)
                    elif 'Spacing' in standard_key:
                        if 'fp' in tolerance_data:
                            self.gear_data['fp_tolerance'] = tolerance_data['fp'].get('left', {}).get('upp', 0)
                        if 'Fp' in tolerance_data:
                            self.gear_data['Fp_tolerance'] = tolerance_data['Fp'].get('left', {}).get('upp', 0)
                        if 'Fr' in tolerance_data:
                            self.gear_data['Fr_tolerance'] = tolerance_data['Fr'].get('left', {}).get('upp', 0)
            
            logger.info("已从公差设置更新gear_data中的profile、lead和spacing公差值")
        
        # Store in deviation_results if it exists, otherwise it will be used when generating report
        if self.deviation_results:
            self.deviation_results['tolerance_settings'] = settings
            # 保存标准名称到deviation_results
            if self.gear_data and 'tolerance_standard' in self.gear_data:
                self.deviation_results['tolerance_standard'] = self.gear_data['tolerance_standard']
        
        # 保存标准名称到measurement_data.basic_info（如果存在）
        if hasattr(self, 'measurement_data') and self.measurement_data and hasattr(self.measurement_data, 'basic_info'):
            if self.gear_data and 'tolerance_standard' in self.gear_data:
                self.measurement_data.basic_info.tolerance_standard = self.gear_data['tolerance_standard']
        
        # 重新评价偏差分析表格
        if hasattr(self, 'deviation_results') and self.deviation_results:
            logger.info("重新评价偏差分析结果")
            self.refresh_deviation_analysis_table()
            
            # 重新生成PDF报表
            if hasattr(self, 'current_file') and self.current_file:
                logger.info("重新生成PDF报表以应用新公差")
                try:
                    self.generate_klingelnberg_pdf_report()
                    QMessageBox.information(self, "成功", "公差设置已更新！\n\n- 偏差分析结果已重新评价\n- PDF报表已更新")
                    
                    # 自动刷新PDF显示
                    if hasattr(self, 'show_klingelnberg_pdf_in_webview'):
                        from PyQt5.QtCore import QTimer
                        QTimer.singleShot(500, self.show_klingelnberg_pdf_in_webview)
                        logger.info("已安排PDF显示刷新")
                        
                except Exception as e:
                    logger.error(f"重新生成PDF失败: {e}")
                    QMessageBox.warning(self, "警告", f"公差设置已更新，偏差分析已重新评价\n\n但PDF报表更新失败:\n{str(e)}")
            else:
                QMessageBox.information(self, "成功", "公差设置已更新，偏差分析结果已重新评价")
        else:
            QMessageBox.information(self, "成功", "公差设置已更新，请重新进行偏差分析或生成报告查看变化")

    def show_analysis_settings(self):
        """打开分析参数设置对话框"""
        # 使用 ToleranceSettingsDialog 替换原有的 AnalysisSettingsDialog
        try:
            # Ensure gear_data is initialized
            if self.gear_data is None:
                self.gear_data = {}
                
            # Sync data from UI tables to gear_data
            if hasattr(self, 'basic_table') and self.basic_table and self.basic_table.rowCount() > 0:
                try:
                    basic_keys = [
                        'program', 'date', 'start_time', 'end_time',
                        'operator', 'location', 'drawing_no', 'order_no', 'type',
                        'customer', 'condition', 'spindle_no', 'purpose', 'accuracy_grade'
                    ]
                    for i, key in enumerate(basic_keys):
                        if i < self.basic_table.rowCount():
                            item = self.basic_table.item(i, 1)
                            if item:
                                self.gear_data[key] = item.text()
                except Exception as e:
                    logger.warning(f"Error syncing basic table: {e}")

            if hasattr(self, 'params_table') and self.params_table and self.params_table.rowCount() > 0:
                try:
                    param_keys = [
                        'module', 'teeth', 'helix_angle', 'pressure_angle', 'modification_coeff', 'width',
                        'tip_diameter', 'root_diameter', 'ball_diameter', 'measured_teeth', 'start_meas_position',
                        'width_reduction', 'mdk', 'wkt', 'accuracy_grade',
                        'F_alpha_tol', 'fH_alpha_tol', 'ff_alpha_tol', 'F_beta_tol', 'fH_beta_tol', 'ff_beta_tol',
                        'Fp_tol', 'fp_tol', 'Fr_tol'
                    ]
                    for i, key in enumerate(param_keys):
                        if i < self.params_table.rowCount():
                            item = self.params_table.item(i, 1)
                            if item:
                                self.gear_data[key] = item.text()
                except Exception as e:
                    logger.warning(f"Error syncing params table: {e}")

            from ui.tolerance_dialog import ToleranceSettingsDialog
            dialog = ToleranceSettingsDialog(self.gear_data, self)
            
            # 确保对话框完成初始化
            if hasattr(dialog, 'init_ui'):
                try:
                    dialog.init_ui()
                except Exception as e:
                    logger.warning(f"调用init_ui失败: {e}")
            
            # 隐藏左侧树形菜单以简化操作 - 多种方法确保隐藏
            if hasattr(dialog, 'tree_widget'):
                dialog.tree_widget.setVisible(False)
                dialog.tree_widget.hide()
                dialog.tree_widget.setMaximumWidth(0)
                logger.info("树形菜单已隐藏（show_analysis_settings）")
            
            # 强制更新对话框布局
            dialog.updateGeometry()
            if dialog.layout():
                dialog.layout().update()
                dialog.layout().activate()
            
            dialog.tolerances_updated.connect(self.update_tolerances)
            
            # 使用QTimer延迟刷新布局和隐藏树形菜单
            from PyQt5.QtCore import QTimer
            def refresh_layout():
                try:
                    if dialog.isVisible():
                        # 再次确保树形菜单隐藏
                        if hasattr(dialog, 'tree_widget'):
                            dialog.tree_widget.setVisible(False)
                            dialog.tree_widget.hide()
                            dialog.tree_widget.setMaximumWidth(0)
                        dialog.updateGeometry()
                        if dialog.layout():
                            dialog.layout().update()
                except Exception as e:
                    logger.debug(f"刷新布局失败: {e}")
            
            QTimer.singleShot(100, refresh_layout)
            
            if dialog.exec_() == QDialog.Accepted:
                # If accepted, we might want to trigger re-analysis or just let the signal handle it
                # The signal update_tolerances already updates self.tolerance_settings
                # We can prompt user to re-analyze
                QMessageBox.information(self, "设置已更新", "公差设置已更新。请重新生成报告以应用更改。")
                        
        except ImportError as e:
            QMessageBox.warning(self, "Error", f"Could not import ToleranceSettingsDialog: {e}")
        except Exception as e:
            QMessageBox.warning(self, "Error", f"Error opening tolerance settings: {e}")        


    def apply_analysis_settings_to_gear_data(self, settings):
        """将分析设置应用到gear_data中"""
        try:
            if not self.gear_data or not settings:
                return
            
            # 应用精度等级设置
            if 'iso_grade' in settings:
                new_grade = settings['iso_grade']
                old_grade = self.gear_data.get('accuracy_grade', 5)
                
                if new_grade != old_grade:
                    self.gear_data['accuracy_grade'] = new_grade
                    logger.info(f"精度等级已从{old_grade}级更新为{new_grade}级")
                    
                    # 重新计算公差
                    self.recalculate_tolerances_from_settings(settings)
            
            # 应用评价范围设置
            if 'profile_range' in settings:
                self.gear_data['profile_range'] = settings['profile_range']
                logger.info(f"齿形评价范围已更新: {settings['profile_range']}")
            
            if 'lead_range' in settings:
                self.gear_data['lead_range'] = settings['lead_range']
                logger.info(f"齿向评价范围已更新: {settings['lead_range']}")
            
            # 应用公差模式设置
            if 'tolerance_mode' in settings:
                self.gear_data['tolerance_mode'] = settings['tolerance_mode']
                logger.info(f"公差模式已更新: {settings['tolerance_mode']}")
            
            # 应用自定义公差设置
            if 'custom_tolerances' in settings and settings['custom_tolerances']:
                self.gear_data['custom_tolerances'] = settings['custom_tolerances']
                logger.info(f"自定义公差已更新: {settings['custom_tolerances']}")
            
            logger.info("分析设置已成功应用到gear_data")
            
        except Exception as e:
            logger.error(f"应用分析设置错误: {str(e)}")

    def recalculate_tolerances_from_settings(self, settings):
        """根据分析设置重新计算公差"""
        try:
            if not self.gear_data:
                return
            
            tolerance_mode = settings.get('tolerance_mode', '使用MKA文件默认值')
            
            if tolerance_mode == "ISO 1328 标准公差":
                # 使用ISO 1328标准计算公差
                iso_grade = settings.get('iso_grade', 5)  # 默认5级精度
                self.calculate_iso1328_tolerances(iso_grade)
                
            elif tolerance_mode == "自定义自由公差":
                # 使用自定义公差
                custom_tolerances = settings.get('custom_tolerances', {})
                self.apply_custom_tolerances(custom_tolerances)
                
            else:
                # 使用MKA文件默认值，保持原有公差
                logger.info("使用MKA文件默认公差值")
                
        except Exception as e:
            logger.error(f"重新计算公差错误: {str(e)}")

    def calculate_iso1328_tolerances(self, grade):
        """根据ISO 1328标准计算公差"""
        try:
            if not self.gear_data:
                return
            
            # 获取齿轮基本参数
            module = self.gear_data.get('module', 1.0)
            teeth_count = self.gear_data.get('teeth_count', 20)
            face_width = self.gear_data.get('face_width', 10.0)
            
            # 根据ISO 1328标准计算公差
            # 齿形公差 F_alpha
            F_alpha_tolerance = self.calculate_F_alpha_tolerance(module, teeth_count, grade)
            
            # 齿向公差 F_beta  
            F_beta_tolerance = self.calculate_F_beta_tolerance(face_width, grade)
            
            # 齿形形状公差 fH_alpha
            fH_alpha_tolerance = self.calculate_fH_alpha_tolerance(module, teeth_count, grade)
            
            # 齿向形状公差 fH_beta
            fH_beta_tolerance = self.calculate_fH_beta_tolerance(face_width, grade)
            
            # 齿形波纹度公差 ff_alpha
            ff_alpha_tolerance = self.calculate_ff_alpha_tolerance(module, teeth_count, grade)
            
            # 周节公差 fp, Fp, Fr
            fp_tolerance, Fp_tolerance, Fr_tolerance = self.calculate_tolerances('spacing', 'left')
            
            # 齿向波纹度公差 ff_beta
            ff_beta_tolerance = self.calculate_ff_beta_tolerance(face_width, grade)
            
            # 更新gear_data中的公差值
            self.gear_data.update({
                'F_alpha_tolerance': F_alpha_tolerance,
                'F_beta_tolerance': F_beta_tolerance,
                'fH_alpha_tolerance': fH_alpha_tolerance,
                'fH_beta_tolerance': fH_beta_tolerance,
                'ff_alpha_tolerance': ff_alpha_tolerance,
                'ff_beta_tolerance': ff_beta_tolerance,
                'fp_tolerance': fp_tolerance,
                'Fp_tolerance': Fp_tolerance,
                'Fr_tolerance': Fr_tolerance,
                'accuracy_grade': grade
            })
            
            logger.info(f"ISO 1328 {grade}级公差已计算并更新")
            logger.info(f"周节公差: fp={fp_tolerance:.1f}, Fp={Fp_tolerance:.1f}, Fr={Fr_tolerance:.1f}")
            
        except Exception as e:
            logger.error(f"计算ISO 1328公差错误: {str(e)}")

    def apply_custom_tolerances(self, custom_tolerances):
        """应用自定义公差"""
        try:
            if not self.gear_data or not custom_tolerances:
                return
            
            # 直接应用自定义公差值
            for key, value in custom_tolerances.items():
                if key in ['F_alpha', 'F_beta', 'fH_alpha', 'fH_beta', 'ff_alpha', 'ff_beta', 'fp', 'Fp', 'Fr']:
                    tolerance_key = f"{key}_tolerance"
                    self.gear_data[tolerance_key] = value
            
            logger.info(f"自定义公差已应用: {custom_tolerances}")
            
        except Exception as e:
            logger.error(f"应用自定义公差错误: {str(e)}")

    def get_current_accuracy_grade(self):
        """获取当前精度等级"""
        if hasattr(self, 'analysis_settings') and self.analysis_settings:
            return self.analysis_settings.get('iso_grade', 5)  # 默认5级精度
        elif self.gear_data:
            return self.gear_data.get('accuracy_grade', 5)  # 默认5级精度
        else:
            return 5  # 默认5级精度


    def get_actual_accuracy_grade_from_tolerance(self, data_type):
        """根据实际公差值计算精度等级"""
        try:
            if not self.gear_data:
                return 5  # 默认5级
            
            # 获取当前公差值
            if data_type == "齿形":
                F_tolerance = self.gear_data.get('F_alpha_tolerance', 0)
                fH_tolerance = self.gear_data.get('fH_alpha_tolerance', 0)
                ff_tolerance = self.gear_data.get('ff_alpha_tolerance', 0)
            elif data_type == "周节":
                F_tolerance = self.gear_data.get('fp_tolerance', 0)
                fH_tolerance = self.gear_data.get('Fp_tolerance', 0)
                ff_tolerance = self.gear_data.get('Fr_tolerance', 0)
            else:  # 齿向
                F_tolerance = self.gear_data.get('F_beta_tolerance', 0)
                fH_tolerance = self.gear_data.get('fH_beta_tolerance', 0)
                ff_tolerance = self.gear_data.get('ff_beta_tolerance', 0)
            
            # 获取齿轮基本参数
            module = self.gear_data.get('module', 1.0)
            teeth_count = self.gear_data.get('teeth_count', 20)
            face_width = self.gear_data.get('face_width', 10.0)
            
            # 根据ISO 1328标准反推精度等级
            calculated_grade = self.calculate_grade_from_tolerance(
                F_tolerance, fH_tolerance, ff_tolerance, 
                module, teeth_count, face_width, data_type
            )
            
            logger.info(f"根据公差值计算得出精度等级: {calculated_grade}级")
            return calculated_grade
            
        except Exception as e:
            logger.error(f"计算实际精度等级错误: {str(e)}")
            return self.gear_data.get('accuracy_grade', 5) if self.gear_data else 5

    def calculate_grade_from_tolerance(self, F_tolerance, fH_tolerance, ff_tolerance, 
                                     module, teeth_count, face_width, data_type):
        """根据公差值反推精度等级"""
        try:
            # 定义ISO 1328标准公差表（简化版）
            # 这里使用简化的计算，实际应用中可能需要更复杂的查表
            grade_tolerance_ranges = {
                3: {'F': (0, 3), 'fH': (0, 2), 'ff': (0, 1)},
                4: {'F': (3, 6), 'fH': (2, 4), 'ff': (1, 2)},
                5: {'F': (6, 10), 'fH': (4, 6), 'ff': (2, 3)},
                6: {'F': (10, 16), 'fH': (6, 10), 'ff': (3, 5)},
                7: {'F': (16, 25), 'fH': (10, 16), 'ff': (5, 8)},
                8: {'F': (25, 40), 'fH': (16, 25), 'ff': (8, 12)},
                9: {'F': (40, 63), 'fH': (25, 40), 'ff': (12, 20)},
                10: {'F': (63, 100), 'fH': (40, 63), 'ff': (20, 32)}
            }
            
            # 根据公差值确定精度等级
            best_grade = 5  # 默认5级
            best_match_score = 0
            
            for grade, ranges in grade_tolerance_ranges.items():
                match_score = 0
                
                # 检查F公差
                if ranges['F'][0] <= F_tolerance <= ranges['F'][1]:
                    match_score += 1
                
                # 检查fH公差
                if ranges['fH'][0] <= fH_tolerance <= ranges['fH'][1]:
                    match_score += 1
                
                # 检查ff公差
                if ranges['ff'][0] <= ff_tolerance <= ranges['ff'][1]:
                    match_score += 1
                
                # 如果匹配度更高，更新最佳等级
                if match_score > best_match_score:
                    best_match_score = match_score
                    best_grade = grade
            
            # 如果没有完全匹配，使用最接近的等级
            if best_match_score == 0:
                # 根据F公差值估算等级
                if F_tolerance <= 3:
                    best_grade = 3
                elif F_tolerance <= 6:
                    best_grade = 4
                elif F_tolerance <= 10:
                    best_grade = 5
                elif F_tolerance <= 16:
                    best_grade = 6
                elif F_tolerance <= 25:
                    best_grade = 7
                elif F_tolerance <= 40:
                    best_grade = 8
                elif F_tolerance <= 63:
                    best_grade = 9
                else:
                    best_grade = 10
            
            logger.info(f"公差值: F={F_tolerance}, fH={fH_tolerance}, ff={ff_tolerance}")
            logger.info(f"计算得出精度等级: {best_grade}级 (匹配度: {best_match_score}/3)")
            
            return best_grade
            
        except Exception as e:
            logger.error(f"根据公差值计算精度等级错误: {str(e)}")
            return 5

    def update_accuracy_grade_display(self):
        """更新所有表格行的精度等级显示"""
        try:
            if not hasattr(self, 'deviation_table') or not self.deviation_table:
                return
            
            # 更新表格中每一行的精度等级显示
            for row in range(self.deviation_table.rowCount()):
                data_type = self.deviation_table.item(row, 2).text()
                actual_grade = self.get_actual_accuracy_grade_from_tolerance(data_type)
                
                # 更新精度等级显示
                grade_item = QTableWidgetItem(f"{actual_grade}级")
                self.deviation_table.setItem(row, 3, grade_item)
            
            logger.info("已更新所有表格行的精度等级显示")
            
        except Exception as e:
            logger.error(f"更新精度等级显示错误: {str(e)}")

    def sync_accuracy_grade_with_tolerance(self):
        """同步精度等级与公差值"""
        try:
            if not self.gear_data:
                return
            
            # 获取当前公差值
            F_alpha_tolerance = self.gear_data.get('F_alpha_tolerance', 0)
            F_beta_tolerance = self.gear_data.get('F_beta_tolerance', 0)
            
            # 根据公差值计算实际精度等级
            module = self.gear_data.get('module', 1.0)
            teeth_count = self.gear_data.get('teeth_count', 20)
            face_width = self.gear_data.get('face_width', 10.0)
            
            # 计算齿形和齿向的精度等级
            profile_grade = self.calculate_grade_from_tolerance(
                F_alpha_tolerance, 
                self.gear_data.get('fH_alpha_tolerance', 0),
                self.gear_data.get('ff_alpha_tolerance', 0),
                module, teeth_count, face_width, "齿形"
            )
            
            flank_grade = self.calculate_grade_from_tolerance(
                F_beta_tolerance,
                self.gear_data.get('fH_beta_tolerance', 0),
                self.gear_data.get('ff_beta_tolerance', 0),
                module, teeth_count, face_width, "齿向"
            )
            
            # 使用较高的精度等级作为整体等级
            actual_grade = max(profile_grade, flank_grade)
            
            # 更新gear_data中的精度等级
            old_grade = self.gear_data.get('accuracy_grade', 5)
            if actual_grade != old_grade:
                self.gear_data['accuracy_grade'] = actual_grade
                logger.info(f"精度等级已从{old_grade}级同步为{actual_grade}级")
            
            # 更新分析设置中的精度等级
            if hasattr(self, 'analysis_settings') and self.analysis_settings:
                self.analysis_settings['iso_grade'] = actual_grade
                logger.info(f"分析设置中的精度等级已同步为{actual_grade}级")
            
            # 更新表格显示
            self.update_accuracy_grade_display()
            
        except Exception as e:
            logger.error(f"同步精度等级错误: {str(e)}")


    def update_deviation_analysis_with_new_grade(self, new_grade):
        """使用新的精度等级更新偏差分析"""
        try:
            if not self.gear_data:
                logger.warning("没有齿轮数据，无法更新偏差分析")
                return
            
            logger.info(f"开始使用新精度等级 {new_grade}级 更新偏差分析")
            
            # 更新gear_data中的精度等级
            old_grade = self.gear_data.get('accuracy_grade', 5)
            self.gear_data['accuracy_grade'] = new_grade
            
            if old_grade != new_grade:
                logger.info(f"精度等级已从 {old_grade}级 更新为 {new_grade}级")
            
            # 重新计算公差值
            self.recalculate_tolerances_with_new_grade(new_grade)
            
            # 更新偏差分析表格
            self.refresh_deviation_analysis_table()
            
            # 重新计算合格率
            self.recalculate_deviation_pass_rate()
            
            logger.info(f"偏差分析已使用新精度等级 {new_grade}级 完成更新")
            
        except Exception as e:
            logger.error(f"更新偏差分析精度等级错误: {str(e)}")

    def recalculate_tolerances_with_new_grade(self, new_grade):
        """使用新精度等级重新计算所有公差值"""
        try:
            logger.info(f"使用精度等级 {new_grade}级 重新计算公差值")
            
            # 获取齿轮基本参数
            module = self.gear_data.get('module', 1.0)
            teeth_count = self.gear_data.get('teeth_count', 20)
            face_width = self.gear_data.get('face_width', 10.0)
            
            # 重新计算齿形公差
            F_alpha_tolerance = self.calculate_F_alpha_tolerance(new_grade, module, teeth_count)
            fH_alpha_tolerance = self.calculate_fH_alpha_tolerance(new_grade, module, teeth_count)
            ff_alpha_tolerance = self.calculate_ff_alpha_tolerance(new_grade, module, teeth_count)
            
            # 重新计算齿向公差
            F_beta_tolerance = self.calculate_F_beta_tolerance(new_grade, module, teeth_count, face_width)
            fH_beta_tolerance = self.calculate_fH_beta_tolerance(new_grade, module, teeth_count, face_width)
            ff_beta_tolerance = self.calculate_ff_beta_tolerance(new_grade, module, teeth_count, face_width)
            
            # 重新计算周节公差
            fp_tolerance, Fp_tolerance, Fr_tolerance = self.calculate_tolerances('spacing', 'left')
            
            # 更新gear_data中的公差值
            self.gear_data.update({
                'F_alpha_tolerance': F_alpha_tolerance,
                'fH_alpha_tolerance': fH_alpha_tolerance,
                'ff_alpha_tolerance': ff_alpha_tolerance,
                'F_beta_tolerance': F_beta_tolerance,
                'fH_beta_tolerance': fH_beta_tolerance,
                'ff_beta_tolerance': ff_beta_tolerance,
                'fp_tolerance': fp_tolerance,
                'Fp_tolerance': Fp_tolerance,
                'Fr_tolerance': Fr_tolerance
            })
            
            logger.info(f"公差值已更新: Fα={F_alpha_tolerance:.1f}, fHα={fH_alpha_tolerance:.1f}, ffα={ff_alpha_tolerance:.1f}")
            logger.info(f"公差值已更新: Fβ={F_beta_tolerance:.1f}, fHβ={fH_beta_tolerance:.1f}, ffβ={ff_beta_tolerance:.1f}")
            logger.info(f"周节公差已更新: fp={fp_tolerance:.1f}, Fp={Fp_tolerance:.1f}, Fr={Fr_tolerance:.1f}")
            
        except Exception as e:
            logger.error(f"重新计算公差值错误: {str(e)}")

    def calculate_tolerances(self, data_type, side):
        """根据ISO1328标准计算公差值 - GearDataViewer版本"""
        try:
            if not self.gear_data:
                # 默认5级精度公差值
                if data_type == 'spacing':
                    return 12.0, 36.0, 28.0  # fp, Fp, Fr
                return 8.0, 5.6, 3.2  # F, fH, ff
            
            # 获取齿轮参数
            module = self.gear_data.get('module', 2.0)
            teeth = self.gear_data.get('teeth', 20)
            width = self.gear_data.get('width', 20)
            
            # 使用分析设置中的公差模式
            tolerance_mode = getattr(self, 'analysis_settings', {}).get('tolerance_mode', '使用MKA文件默认值')
            iso_grade = getattr(self, 'analysis_settings', {}).get('iso_grade', 5)  # 默认5级精度
            custom_tolerances = getattr(self, 'analysis_settings', {}).get('custom_tolerances', {})
            
            # 如果使用自定义公差
            if tolerance_mode == "自定义自由公差":
                if data_type == 'profile':
                    return (custom_tolerances.get('F_alpha', 8.0), 
                           custom_tolerances.get('fH_alpha', 5.6), 
                           custom_tolerances.get('ff_alpha', 3.2))
                elif data_type == 'spacing':
                    return (custom_tolerances.get('fp', 12.0), 
                           custom_tolerances.get('Fp', 36.0), 
                           custom_tolerances.get('Fr', 28.0))
                else:
                    return (custom_tolerances.get('F_beta', 8.0), 
                           custom_tolerances.get('fH_beta', 5.6), 
                           custom_tolerances.get('ff_beta', 3.2))
            
            # 使用ISO 1328标准或MKA文件默认值
            accuracy_grade = iso_grade if tolerance_mode == "ISO 1328 标准公差" else self.gear_data.get('accuracy_grade', 5)
            
            # 使用固定公差查找表（DIN 3962标准）
            if data_type == 'profile':
                # 齿形公差查找表 (Fa, fHa, ffa)
                profile_tolerance_table = {
                    1: (3.0, 4.0, 5.0),
                    2: (4.0, 6.0, 7.0),
                    3: (5.5, 8.0, 10.0),
                    4: (8.0, 12.0, 14.0),
                    5: (11.0, 16.0, 20.0),
                    6: (16.0, 22.0, 28.0),
                    7: (22.0, 32.0, 40.0),
                    8: (28.0, 45.0, 56.0),
                    9: (40.0, 63.0, 80.0),
                    10: (63.0, 100.0, 125.0),
                    11: (100.0, 160.0, 200.0),
                    12: (160.0, 250.0, 315.0)
                }
                
                if accuracy_grade in profile_tolerance_table:
                    fH_alpha, ff_alpha, F_alpha = profile_tolerance_table[accuracy_grade]
                else:
                    # 默认5级
                    fH_alpha, ff_alpha, F_alpha = profile_tolerance_table[5]
                
                logger.info(f"齿形公差（查表） - 精度等级: {accuracy_grade}, F_alpha: {F_alpha:.1f}, fH_alpha: {fH_alpha:.1f}, ff_alpha: {ff_alpha:.1f}")
                
                return F_alpha, fH_alpha, ff_alpha
                
            elif data_type == 'spacing':
                # 周节公差查找表 (fp, Fp, Fr)
                spacing_tolerance_table = {
                    1: (3.0, 9.0, 7.0),
                    2: (4.5, 14.0, 10.0),
                    3: (6.0, 18.0, 14.0),
                    4: (8.0, 25.0, 20.0),
                    5: (12.0, 36.0, 28.0),
                    6: (16.0, 45.0, 40.0),
                    7: (22.0, 71.0, 56.0),
                    8: (32.0, 90.0, 80.0),
                    9: (45.0, 125.0, 110.0),
                    10: (71.0, 200.0, 160.0),
                    11: (110.0, 320.0, 220.0),
                    12: (180.0, 560.0, 320.0)
                }
                
                if accuracy_grade in spacing_tolerance_table:
                    fp, Fp, Fr = spacing_tolerance_table[accuracy_grade]
                else:
                    # 默认5级
                    fp, Fp, Fr = spacing_tolerance_table[5]
                
                logger.info(f"周节公差（查表） - 精度等级: {accuracy_grade}, fp: {fp:.1f}, Fp: {Fp:.1f}, Fr: {Fr:.1f}")
                
                return fp, Fp, Fr
                
            else:
                # 齿向公差查找表 (Fb, fHb, ffb)
                lead_tolerance_table = {
                    1: (4.0, 5.0, 6.0),
                    2: (6.0, 7.0, 9.0),
                    3: (8.0, 10.0, 12.0),
                    4: (12.0, 14.0, 18.0),
                    5: (17.0, 20.0, 25.0),
                    6: (24.0, 28.0, 36.0),
                    7: (34.0, 40.0, 50.0),
                    8: (48.0, 56.0, 71.0),
                    9: (68.0, 80.0, 100.0),
                    10: (96.0, 112.0, 140.0),
                    11: (135.0, 160.0, 200.0),
                    12: (190.0, 224.0, 280.0)
                }
                
                if accuracy_grade in lead_tolerance_table:
                    fH_beta, ff_beta, F_beta = lead_tolerance_table[accuracy_grade]
                else:
                    # 默认5级
                    fH_beta, ff_beta, F_beta = lead_tolerance_table[5]
                
                logger.info(f"齿向公差（查表） - 精度等级: {accuracy_grade}, F_beta: {F_beta:.1f}, fH_beta: {fH_beta:.1f}, ff_beta: {ff_beta:.1f}")
                
                return F_beta, fH_beta, ff_beta
                
        except Exception as e:
            logger.error(f"公差计算错误: {e}")
            # 返回默认5级精度公差值
            if data_type == 'spacing':
                return 12.0, 36.0, 28.0  # fp, Fp, Fr
            return 8.0, 5.6, 3.2

    def refresh_deviation_analysis_table(self):
        """刷新偏差分析表格，使用新的公差值重新评价"""
        try:
            if not hasattr(self, 'deviation_table') or not self.deviation_table:
                logger.warning("偏差分析表格不存在")
                return
            
            logger.info("开始刷新偏差分析表格")
            
            # 更新表格中每一行的评价结果
            for row in range(self.deviation_table.rowCount()):
                self.update_deviation_row_evaluation(row)
            
            logger.info("偏差分析表格刷新完成")
            
        except Exception as e:
            logger.error(f"刷新偏差分析表格错误: {str(e)}")

    def update_deviation_row_evaluation(self, row):
        """更新指定行的偏差评价结果"""
        try:
            if not self.deviation_table or row >= self.deviation_table.rowCount():
                return
            
            # 获取数据类型（齿形或齿向）
            data_type_item = self.deviation_table.item(row, 2)
            if not data_type_item:
                return
            
            data_type = data_type_item.text()
            
            # 获取偏差值
            F_value = float(self.deviation_table.item(row, 4).text())
            fH_value = float(self.deviation_table.item(row, 5).text())
            ff_value = float(self.deviation_table.item(row, 6).text())
            
            # 获取对应的公差值
            if data_type == "齿形":
                F_tolerance = self.gear_data.get('F_alpha_tolerance', 0)
                fH_tolerance = self.gear_data.get('fH_alpha_tolerance', 0)
                ff_tolerance = self.gear_data.get('ff_alpha_tolerance', 0)
            elif data_type == "周节":
                F_tolerance = self.gear_data.get('fp_tolerance', 0)
                fH_tolerance = self.gear_data.get('Fp_tolerance', 0)
                ff_tolerance = self.gear_data.get('Fr_tolerance', 0)
            else:  # 齿向
                F_tolerance = self.gear_data.get('F_beta_tolerance', 0)
                fH_tolerance = self.gear_data.get('fH_beta_tolerance', 0)
                ff_tolerance = self.gear_data.get('ff_beta_tolerance', 0)
            
            # 更新公差显示
            self.deviation_table.setItem(row, 7, QTableWidgetItem(f"{F_tolerance:.1f}"))
            self.deviation_table.setItem(row, 8, QTableWidgetItem(f"{fH_tolerance:.1f}"))
            self.deviation_table.setItem(row, 9, QTableWidgetItem(f"{ff_tolerance:.1f}"))
            
            # 重新评价状态
            F_status = "合格" if F_value <= F_tolerance else "超差"
            fH_status = "合格" if abs(fH_value) <= fH_tolerance else "超差"
            ff_status = "合格" if ff_value <= ff_tolerance else "超差"
            
            # 获取偏差值单元格并设置粗体（如果超差）
            from PyQt5.QtGui import QFont
            
            F_value_item = self.deviation_table.item(row, 4)
            if F_value_item and F_status == "超差":
                font = F_value_item.font()
                font.setBold(True)
                F_value_item.setFont(font)
                F_value_item.setForeground(QColor(200, 0, 0))  # 红色字体
            
            fH_value_item = self.deviation_table.item(row, 5)
            if fH_value_item and fH_status == "超差":
                font = fH_value_item.font()
                font.setBold(True)
                fH_value_item.setFont(font)
                fH_value_item.setForeground(QColor(200, 0, 0))  # 红色字体
            
            ff_value_item = self.deviation_table.item(row, 6)
            if ff_value_item and ff_status == "超差":
                font = ff_value_item.font()
                font.setBold(True)
                ff_value_item.setFont(font)
                ff_value_item.setForeground(QColor(200, 0, 0))  # 红色字体
            
            # 更新状态显示
            F_status_item = QTableWidgetItem(F_status)
            fH_status_item = QTableWidgetItem(fH_status)
            ff_status_item = QTableWidgetItem(ff_status)
            
            # 设置背景颜色
            F_status_item.setBackground(QColor(144, 238, 144) if F_status == "合格" else QColor(255, 182, 193))
            fH_status_item.setBackground(QColor(144, 238, 144) if fH_status == "合格" else QColor(255, 182, 193))
            ff_status_item.setBackground(QColor(144, 238, 144) if ff_status == "合格" else QColor(255, 182, 193))
            
            self.deviation_table.setItem(row, 10, F_status_item)
            self.deviation_table.setItem(row, 11, fH_status_item)
            self.deviation_table.setItem(row, 12, ff_status_item)
            
            # 更新精度等级显示
            current_grade = self.gear_data.get('accuracy_grade', 5)
            grade_item = QTableWidgetItem(f"{current_grade}级")
            self.deviation_table.setItem(row, 3, grade_item)
            
        except Exception as e:
            logger.error(f"更新偏差行评价错误 (行{row}): {str(e)}")

    def recalculate_deviation_pass_rate(self):
        """重新计算偏差分析合格率"""
        try:
            if not hasattr(self, 'deviation_table') or not self.deviation_table:
                return
            
            total_items = 0
            pass_items = 0
            
            for row in range(self.deviation_table.rowCount()):
                # 检查F、fH、ff三个状态
                F_status = self.deviation_table.item(row, 10).text() if self.deviation_table.item(row, 10) else ""
                fH_status = self.deviation_table.item(row, 11).text() if self.deviation_table.item(row, 11) else ""
                ff_status = self.deviation_table.item(row, 12).text() if self.deviation_table.item(row, 12) else ""
                
                total_items += 3  # 每行3个评价项目
                
                if F_status == "合格":
                    pass_items += 1
                if fH_status == "合格":
                    pass_items += 1
                if ff_status == "合格":
                    pass_items += 1
            
            # 计算合格率
            pass_rate = (pass_items / total_items * 100) if total_items > 0 else 0
            
            # 更新合格率显示
            if hasattr(self, 'deviation_pass_rate_label'):
                self.deviation_pass_rate_label.setText(f"合格率: {pass_items}/{total_items} ({pass_rate:.1f}%)")
            
            logger.info(f"偏差分析合格率已更新: {pass_items}/{total_items} ({pass_rate:.1f}%)")
            
        except Exception as e:
            logger.error(f"重新计算合格率错误: {str(e)}")

    def force_deviation_analysis_refresh(self):
        """强制刷新偏差分析（用于手动触发）"""
        try:
            current_grade = self.get_current_accuracy_grade()
            logger.info(f"手动触发偏差分析刷新，当前精度等级: {current_grade}级")
            
            self.update_deviation_analysis_with_new_grade(current_grade)
            
            # 显示更新完成消息
            QMessageBox.information(self, "更新完成", f"偏差分析已使用精度等级 {current_grade}级 重新评价完成！")
            
        except Exception as e:
            logger.error(f"强制刷新偏差分析错误: {str(e)}")
            QMessageBox.warning(self, "更新失败", f"偏差分析更新失败: {str(e)}")

    def open_file(self, file_path):
        """使用系统默认程序打开文件"""
        if not file_path:
            return

        try:
            if sys.platform == "win32":
                os.startfile(file_path)
            elif sys.platform == "darwin":  # macOS
                subprocess.call(("open", file_path))
            else:  # Linux
                subprocess.call(("xdg-open", file_path))

        except Exception as e:
            QMessageBox.warning(self, "打开失败", f"无法打开文件:\n{str(e)}")

