                        error_ax.text(0.5, 0.7, "所有齿的齿向偏差曲线图创建失败", ha='center', va='center', fontsize=16, fontweight='bold')
                        error_ax.text(0.5, 0.5, f"错误: {str(e)}", ha='center', va='center', fontsize=12)
