    def _plot_single_profile(self, ax, result):
        """绘制单个齿的齿形偏差曲线"""
        side = result['side']
        tooth = result['tooth']

        # 获取展长值
        start_measure = self.gear_data['齿形起测点展长'][side]
        start_eval = self.gear_data['齿形起评点展长'][side]
        end_eval = self.gear_data['齿形终评点展长'][side]
        end_measure = self.gear_data['齿形终测点展长'][side]

        # 获取测量数据
        if side == 'left' and tooth in self.profile_data['left']:
            values = self.profile_data['left'][tooth]
        elif side == 'right' and tooth in self.profile_data['right']:
            values = self.profile_data['right'][tooth]
        else:
            return

        # 转换为numpy数组
        values = np.array(values)

        # 计算每个点的实际位置
        x_positions = np.linspace(start_measure, end_measure, len(values))

        # 获取评价范围内的数据
        eval_data = values[result['start_eval_index']:result['end_eval_index'] + 1]
        eval_x = x_positions[result['start_eval_index']:result['end_eval_index'] + 1]

        # 计算最小二乘拟合直线
        x = np.arange(len(eval_data))
        slope, intercept = np.polyfit(x, eval_data, 1)
        trend = slope * x + intercept

        # 绘制原始数据
        ax.plot(eval_x, eval_data, 'b-', label="原始数据", linewidth=0.8)

        # 绘制拟合直线
        ax.plot(eval_x, trend, 'r-', label="拟合直线", linewidth=0.8)

        # 标记关键点
        ax.axvline(x=start_measure, color='r', linestyle='--', linewidth=0.5)
        ax.axvline(x=start_eval, color='g', linestyle='-.', linewidth=0.5)
        ax.axvline(x=end_eval, color='g', linestyle='-.', linewidth=0.5)
        ax.axvline(x=end_measure, color='r', linestyle='--', linewidth=0.5)

        # 设置标题
        ax.set_title(f"齿号 {tooth} ({'左' if side == 'left' else '右'}齿面)", fontsize=10)
        ax.set_xlabel("展长 (mm)", fontsize=8)
        ax.set_ylabel("偏差 (μm)", fontsize=8)

        # 缩小字体和标记大小
        ax.tick_params(axis='both', which='major', labelsize=6)

        # 添加网格
        ax.grid(True, linestyle='--', alpha=0.2, color=ORDER_COLORS['grid'],

               linewidth=0.8, zorder=0)

    def _plot_single_flank(self, ax, result):
        """绘制单个齿的齿向偏差曲线"""
        side = result['side']
        tooth = result['tooth']

        # 获取齿宽位置
        start_measure = self.gear_data['齿向起测点'][side]
        start_eval = self.gear_data['齿向起评点'][side]
        end_eval = self.gear_data['齿向终评点'][side]
        end_measure = self.gear_data['齿向终测点'][side]

        # 获取测量数据
        if side == 'left' and tooth in self.flank_data['left']:
            values = self.flank_data['left'][tooth]
        elif side == 'right' and tooth in self.flank_data['right']:
            values = self.flank_data['right'][tooth]
        else:
            return

        # 转换为numpy数组
        values = np.array(values)

        # 计算每个点的实际位置
        x_positions = np.linspace(start_measure, end_measure, len(values))

        # 获取评价范围内的数据
        eval_data = values[result['start_eval_index']:result['end_eval_index'] + 1]
        eval_x = x_positions[result['start_eval_index']:result['end_eval_index'] + 1]

        # 计算最小二乘拟合直线
        x = np.arange(len(eval_data))
        slope, intercept = np.polyfit(x, eval_data, 1)
        trend = slope * x + intercept

        # 绘制原始数据
        ax.plot(eval_x, eval_data, 'b-', label="原始数据", linewidth=0.8)

        # 绘制拟合直线
        ax.plot(eval_x, trend, 'r-', label="拟合直线", linewidth=0.8)

        # 标记关键点
        ax.axvline(x=start_measure, color='r', linestyle='--', linewidth=0.5)
        ax.axvline(x=start_eval, color='g', linestyle='-.', linewidth=0.5)
        ax.axvline(x=end_eval, color='g', linestyle='-.', linewidth=0.5)
        ax.axvline(x=end_measure, color='r', linestyle='--', linewidth=0.5)

        # 设置标题
        ax.set_title(f"齿号 {tooth} ({'左' if side == 'left' else '右'}齿面)", fontsize=10)
        ax.set_xlabel("齿宽位置 (mm)", fontsize=8)
        ax.set_ylabel("偏差 (μm)", fontsize=8)

        # 缩小字体和标记大小
        ax.tick_params(axis='both', which='major', labelsize=6)

        # 添加网格
        ax.grid(True, linestyle='--', alpha=0.2, color=ORDER_COLORS['grid'],

               linewidth=0.8, zorder=0)

    def _resolve_teeth_count(self, gear_data=None):
        """返回有效齿数，必要时从测量数据推断并回填"""
        try:
            gd = gear_data or getattr(self, 'gear_data', {}) or {}
            candidates = []

            def add_candidate(val):
                try:
                    if val is None:
                        return
                    v = int(float(val))
                    if v > 0:
                        candidates.append(v)
                except (TypeError, ValueError):
                    return

            # 直接字段
            add_candidate(gd.get('齿数'))
            add_candidate(gd.get('teeth'))
            add_candidate(gd.get('测量齿数'))
            add_candidate(gd.get('measured_teeth'))

            # 从测量数据长度推断
            for data in [
                getattr(self, 'profile_data', None),
                getattr(self, 'flank_data', None),
                getattr(self, 'pitch_data', None),
                getattr(self, 'topography_data', None),
            ]:
                if isinstance(data, dict):
                    for side_key in ['left', 'right']:
                        side = data.get(side_key)
                        if isinstance(side, dict) and side:
                            add_candidate(len(side))
                    # 如果不是左右结构，尝试直接使用长度
                    if data and not any(k in data for k in ['left', 'right']):
                        add_candidate(len(data))

            teeth = max(candidates) if candidates else 0
            if teeth > 0:
                gd.setdefault('齿数', teeth)
                gd.setdefault('teeth', teeth)
            return teeth
        except Exception as e:
            logger.error(f"解析齿数失败: {e}")
            return 0

