            ["Loc. of check", "VCST CZ", "Base Cir. db", f"{gear_data.get('基圆直径', 0):.3f}mm", "Stylus-Ø", "0.0mm"],
            ["Condition:", "", "Base Helix ang", "0.000°", "Add.Mod.Coe", f"{gear_data.get('变位系数', 0):.3f}"]
