        # 齿向数据表格
        ax_lead_table = fig.add_subplot(gs[8, :]) # 注意：原代码是gs[6, :]，这里应该是gs[8, :]因为中间插入了图表行(Row 6, 7 occupied by charts? No, charts are in Row 6. Table should be in Row 8 based on height_ratios?)
        # height_ratios=[2.5, 0.2, 3.0, 0.2, 1.5, 0.2, 3.0, 0.2, 1.5, 0.2, 1.5, 0.2]
