    def _create_klingelnberg_gear_data_page(self):
        """创建齿轮数据概览页"""
        fig = Figure(figsize=(8.27, 11.69), dpi=150)
        fig.patch.set_facecolor('white')
        
        # 标题
        fig.text(0.5, 0.94, "Gear Data Overview / 齿轮数据概览",
                ha='center', va='top', fontsize=18, fontweight='bold', color='#1E3A5F')
        
        # 齿轮参数表格
        ax = fig.add_subplot(111)
        ax.axis('off')
        
        gear_params = [
            ["Module / 模数", "mn", f"{self.gear_data.get('模数', 0):.3f}", "mm"],
            ["Teeth / 齿数", "z", f"{self.gear_data.get('齿数', 0)}", "-"],
            ["Pressure Angle / 压力角", "α", f"{self.gear_data.get('压力角', 0):.2f}", "°"],
            ["Helix Angle / 螺旋角", "β", f"{self.gear_data.get('螺旋角', 0):.2f}", "°"],
            ["Face Width / 齿宽", "b", f"{self.gear_data.get('齿宽', 0):.2f}", "mm"],
            ["Quality Grade / 精度", "ISO", f"1328-{self.gear_data.get('精度等级', 5)}", "-"]
        ]
        
        table = ax.table(cellText=gear_params,
                        colLabels=["Parameter / 参数", "Symbol", "Value / 数值", "Unit"],
                        loc='center',
                        cellLoc='center',
                        colWidths=[0.4, 0.15, 0.25, 0.2])
        
        table.auto_set_font_size(False)
        table.set_fontsize(10)
        table.scale(1, 2.0)
        
        # 表头样式
        for i in range(4):
            cell = table[(0, i)]
            cell.set_facecolor('#1E3A5F')
            cell.set_text_props(weight='bold', color='white')
        
        # 交替行颜色 - 优化循环性能
        for i in range(len(gear_params)):
            row_color = 'white' if i % 2 == 0 else '#F0F0F0'
            for j in range(4):
                cell = table[(i+1, j)]
                cell.set_facecolor(row_color)
        
        return fig

