    def _plot_single_tooth_profile(self, ax, report_data, side, tooth_number):
        """绘制单个齿号的齿形图表"""
        # 强制设置白色背景
        ax.set_facecolor('white')
        
        try:
            # 获取齿轮数据
            gear_data = report_data['gear_data']
            deviation_results = report_data['deviation_results']
            
            # 尝试查找特定齿号和齿面的数据
            profile_data = None
            for key, result in deviation_results['profile'].items():
                if result['side'] == side and result['tooth'] == tooth_number:
                    profile_data = result
                    break
            
            # 安全获取展长值，提供默认值
            start_measure = gear_data.get('齿形起测点展长', {}).get(side, 0.0)
            start_eval = gear_data.get('齿形起评点展长', {}).get(side, 0.0)
            end_eval = gear_data.get('齿形终评点展长', {}).get(side, 10.0)
            end_measure = gear_data.get('齿形终测点展长', {}).get(side, 10.0)
            
            # 获取测量数据
            values = None
            
            # 尝试多种数据源
            if profile_data:
                if hasattr(self, 'profile_data') and self.profile_data:
                    if side == 'left' and tooth_number in self.profile_data.get('left', {}):
                        values = self.profile_data['left'][tooth_number]
                    elif side == 'right' and tooth_number in self.profile_data.get('right', {}):
                        values = self.profile_data['right'][tooth_number]
            
            # 如果没有找到数据，使用模拟数据
            if values is None:
                # 生成模拟的齿形偏差数据
                import random
                num_points = 100
                values = [random.uniform(-5, 5) for _ in range(num_points)]
                ax.text(0.02, 0.98, "模拟数据", transform=ax.transAxes, fontsize=6, 
                       color='red', fontweight='bold')
            
            # 转换为numpy数组
            values = np.array(values)
            
            # 计算每个点的实际位置
            x_positions = np.linspace(start_measure, end_measure, len(values))
            
            # 获取评价范围内的数据
            start_idx = 0
            end_idx = len(values)-1
            if profile_data:
                start_idx = profile_data.get('start_eval_index', 0)
                end_idx = profile_data.get('end_eval_index', len(values)-1)
                start_idx = max(0, min(start_idx, len(values)-1))
                end_idx = max(start_idx, min(end_idx, len(values)-1))
            
            eval_data = values[start_idx:end_idx + 1]
            eval_x = x_positions[start_idx:end_idx + 1]
            
            # 计算拟合直线
            if len(eval_data) > 1:
                x = np.arange(len(eval_data))
                slope, intercept = np.polyfit(x, eval_data, 1)
                trend = slope * x + intercept
                
                # 绘制图表 - X轴和Y轴对调
                ax.plot(eval_data, eval_x, 'k-', linewidth=1.0, label='实际轮廓')
                ax.plot(trend, eval_x, 'r--', linewidth=1.0, label='评定线')
                
                # 添加网格
                ax.grid(True, linestyle=':', alpha=0.5, color='gray')
                
                # 设置坐标轴 - X轴和Y轴对调
                ax.set_xlabel('偏差 (μm)', fontsize=6)
                ax.set_ylabel('展长 (mm)', fontsize=6)
                ax.tick_params(axis='both', which='major', labelsize=5)
                
                # 标记关键点 - 改为水平线
                if start_eval != end_eval:
                    ax.axhline(y=start_eval, color='g', linestyle='-.', alpha=0.7, linewidth=0.8)
                    ax.axhline(y=end_eval, color='g', linestyle='-.', alpha=0.7, linewidth=0.8)
                
                # 添加标题
                ax.set_title(f'齿号 {tooth_number}', fontsize=7, fontweight='bold')
            else:
                ax.text(0.5, 0.5, "数据不足", ha='center', va='center', 
                       transform=ax.transAxes, fontsize=10, color='orange')
                
        except Exception as e:
            ax.text(0.5, 0.5, f"绘图错误: {str(e)}", ha='center', va='center', 
                   transform=ax.transAxes, fontsize=8, color='red')
    
