    def _plot_professional_lead_chart(self, ax, report_data):
        """绘制专业格式的齿向图表"""
        # 获取偏差结果
        deviation_results = report_data['deviation_results']
        
        # 创建左右齿面子图
        ax.axis('off')
        
        # 找到左右齿面的数据
        left_data = None
        right_data = None
        
        for key, result in deviation_results['flank'].items():
            if result['side'] == 'left':
                left_data = result
            elif result['side'] == 'right':
                right_data = result
        
        # 左齿面图表
        ax_left = ax.inset_axes([0.05, 0.1, 0.4, 0.8])
        ax_left.set_facecolor('white')
        self._plot_single_lead_professional(ax_left, report_data, left_data, 'left')
        
        # 右齿面图表
        ax_right = ax.inset_axes([0.55, 0.1, 0.4, 0.8])
        ax_right.set_facecolor('white')
        self._plot_single_lead_professional(ax_right, report_data, right_data, 'right')
        
        # 中间标记
        ax.text(0.5, 0.05, "Top", ha='center', va='bottom', fontsize=8, fontweight='bold',
                transform=ax.transAxes)
        ax.text(0.5, 0.95, "Bottom", ha='center', va='top', fontsize=8, fontweight='bold',
                transform=ax.transAxes)
    
