    def create_detail_page(self, report_data):
        """创建详细数据页"""
        fig = Figure(figsize=(8.27, 11.69), dpi=100)

        # 标题
        fig.suptitle("详细偏差数据", fontsize=18, fontweight='bold')

        # 创建两个子图 - 齿形和齿向
        ax1 = fig.add_subplot(211)
        ax1.set_title("齿形偏差数据", fontsize=14)
        ax1.axis('off')

        # 齿形数据表格
        profile_data = []
        try:
            deviation_results = report_data.get('deviation_results', {})
            results = deviation_results.get('profile', {})
            sorted_keys = sorted(results.keys(), key=lambda x: (int(x[1:]) if x[1:].isdigit() else 0))

            for key in sorted_keys:
                result = results[key]
                side = "左" if result.get('side') == 'left' else "右"
                
                # 安全获取数据，提供默认值
                F_alpha = result.get('F_alpha', 0.0)
                fH_alpha = result.get('fH_alpha', 0.0)
                ff_alpha = result.get('ff_alpha', 0.0)
                F_alpha_tolerance = result.get('F_alpha_tolerance', 12.0)
                fH_alpha_tolerance = result.get('fH_alpha_tolerance', 7.0)
                ff_alpha_tolerance = result.get('ff_alpha_tolerance', 10.0)
                F_alpha_status = result.get('F_alpha_status', "未知")
                fH_alpha_status = result.get('fH_alpha_status', "未知")
                ff_alpha_status = result.get('ff_alpha_status', "未知")

                profile_data.append([
                    str(result.get('tooth', 0)),
                    side,
                    f"{F_alpha:.2f}",
                    f"{fH_alpha:.2f}",
                    f"{ff_alpha:.2f}",
                    f"{F_alpha_tolerance:.2f}",
                    f"{fH_alpha_tolerance:.2f}",
                    f"{ff_alpha_tolerance:.2f}",
                    F_alpha_status,
                    fH_alpha_status,
                    ff_alpha_status
                ])
        except Exception as e:
            # 添加错误信息到表格
            profile_data.append([f"错误: {str(e)}", "", "", "", "", "", "", "", "", "", ""])

        col_labels = ["齿号", "齿面", "F_alpha(μm)", "fH_alpha(μm)", "ff_alpha(μm)",
                      "F_alpha公差(μm)", "fH_alpha公差(μm)", "ff_alpha公差(μm)",
                      "F_alpha状态", "fH_alpha状态", "ff_alpha状态"]

        table1 = plt.table(cellText=profile_data,
                          colLabels=col_labels,
                          loc='center',
                          cellLoc='center')
        # 优化表格样式设置循环
        for i, row in enumerate(profile_data):
            # 检查状态并设置样式
            status_columns = [(8, 2), (9, 3), (10, 4)]  # (状态列索引, 数据列索引)
            
            for status_col, data_col in status_columns:
                if row[status_col] == "超差":
                    cell = table1[i + 1, data_col]
                    cell.set_text_props(**{'weight': 'bold', 'color': 'red'})
        table1.auto_set_font_size(False)
        table1.set_fontsize(9)
        table1.scale(1, 1.2)

        # 齿向数据表格
        ax2 = fig.add_subplot(212)
        ax2.set_title("齿向偏差数据", fontsize=14)
        ax2.axis('off')

        flank_data = []
        try:
            deviation_results = report_data.get('deviation_results', {})
            results = deviation_results.get('flank', {})
            sorted_keys = sorted(results.keys(), key=lambda x: (int(x[1:]) if x[1:].isdigit() else 0))

            for key in sorted_keys:
                result = results[key]
                side = "左" if result.get('side') == 'left' else "右"
                
                # 安全获取数据，提供默认值
                F_beta = result.get('F_beta', 0.0)
                fH_beta = result.get('fH_beta', 0.0)
                ff_beta = result.get('ff_beta', 0.0)
                F_beta_tolerance = result.get('F_beta_tolerance', 17.0)
                fH_beta_tolerance = result.get('fH_beta_tolerance', 7.0)
                ff_beta_tolerance = result.get('ff_beta_tolerance', 10.0)
                F_beta_status = result.get('F_beta_status', "未知")
                fH_beta_status = result.get('fH_beta_status', "未知")
                ff_beta_status = result.get('ff_beta_status', "未知")
                
                flank_data.append([
                    str(result.get('tooth', 0)),
                    side,
                    f"{F_beta:.2f}",
                    f"{fH_beta:.2f}",
                    f"{ff_beta:.2f}",
                    f"{F_beta_tolerance:.2f}",
                    f"{fH_beta_tolerance:.2f}",
                    f"{ff_beta_tolerance:.2f}",
                    F_beta_status,
                    fH_beta_status,
                    ff_beta_status
                ])
        except Exception as e:
            # 添加错误信息到表格
            flank_data.append([f"错误: {str(e)}", "", "", "", "", "", "", "", "", "", ""])

        col_labels = ["齿号", "齿面", "F_beta(μm)", "fH_beta(μm)", "ff_beta(μm)",
                      "F_beta公差(μm)", "fH_beta公差(μm)", "ff_beta公差(μm)",
                      "F_beta状态", "fH_beta状态", "ff_beta状态"]

        table2 = plt.table(cellText=flank_data,
                          colLabels=col_labels,
                          loc='center',
                          cellLoc='center')
        # 优化表格样式设置循环
        for i, row in enumerate(flank_data):
            # 检查状态并设置样式
            status_columns = [(8, 2), (9, 3), (10, 4)]  # (状态列索引, 数据列索引)
            
            for status_col, data_col in status_columns:
                if row[status_col] == "超差":
                    cell = table2[i + 1, data_col]
                    cell.set_text_props(**{'weight': 'bold', 'color': 'red'})
        table2.auto_set_font_size(False)
        table2.set_fontsize(9)
        table2.scale(1, 1.2)

        fig.tight_layout(pad=3.0)
        return fig

    def create_frequency_chart(self, freq_data, title):
        """创建频率分析图表"""
        fig = Figure(figsize=(11, 8), dpi=100)
        fig.patch.set_facecolor('#F8F9FA')
        
        # 专业颜色方案
        PRIMARY_BLUE = '#1E3A5F'
        SECONDARY_BLUE = '#2C5282'
        ACCENT_GRAY = '#4A5568'
        FREQ_COLOR = '#3498DB'  # 频率域蓝色
        WAVELENGTH_COLOR = '#27AE60'  # 空间域绿色
        HIGHLIGHT_COLOR = '#E74C3C'  # 高亮红色
        GRID_COLOR = '#BDC3C7'
        
        # 页面标题
        fig.suptitle(title, fontsize=18, fontweight='bold', color=PRIMARY_BLUE, y=0.95)
        
        # 频率域分析图表
        ax1 = fig.add_subplot(211)
        ax1.set_facecolor('white')
        
        # 绘制频谱图 (频率域)
        freqs = freq_data.get('freqs', freq_data.get('frequencies', []))
        magnitudes = freq_data['magnitudes']
        top_freqs = freq_data['top_freqs']
        top_magnitudes = freq_data['top_magnitudes']

        # 主频谱线
        ax1.plot(freqs, magnitudes, color=FREQ_COLOR, linewidth=1.5, alpha=0.8, 
                label='Frequency Spectrum')
        
        # 主要频率分量标记
        ax1.plot(top_freqs, top_magnitudes, 'o', color=HIGHLIGHT_COLOR, markersize=8,
                markerfacecolor='white', markeredgewidth=2, markeredgecolor=HIGHLIGHT_COLOR,
                label='Top 10 Components')

        # 标记前10个主要频率分量 - 专业标注
        for i, (freq, mag) in enumerate(zip(top_freqs, top_magnitudes)):
            ax1.annotate(f'F{i + 1}: {freq:.1f}Hz\n{mag:.2f}',
                         xy=(freq, mag),
                         xytext=(freq * 1.1, mag * 0.9),
                         fontsize=8,
                         bbox=dict(boxstyle="round,pad=0.3", facecolor='white', 
                                 edgecolor=ACCENT_GRAY, alpha=0.9),
                         arrowprops=dict(arrowstyle="->", 
                                       connectionstyle="arc3,rad=0.1",
                                       color=ACCENT_GRAY))

        ax1.set_title("Frequency Domain Analysis / 频率域分析", 
                     fontsize=14, fontweight='bold', color=PRIMARY_BLUE, pad=15)
        ax1.set_xlabel("Frequency (Hz) / 频率 (Hz)", fontsize=11, color=ACCENT_GRAY)
        ax1.set_ylabel("Magnitude / 幅度", fontsize=11, color=ACCENT_GRAY)
        ax1.grid(True, linestyle='--', alpha=0.4, color=GRID_COLOR)
        ax1.legend(frameon=True, framealpha=0.9, facecolor='white', 
                  edgecolor=ACCENT_GRAY, fontsize=9)
        
        # 设置坐标轴样式
        ax1.spines['top'].set_visible(False)
        ax1.spines['right'].set_visible(False)
        ax1.spines['left'].set_color(ACCENT_GRAY)
        ax1.spines['bottom'].set_color(ACCENT_GRAY)
        ax1.tick_params(colors=ACCENT_GRAY)

        # 空间域分析图表
        ax2 = fig.add_subplot(212)
        ax2.set_facecolor('white')

        # 绘制波长谱图 (空间域)
        wavelengths = freq_data['wavelengths']
        top_wavelengths = freq_data['top_wavelengths']

        # 只显示波长在合理范围内的点 (0.1mm - 100mm)
        valid_mask = (wavelengths > 0.1) & (wavelengths < 100)
        wavelengths = wavelengths[valid_mask]
        magnitudes = magnitudes[valid_mask]

        ax2.plot(wavelengths, magnitudes, color=WAVELENGTH_COLOR, linewidth=1.5, 
                alpha=0.8, label='Wavelength Spectrum')
        ax2.plot(top_wavelengths, top_magnitudes, 'o', color=HIGHLIGHT_COLOR, markersize=8,
                markerfacecolor='white', markeredgewidth=2, markeredgecolor=HIGHLIGHT_COLOR,
                label='Top 10 Components')

        # 标记前10个主要波长分量
        for i, (wavelength, mag) in enumerate(zip(top_wavelengths, top_magnitudes)):
            ax2.annotate(f'F{i + 1}: {wavelength:.2f}mm\n{mag:.2f}',
                         xy=(wavelength, mag),
                         xytext=(wavelength * 1.1, mag * 0.9),
                         fontsize=8,
                         bbox=dict(boxstyle="round,pad=0.3", facecolor='white', 
                                 edgecolor=ACCENT_GRAY, alpha=0.9),
                         arrowprops=dict(arrowstyle="->", 
                                       connectionstyle="arc3,rad=0.1",
                                       color=ACCENT_GRAY))

        ax2.set_title("Spatial Domain Analysis / 空间域分析", 
                     fontsize=14, fontweight='bold', color=PRIMARY_BLUE, pad=15)
        ax2.set_xlabel("Wavelength (mm) / 波长 (mm)", fontsize=11, color=ACCENT_GRAY)
        ax2.set_ylabel("Magnitude / 幅度", fontsize=11, color=ACCENT_GRAY)
        ax2.set_xscale('log')  # 对数坐标更适合显示不同尺度的波长
        ax2.grid(True, linestyle='--', alpha=0.4, color=GRID_COLOR, which='both')
        ax2.legend(frameon=True, framealpha=0.9, facecolor='white', 
                  edgecolor=ACCENT_GRAY, fontsize=9)
        
        # 设置坐标轴样式
        ax2.spines['top'].set_visible(False)
        ax2.spines['right'].set_visible(False)
        ax2.spines['left'].set_color(ACCENT_GRAY)
        ax2.spines['bottom'].set_color(ACCENT_GRAY)
        ax2.tick_params(colors=ACCENT_GRAY)

        # 添加分析说明
        fig.text(0.02, 0.02, 
                "Analysis Note: Top 10 frequency components are highlighted for detailed inspection",
                fontsize=9, color=ACCENT_GRAY, style='italic')
        
        fig.tight_layout(rect=[0, 0.03, 1, 0.95])
        return fig

