    def init_undulation_tab(self, layout):
        """初始化波纹度分析标签页 - 使用TAB布局"""
        # 添加说明标签
        info_label = QLabel("波纹度(Undulation)分析 - ISO1328标准")
        info_label.setStyleSheet("font-weight: bold; color: #2c3e50; padding: 5px;")
        layout.addWidget(info_label)

        # 创建TAB控件
        self.undulation_tab_widget = QTabWidget()
        layout.addWidget(self.undulation_tab_widget)

        # 创建第一个TAB：参数说明
        self.create_parameters_tab()
        
        # 创建第二个TAB：分析结果
        self.create_analysis_results_tab()
        
        # 创建第三个TAB：图表显示
        self.create_charts_tab()
        
        # 创建第四个TAB：频率分析
        self.create_frequency_tab()

        # 添加按钮
        btn_layout = QHBoxLayout()

        self.analyze_btn = QPushButton("分析波纹度")
        self.analyze_btn.setStyleSheet(
            "QPushButton { background-color: #7A9E7E; color: #F9F6F0; padding: 8px; border-radius: 4px; }"
            "QPushButton:hover { background-color: #5F7D61; }"
            "QPushButton:disabled { background-color: #95a5a6; }"
        )
        self.analyze_btn.clicked.connect(self.analyze_undulation)
        self.analyze_btn.setEnabled(False)

        self.export_report_btn = QPushButton("导出报告")
        self.export_report_btn.setStyleSheet(
            "QPushButton { background-color: #7A9E7E; color: #F9F6F0; padding: 8px; border-radius: 4px; }"
            "QPushButton:hover { background-color: #5F7D61; }"
            "QPushButton:disabled { background-color: #95a5a6; }"
        )
        self.export_report_btn.clicked.connect(self.export_undulation_report)
        self.export_report_btn.setEnabled(False)

        btn_layout.addWidget(self.analyze_btn)
        btn_layout.addWidget(self.export_report_btn)
        btn_layout.addStretch()

        layout.addLayout(btn_layout)

