    def create_analysis_results_tab(self):
        """创建分析结果TAB"""
        results_widget = QWidget()
        results_layout = QVBoxLayout(results_widget)
        
        # 创建统计信息区域
        stats_layout = QHBoxLayout()

        self.stats_label = QLabel("未进行波纹度分析")
