    @pyqtSlot()
    def open_mka_file(self):
        """打开MKA文件并解析数据"""
        # 获取上次打开文件的文件夹
        initial_dir = ""
        last_file = self.load_last_file_path()
        if last_file and os.path.exists(last_file):
            initial_dir = os.path.dirname(last_file)
        elif hasattr(self, 'current_file') and self.current_file and os.path.exists(self.current_file):
            initial_dir = os.path.dirname(self.current_file)
        
        file_path, _ = QFileDialog.getOpenFileName(
            self, "选择MKA文件", initial_dir, "MKA文件 (*.mka);;所有文件 (*.*)"
        )

        if not file_path:
            return

        # 检查文件大小
        file_size = os.path.getsize(file_path)
        if file_size > 50 * 1024 * 1024:
            reply = QMessageBox.question(
                self, "大文件警告",
                f"您选择的文件较大 ({file_size / (1024 * 1024):.1f}MB)，处理可能需要较长时间。\n确定要加载吗？",
                QMessageBox.Yes | QMessageBox.No
            )
            if reply == QMessageBox.No:
                return

        # 如果已有线程在运行，先取消它
        if self.processing_thread and self.processing_thread.isRunning():
            self.processing_thread.cancel()
            self.processing_thread.wait(1000)

        # 禁用UI控件
        self.set_ui_enabled(False)
        self.progress_bar.setVisible(True)
        self.progress_label.setVisible(True)
        self.progress_label.setText("正在准备加载文件...")
        self.status_bar.showMessage(f"正在加载文件: {os.path.basename(file_path)}")
        logger.info(f"用户选择文件: {file_path}")

        # 创建并启动处理线程
        self.processing_thread = FileProcessingThread(file_path, self)
        self.processing_thread.finished.connect(self.on_file_loaded)
        self.processing_thread.error.connect(self.on_file_error)
        self.processing_thread.progress.connect(self.on_progress_update)
        self.processing_thread.start()

    @pyqtSlot(str)
    def on_progress_update(self, message):
        """更新进度消息"""
        if self._closing:
            return

        self.progress_label.setText(message)
        self.status_bar.showMessage(message)

    @pyqtSlot(dict, dict, dict, dict, dict, str)
    def on_file_loaded(self, gear_data, flank_data, profile_data, pitch_data, topography_data, file_path):
        """文件加载完成处理"""
        import copy
        try:
            if self._closing:
                logger.info("窗口正在关闭，跳过文件加载完成处理")
                return

            self.gear_data = gear_data
            self.flank_data = copy.deepcopy(flank_data)
            self.profile_data = copy.deepcopy(profile_data)
            self.pitch_data = pitch_data
            self.topography_data = topography_data
            self.current_file = file_path
            
            # 确保gear_data包含周节公差的默认值（如果不存在）
            if self.gear_data and not self.gear_data.get('fp_tolerance'):
                fp_default, Fp_default, Fr_default = self.calculate_tolerances('spacing', 'left')
                self.gear_data.setdefault('fp_tolerance', fp_default)
                self.gear_data.setdefault('Fp_tolerance', Fp_default)
                self.gear_data.setdefault('Fr_tolerance', Fr_default)
                logger.info(f"已初始化周节公差默认值: fp={fp_default:.1f}, Fp={Fp_default:.1f}, Fr={Fr_default:.1f}")

            # 调试打印，确认数据不同
            try:
                left1_flank = list(self.flank_data.get('left', {}).items())[:1]
                left1_profile = list(self.profile_data.get('left', {}).items())[:1]
                print("[DEBUG] flank_data left 1:", left1_flank)
                print("[DEBUG] profile_data left 1:", left1_profile)
                if left1_flank and left1_profile and left1_flank[0][1] == left1_profile[0][1]:
                    print("[DEBUG] ❌ 警告：齿形和齿向数据内容完全相同！")
                else:
                    print("[DEBUG] ✅ 齿形和齿向数据内容不同")
            except Exception as e:
                print("[DEBUG] 数据调试打印异常：", e)

            # 应用新的数据处理流程
            logger.info("开始应用新的数据处理流程")
            
            # 获取齿数
            teeth_count = self.gear_data.get('齿数', 0)
            if teeth_count <= 0:
                logger.warning("齿数为0，无法应用数据处理流程")
            else:
                # 处理齿形数据
                if self.profile_data:
                    processed_profile = process_gear_data(self.profile_data, teeth_count)
                    self.processed_profile_data = processed_profile['processed_data']
                    self.profile_angle_data = processed_profile['angle_data']
                    logger.info(f"齿形数据处理完成: 左齿面 {len(self.processed_profile_data.get('left', {}))} 个齿, 右齿面 {len(self.processed_profile_data.get('right', {}))} 个齿")
                
                # 处理齿向数据
                if self.flank_data:
                    processed_flank = process_gear_data(self.flank_data, teeth_count)
                    self.processed_flank_data = processed_flank['processed_data']
                    self.flank_angle_data = processed_flank['angle_data']
                    logger.info(f"齿向数据处理完成: 左齿面 {len(self.processed_flank_data.get('left', {}))} 个齿, 右齿面 {len(self.processed_flank_data.get('right', {}))} 个齿")

            # 计算展长值并添加到gear_data
            self.calculate_spread_length_values()

            # 更新UI
            self.file_label.setText(f"当前文件: {os.path.basename(file_path)}")
            self.display_data()
            
            # 安全地启用按钮
            if hasattr(self, 'export_btn') and self.export_btn:
                self.export_btn.setEnabled(True)
            
            # 自动显示与当前文件对应的PDF
            if hasattr(self, 'show_klingelnberg_pdf_in_webview'):
                logger.info("文件加载完成，准备显示PDF")
                # 设置标志表示文件已加载，需要显示PDF
                self._file_loaded_needs_pdf = True
                # 如果report_webview已经初始化，直接显示PDF
                if hasattr(self, 'report_webview'):
                    logger.info("report_webview已初始化，直接调用show_klingelnberg_pdf_in_webview")
                    self.show_klingelnberg_pdf_in_webview()
                else:
                    logger.info("report_webview未初始化，将在初始化后显示PDF")
            if hasattr(self, 'export_flank_btn') and self.export_flank_btn:
                self.export_flank_btn.setEnabled(True)
            if hasattr(self, 'analyze_btn') and self.analyze_btn:
                self.analyze_btn.setEnabled(True)  # 启用波纹度分析按钮
            if hasattr(self, 'run_undulation_analysis_action') and self.run_undulation_analysis_action:
                self.run_undulation_analysis_action.setEnabled(True)  # 启用工具栏波纹度分析按钮
            if hasattr(self, 'analyze_deviation_btn') and self.analyze_deviation_btn:
                self.analyze_deviation_btn.setEnabled(True)  # 启用偏差分析按钮
            if hasattr(self, 'analyze_freq_btn') and self.analyze_freq_btn:
                self.analyze_freq_btn.setEnabled(True)  # 启用频率分析按钮
            # 启用Ripple分析相关按钮
            if hasattr(self, 'analyze_ripple_btn') and self.analyze_ripple_btn:
                self.analyze_ripple_btn.setEnabled(True)  # 启用Ripple分析按钮
            if hasattr(self, 'settings_btn') and self.settings_btn:
                self.settings_btn.setEnabled(True)  # 启用Ripple设置按钮
            if hasattr(self, 'report_btn') and self.report_btn:
                self.report_btn.setEnabled(True)  # 启用报表生成按钮

            # 确保profile页面已加载
            if not self._page_config.get('profile', {}).get('loaded', False):
                logger.info("强制加载profile页面")
                self._load_page('profile')
            
            # 确保报表页面已加载，以便显示PDF
            if not self._page_config.get('report', {}).get('loaded', False):
                logger.info("强制加载报表页面以显示PDF")
                self._load_page('report')
                # 添加延迟调用PDF加载，确保WebView完全初始化
                QTimer.singleShot(500, self.show_klingelnberg_pdf_in_webview)
            
            # 显示齿向和齿形数据
            self.display_measurement_data(self.flank_data, "齿向")
            self.display_measurement_data(self.profile_data, "齿形")

            # 更新状态
            self.status_bar.showMessage(f"文件加载成功: {os.path.basename(file_path)}", 5000)
            logger.info(f"UI更新完成: {file_path}")
            
            # 保存最后打开的文件路径
            self.save_last_file_path(file_path)
        except Exception as e:
            logger.exception(f"UI更新错误: {str(e)}")
            if not self._closing:
                QMessageBox.critical(self, "错误", f"显示数据时发生错误:\n{str(e)}")
                self.status_bar.showMessage(f"显示数据失败: {str(e)}", 5000)
        finally:
            # 恢复UI控件
            if not self._closing:
                self.set_ui_enabled(True)
                self.progress_bar.setVisible(False)
                self.progress_label.setVisible(False)
                
                # 刷新曲线图表
                if hasattr(self, 'create_curve_charts'):
                    QTimer.singleShot(500, self.create_curve_charts)
                
                # 自动依次执行三大分析
                QTimer.singleShot(10, lambda: self.analyze_deviation(force_reanalysis=True))
                QTimer.singleShot(1000, lambda: self.start_pitch_analysis())
                QTimer.singleShot(2000, lambda: self.start_ripple_analysis(force_reanalysis=True))

    def save_last_file_path(self, file_path):
        """保存最后打开的文件路径到配置"""
        try:
            settings = QSettings("GearAnalysis", "GearDataViewer")
            settings.setValue("last_file_path", file_path)
            logger.info(f"已保存最后打开的文件路径: {file_path}")
        except Exception as e:
            logger.error(f"保存文件路径失败: {str(e)}")

    def save_ripple_spectrum_settings(self):
        """保存齿廓波纹频谱设置到配置"""
        try:
            settings = QSettings("GearAnalysis", "GearDataViewer")
            data = {
                "profile_helix_settings": self.ripple_spectrum_settings.profile_helix_settings,
                "evaluation_settings": self.ripple_spectrum_settings.evaluation_settings,
                "display_settings": self.ripple_spectrum_settings.display_settings
            }
            settings.setValue("ripple_spectrum_settings", json.dumps(data, ensure_ascii=False))
        except Exception as e:
            logger.warning(f"保存齿廓波纹频谱设置失败: {str(e)}")

    def load_last_file_path(self):
        """从配置中加载最后打开的文件路径"""
        try:
            settings = QSettings("GearAnalysis", "GearDataViewer")
            file_path = settings.value("last_file_path", "")
            return file_path if file_path else None
        except Exception as e:
            logger.error(f"加载文件路径失败: {str(e)}")
            return None

    def load_ripple_spectrum_settings(self):
        """加载齿廓波纹频谱设置"""
        try:
            settings = QSettings("GearAnalysis", "GearDataViewer")
            raw = settings.value("ripple_spectrum_settings", "")
            if not raw:
                return
            data = json.loads(raw)
            if not isinstance(data, dict):
                return
            ph = data.get("profile_helix_settings")
            ev = data.get("evaluation_settings")
            ds = data.get("display_settings")
            if isinstance(ph, dict):
                self.ripple_spectrum_settings.update_profile_helix_settings(**ph)
            if isinstance(ev, dict):
                self.ripple_spectrum_settings.update_evaluation_settings(**ev)
            if isinstance(ds, dict):
                self.ripple_spectrum_settings.update_display_settings(**ds)
        except Exception as e:
            logger.warning(f"加载齿廓波纹频谱设置失败: {str(e)}")

    def load_last_file(self):
        """自动加载上次打开的文件"""
        try:
            file_path = self.load_last_file_path()
            if file_path and os.path.exists(file_path):
                logger.info(f"正在自动加载上次打开的文件: {file_path}")
                
                # 检查文件大小
                file_size = os.path.getsize(file_path)
                if file_size > 50 * 1024 * 1024:
                    logger.warning(f"上次打开的文件较大 ({file_size / (1024 * 1024):.1f}MB)，跳过自动加载")
                    return
                
                # 禁用UI控件
                self.set_ui_enabled(False)
                self.progress_bar.setVisible(True)
                self.progress_label.setVisible(True)
                self.progress_label.setText("正在自动加载上次打开的文件...")
                self.status_bar.showMessage(f"正在加载文件: {os.path.basename(file_path)}")
                
                # 创建并启动处理线程
                self.processing_thread = FileProcessingThread(file_path, self)
                self.processing_thread.finished.connect(self.on_file_loaded)
                self.processing_thread.error.connect(self.on_file_error)
                self.processing_thread.progress.connect(self.on_progress_update)
                self.processing_thread.start()
            elif file_path:
                logger.warning(f"上次打开的文件不存在: {file_path}")
            else:
                logger.info("没有找到上次打开的文件记录")
        except Exception as e:
            logger.error(f"自动加载文件失败: {str(e)}")


    def calculate_spread_length_values(self):
        """计算展长值并添加到gear_data中"""
        if not self.gear_data:
            return

        # 计算基圆直径
        self.base_diameter = self.calculate_base_diameter()

        # 需要计算展长的直径参数
        diameter_fields = [
            '齿形起测点直径', '齿形起评点直径', '齿形终评点直径', '齿形终测点直径'
        ]

        # 参考点：起测点直径（用于计算展长的参考点）
        ref_diameter_dict = self.gear_data.get('齿形起测点直径', {'left': 0.0, 'right': 0.0})

        # 计算每个直径参数的展长
        spread_data = {}
        for field in diameter_fields:
            # 获取直径值
            diameter_dict = self.gear_data.get(field, {'left': 0.0, 'right': 0.0})
            spread_dict = {'left': 0.0, 'right': 0.0}
            for side in ['left', 'right']:
                diameter = diameter_dict[side]
                ref_diameter = ref_diameter_dict[side]
                spread = self.calculate_spread_length(diameter, ref_diameter)
                spread_dict[side] = spread
            # 存储展长，键名为原字段名替换"直径"为"展长"
            spread_field = field.replace('直径', '展长')
            spread_data[spread_field] = spread_dict

        # 将展长数据添加到gear_data
        self.gear_data.update(spread_data)

    @pyqtSlot(str)
    def on_file_error(self, error_msg):
        """文件处理错误处理"""
        if self._closing:
            logger.info("窗口正在关闭，跳过文件错误处理")
            return

        QMessageBox.critical(self, "错误", f"无法读取文件:\n{error_msg}")
        self.status_bar.showMessage(f"文件加载失败: {error_msg}", 5000)
        logger.error(f"文件加载失败: {error_msg}")

        # 恢复UI控件
        self.set_ui_enabled(True)
        self.progress_bar.setVisible(False)
        self.progress_label.setVisible(False)

    def set_ui_enabled(self, enabled):
        """启用或禁用UI控件，现在主要控制动作"""
        is_data_loaded = enabled and bool(self.gear_data)
        
        
        # 报告动作在分析完成后启用
        analysis_done = is_data_loaded and bool(self.deviation_results) and bool(self.undulation_results)
        self.html_report_action.setEnabled(analysis_done)
        self.pdf_report_action.setEnabled(analysis_done)
        self.view_spectrum_pdf_action.setEnabled(is_data_loaded)

    def closeEvent(self, event):
        """处理窗口关闭事件"""
        try:
            # 设置关闭标志
            self._closing = True
            
            # 取消所有正在运行的线程
            if self.processing_thread and self.processing_thread.isRunning():
                self.processing_thread.cancel()
                self.processing_thread.wait(1000)
            
            if self.analysis_thread and self.analysis_thread.isRunning():
                self.analysis_thread.terminate()
                self.analysis_thread.wait(1000)
            
            if self.deviation_thread and self.deviation_thread.isRunning():
                self.deviation_thread.terminate()
                self.deviation_thread.wait(1000)
            
            if self.pitch_thread and self.pitch_thread.isRunning():
                self.pitch_thread.terminate()
                self.pitch_thread.wait(1000)
            
            if self.reconstruction_thread and self.reconstruction_thread.isRunning():
                self.reconstruction_thread.terminate()
                self.reconstruction_thread.wait(1000)
            
            # 确保设置已保存（虽然在on_file_loaded中已保存，但这里再确认一次）
            if self.current_file:
                self.save_last_file_path(self.current_file)
            
            logger.info("应用程序正常关闭")
            event.accept()
        except Exception as e:
            logger.error(f"关闭窗口时发生错误: {str(e)}")
            event.accept()

    def calculate_base_diameter(self):
        """计算基圆直径"""
        module = self.gear_data.get('模数', 0.0)
        teeth = self.gear_data.get('齿数', 0)
        pressure_angle = self.gear_data.get('压力角', 0.0)

        if module > 0 and teeth > 0 and pressure_angle > 0:
            # 压力角转换为弧度
            pressure_angle_rad = math.radians(pressure_angle)
            # 基圆直径 = 模数 * 齿数 * cos(压力角)
            base_diameter = module * teeth * math.cos(pressure_angle_rad)
            return base_diameter
        return 0.0

    def calculate_spread_length(self, diameter, reference_diameter):
        """
        计算展长
        :param diameter: 当前点直径 (mm)
        :param reference_diameter: 参考点直径 (起测点直径) (mm)
        :return: 展长 (mm)
        """
        # 计算半径
        r = diameter / 2
        ref_r = reference_diameter / 2
        base_r = self.base_diameter / 2

        # 确保直径大于基圆直径
        if diameter <= self.base_diameter or reference_diameter <= self.base_diameter:
            return 0.0

        # 展长公式: spread = √(r² - rb²) - √(r0² - rb²)
        spread = math.sqrt(r ** 2 - base_r ** 2) - math.sqrt(ref_r ** 2 - base_r ** 2)
        return spread

    def display_data(self):
        """在界面中显示数据"""
        if not self.gear_data:
            return

        # 计算基圆直径
        self.base_diameter = self.calculate_base_diameter()

        try:
            # 显示基本信息
            basic_fields = [
                '程序名', '日期', '开始测量时间', '结束测量时间',
                '操作员', '检查地点', '图号', '序号', '类型',
                '客户', '状况', '轴号', '研究目的', '精度等级'
            ]

            # 安全地更新基本信息表格
            if hasattr(self, 'basic_table') and self.basic_table:
                for i, field in enumerate(basic_fields):
                    value = self.gear_data.get(field, '')
                    item = QTableWidgetItem(str(value))
                    item.setFlags(item.flags() & ~Qt.ItemIsEditable)
                    self.basic_table.setItem(i, 1, item)

            # 显示齿轮参数（不包含公差参数）
            param_fields = [
                '模数', '齿数', '螺旋角', '压力角', '变位系数', '齿宽',
                '齿顶圆直径', '齿根圆直径', '球径', '测量齿数', '齿向起测点位置',
                '齿向测量缩减百分比', '跨棒距名义值', '公法线名义值', '精度等级'
                # 不再显示公差值
                # '齿形公差', '齿形斜率公差', '齿形形状公差',
                # '齿向公差', '齿向斜率公差', '齿向形状公差'
            ]

            # 安全地更新参数表格
            if hasattr(self, 'params_table') and self.params_table:
                for i, field in enumerate(param_fields):
                    value = self.gear_data.get(field, 0)
                    if field == '齿向测量缩减百分比':
                        item = QTableWidgetItem(f"{value}%")
                    else:
                        item = QTableWidgetItem(str(value))

                    item.setFlags(item.flags() & ~Qt.ItemIsEditable)
                    self.params_table.setItem(i, 1, item)

            # 显示左右齿面参数
            side_fields = [
                '齿形起测点直径', '齿形起评点直径', '齿形终评点直径', '齿形终测点直径',
                '齿轮展长', '齿向测量位置', '分度圆直径', '内部测量圆直径', '外部测量圆直径',
                '齿向起测点', '齿向起评点', '齿向终评点', '齿向终测点',
                '齿形测量位置', '齿形下方测量位置', '齿形上方测量位置',
                '齿形起测点展长', '齿形起评点展长', '齿形终评点展长', '齿形终测点展长'
            ]

            # 安全地更新齿面参数表格
            if hasattr(self, 'sides_table') and self.sides_table:
                for i, field in enumerate(side_fields):
                    # 前16行是原始参数
                    if i < 16:
                        values = self.gear_data.get(field, {'left': 0.0, 'right': 0.0})

                        # 计算差值
                        diff = values['left'] - values['right']

                        # 左值
                        left_item = QTableWidgetItem(f"{values['left']:.3f}")
                        left_item.setFlags(left_item.flags() & ~Qt.ItemIsEditable)
                        self.sides_table.setItem(i, 1, left_item)

                        # 右值
                        right_item = QTableWidgetItem(f"{values['right']:.3f}")
                        right_item.setFlags(right_item.flags() & ~Qt.ItemIsEditable)
                        self.sides_table.setItem(i, 2, right_item)

                        # 差值
                        diff_item = QTableWidgetItem(f"{diff:.3f}")
                        diff_item.setFlags(diff_item.flags() & ~Qt.ItemIsEditable)

                        # 根据差值大小设置不同样式
                        abs_diff = abs(diff)
                        if abs_diff > 0.05:  # 差值大于0.05mm
                            diff_item.setBackground(QColor(255, 255, 0))  # 黄色
                            diff_item.setData(Qt.UserRole, "highlighted")
                        elif abs_diff > 0.01:  # 差值大于0.01mm
                            diff_item.setBackground(QColor(211, 211, 211))  # 浅灰色

                        self.sides_table.setItem(i, 3, diff_item)

                    # 后4行是展长参数
                    else:
                        # 获取展长值
                        values = self.gear_data.get(field, {'left': 0.0, 'right': 0.0})

                        # 计算差值
                        diff = values['left'] - values['right']

                        # 左展长
                        left_item = QTableWidgetItem(f"{values['left']:.3f}")
                        left_item.setFlags(left_item.flags() & ~Qt.ItemIsEditable)
                        self.sides_table.setItem(i, 1, left_item)

                        # 右展长
                        right_item = QTableWidgetItem(f"{values['right']:.3f}")
                        right_item.setFlags(right_item.flags() & ~Qt.ItemIsEditable)
                        self.sides_table.setItem(i, 2, right_item)

                        # 差值
                        diff_item = QTableWidgetItem(f"{diff:.3f}")
                        diff_item.setFlags(diff_item.flags() & ~Qt.ItemIsEditable)

                        # 根据差值大小设置不同样式
                        abs_diff = abs(diff)
                        if abs_diff > 0.05:  # 差值大于0.05mm
                            diff_item.setBackground(QColor(255, 255, 0))  # 黄色
                            diff_item.setData(Qt.UserRole, "highlighted")
                        elif abs_diff > 0.01:  # 差值大于0.01mm
                            diff_item.setBackground(QColor(211, 211, 211))  # 浅灰色

                        self.sides_table.setItem(i, 3, diff_item)
        except Exception as e:
            logger.exception(f"数据显示错误: {str(e)}")
            if not self._closing:
                QMessageBox.critical(self, "错误", f"显示数据时发生错误:\n{str(e)}")

    def display_measurement_data(self, data, data_name, retry_count=0):
        """显示测量数据（齿向或齿形）"""
        # 限制重试次数，避免无限循环
        if retry_count > 10:
            logger.warning(f"{data_name}数据控件重试次数超过限制，放弃显示")
            return
            
        # 确保UI完全初始化 - 按需加载页面
        target_page = 'flank' if data_name == "齿向" else 'profile'
        if hasattr(self, '_page_config') and target_page in self._page_config and not self._page_config[target_page]['loaded']:
            logger.info(f"自动加载{target_page}页面以显示数据")
            self._load_page(target_page)
            
        # 确保UI完全初始化
        if not hasattr(self, 'flank_text_area') or not hasattr(self, 'profile_text_area'):
            # 如果控件还没有初始化，延迟显示数据
            QTimer.singleShot(100, lambda: self.display_measurement_data(data, data_name, retry_count + 1))
            return
            
        if data_name == "齿向":
            # 检查齿向控件是否存在且有效
            if (not hasattr(self, 'flank_text_area') or 
                not hasattr(self, 'flank_status_label') or
                self.flank_text_area is None or 
                self.flank_status_label is None):
                logger.debug(f"齿向数据控件未就绪，重试显示")
                QTimer.singleShot(200, lambda: self.display_measurement_data(data, data_name, retry_count + 1))
                return
            text_area = self.flank_text_area
            status_label = self.flank_status_label
        else:  # 齿形
            # 检查齿形控件是否存在且有效
            if (not hasattr(self, 'profile_text_area') or 
                not hasattr(self, 'profile_status_label') or
                self.profile_text_area is None or 
                self.profile_status_label is None):
                logger.debug(f"齿形数据控件未就绪，重试显示")
                QTimer.singleShot(200, lambda: self.display_measurement_data(data, data_name, retry_count + 1))
                return
            text_area = self.profile_text_area
            status_label = self.profile_status_label

        # 验证控件是否为有效的Qt对象
        try:
            if not text_area or not status_label:
                logger.debug(f"{data_name}数据控件为空，重试显示")
                QTimer.singleShot(200, lambda: self.display_measurement_data(data, data_name, retry_count + 1))
                return
                
            # 检查控件是否可访问（没有被删除）
            text_area.objectName()  # 这会在控件被删除时抛出异常
            status_label.objectName()
        except RuntimeError:
            logger.debug(f"{data_name}数据控件已被删除，重试显示")
            QTimer.singleShot(200, lambda: self.display_measurement_data(data, data_name, retry_count + 1))
            return

        if not data:
            try:
                status_label.setText(f"未找到{data_name}数据")
            except Exception as e:
                logger.debug(f"设置状态标签失败: {str(e)}")
            return

        # 限制显示的齿数
        MAX_DISPLAY_TEETH = 5  # 最多显示5个齿

        text_content = ""
        total_left = 0
        total_right = 0

        # 左齿面数据
        if 'left' in data and data['left']:
            left_teeth = sorted(data['left'].keys())
            total_left = len(left_teeth)
            text_content += f"左齿面数据:\n{'=' * 40}\n"
            for tooth in left_teeth[:MAX_DISPLAY_TEETH]:
                values = data['left'][tooth]
                text_content += f"齿号: {tooth}\n"
                # 显示所有480个点（每10个点一行）
                for i in range(0, len(values), 10):
                    line_values = values[i:i + 10]
                    line_str = " ".join([f"{val:8.3f}" for val in line_values])
                    text_content += line_str + "\n"
                text_content += "\n"
            text_content += f"总计左齿面: {total_left} 个齿\n\n"

        # 右齿面数据
        if 'right' in data and data['right']:
            right_teeth = sorted(data['right'].keys())
            total_right = len(right_teeth)
            text_content += f"右齿面数据:\n{'=' * 40}\n"
            for tooth in right_teeth[:MAX_DISPLAY_TEETH]:
                values = data['right'][tooth]
                text_content += f"齿号: {tooth}\n"
                # 显示所有480个点（每10个点一行）
                for i in range(0, len(values), 10):
                    line_values = values[i:i + 10]
                    line_str = " ".join([f"{val:8.3f}" for val in line_values])
                    text_content += line_str + "\n"
                text_content += "\n"
            text_content += f"总计右齿面: {total_right} 个齿\n"
        else:
            text_content += f"未找到右齿面{data_name}数据\n"

        try:
            text_area.setText(text_content)
            status_label.setText(
                f"已加载{data_name}数据: 左齿面 {total_left} 个齿, 右齿面 {total_right} 个齿")
            logger.debug(f"成功显示{data_name}数据")
        except Exception as e:
            logger.debug(f"设置{data_name}数据显示时出错: {str(e)}")

    def run_undulation_analysis_from_toolbar(self):
        """从工具栏执行波纹度分析"""
        if not self.profile_data and not self.flank_data:
            QMessageBox.warning(self, "警告", "请先打开包含齿形或齿向数据的MKA文件")
            return
        
        self.analyze_undulation()
        
        self.run_undulation_analysis_action.setEnabled(True)

    def analyze_undulation(self):
        """执行波纹度分析"""
        if not self.profile_data and not self.flank_data:
            QMessageBox.warning(self, "警告", "没有可用的齿形或齿向数据")
            return

        # 禁用按钮
        if hasattr(self, 'analyze_btn') and self.analyze_btn:
            self.analyze_btn.setEnabled(False)
        if hasattr(self, 'export_report_btn') and self.export_report_btn:
            self.export_report_btn.setEnabled(False)
        if hasattr(self, 'analyze_freq_btn') and self.analyze_freq_btn:
            self.analyze_freq_btn.setEnabled(False)

        # 显示进度条
        self.progress_bar.setVisible(True)
        self.progress_label.setVisible(True)
        self.progress_label.setText("正在分析波纹度...")

        # 使用处理后的数据进行分析
        profile_data_to_use = getattr(self, 'processed_profile_data', self.profile_data)
        flank_data_to_use = getattr(self, 'processed_flank_data', self.flank_data)
        
        logger.info(f"使用处理后的数据进行波纹度分析: 齿形数据{len(profile_data_to_use.get('left', {}))}个齿, 齿向数据{len(flank_data_to_use.get('left', {}))}个齿")

        # 启动分析线程
        self.analysis_thread = UndulationAnalysisThread(
            profile_data_to_use, flank_data_to_use, self.gear_data, self
        )
        self.analysis_thread.finished.connect(self.on_undulation_analysis_complete)
        self.analysis_thread.progress.connect(self.on_progress_update)
        self.analysis_thread.start()

    def on_undulation_analysis_complete(self, results):
        """波纹度分析完成"""
        self.undulation_results = results
        self.display_undulation_results()
        if hasattr(self, 'export_report_btn') and self.export_report_btn:
            self.export_report_btn.setEnabled(True)
        if hasattr(self, 'analyze_btn') and self.analyze_btn:
            self.analyze_btn.setEnabled(True)
        if hasattr(self, 'analyze_freq_btn') and self.analyze_freq_btn:
            self.analyze_freq_btn.setEnabled(True)

        # 隐藏进度条
        self.progress_bar.setVisible(False)
        self.progress_label.setVisible(False)

        self.status_bar.showMessage("波纹度分析完成", 5000)

    def display_undulation_results(self):
        """显示波纹度分析结果"""
        if not self.undulation_results:
            return

        if not hasattr(self, 'undulation_table') or self.undulation_table is None:
            logger.warning("undulation_table未初始化，跳过结果显示")
            return

        self.undulation_table.setRowCount(0)

        row = 0
        for key, result in self.undulation_results['profile'].items():
            self.add_undulation_row(row, result, "齿形")
            row += 1

        for key, result in self.undulation_results['flank'].items():
            self.add_undulation_row(row, result, "齿向")
            row += 1

        stats = self.undulation_results['stats']
        stats_text = (
            f"齿形波纹度: 总数 {stats['profile']['total']} | "
            f"合格 {stats['profile']['passed']} | "
            f"超差 {stats['profile']['failed']} | "
            f"平均W值 {stats['profile']['avg_w']:.3f}μm | "
            f"平均RMS {stats['profile']['avg_rms']:.3f}μm\n"
            f"齿向波纹度: 总数 {stats['flank']['total']} | "
            f"合格 {stats['flank']['passed']} | "
            f"超差 {stats['flank']['failed']} | "
            f"平均W值 {stats['flank']['avg_w']:.3f}μm | "
            f"平均RMS {stats['flank']['avg_rms']:.3f}μm"
        )
        if hasattr(self, 'stats_label') and self.stats_label:
            self.stats_label.setText(stats_text)

    def add_undulation_row(self, row, result, data_type):
        """添加一行波纹度结果到表格"""
        if not hasattr(self, 'undulation_table') or self.undulation_table is None:
            return
        
        self.undulation_table.insertRow(row)

        tooth_item = QTableWidgetItem(str(result['tooth']))
        self.undulation_table.setItem(row, 0, tooth_item)

        side_item = QTableWidgetItem("左" if result['side'] == 'left' else "右")
        self.undulation_table.setItem(row, 1, side_item)

        type_item = QTableWidgetItem(data_type)
        self.undulation_table.setItem(row, 2, type_item)

        w_item = QTableWidgetItem(f"{result['w_value']:.3f}")
        self.undulation_table.setItem(row, 3, w_item)

        try:
            tol_value = result.get('tolerance', 0.0)
            tol_item = QTableWidgetItem(f"{tol_value:.3f}")
            self.undulation_table.setItem(row, 4, tol_item)
        except Exception:
            tol_item = QTableWidgetItem("0.000")
            self.undulation_table.setItem(row, 4, tol_item)

        rms_item = QTableWidgetItem(f"{result['rms_value']:.3f}")
        self.undulation_table.setItem(row, 5, rms_item)

        status_item = QTableWidgetItem(result['status'])
        self.undulation_table.setItem(row, 6, status_item)

        if result['status'] == "合格":
            status_item.setBackground(QColor(144, 238, 144))
        else:
            status_item.setBackground(QColor(255, 182, 193))

    def on_undulation_row_selected(self):
        """当选择表格行时显示详细视图"""
        if not hasattr(self, 'undulation_table') or self.undulation_table is None:
            return
        
        selected_items = self.undulation_table.selectedItems()
        if not selected_items:
            return

        row = selected_items[0].row()

        tooth = self.undulation_table.item(row, 0).text()
        side = "left" if self.undulation_table.item(row, 1).text() == "左" else "right"
        data_type = "profile" if self.undulation_table.item(row, 2).text() == "齿形" else "flank"
        key = f"{'L' if side == 'left' else 'R'}{tooth}"

        if data_type in self.undulation_results and key in self.undulation_results[data_type]:
            self.current_detail = self.undulation_results[data_type][key]
            self.display_detail_view()

    def display_detail_view(self):
        """显示详细视图"""
        if not self.current_detail:
            return

        side_text = '左' if self.current_detail['side'] == 'left' else '右'
        type_text = '齿形' if self.current_detail['data_type'] == 'profile' else '齿向'
        
        orders = self.current_detail.get('orders', [])
        amplitudes = self.current_detail.get('amplitudes', [])
        high_order = self.current_detail.get('high_order', {})
        
        orders_str = ', '.join([str(o) for o in orders[:5]]) if len(orders) > 0 else '-'
        
        if hasattr(self, 'detail_label') and self.detail_label:
            self.detail_label.setText(
                f"齿号: {self.current_detail['tooth']} | "
                f"齿面: {side_text} | "
                f"类型: {type_text} | "
                f"W值: {self.current_detail['w_value']:.3f}μm | "
                f"RMS: {self.current_detail['rms_value']:.3f}μm | "
                f"前5波数: {orders_str}"
            )

        if not hasattr(self, 'feature_table') or self.feature_table is None:
            return
            
        self.feature_table.setRowCount(0)
        
        teeth_count = self.gear_data.get('teeth', self.gear_data.get('齿数', 0)) if self.gear_data else 0
        for i, (order, amp) in enumerate(zip(orders, amplitudes)):
            self.feature_table.insertRow(i)
            is_high_order = "是" if order >= teeth_count else "否"
            self.feature_table.setItem(i, 0, QTableWidgetItem(f"{order}"))
            self.feature_table.setItem(i, 1, QTableWidgetItem(f"{amp:.4f}"))
            self.feature_table.setItem(i, 2, QTableWidgetItem(is_high_order))

        # 更新图表
        self.display_undulation_chart()

    def display_undulation_chart(self):
        """显示波纹度图表 - 四种分析图（左齿形、右齿形、左齿向、右齿向）"""
        if not self.undulation_results:
            return

        if not hasattr(self, 'figure') or self.figure is None:
            logger.warning("figure未初始化，跳过图表显示")
            return
        
        if not hasattr(self, 'canvas') or self.canvas is None:
            logger.warning("canvas未初始化，跳过图表显示")
            return

        self.figure.clear()
        
        spectrum_data = self.undulation_results.get('spectrum_data', {})
        teeth_count = self.gear_data.get('teeth', self.gear_data.get('齿数', 0)) if self.gear_data else 0
        
        plot_keys = [
            ('L_profile', '左齿形 (Left Profile)'),
            ('R_profile', '右齿形 (Right Profile)'),
            ('L_helix', '左齿向 (Left Helix)'),
            ('R_helix', '右齿向 (Right Helix)')
        ]
        
        available_plots = [(k, t) for k, t in plot_keys if k in spectrum_data]
        
        if not available_plots:
            ax = self.figure.add_subplot(111)
            ax.text(0.5, 0.5, '无可用数据', ha='center', va='center', fontsize=14)
            self.canvas.draw()
            return
        
        n_plots = len(available_plots)
        n_cols = 2
        n_rows = (n_plots + 1) // 2
        
        for idx, (key, title) in enumerate(available_plots):
            ax = self.figure.add_subplot(n_rows, n_cols, idx + 1)
            
            data = spectrum_data[key]
            spectrum = data['spectrum']
            high_order = data['high_order']
            interp_angles = data['interp_angles']
            interp_values = data['interp_values']
            
            ax.plot(interp_angles, interp_values, 'b-', alpha=0.5, label='原始信号', linewidth=0.8)
            ax.plot(interp_angles, spectrum['reconstructed'], 'r-', alpha=0.8, label='重构信号', linewidth=1)
            
            orders = spectrum['orders']
            amplitudes = spectrum['amplitudes']
            
            bar_colors = ['red' if o >= teeth_count else 'steelblue' for o in orders]
            
            ax2 = ax.twinx()
            bars = ax2.bar(range(len(orders)), amplitudes, color=bar_colors, alpha=0.3, width=0.8)
            ax2.set_ylabel('振幅 (μm)', fontsize=8)
            ax2.tick_params(axis='y', labelsize=7)
            
            ax.set_xlabel('旋转角度 (°)', fontsize=8)
            ax.set_ylabel('偏差 (μm)', fontsize=8)
            ax.set_title(f'{title}\nW={high_order["total_high_order_amplitude"]:.3f}μm, RMS={high_order["high_order_rms"]:.3f}μm', fontsize=9)
            ax.set_xlim(0, 360)
            ax.grid(True, alpha=0.3)
            ax.tick_params(axis='both', labelsize=7)
            
            if idx == 0:
                ax.legend(loc='upper right', fontsize=7)
        
        self.figure.tight_layout()
        self.canvas.draw()

    def export_undulation_report(self):
        """导出波纹度分析报告"""
        if not self.undulation_results or not self.current_file:
            QMessageBox.warning(self, "警告", "没有可导出的波纹度数据")
            return

        output_path, _ = QFileDialog.getSaveFileName(
            self, "保存波纹度分析报告",
            os.path.splitext(self.current_file)[0] + "_波纹度报告.txt",
            "文本文件 (*.txt)"
        )

        if not output_path:
            return

        try:
            with open(output_path, 'w', encoding='utf-8') as f:
                # 写入报告头部
                f.write("=" * 80 + "\n")
                f.write(f"齿轮波纹度分析报告\n")
                f.write(f"文件: {os.path.basename(self.current_file)}\n")
                f.write(f"生成时间: {datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n")
                f.write("=" * 80 + "\n\n")

                # 写入基本信息
                f.write("[齿轮基本信息]\n")
                f.write("-" * 80 + "\n")
                f.write(f"图号: {self.gear_data.get('图号', '')}\n")
                f.write(f"序号: {self.gear_data.get('序号', '')}\n")
                f.write(f"模数: {self.gear_data.get('模数', 0.0)} mm\n")
                f.write(f"齿数: {self.gear_data.get('齿数', 0)}\n")
                f.write(f"压力角: {self.gear_data.get('压力角', 0.0)}°\n")
                f.write(f"螺旋角: {self.gear_data.get('螺旋角', 0.0)}°\n")
                f.write(f"精度等级: {self.gear_data.get('精度等级', 5)}\n")
                f.write("\n")

                # 写入统计信息
                stats = self.undulation_results['stats']
                f.write("[波纹度统计]\n")
                f.write("-" * 80 + "\n")
                f.write(f"齿形波纹度:\n")
                f.write(f"  总数: {stats['profile']['total']}\n")
                f.write(f"  合格: {stats['profile']['passed']}\n")
                f.write(f"  超差: {stats['profile']['failed']}\n")
                f.write(f"  平均W值: {stats['profile']['avg_w']:.1f} μm\n")
                f.write(f"  平均RMS值: {stats['profile']['avg_rms']:.1f} μm\n\n")
                f.write(f"齿向波纹度:\n")
                f.write(f"  总数: {stats['flank']['total']}\n")
                f.write(f"  合格: {stats['flank']['passed']}\n")
                f.write(f"  超差: {stats['flank']['failed']}\n")
                f.write(f"  平均W值: {stats['flank']['avg_w']:.1f} μm\n")
                f.write(f"  平均RMS值: {stats['flank']['avg_rms']:.1f} μm\n\n")

                # 写入详细结果
                f.write("[详细波纹度分析]\n")
                f.write("-" * 80 + "\n")
                f.write(f"{'齿号':<6}{'齿面':<6}{'类型':<8}{'W值(μm)':<12}{'公差(μm)':<12}{'RMS(μm)':<12}{'状态':<10}\n")

                # 齿形数据
                for key, result in self.undulation_results['profile'].items():
                    side = "左" if result['side'] == 'left' else "右"
                    status = "合格" if result['status'] == "合格" else "超差"
                    f.write(
                        f"{result['tooth']:<6}{side:<6}{'齿形':<8}{result.get('w_value', 0.0):<12.1f}"
                        f"{result.get('tolerance', 0.0):<12.1f}{result.get('rms_value', 0.0):<12.1f}{status:<10}\n"
                    )

                # 齿向数据
                for key, result in self.undulation_results['flank'].items():
                    side = "左" if result['side'] == 'left' else "右"
                    status = "合格" if result['status'] == "合格" else "超差"
                    f.write(
                        f"{result['tooth']:<6}{side:<6}{'齿向':<8}{result.get('w_value', 0.0):<12.1f}"
                        f"{result.get('tolerance', 0.0):<12.1f}{result.get('rms_value', 0.0):<12.1f}{status:<10}\n"
                    )

                # 写入报告尾部
                f.write("\n" + "=" * 80 + "\n")
                f.write("报告结束\n")
                f.write("=" * 80 + "\n")

            # 创建自定义消息框
            msg_box = QMessageBox(self)
            msg_box.setWindowTitle("导出成功")
            msg_box.setIcon(QMessageBox.Information)
            msg_box.setText(f"波纹度分析报告已成功导出到:\n{output_path}")

            # 添加按钮
            open_file_btn = msg_box.addButton("打开文件", QMessageBox.ActionRole)
            open_folder_btn = msg_box.addButton("打开文件夹位置", QMessageBox.ActionRole)
            close_btn = msg_box.addButton("关闭", QMessageBox.RejectRole)

            # 显示消息框
            msg_box.exec_()

            # 处理按钮点击
            clicked_btn = msg_box.clickedButton()
            if clicked_btn == open_file_btn:
                self.open_file(output_path)
            elif clicked_btn == open_folder_btn:
                self.open_folder(output_path)

            logger.info(f"波纹度报告导出成功: {output_path}")

        except Exception as e:
            QMessageBox.critical(self, "导出失败", f"无法导出波纹度分析报告:\n{str(e)}")
            self.status_bar.showMessage(f"波纹度报告导出失败: {str(e)}", 5000)
            logger.error(f"波纹度报告导出失败: {str(e)}")

    def analyze_deviation(self, force_reanalysis=False):
        """执行ISO1328偏差分析"""
        if (not self.profile_data and not self.flank_data) or not self.gear_data:
            QMessageBox.warning(self, "警告", "没有可用的齿形、齿向或基本数据")
            return

        # 如果不是强制重分析，且已有结果，则不重复分析
        if self.deviation_results and not force_reanalysis:
            self.display_deviation_results()
            return

        # 使用处理后的数据进行分析
        profile_data_to_use = getattr(self, 'processed_profile_data', self.profile_data)
        flank_data_to_use = getattr(self, 'processed_flank_data', self.flank_data)
        
        logger.info(f"使用处理后的数据进行偏差分析: 齿形数据{len(profile_data_to_use.get('left', {}))}个齿, 齿向数据{len(flank_data_to_use.get('left', {}))}个齿")

        # 禁用按钮（检查按钮是否存在）
        if hasattr(self, 'analyze_deviation_btn'):
            self.analyze_deviation_btn.setEnabled(False)
        if hasattr(self, 'export_deviation_btn'):
            self.export_deviation_btn.setEnabled(False)

        # 显示进度条
        self.progress_bar.setVisible(True)
        self.progress_label.setVisible(True)
        self.progress_label.setText("正在分析ISO1328偏差...")

        # 启动分析线程
        self.deviation_thread = DeviationAnalysisThread(
            profile_data_to_use, flank_data_to_use, self.pitch_data, self.gear_data, self.analysis_settings
        )
        self.deviation_thread.finished.connect(self.on_deviation_analysis_complete)
        self.deviation_thread.progress.connect(self.on_progress_update)
        self.deviation_thread.start()

    def on_deviation_analysis_complete(self, results):
        """偏差分析完成"""
        self.deviation_results = results
        self.display_deviation_results()
        # 启用按钮（检查按钮是否存在）
        if hasattr(self, 'export_deviation_btn'):
            self.export_deviation_btn.setEnabled(True)
        if hasattr(self, 'analyze_deviation_btn'):
            self.analyze_deviation_btn.setEnabled(True)

        # 隐藏进度条
        self.progress_bar.setVisible(False)
        self.progress_label.setVisible(False)

        self.status_bar.showMessage("ISO1328偏差分析完成", 5000)
        
        # 自动启动周节偏差分析
        if self.pitch_data and not hasattr(self, 'pitch_results'):
            QTimer.singleShot(100, self.start_pitch_analysis)
        
        if self.undulation_results:
            self.html_report_action.setEnabled(True)
            self.pdf_report_action.setEnabled(True)
            self.klingelnberg_report_action.setEnabled(True)
            self.rotation_waviness_report_action.setEnabled(True)       

    def display_deviation_results(self):
        """显示偏差分析结果"""
        if not self.deviation_results:
            return

        # 检查deviation_table属性是否存在
        if not hasattr(self, 'deviation_table'):
            return
            
        # 清空表格
        self.deviation_table.setRowCount(0)

        # 显示齿形偏差结果
        row = 0
        for key, result in self.deviation_results['profile'].items():
            self.add_deviation_row(row, result, "齿形")
            row += 1

        # 显示齿向偏差结果
        for key, result in self.deviation_results['flank'].items():
            self.add_deviation_row(row, result, "齿向")
            row += 1

        # 显示周节偏差结果
        if 'spacing' in self.deviation_results:
            for key, result in self.deviation_results['spacing'].items():
                self.add_deviation_row(row, result, "周节")
            row += 1

        # 更新统计信息
        stats = self.deviation_results['stats']

        # 齿形统计信息
        # 齿形统计信息
        profile_total = stats['profile']['total']
        profile_passed = stats['profile']['passed']
        if profile_total > 0:
            profile_rate = profile_passed / profile_total * 100
            profile_rate_str = f"{profile_passed}/{profile_total} ({profile_rate:.1f}%)"
        else:
            profile_rate_str = "0/0 (0.0%)"
        profile_stats_text = (
            f"齿形偏差统计:\n"
            f"平均 F_alpha: {stats['profile']['avg_F_alpha']:.1f}μm | "
            f"平均 fH_alpha: {stats['profile']['avg_fH_alpha']:.1f}μm | "
            f"平均 ff_alpha: {stats['profile']['avg_ff_alpha']:.1f}μm\n"
            f"最大 F_alpha: {stats['profile']['max_F_alpha']:.1f}μm | "
            f"最大 fH_alpha: {stats['profile']['max_fH_alpha']:.1f}μm | "
            f"最大 ff_alpha: {stats['profile']['max_ff_alpha']:.1f}μm\n"
            f"合格率: {profile_rate_str}"
        )

        # 齿向统计信息
        flank_total = stats['flank']['total']
        flank_passed = stats['flank']['passed']
        if flank_total > 0:
            flank_rate = flank_passed / flank_total * 100
            flank_rate_str = f"{flank_passed}/{flank_total} ({flank_rate:.1f}%)"
        else:
            flank_rate_str = "0/0 (0.0%)"
        flank_stats_text = (
            f"齿向偏差统计:\n"
            f"平均 F_beta: {stats['flank']['avg_F_beta']:.1f}μm | "
            f"平均 fH_beta: {stats['flank']['avg_fH_beta']:.1f}μm | "
            f"平均 ff_beta: {stats['flank']['avg_ff_beta']:.1f}μm\n"
            f"最大 F_beta: {stats['flank']['max_F_beta']:.1f}μm | "
            f"最大 fH_beta: {stats['flank']['max_fH_beta']:.1f}μm | "
            f"最大 ff_beta: {stats['flank']['max_ff_beta']:.1f}μm\n"
            f"合格率: {flank_rate_str}"
        )
      
        # 周节统计信息
        spacing_stats_text = ""
        if 'spacing' in stats:
            spacing_total = stats['spacing']['total']
            spacing_passed = stats['spacing']['passed']
            if spacing_total > 0:
                spacing_rate = spacing_passed / spacing_total * 100
                spacing_rate_str = f"{spacing_passed}/{spacing_total} ({spacing_rate:.1f}%)"
            else:
                spacing_rate_str = "0/0 (0.0%)"
            spacing_stats_text = (
                f"周节偏差统计:\n"
                f"平均 fp: {stats['spacing']['avg_fp']:.1f}μm | "
                f"平均 Fp: {stats['spacing']['avg_Fp']:.1f}μm | "
                f"平均 Fr: {stats['spacing']['avg_Fr']:.1f}μm\n"
                f"最大 fp: {stats['spacing']['max_fp']:.1f}μm | "
                f"最大 Fp: {stats['spacing']['max_Fp']:.1f}μm | "
                f"最大 Fr: {stats['spacing']['max_Fr']:.1f}μm\n"
                f"合格率: {spacing_rate_str}"
            )

        # 更新统计标签
        if hasattr(self, 'profile_stats_label'):
            self.profile_stats_label.setText(profile_stats_text)
        if hasattr(self, 'flank_stats_label'):
            flank_text = flank_stats_text
            if spacing_stats_text:
                flank_text += "\n\n" + spacing_stats_text
            self.flank_stats_label.setText(flank_text)

    def add_deviation_row(self, row, result, data_type):
        """添加一行偏差结果到表格"""
        self.deviation_table.insertRow(row)

        # 齿号
        tooth_item = QTableWidgetItem(str(result['tooth']))
        self.deviation_table.setItem(row, 0, tooth_item)

        # 齿面
        side_item = QTableWidgetItem("左" if result['side'] == 'left' else "右")
        self.deviation_table.setItem(row, 1, side_item)

        # 数据类型
        type_item = QTableWidgetItem(data_type)
        self.deviation_table.setItem(row, 2, type_item)

        # 精度等级 - 根据实际公差计算
        actual_grade = self.get_actual_accuracy_grade_from_tolerance(data_type)
        accuracy_item = QTableWidgetItem(f"{actual_grade}级")
        self.deviation_table.setItem(row, 3, accuracy_item)

        # 偏差值
        if data_type == "齿形":
            F_value = result['F_alpha']
            fH_value = result['fH_alpha']
            ff_value = result['ff_alpha']
            F_tolerance = result['F_alpha_tolerance']
            fH_tolerance = result['fH_alpha_tolerance']
            ff_tolerance = result['ff_alpha_tolerance']
            F_status = result['F_alpha_status']
            fH_status = result['fH_alpha_status']
            ff_status = result['ff_alpha_status']
        elif data_type == "周节":
            # 周节数据使用fp、Fp、Fr
            F_value = result['fp']
            fH_value = result['Fp']
            ff_value = result['Fr']
            F_tolerance = result['fp_tolerance']
            fH_tolerance = result['Fp_tolerance']
            ff_tolerance = result['Fr_tolerance']
            F_status = result['fp_status']
            fH_status = result['Fp_status']
            ff_status = result['Fr_status']
        else:
            F_value = result['F_beta']
            fH_value = result['fH_beta']
            ff_value = result['ff_beta']
            F_tolerance = result['F_beta_tolerance']
            fH_tolerance = result['fH_beta_tolerance']
            ff_tolerance = result['ff_beta_tolerance']
            F_status = result['F_beta_status']
            fH_status = result['fH_beta_status']
            ff_status = result['ff_beta_status']

        # F值 - 超差时设置粗体和红色
        F_item = QTableWidgetItem(f"{F_value:.1f}")
        if F_status == "超差":
            font = F_item.font()
            font.setBold(True)
            F_item.setFont(font)
            F_item.setForeground(QColor(200, 0, 0))  # 红色字体
        self.deviation_table.setItem(row, 4, F_item)

        # fH值 - 超差时设置粗体和红色
        fH_item = QTableWidgetItem(f"{fH_value:.1f}")
        if fH_status == "超差":
            font = fH_item.font()
            font.setBold(True)
            fH_item.setFont(font)
            fH_item.setForeground(QColor(200, 0, 0))  # 红色字体
        self.deviation_table.setItem(row, 5, fH_item)

        # ff值 - 超差时设置粗体和红色
        ff_item = QTableWidgetItem(f"{ff_value:.1f}")
        if ff_status == "超差":
            font = ff_item.font()
            font.setBold(True)
            ff_item.setFont(font)
            ff_item.setForeground(QColor(200, 0, 0))  # 红色字体
        self.deviation_table.setItem(row, 6, ff_item)

        # 公差值
        F_tol_item = QTableWidgetItem(f"{F_tolerance:.1f}")
        self.deviation_table.setItem(row, 7, F_tol_item)

        fH_tol_item = QTableWidgetItem(f"{fH_tolerance:.1f}")
        self.deviation_table.setItem(row, 8, fH_tol_item)

        ff_tol_item = QTableWidgetItem(f"{ff_tolerance:.1f}")
        self.deviation_table.setItem(row, 9, ff_tol_item)

        # 状态
        F_status_item = QTableWidgetItem(F_status)
        self.deviation_table.setItem(row, 10, F_status_item)

        fH_status_item = QTableWidgetItem(fH_status)
        self.deviation_table.setItem(row, 11, fH_status_item)

        # ff状态 (第12列)
        ff_status_item = QTableWidgetItem(ff_status)
        self.deviation_table.setItem(row, 12, ff_status_item)

        # 根据状态设置颜色
        status_color = QColor(144, 238, 144) if F_status == "合格" else QColor(255, 182, 193)  # 浅绿/浅红
        F_status_item.setBackground(status_color)

        status_color = QColor(144, 238, 144) if fH_status == "合格" else QColor(255, 182, 193)
        fH_status_item.setBackground(status_color)

        status_color = QColor(144, 238, 144) if ff_status == "合格" else QColor(255, 182, 193)
        ff_status_item.setBackground(status_color)

    def on_deviation_row_selected(self):
        """当选择偏差表格行时显示详细视图"""
        selected_items = self.deviation_table.selectedItems()
        if not selected_items:
            return

        row = selected_items[0].row()

        # 获取结果
        tooth = self.deviation_table.item(row, 0).text()
        side = "left" if self.deviation_table.item(row, 1).text() == "左" else "right"
        type_text = self.deviation_table.item(row, 2).text()
        if type_text == "齿形":
            data_type = "profile"
        elif type_text == "周节":
            data_type = "spacing"
        else:
            data_type = "flank"
        key = f"{'L' if side == 'left' else 'R'}{tooth}"

        # 获取详细结果
        if data_type == "profile" and 'profile' in self.deviation_results and key in self.deviation_results['profile']:
            result = self.deviation_results['profile'][key]
            self.display_deviation_detail(result, "齿形")
        elif data_type == "flank" and 'flank' in self.deviation_results and key in self.deviation_results['flank']:
            result = self.deviation_results['flank'][key]
            self.display_deviation_detail(result, "齿向")

    def display_deviation_detail(self, result, data_type):
        """显示偏差详细信息"""
        # 更新标签
        self.deviation_detail_label.setText(
            f"齿号: {result['tooth']} | "
            f"齿面: {'左' if result['side'] == 'left' else '右'} | "
            f"类型: {data_type}"
        )

        # 更新公差表格
        self.tolerance_table.setRowCount(3)
        self.tolerance_table.setVerticalHeaderLabels(["总偏差", "斜率偏差", "形状偏差"])

        # 添加数据
        if data_type == "齿形":
            F_value = result['F_alpha']
            fH_value = result['fH_alpha']
            ff_value = result['ff_alpha']
            F_tolerance = result['F_alpha_tolerance']
            fH_tolerance = result['fH_alpha_tolerance']
            ff_tolerance = result['ff_alpha_tolerance']
            F_status = result['F_alpha_status']
            fH_status = result['fH_alpha_status']
            ff_status = result['ff_alpha_status']
        else:
            F_value = result['F_beta']
            fH_value = result['fH_beta']
            ff_value = result['ff_beta']
            F_tolerance = result['F_beta_tolerance']
            fH_tolerance = result['fH_beta_tolerance']
            ff_tolerance = result['ff_beta_tolerance']
            F_status = result['F_beta_status']
            fH_status = result['fH_beta_status']
            ff_status = result['ff_beta_status']

        # 总偏差
        self.tolerance_table.setItem(0, 0, QTableWidgetItem(f"{F_value:.2f}"))
        self.tolerance_table.setItem(0, 1, QTableWidgetItem(f"{F_tolerance:.2f}"))
        self.tolerance_table.setItem(0, 2, QTableWidgetItem(F_status))
        # 设置状态颜色
        if F_status == "合格":
            self.tolerance_table.item(0, 2).setBackground(QColor(144, 238, 144))
        else:
            self.tolerance_table.item(0, 2).setBackground(QColor(255, 182, 193))

        # 斜率偏差
        self.tolerance_table.setItem(1, 0, QTableWidgetItem(f"{fH_value:.2f}"))
        self.tolerance_table.setItem(1, 1, QTableWidgetItem(f"{fH_tolerance:.2f}"))
        self.tolerance_table.setItem(1, 2, QTableWidgetItem(fH_status))
        if fH_status == "合格":
            self.tolerance_table.item(1, 2).setBackground(QColor(144, 238, 144))
        else:
            self.tolerance_table.item(1, 2).setBackground(QColor(255, 182, 193))

        # 形状偏差
        self.tolerance_table.setItem(2, 0, QTableWidgetItem(f"{ff_value:.2f}"))
        self.tolerance_table.setItem(2, 1, QTableWidgetItem(f"{ff_tolerance:.2f}"))
        self.tolerance_table.setItem(2, 2, QTableWidgetItem(ff_status))
        if ff_status == "合格":
            self.tolerance_table.item(2, 2).setBackground(QColor(144, 238, 144))
        else:
            self.tolerance_table.item(2, 2).setBackground(QColor(255, 182, 193))

        # 更新图表
        self.display_deviation_chart(result, data_type)

    def display_deviation_chart(self, result, data_type):
        """显示偏差图表"""
        if not result:
            return

        # 清除之前的图表
        self.deviation_figure.clear()
        ax = self.deviation_figure.add_subplot(111)

        # 获取数据
        side = result['side']
        tooth = result['tooth']

        if data_type == "齿形":
            # 获取测量数据
            if side == 'left' and tooth in self.profile_data['left']:
                values = self.profile_data['left'][tooth]
            elif side == 'right' and tooth in self.profile_data['right']:
                values = self.profile_data['right'][tooth]
            else:
                return

            # 获取展长值
            start_measure = self.gear_data['齿形起测点展长'][side]
            start_eval = self.gear_data['齿形起评点展长'][side]
            end_eval = self.gear_data['齿形终评点展长'][side]
            end_measure = self.gear_data['齿形终测点展长'][side]
            x_label = "展长 (mm)"
        else:
            # 获取测量数据
            if side == 'left' and tooth in self.flank_data['left']:
                values = self.flank_data['left'][tooth]
            elif side == 'right' and tooth in self.flank_data['right']:
                values = self.flank_data['right'][tooth]
            else:
                return

            # 获取齿宽位置
            start_measure = self.gear_data['齿向起测点'][side]
            start_eval = self.gear_data['齿向起评点'][side]
            end_eval = self.gear_data['齿向终评点'][side]
            end_measure = self.gear_data['齿向终测点'][side]
            x_label = "齿宽位置 (mm)"

        # 转换为numpy数组
        values = np.array(values)

        # 计算每个点的实际位置
        x_positions = np.linspace(start_measure, end_measure, len(values))

        # 获取评价范围内的数据，如果没有索引信息则使用全部数据
        start_eval_index = result.get('start_eval_index', 0)
        end_eval_index = result.get('end_eval_index', len(values) - 1)
        
        eval_data = values[start_eval_index:end_eval_index + 1]
        eval_x = x_positions[start_eval_index:end_eval_index + 1]

        # 计算最小二乘拟合直线
        x = np.arange(len(eval_data))
        slope, intercept = np.polyfit(x, eval_data, 1)
        trend = slope * x + intercept

        # 绘制原始数据
        ax.plot(eval_x, eval_data, 'b-', label="原始数据", linewidth=0.8)

        # 绘制拟合直线
        ax.plot(eval_x, trend, 'r-', label="拟合直线", linewidth=0.8)

        # 标记关键点
        ax.axvline(x=start_measure, color='r', linestyle='--', label="起测点")
        ax.axvline(x=start_eval, color='g', linestyle='-.', label="起评点")
        ax.axvline(x=end_eval, color='g', linestyle='-.', label="终评点")
        ax.axvline(x=end_measure, color='r', linestyle='--', label="终测点")

        # 添加图例
        ax.legend()

        # 设置图表标题和标签
        ax.set_title(
            f"{data_type}偏差分析 - 齿号 {tooth} "
            f"({'左' if side == 'left' else '右'}齿面)"
        )
        ax.set_xlabel(x_label)
        ax.set_ylabel("偏差 (μm)")

        # 更新图表
        self.deviation_canvas.draw()

    def export_data(self):
        """导出齿轮基本数据"""
        if not self.gear_data:
            QMessageBox.warning(self, "警告", "没有可导出的数据")
            return

        output_path, _ = QFileDialog.getSaveFileName(
            self, "保存齿轮数据",
            os.path.splitext(self.current_file)[0] + "_齿轮数据.txt",
            "文本文件 (*.txt)"
        )

        if not output_path:
            return

        try:
            with open(output_path, 'w', encoding='utf-8') as f:
                # 写入基本信息
                f.write("=" * 80 + "\n")
                f.write(f"齿轮基本数据\n")
                f.write(f"文件: {os.path.basename(self.current_file)}\n")
                f.write(f"生成时间: {datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n")
                f.write("=" * 80 + "\n\n")

                # 写入齿轮参数
                f.write("[齿轮参数]\n")
                f.write("-" * 80 + "\n")
                for key, value in self.gear_data.items():
                    if isinstance(value, dict):
                        # 左右齿面参数
                        f.write(f"{key}:\n")
                        f.write(f"  左: {value.get('left', 0.0)}\n")
                        f.write(f"  右: {value.get('right', 0.0)}\n")
                    else:
                        f.write(f"{key}: {value}\n")
                f.write("\n")

            QMessageBox.information(self, "导出成功", f"齿轮数据已成功导出到:\n{output_path}")
            self.status_bar.showMessage(f"齿轮数据导出成功: {output_path}", 5000)
            logger.info(f"齿轮数据导出成功: {output_path}")
        except Exception as e:
            QMessageBox.critical(self, "导出失败", f"无法导出齿轮数据:\n{str(e)}")
            self.status_bar.showMessage(f"齿轮数据导出失败: {str(e)}", 5000)
            logger.error(f"齿轮数据导出失败: {str(e)}")

