    def export_deviation_report(self):
        """导出偏差分析报告"""
        if not self.deviation_results:
            QMessageBox.warning(self, "警告", "没有可导出的偏差数据")
            return

        output_path, _ = QFileDialog.getSaveFileName(
            self, "保存偏差分析报告",
            os.path.splitext(self.current_file)[0] + "_偏差分析报告.txt",
            "文本文件 (*.txt)"
        )

        if not output_path:
            return

        try:
            with open(output_path, 'w', encoding='utf-8') as f:
                # 写入报告头部
                f.write("=" * 80 + "\n")
                f.write(f"齿轮偏差分析报告\n")
                f.write(f"文件: {os.path.basename(self.current_file)}\n")
                f.write(f"生成时间: {datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n")
                f.write("=" * 80 + "\n\n")

                # 写入基本信息
                f.write("[齿轮基本信息]\n")
                f.write("-" * 80 + "\n")
                f.write(f"图号: {self.gear_data.get('图号', '')}\n")
                f.write(f"序号: {self.gear_data.get('序号', '')}\n")
                f.write(f"模数: {self.gear_data.get('模数', 0.0)} mm\n")
                f.write(f"齿数: {self.gear_data.get('齿数', 0)}\n")
                f.write(f"精度等级: {self.gear_data.get('精度等级', 5)}\n")
                f.write("\n")

                # 写入统计信息
                stats = self.deviation_results['stats']
                f.write("[偏差统计]\n")
                f.write("-" * 80 + "\n")
                f.write(f"齿形偏差:\n")
                f.write(f"  总数: {stats['profile']['total']}\n")
                f.write(f"  合格: {stats['profile']['passed']}\n")
                f.write(f"  超差: {stats['profile']['failed']}\n")
                f.write(f"  平均F_alpha: {stats['profile']['avg_F_alpha']:.1f} μm\n")
                f.write(f"  平均fH_alpha: {stats['profile']['avg_fH_alpha']:.1f} μm\n")
                f.write(f"  平均ff_alpha: {stats['profile']['avg_ff_alpha']:.1f} μm\n\n")
                f.write(f"齿向偏差:\n")
                f.write(f"  总数: {stats['flank']['total']}\n")
                f.write(f"  合格: {stats['flank']['passed']}\n")
                f.write(f"  超差: {stats['flank']['failed']}\n")
                f.write(f"  平均F_beta: {stats['flank']['avg_F_beta']:.1f} μm\n")
                f.write(f"  平均fH_beta: {stats['flank']['avg_fH_beta']:.1f} μm\n")
                f.write(f"  平均ff_beta: {stats['flank']['avg_ff_beta']:.1f} μm\n\n")

                # 写入详细结果
                f.write("[详细偏差分析]\n")
                f.write("-" * 80 + "\n")
                f.write(f"{'齿号':<6}{'齿面':<6}{'类型':<8}{'F_alpha/F_beta':<10}{'fH_alpha/fH_beta':<10}{'ff_alpha/ff_beta':<10}{'状态':<10}\n")

                # 齿形数据
                for key, result in self.deviation_results['profile'].items():
                    side = "左" if result['side'] == 'left' else "右"
                    status = "合格" if result['F_alpha_status'] == "合格" and result['fH_alpha_status'] == "合格" and result[
                        'ff_alpha_status'] == "合格" else "超差"
                    f.write(
                        f"{result['tooth']:<6}{side:<6}{'齿形':<8}"
                        f"{result['F_alpha']:<10.1f}{result['fH_alpha']:<10.1f}{result['ff_alpha']:<10.1f}"
                        f"{status:<10}\n"
                    )

                # 齿向数据
                for key, result in self.deviation_results['flank'].items():
                    side = "左" if result['side'] == 'left' else "右"
                    status = "合格" if result['F_beta_status'] == "合格" and result['fH_beta_status'] == "合格" and result[
                        'ff_beta_status'] == "合格" else "超差"
                    f.write(
                        f"{result['tooth']:<6}{side:<6}{'齿向':<8}"
                        f"{result['F_beta']:<10.1f}{result['fH_beta']:<10.1f}{result['ff_beta']:<10.1f}"
                        f"{status:<10}\n"
                    )

                # 写入报告尾部
                f.write("\n" + "=" * 80 + "\n")
                f.write("报告结束\n")
                f.write("=" * 80 + "\n")

            QMessageBox.information(self, "导出成功", f"偏差分析报告已成功导出到:\n{output_path}")
            self.status_bar.showMessage(f"偏差报告导出成功: {output_path}", 5000)
            logger.info(f"偏差报告导出成功: {output_path}")
        except Exception as e:
            QMessageBox.critical(self, "导出失败", f"无法导出偏差分析报告:\n{str(e)}")
            self.status_bar.showMessage(f"偏差报告导出失败: {str(e)}", 5000)
            logger.error(f"偏差报告导出失败: {str(e)}")

