    def _update_normalized_order_analysis(self, canvas, data_type, side, order_range, normalize_method, filter_type="无滤波"):
        """更新归一化阶次分析图表"""
        try:
            fig = canvas.figure
            fig.clear()

            # 确定数据源
            if data_type == "齿形数据":
                data_source = self.profile_data
                title_prefix = "齿形"
                ylabel = "归一化振幅"
            else:
                data_source = self.flank_data
                title_prefix = "齿向"
                ylabel = "归一化振幅"

            if not data_source:
                ax = fig.add_subplot(111)
                ax.text(0.5, 0.5, "没有可用的数据", ha='center', va='center', transform=ax.transAxes)
                canvas.draw()
                return

            # 确定要显示的齿面
            sides_to_show = []
            if side == "左齿面":
                sides_to_show = [('left', '左齿面')]
            elif side == "右齿面":
                sides_to_show = [('right', '右齿面')]
            else:  # 全部
                sides_to_show = [('left', '左齿面'), ('right', '右齿面')]

            # 解析阶次范围
            max_orders = int(order_range.split('-')[1])

            # 创建子图
            num_sides = len(sides_to_show)
            if num_sides == 1:
                ax = fig.add_subplot(111)
                axes = [ax]
            else:
                axes = []
                for i in range(num_sides):
                    ax = fig.add_subplot(1, 2, i+1)
                    axes.append(ax)

            for idx, (side_key, side_name) in enumerate(sides_to_show):
                ax = axes[idx]
                
                if side_key not in data_source:
                    ax.text(0.5, 0.5, f"没有{side_name}数据", ha='center', va='center', transform=ax.transAxes)
                    continue

                side_data = data_source[side_key]
                
                # 收集所有齿的数据
                all_data = []
                for tooth_id, tooth_data in side_data.items():
                    if isinstance(tooth_data, (list, np.ndarray)) and len(tooth_data) > 0:
                        all_data.append(tooth_data)
                
                if not all_data:
                    ax.text(0.5, 0.5, f"没有{side_name}有效数据", ha='center', va='center', transform=ax.transAxes)
                    continue

                # 计算平均曲线
                avg_data = np.mean(all_data, axis=0)
                
                # 应用滤波器和窗函数
                filter_params = self.get_normalized_order_filter_params()
                # 根据传入的filter_type参数更新滤波设置
                if filter_type != "无滤波":
                    # 创建临时的滤波参数
                    temp_filter_params = filter_params.copy()
                    temp_filter_params['filter_type'] = filter_type
                    
                    # 应用窗函数
                    avg_data = self.apply_window_function(avg_data, temp_filter_params['window_type'])
                    # 应用滤波器
                    avg_data = self.apply_filter_to_data(avg_data, temp_filter_params)
                
                # 进行FFT分析获取阶次谱
                fft_result = np.fft.fft(avg_data)
                fft_magnitude = np.abs(fft_result)
                
                # 获取阶次数据
                orders = np.arange(1, min(max_orders + 1, len(fft_magnitude) // 2 + 1))
                amplitudes = fft_magnitude[1:len(orders) + 1]  # 跳过DC分量
                
                # 归一化处理
                if normalize_method == "最大值归一化":
                    if np.max(amplitudes) > 0:
                        normalized_amplitudes = amplitudes / np.max(amplitudes)
                    else:
                        normalized_amplitudes = amplitudes
                elif normalize_method == "标准差归一化":
                    if np.std(amplitudes) > 0:
                        normalized_amplitudes = (amplitudes - np.mean(amplitudes)) / np.std(amplitudes)
                    else:
                        normalized_amplitudes = amplitudes
                elif normalize_method == "范围归一化":
                    amp_range = np.max(amplitudes) - np.min(amplitudes)
                    if amp_range > 0:
                        normalized_amplitudes = (amplitudes - np.min(amplitudes)) / amp_range
                    else:
                        normalized_amplitudes = amplitudes
                else:
                    normalized_amplitudes = amplitudes
                
                # 绘制归一化阶次分析图
                bars = ax.bar(orders, normalized_amplitudes, width=0.8, alpha=0.7, 
                             color='lightcoral', edgecolor='darkred', linewidth=0.5)
                
                # 标记主要阶次（振幅大于平均值的阶次）
                mean_amplitude = np.mean(normalized_amplitudes)
                dominant_indices = [i for i, amp in enumerate(normalized_amplitudes) if amp > mean_amplitude * 1.5]
                
                # 高亮显示主要阶次
                for i in dominant_indices:
                    if i < len(bars):
                        bars[i].set_color('darkred')
                        bars[i].set_alpha(0.9)
                        # 添加标注
                        ax.annotate(f'{normalized_amplitudes[i]:.3f}', 
                                  xy=(orders[i], normalized_amplitudes[i]), 
                                  xytext=(0, 10), textcoords='offset points',
                                  ha='center', va='bottom', fontsize=8,
                                  bbox=dict(boxstyle='round,pad=0.3', facecolor='lightyellow', alpha=0.8))

                ax.set_title(f"{title_prefix}归一化阶次分析 - {side_name}（{normalize_method}）")
                ax.set_xlabel("阶次")
                ax.set_ylabel(ylabel)
                ax.grid(True, alpha=0.3)
                
                # 设置x轴刻度
                if max_orders <= 50:
                    ax.set_xticks(orders[::5])
                elif max_orders <= 100:
                    ax.set_xticks(orders[::10])
                else:
                    ax.set_xticks(orders[::20])
                
                # 添加统计信息
                total_ripple = np.sum(normalized_amplitudes)
                peak_amplitude = np.max(normalized_amplitudes)
                dominant_count = len(dominant_indices)
                
                info_text = f"归一化方式: {normalize_method}\n总波纹度: {total_ripple:.3f}\n峰值振幅: {peak_amplitude:.3f}\n主要阶次数: {dominant_count}"
                ax.text(0.02, 0.98, info_text, transform=ax.transAxes, 
                       verticalalignment='top', fontsize=10,
                       bbox=dict(boxstyle='round,pad=0.5', facecolor='lightcoral', alpha=0.8))

            fig.tight_layout()
            canvas.draw()

        except Exception as e:
            logger.error(f"更新归一化阶次分析失败: {str(e)}")

