    def _update_pitch_order_analysis(self, canvas, side, order_range, normalize_method, filter_type="无滤波"):
        """更新周节阶次分析图表"""
        try:
            fig = canvas.figure
            fig.clear()

            if not self.pitch_data:
                ax = fig.add_subplot(111)
                ax.text(0.5, 0.5, "没有可用的周节数据", ha='center', va='center', transform=ax.transAxes)
                canvas.draw()
                return

            # 确定要显示的齿面
            sides_to_show = []
            if side == "左齿面":
                sides_to_show = [('left', '左齿面')]
            elif side == "右齿面":
                sides_to_show = [('right', '右齿面')]
            else:  # 全部
                sides_to_show = [('left', '左齿面'), ('right', '右齿面')]

            # 解析阶次范围
            max_orders = int(order_range.split('-')[1])

            # 创建子图
            num_sides = len(sides_to_show)
            if num_sides == 1:
                ax = fig.add_subplot(111)
                axes = [ax]
            else:
                axes = []
                for i in range(num_sides):
                    ax = fig.add_subplot(1, 2, i+1)
                    axes.append(ax)

            for idx, (side_key, side_name) in enumerate(sides_to_show):
                ax = axes[idx]
                
                if side_key not in self.pitch_data:
                    ax.text(0.5, 0.5, f"没有{side_name}周节数据", ha='center', va='center', transform=ax.transAxes)
                    continue

                side_data = self.pitch_data[side_key]
                
                # 收集所有齿的周节数据
                all_pitch_data = []
                fp_values = []  # 专门收集fp值用于阶次分析
                
                for tooth_id, tooth_data in side_data.items():
                    # 处理不同的数据格式
                    if isinstance(tooth_data, (list, np.ndarray)) and len(tooth_data) > 0:
                        all_pitch_data.append(tooth_data)
                        if len(tooth_data) == 1:
                            fp_values.append(tooth_data[0])
                    elif isinstance(tooth_data, dict):
                        # 如果是字典格式，提取数值数据
                        if 'fp' in tooth_data:
                            fp_values.append(tooth_data['fp'])
                            all_pitch_data.append([tooth_data['fp']])
                        elif 'Fp' in tooth_data:
                            all_pitch_data.append([tooth_data['Fp']])
                        elif 'Fr' in tooth_data:
                            all_pitch_data.append([tooth_data['Fr']])
                        elif 'phi' in tooth_data:
                            all_pitch_data.append([tooth_data['phi']])
                        else:
                            # 尝试提取所有数值
                            values = [v for v in tooth_data.values() if isinstance(v, (int, float))]
                            if values:
                                all_pitch_data.append(values)
                                if len(values) == 1:
                                    fp_values.append(values[0])
                
                # 如果收集到了fp值，使用fp值进行阶次分析
                if fp_values:
                    logger.info(f"{side_name}收集到 {len(fp_values)} 个fp值: {fp_values[:5]}...")  # 只显示前5个
                    # 将fp值转换为numpy数组用于FFT分析
                    avg_pitch_data = np.array(fp_values)
                elif all_pitch_data:
                    # 使用原来的方法
                    avg_pitch_data = np.mean(all_pitch_data, axis=0)
                else:
                    ax.text(0.5, 0.5, f"没有{side_name}有效周节数据", ha='center', va='center', transform=ax.transAxes)
                    continue
                
                # 如果数据点太少，进行插值扩展
                if len(avg_pitch_data) < 10:
                    # 使用线性插值扩展数据点
                    original_length = len(avg_pitch_data)
                    target_length = max(50, len(all_pitch_data) * 10)  # 至少50个点
                    
                    if original_length == 1:
                        # 如果只有一个点，创建重复数据
                        avg_pitch_data = np.full(target_length, avg_pitch_data[0])
                    else:
                        # 线性插值扩展
                        x_original = np.linspace(0, 1, original_length)
                        x_new = np.linspace(0, 1, target_length)
                        avg_pitch_data = np.interp(x_new, x_original, avg_pitch_data)
                
                # 应用滤波器和窗函数
                filter_params = self.get_pitch_order_filter_params()
                # 根据传入的filter_type参数更新滤波设置
                if filter_type != "无滤波":
                    # 创建临时的滤波参数
                    temp_filter_params = filter_params.copy()
                    temp_filter_params['filter_type'] = filter_type
                    
                    # 应用窗函数
                    avg_pitch_data = self.apply_window_function(avg_pitch_data, temp_filter_params['window_type'])
                    # 应用滤波器
                    avg_pitch_data = self.apply_filter_to_data(avg_pitch_data, temp_filter_params)
                
                # 进行FFT分析获取阶次谱
                fft_result = np.fft.fft(avg_pitch_data)
                fft_magnitude = np.abs(fft_result)
                
                # 获取阶次数据
                orders = np.arange(1, min(max_orders + 1, len(fft_magnitude) // 2 + 1))
                amplitudes = fft_magnitude[1:len(orders) + 1]  # 跳过DC分量
                
                # 归一化处理
                if normalize_method == "最大值归一化":
                    if np.max(amplitudes) > 0:
                        normalized_amplitudes = amplitudes / np.max(amplitudes)
                    else:
                        normalized_amplitudes = amplitudes
                elif normalize_method == "标准差归一化":
                    if np.std(amplitudes) > 0:
                        normalized_amplitudes = (amplitudes - np.mean(amplitudes)) / np.std(amplitudes)
                    else:
                        normalized_amplitudes = amplitudes
                elif normalize_method == "范围归一化":
                    amp_range = np.max(amplitudes) - np.min(amplitudes)
                    if amp_range > 0:
                        normalized_amplitudes = (amplitudes - np.min(amplitudes)) / amp_range
                    else:
                        normalized_amplitudes = amplitudes
                else:  # 原始数据
                    normalized_amplitudes = amplitudes
                
                # 绘制周节阶次分析图
                if normalize_method == "原始数据":
                    color = 'steelblue'
                    edge_color = 'navy'
                    ylabel = "原始振幅"
                else:
                    color = 'lightgreen'
                    edge_color = 'darkgreen'
                    ylabel = "归一化振幅"
                
                bars = ax.bar(orders, normalized_amplitudes, width=0.8, alpha=0.7, 
                             color=color, edgecolor=edge_color, linewidth=0.5)
                
                # 标记主要阶次（振幅大于平均值的阶次）
                mean_amplitude = np.mean(normalized_amplitudes)
                dominant_indices = [i for i, amp in enumerate(normalized_amplitudes) if amp > mean_amplitude * 1.5]
                
                # 高亮显示主要阶次
                for i in dominant_indices:
                    if i < len(bars):
                        bars[i].set_color('darkgreen')
                        bars[i].set_alpha(0.9)
                        # 添加标注
                        ax.annotate(f'{normalized_amplitudes[i]:.3f}', 
                                  xy=(orders[i], normalized_amplitudes[i]), 
                                  xytext=(0, 10), textcoords='offset points',
                                  ha='center', va='bottom', fontsize=8,
                                  bbox=dict(boxstyle='round,pad=0.3', facecolor='lightyellow', alpha=0.8))

                ax.set_title(f"周节阶次分析 - {side_name}（{normalize_method}）")
                ax.set_xlabel("阶次")
                ax.set_ylabel(ylabel)
                ax.grid(True, alpha=0.3)
                
                # 设置x轴刻度
                if max_orders <= 50:
                    ax.set_xticks(orders[::5])
                elif max_orders <= 100:
                    ax.set_xticks(orders[::10])
                else:
                    ax.set_xticks(orders[::20])
                
                # 添加统计信息
                total_ripple = np.sum(normalized_amplitudes)
                peak_amplitude = np.max(normalized_amplitudes)
                dominant_count = len(dominant_indices)
                
                info_text = f"归一化方式: {normalize_method}\n总波纹度: {total_ripple:.3f}\n峰值振幅: {peak_amplitude:.3f}\n主要阶次数: {dominant_count}"
                ax.text(0.02, 0.98, info_text, transform=ax.transAxes, 
                       verticalalignment='top', fontsize=10,
                       bbox=dict(boxstyle='round,pad=0.5', facecolor='lightgreen', alpha=0.8))

            fig.tight_layout()
            canvas.draw()

        except Exception as e:
            logger.error(f"更新周节阶次分析失败: {str(e)}")

    def create_rotation_angle_undulation_analysis(self):
        """创建旋转角范围内的波纹度分析"""
        try:
            # 添加详细的调试信息
            logger.info("=== 旋转角波纹度分析调试信息 ===")
            logger.info(f"profile_data检查: {hasattr(self, 'profile_data')}")
            if hasattr(self, 'profile_data'):
                logger.info(f"profile_data内容: {self.profile_data}")
                if isinstance(self.profile_data, dict):
                    logger.info(f"profile_data键: {list(self.profile_data.keys())}")
                    if 'left' in self.profile_data:
                        logger.info(f"左齿面profile数据: {len(self.profile_data['left'])} 个齿")
                        if self.profile_data['left']:
                            logger.info(f"左齿面示例数据: {list(self.profile_data['left'].items())[:2]}")
                    if 'right' in self.profile_data:
                        logger.info(f"右齿面profile数据: {len(self.profile_data['right'])} 个齿")
                        if self.profile_data['right']:
                            logger.info(f"右齿面示例数据: {list(self.profile_data['right'].items())[:2]}")
            
            logger.info(f"flank_data检查: {hasattr(self, 'flank_data')}")
            if hasattr(self, 'flank_data'):
                logger.info(f"flank_data内容: {self.flank_data}")
                if isinstance(self.flank_data, dict):
                    logger.info(f"flank_data键: {list(self.flank_data.keys())}")
                    if 'left' in self.flank_data:
                        logger.info(f"左齿面flank数据: {len(self.flank_data['left'])} 个齿")
                        if self.flank_data['left']:
                            logger.info(f"左齿面示例数据: {list(self.flank_data['left'].items())[:2]}")
                    if 'right' in self.flank_data:
                        logger.info(f"右齿面flank数据: {len(self.flank_data['right'])} 个齿")
                        if self.flank_data['right']:
                            logger.info(f"右齿面示例数据: {list(self.flank_data['right'].items())[:2]}")
            
            # 检查是否有数据
            has_profile_data = hasattr(self, 'profile_data') and self.profile_data
            has_flank_data = hasattr(self, 'flank_data') and self.flank_data
            
            if not has_profile_data and not has_flank_data:
                logger.warning("没有可用的数据来进行旋转角波纹度分析")
                QMessageBox.warning(self, "警告", "没有可用的齿形或齿向数据来进行旋转角波纹度分析\n请先加载包含测量数据的MKA文件")
                return
            
            # 创建对话框
            dialog = QDialog(self)
            dialog.setWindowTitle("旋转角范围内的波纹度分析")
            dialog.setModal(True)
            dialog.resize(800, 600)
            
            layout = QVBoxLayout(dialog)
            
            # 参数设置区域
            param_group = QGroupBox("分析参数")
            param_layout = QFormLayout(param_group)
            
            # 数据类型选择
            data_type_combo = QComboBox()
            data_type_combo.addItems(["齿形数据", "齿向数据"])
            param_layout.addRow("数据类型:", data_type_combo)
            
            # 齿面选择
            side_combo = QComboBox()
            side_combo.addItems(["左齿面", "右齿面"])
            param_layout.addRow("齿面:", side_combo)
            
            # 主导阶次选择
            order_spin = QSpinBox()
            order_spin.setRange(1, 20)
            order_spin.setValue(1)
            order_spin.setToolTip("选择主导阶次，默认为1阶")
            param_layout.addRow("主导阶次:", order_spin)
            
            # 分析按钮
            analyze_btn = QPushButton("开始分析")
            param_layout.addRow("", analyze_btn)
            
            layout.addWidget(param_group)
            
            # 图表显示区域
            chart_group = QGroupBox("分析结果")
            chart_layout = QVBoxLayout(chart_group)
            
            # 创建matplotlib画布
            from matplotlib.backends.backend_qt5agg import FigureCanvasQTAgg as FigureCanvas
            from matplotlib.figure import Figure
            import matplotlib.pyplot as plt
            
            fig = Figure(figsize=(12, 8))
            canvas = CustomFigureCanvas(fig)
            chart_layout.addWidget(canvas)
            
            layout.addWidget(chart_group)
            
            def perform_analysis():
                """执行旋转角波纹度分析"""
                try:
                    data_type = data_type_combo.currentText()
                    side = side_combo.currentText()
                    dominant_order = order_spin.value()
                    
                    # 获取数据
                    if data_type == "齿形数据":
                        if side == "左齿面":
                            data = self.profile_data.get('left', {})
                        else:
                            data = self.profile_data.get('right', {})
                    else:
                        if side == "左齿面":
                            data = self.flank_data.get('left', {})
                        else:
                            data = self.flank_data.get('right', {})
                    
                    if not data:
                        QMessageBox.warning(dialog, "警告", f"没有找到{side}的{data_type}")
                        return
                    
                    # 清空图表
                    fig.clear()
                    
                    # 创建四个子图
                    gs = fig.add_gridspec(2, 2, hspace=0.3, wspace=0.3)
                    
                    # 分析四个组合
                    combinations = [
                        ("右侧齿廓和齿距", "right", "profile"),
                        ("左侧齿廓和齿距", "left", "profile"),
                        ("右侧齿向和齿距", "right", "flank"),
                        ("左侧齿向和齿距", "left", "flank")
                    ]
                    
                    for i, (title, side_key, data_type_key) in enumerate(combinations):
                        ax = fig.add_subplot(gs[i//2, i%2])
                        
                        # 获取数据
                        if data_type_key == "profile":
                            current_data = self.profile_data.get(side_key, {})
                        else:
                            current_data = self.flank_data.get(side_key, {})
                        
                        if not current_data:
                            ax.text(0.5, 0.5, f"无{title}数据", 
                                   ha='center', va='center', transform=ax.transAxes)
                            ax.set_title(f"{title}\n(无数据)")
                            continue
                        
                        # 计算旋转角范围内的波纹度
                        undulation_data = self.calculate_rotation_angle_undulation(
                            current_data, dominant_order, data_type_key
                        )
                        
                        if undulation_data is None:
                            ax.text(0.5, 0.5, f"计算失败", 
                                   ha='center', va='center', transform=ax.transAxes)
                            ax.set_title(f"{title}\n(计算失败)")
                            continue
                        
                        # 绘制图表
                        orders = undulation_data['orders']
                        amplitudes = undulation_data['amplitudes']
                        
                        ax.plot(orders, amplitudes, 'r-', linewidth=1, alpha=0.8, label='实际数据')
                        ax.plot(orders, undulation_data['smoothed'], 'b-', linewidth=2, label='平滑曲线')
                        
                        # 标记主导阶次
                        if dominant_order <= len(orders):
                            ax.axvline(x=dominant_order, color='g', linestyle='--', alpha=0.7, label=f'主导阶次{dominant_order}')
                        
                        ax.set_xlabel('阶次')
                        ax.set_ylabel('幅值')
                        ax.set_title(f"{title}\nA1: {undulation_data['A1']:.2f}, O: {undulation_data['O']}, Pw: {undulation_data['Pw']:.1f}")
                        ax.grid(True, alpha=0.3)
                        ax.legend()
                    
                    canvas.draw()
                    
                except Exception as e:
                    logger.error(f"旋转角波纹度分析失败: {str(e)}")
                    QMessageBox.critical(dialog, "错误", f"分析失败: {str(e)}")
            
            analyze_btn.clicked.connect(perform_analysis)
            
            # 显示对话框
            dialog.exec_()
            
        except Exception as e:
            logger.error(f"创建旋转角波纹度分析对话框失败: {str(e)}")
            QMessageBox.critical(self, "错误", f"创建分析对话框失败: {str(e)}")

    def calculate_rotation_angle_undulation(self, data, dominant_order, data_type):
        """计算旋转角范围内的波纹度
        
        使用渐开线极角计算方法，将多齿数据按极角排列组成0-360度曲线。
        
        算法说明:
        1. 获取齿轮参数（模数、齿数、压力角等）
        2. 计算基圆半径: rb = m * z * cos(α) / 2
        3. 计算节距角: pitch_angle = 360° / z
        4. 对每个齿:
           - 根据渐开线理论计算每个测量点的极角
           - 将齿序号*节距角与测量点极角组合
        5. 合并所有齿的数据，按角度排序
        6. 进行FFT频谱分析
        """
        try:
            logger.info(f"开始计算旋转角波纹度 - 数据类型: {data_type}, 主导阶次: {dominant_order}")
            logger.info(f"输入数据检查: {type(data)}, 长度: {len(data) if data else 0}")
            
            if not data:
                logger.warning("输入数据为空")
                return None
            
            module = self.gear_data.get('模数', 0.0) if hasattr(self, 'gear_data') and self.gear_data else 0.0
            teeth_count = self.gear_data.get('齿数', 0) if hasattr(self, 'gear_data') and self.gear_data else 0
            pressure_angle = self.gear_data.get('压力角', 20.0) if hasattr(self, 'gear_data') and self.gear_data else 20.0
            base_diameter = self.gear_data.get('基圆直径', 0.0) if hasattr(self, 'gear_data') and self.gear_data else 0.0
            
            if module <= 0 or teeth_count <= 0:
                logger.warning(f"齿轮参数无效: 模数={module}, 齿数={teeth_count}")
                return None
            
            logger.info(f"齿轮参数: 模数={module}, 齿数={teeth_count}, 压力角={pressure_angle}°, 基圆直径={base_diameter}")
            
            pitch_radius = module * teeth_count / 2.0
            if base_diameter > 0:
                base_radius = base_diameter / 2.0
            else:
                base_radius = pitch_radius * np.cos(np.radians(pressure_angle))
            
            pitch_angle_deg = 360.0 / teeth_count
            
            logger.info(f"计算参数: 分度圆半径={pitch_radius:.3f}mm, 基圆半径={base_radius:.3f}mm, 节距角={pitch_angle_deg:.2f}°")
            
            eval_start_spread = None
            if data_type == 'profile':
                eval_start_spread = self.gear_data.get('齿形起评点展长', {}).get('left', 0.0) if hasattr(self, 'gear_data') else None
            
            all_angles = []
            all_values = []
            all_tooth_indices = []
            
            logger.info(f"开始处理{len(data)}个齿的数据...")
            for tooth_id, tooth_data in data.items():
                logger.info(f"处理齿{tooth_id}: 类型={type(tooth_data)}, 长度={len(tooth_data) if hasattr(tooth_data, '__len__') else 'N/A'}")
                
                if isinstance(tooth_data, (list, np.ndarray)) and len(tooth_data) > 0:
                    tooth_values = np.array(tooth_data)
                    num_points = len(tooth_values)
                    
                    tooth_index = int(tooth_id) - 1 if isinstance(tooth_id, (int, str)) and str(tooth_id).isdigit() else 0
                    if tooth_index < 0:
                        tooth_index = 0
                    if tooth_index >= teeth_count:
                        tooth_index = teeth_count - 1
                    
                    tooth_base_angle = tooth_index * pitch_angle_deg
                    
                    if data_type == 'profile':
                        spread_lengths = np.linspace(0, module * 2.0, num_points)
                        radii = np.sqrt(spread_lengths ** 2 + base_radius ** 2)
                    else:
                        radii = np.linspace(base_radius * 1.05, pitch_radius * 1.15, num_points)
                    
                    point_polar_angles = calculate_involute_polar_angle_array(radii, base_radius)
                    
                    if eval_start_spread and eval_start_spread > 0:
                        start_radius = np.sqrt(eval_start_spread ** 2 + base_radius ** 2)
                        start_polar_angle = calculate_involute_polar_angle(start_radius, base_radius)
                    else:
                        start_idx = int(num_points * 0.2)
                        start_polar_angle = point_polar_angles[start_idx] if start_idx < num_points else 0
                    
                    point_polar_angles_deg = np.degrees(point_polar_angles - start_polar_angle)
                    
                    final_angles = tooth_base_angle + point_polar_angles_deg
                    
                    all_angles.extend(final_angles.tolist())
                    all_values.extend(tooth_values.tolist())
                    all_tooth_indices.extend([tooth_id] * num_points)
                    
                    logger.info(f"✅ 齿{tooth_id}数据有效，角度范围: {min(final_angles):.2f}° - {max(final_angles):.2f}°")
                else:
                    logger.warning(f"❌ 齿{tooth_id}数据无效: {tooth_data}")
            
            logger.info(f"收集到{len(all_angles)}个数据点")
            
            if not all_angles:
                logger.warning("没有收集到有效的数据点")
                return None
            
            all_angles = np.array(all_angles)
            all_values = np.array(all_values)
            
            all_angles = all_angles % 360.0
            all_angles[all_angles < 0] += 360.0
            
            sort_indices = np.argsort(all_angles)
            all_angles = all_angles[sort_indices]
            all_values = all_values[sort_indices]
            
            logger.info(f"排序后角度范围: {all_angles[0]:.2f}° - {all_angles[-1]:.2f}°")
            
            unique_angles, unique_indices = np.unique(np.round(all_angles, 3), return_index=True)
            unique_values = all_values[unique_indices]
            
            logger.info(f"去重后数据点数: {len(unique_angles)}")
            
            num_interp_points = 360
            interp_angles = np.linspace(0, 360, num_interp_points)
            interp_values = np.interp(interp_angles, unique_angles, unique_values, period=360)
            
            logger.info(f"插值后数据点数: {len(interp_values)}")
            
            logger.info("开始FFT分析...")
            fft_result = np.fft.fft(interp_values)
            fft_magnitude = np.abs(fft_result)
            logger.info(f"FFT分析完成，结果长度: {len(fft_magnitude)}")
            
            half_length = len(fft_magnitude) // 2
            orders = np.arange(1, half_length + 1)
            amplitudes = fft_magnitude[1:half_length + 1]
            logger.info(f"阶次分析完成，阶次范围: 1-{len(orders)}")
            
            logger.info("开始平滑处理...")
            from scipy.signal import savgol_filter
            window_length = min(5, len(amplitudes)//4*2+1)
            if window_length < 3:
                window_length = 3
            smoothed = savgol_filter(amplitudes, window_length, 2)
            logger.info(f"平滑处理完成，窗口长度: {window_length}")
            
            A1 = amplitudes[dominant_order-1] if dominant_order <= len(amplitudes) else 0
            O = dominant_order
            Pw = np.max(amplitudes) - np.min(amplitudes)
            logger.info(f"关键参数计算完成: A1={A1:.4f}, O={O}, Pw={Pw:.4f}")
            
            return {
                'orders': orders,
                'amplitudes': amplitudes,
                'smoothed': smoothed,
                'A1': A1,
                'O': O,
                'Pw': Pw,
                'rotation_angles': np.radians(interp_angles),
                'avg_data': interp_values,
                'raw_angles': all_angles,
                'raw_values': all_values,
                'unique_angles': unique_angles,
                'unique_values': unique_values
            }
            
        except Exception as e:
            logger.error(f"计算旋转角波纹度失败: {str(e)}")
            import traceback
            logger.error(traceback.format_exc())
            return None

