    def open_ripple_spectrum_settings(self):
        """打开齿廓波纹频谱设置对话框"""
        from PyQt5.QtWidgets import QDialog, QVBoxLayout, QHBoxLayout, QGroupBox, QFormLayout, \
                                   QLineEdit, QSpinBox, QComboBox, QCheckBox, QDialogButtonBox, \
                                   QDoubleSpinBox, QLabel
        from PyQt5.QtCore import Qt
        
        # 创建对话框
        dialog = QDialog(self)
        dialog.setWindowTitle("齿廓波纹频谱设置")
        dialog.setGeometry(200, 200, 720, 600)
        dialog.setMinimumSize(600, 500)
        
        main_layout = QVBoxLayout(dialog)
        content_widget = QWidget()
        content_layout = QVBoxLayout(content_widget)
        content_layout.setContentsMargins(6, 6, 6, 6)
        content_layout.setSpacing(8)
        
        # --- 1. 齿廓和齿向设置 --- 
        profile_helix_group = QGroupBox("齿廓和齿向设置")
        profile_helix_layout = QFormLayout(profile_helix_group)
        
        # 评价方法
        eval_method_label = QLabel("评价方法")
        eval_method_combo = QComboBox()
        eval_method_combo.addItems(["高阶评价法", "全阶次评价法"])
        profile_helix_layout.addRow(eval_method_label, eval_method_combo)
        
        # 仅显示高阶分量
        high_orders_check = QCheckBox("仅显示与齿数相当或更高的阶次分量")
        high_orders_check.setChecked(True)
        profile_helix_layout.addRow(high_orders_check)

        # 频谱计算方式
        spectrum_method_label = QLabel("频谱计算方式")
        spectrum_method_combo = QComboBox()
        spectrum_method_combo.addItems(["逐齿FFT后平均(原版)", "先平均时域再FFT", "拼接后FFT"])
        # 默认选择（优先使用已有设置）
        current_settings = getattr(self, 'ripple_spectrum_settings', None)
        if current_settings:
            method = current_settings.profile_helix_settings.get('spectrum_method', 'per_tooth_avg')
            if method == 'concat':
                spectrum_method_combo.setCurrentIndex(2)
            elif method == 'time_average':
                spectrum_method_combo.setCurrentIndex(1)
            else:
                spectrum_method_combo.setCurrentIndex(0)
        profile_helix_layout.addRow(spectrum_method_label, spectrum_method_combo)

        # FFT幅值归一化
        fft_norm_check = QCheckBox("FFT幅值使用 2/n（单边谱）")
        fft_norm_check.setChecked(True)
        profile_helix_layout.addRow(fft_norm_check)
        
        # 滤波器参数
        filter_group = QGroupBox("RC低通滤波器参数")
        filter_layout = QFormLayout(filter_group)
        
        max_depth_label = QLabel("最大波深 (μm)")
        max_depth_spin = QDoubleSpinBox()
        max_depth_spin.setRange(0.1, 10.0)
        max_depth_spin.setSingleStep(0.1)
        max_depth_spin.setValue(2.0)
        filter_layout.addRow(max_depth_label, max_depth_spin)
        
        attenuation_ratio_label = QLabel("衰减比")
        attenuation_ratio_spin = QSpinBox()
        attenuation_ratio_spin.setRange(100, 10000)
        attenuation_ratio_spin.setSingleStep(100)
        attenuation_ratio_spin.setValue(5000)
        filter_layout.addRow(attenuation_ratio_label, attenuation_ratio_spin)

        attenuation_mode_label = QLabel("衰减比作用")
        attenuation_mode_combo = QComboBox()
        attenuation_mode_combo.addItems(["换算截止频率", "缩放RC时间常数", "直接作为alpha"])
        filter_layout.addRow(attenuation_mode_label, attenuation_mode_combo)
        
        profile_helix_layout.addRow(filter_group)
        
        content_layout.addWidget(profile_helix_group)
        
        # --- 2. 评价设置 --- 
        evaluation_group = QGroupBox("评价设置")
        evaluation_layout = QFormLayout(evaluation_group)
        
        # 阶次计算方式
        order_calc_label = QLabel("阶次计算方式")
        order_calc_combo = QComboBox()
        order_calc_combo.addItems(["基于齿数(ZE)", "自定义基准阶次"])
        evaluation_layout.addRow(order_calc_label, order_calc_combo)
        
        # 波形标准
        waveform_group = QGroupBox("波形标准")
        waveform_layout = QFormLayout(waveform_group)
        
        R_label = QLabel("R (允许波深)")
        R_spin = QDoubleSpinBox()
        R_spin.setRange(0.1, 10.0)
        R_spin.setSingleStep(0.1)
        R_spin.setValue(2.0)
        waveform_layout.addRow(R_label, R_spin)
        
        N0_label = QLabel("N0 (公差曲线常数)")
        N0_spin = QDoubleSpinBox()
        N0_spin.setRange(0.5, 5.0)
        N0_spin.setSingleStep(0.1)
        N0_spin.setValue(1.0)
        waveform_layout.addRow(N0_label, N0_spin)
        
        K_label = QLabel("K (修正值)")
        K_spin = QDoubleSpinBox()
        K_spin.setRange(-5.0, 5.0)
        K_spin.setSingleStep(0.1)
        K_spin.setValue(0.0)
        waveform_layout.addRow(K_label, K_spin)
        
        evaluation_layout.addRow(waveform_group)
        
        content_layout.addWidget(evaluation_group)
        
        # --- 3. 显示设置 --- 
        display_group = QGroupBox("显示设置")
        display_layout = QFormLayout(display_group)
        
        # 放大系数
        magnification_label = QLabel("放大系数")
        magnification_combo = QComboBox()
        magnification_combo.addItems(["自动缩放", "1x", "2x", "5x", "10x"])
        display_layout.addRow(magnification_label, magnification_combo)
        
        # 阶次分类
        ze_markers_check = QCheckBox("显示ZE, 2ZE, 3ZE等标记")
        ze_markers_check.setChecked(True)
        display_layout.addRow(ze_markers_check)
        
        content_layout.addWidget(display_group)

        # 使用当前设置初始化控件
        current_settings = getattr(self, 'ripple_spectrum_settings', None)
        if current_settings:
            ph = current_settings.profile_helix_settings
            ev = current_settings.evaluation_settings
            ds = current_settings.display_settings

            eval_method_combo.setCurrentIndex(0 if ph.get('evaluation_method', 'high_order') == 'high_order' else 1)
            high_orders_check.setChecked(ph.get('order_filtering', {}).get('only_high_orders', True))

            filter_params = ph.get('filter_params', {})
            if 'max_depth' in filter_params:
                max_depth_spin.setValue(float(filter_params.get('max_depth', 2.0)))
            if 'attenuation_ratio' in filter_params:
                attenuation_ratio_spin.setValue(int(filter_params.get('attenuation_ratio', 5000)))
            mode = filter_params.get('attenuation_mode', 'fc_from_ratio')
            if mode == 'scale_rc':
                attenuation_mode_combo.setCurrentIndex(1)
            elif mode == 'alpha_direct':
                attenuation_mode_combo.setCurrentIndex(2)
            else:
                attenuation_mode_combo.setCurrentIndex(0)
            fft_norm_check.setChecked(ph.get('fft_use_2_over_n', True))

            order_calc_combo.setCurrentIndex(0 if ev.get('order_calculation', {}).get('base_order', 'ze') == 'ze' else 1)

            waveform = ev.get('waveform_standard', {})
            if 'R' in waveform:
                R_spin.setValue(float(waveform.get('R', 2.0)))
            if 'N0' in waveform:
                N0_spin.setValue(float(waveform.get('N0', 1.0)))
            if 'K' in waveform:
                K_spin.setValue(float(waveform.get('K', 0.0)))

            magnification = ds.get('magnification', {})
            if magnification.get('auto_scale', True):
                magnification_combo.setCurrentIndex(0)
            else:
                factor = float(magnification.get('manual_factor', 1.0) or 1.0)
                factor_map = {1.0: 1, 2.0: 2, 5.0: 3, 10.0: 4}
                magnification_combo.setCurrentIndex(factor_map.get(factor, 1))

            ze_markers_check.setChecked(ds.get('order_classification', {}).get('show_ze_markers', True))
        
        # 使用滚动区域，避免窗口较小时内容被遮挡
        scroll_area = QScrollArea()
        scroll_area.setWidgetResizable(True)
        scroll_area.setWidget(content_widget)
        main_layout.addWidget(scroll_area)

        # 按钮
        button_box = QDialogButtonBox(QDialogButtonBox.Ok | QDialogButtonBox.Cancel)
        button_box.accepted.connect(dialog.accept)
        button_box.rejected.connect(dialog.reject)
        main_layout.addWidget(button_box)
        
        # 显示对话框
        if dialog.exec_() == QDialog.Accepted:
            # 创建设置对象
            settings = RippleSpectrumSettings()
            
            # 更新齿廓和齿向设置
            spectrum_method_map = {
                0: 'per_tooth_avg',
                1: 'time_average',
                2: 'concat'
            }
            settings.update_profile_helix_settings(
                evaluation_method='high_order' if eval_method_combo.currentIndex() == 0 else 'all_orders',
                spectrum_method=spectrum_method_map.get(spectrum_method_combo.currentIndex(), 'per_tooth_avg'),
                order_filtering={
                    'only_high_orders': high_orders_check.isChecked(),
                    'max_order': 500
                },
                filter_params={
                    'max_depth': max_depth_spin.value(),
                    'attenuation_ratio': attenuation_ratio_spin.value(),
                    'attenuation_mode': 'scale_rc' if attenuation_mode_combo.currentIndex() == 1 else (
                        'alpha_direct' if attenuation_mode_combo.currentIndex() == 2 else 'fc_from_ratio'
                    )
                },
                fft_use_2_over_n=fft_norm_check.isChecked()
            )
            
            # 更新评价设置
            settings.update_evaluation_settings(
                order_calculation={
                    'base_order': 'ze' if order_calc_combo.currentIndex() == 0 else 'custom'
                },
                waveform_standard={
                    'R': R_spin.value(),
                    'N0': N0_spin.value(),
                    'K': K_spin.value()
                }
            )
            
            # 更新显示设置
            settings.update_display_settings(
                magnification={
                    'auto_scale': magnification_combo.currentIndex() == 0,
                    'manual_factor': float(magnification_combo.currentText().replace('x', '')) if magnification_combo.currentIndex() != 0 else 1.0
                },
                order_classification={
                    'show_ze_markers': ze_markers_check.isChecked()
                }
            )
            
            # 保存设置到实例变量
            self.ripple_spectrum_settings = settings
            self.save_ripple_spectrum_settings()
            
            QMessageBox.information(self, "成功", "设置已保存！")
            # 自动重新生成PDF并刷新显示
            try:
                self.generate_klingelnberg_pdf_report(auto_generate=True)
                self.show_report_in_webview()
            except Exception as e:
                logger.warning(f"自动生成PDF失败: {e}")
    
