    def show_frequency_analysis(self):
        """显示频率分析结果"""
        if not hasattr(self, 'undulation_results') or not self.undulation_results or 'frequency' not in self.undulation_results:
            QMessageBox.warning(self, "警告", "没有可用的频率分析数据，请先进行波纹度分析")
            return

        # 清除图表
        self.freq_figure.clear()

        # 创建子图
        ax1 = self.freq_figure.add_subplot(211)
        ax2 = self.freq_figure.add_subplot(212)

        # 显示齿形频率分析
        if 'profile' in self.undulation_results['frequency']:
            self.plot_frequency_chart(ax1, ax2,
                                      self.undulation_results['frequency']['profile'],
                                      "齿形平均曲线频率分析")
        # 如果没有齿形数据，显示齿向数据
        elif 'flank' in self.undulation_results['frequency']:
            self.plot_frequency_chart(ax1, ax2,
                                      self.undulation_results['frequency']['flank'],
                                      "齿向平均曲线频率分析")

        # 更新图表
        self.freq_canvas.draw()

    def plot_frequency_chart(self, ax1, ax2, freq_data, title):
        """在指定轴上绘制频率分析图表"""
        try:
            # 绘制频谱图 (频率域)
            freqs = freq_data['frequencies']
            magnitudes = freq_data['magnitudes']
            top_freqs = freq_data['top_freqs']
            top_magnitudes = freq_data['top_magnitudes']

            ax1.clear()
            ax1.plot(freqs, magnitudes, 'b-', linewidth=1)
            ax1.plot(top_freqs, top_magnitudes, 'ro', markersize=8)

            # 标记前5个主要频率分量
            for i, (freq, mag) in enumerate(zip(top_freqs[:5], top_magnitudes[:5])):
                ax1.annotate(f'F{i + 1}\n{freq:.1f}Hz',
                             xy=(freq, mag),
                             xytext=(freq * 1.1, mag * 1.1),
                             fontsize=8,
                             arrowprops=dict(facecolor='red', shrink=0.05, width=1, headwidth=5))

            ax1.set_title(f"{title} - 频率域", fontsize=12)
            ax1.set_xlabel("频率 (Hz)")
            ax1.set_ylabel("幅度")
            ax1.grid(True, linestyle='--', alpha=0.3)

            # 绘制波长谱图 (空间域)
            wavelengths = freq_data['wavelengths']
            top_wavelengths = freq_data['top_wavelengths']

            # 只显示波长在合理范围内的点 (0.1mm - 100mm)
            import numpy as np
            valid_mask = (wavelengths > 0.1) & (wavelengths < 100)
            wavelengths_filtered = wavelengths[valid_mask]
            magnitudes_filtered = magnitudes[valid_mask]

            ax2.clear()
            ax2.plot(wavelengths_filtered, magnitudes_filtered, 'g-', linewidth=1)
            ax2.plot(top_wavelengths, top_magnitudes, 'ro', markersize=8)

            # 标记前5个主要波长分量
            for i, (wavelength, mag) in enumerate(zip(top_wavelengths[:5], top_magnitudes[:5])):
                if 0.1 <= wavelength <= 100:  # 只标记合理范围内的波长
                    ax2.annotate(f'W{i + 1}\n{wavelength:.2f}mm',
                                 xy=(wavelength, mag),
                                 xytext=(wavelength * 1.1, mag * 1.1),
                                 fontsize=8,
                                 arrowprops=dict(facecolor='red', shrink=0.05, width=1, headwidth=5))

            ax2.set_title(f"{title} - 空间域", fontsize=12)
            ax2.set_xlabel("波长 (mm)")
            ax2.set_ylabel("幅度")
            ax2.set_xscale('log')  # 对数坐标更适合显示不同尺度的波长
            ax2.grid(True, linestyle='--', alpha=0.3, which='both')

            # 使用更安全的布局方法
            try:
                self.freq_figure.tight_layout(pad=1.0)
            except Exception as e:
                logger.warning(f"频率图表tight_layout失败，使用手动调整: {e}")
                self.freq_figure.subplots_adjust(left=0.1, right=0.95, top=0.95, bottom=0.1, hspace=0.3)
            
        except Exception as e:
            print(f"绘制频率图表时出错: {e}")
            ax1.clear()
            ax2.clear()
            ax1.text(0.5, 0.5, f"数据显示错误:\n{str(e)}", 
                    transform=ax1.transAxes, ha='center', va='center')
            ax2.text(0.5, 0.5, "请检查数据格式", 
                    transform=ax2.transAxes, ha='center', va='center')

    def closeEvent(self, event):
        """关闭事件处理"""
        self._closing = True

        # 保存导航栏状态
        if hasattr(self, 'nav_dock') and self.nav_dock:
            self.save_nav_state()

        # 取消正在运行的线程
        if self.processing_thread and self.processing_thread.isRunning():
            self.processing_thread.cancel()
            self.processing_thread.wait(2000)

        if self.analysis_thread and self.analysis_thread.isRunning():
            self.analysis_thread.cancel()
            self.analysis_thread.wait(2000)

        if self.deviation_thread and self.deviation_thread.isRunning():
            self.deviation_thread.cancel()
            self.deviation_thread.wait(2000)

        event.accept()

