    def update_ripple_parameters_display(self):
        """更新波纹度参数显示区域"""
        if not self.ripple_results:
            self.ripple_results_display.setText("尚未进行Ripple分析")
            self.quality_assessment_label.setText("质量评价：未分析")
            self.quality_assessment_label.setStyleSheet("""
                QLabel {
                    font-size: 12px;
                    font-weight: bold;
                    color: #7f8c8d;
                    background-color: #ecf0f1;
                    padding: 6px;
                    border-radius: 4px;
                    border: 1px solid #bdc3c7;
                    text-align: center;
                }
            """)
            return

        # 从分析结果中提取数据
        stats = self.ripple_results.get('stats', {})
        
        # 构建详细的分析结果文本
        result_text = "<b>齿面波纹度参数分析结果：</b><br><br>"
        
        # 齿形分析结果
        profile_stats = stats.get('profile', {})
        result_text += "<b>齿形波纹度：</b><br>"
        
        if profile_stats.get('left_analyzed') or profile_stats.get('right_analyzed'):
            if profile_stats.get('left_analyzed'):
                # 获取左侧数据，优先从ripple_results中获取详细数据
                left_wt = profile_stats.get('left_ripple', 0)
                left_wq = profile_stats.get('left_rms', 0)
                left_wa = profile_stats.get('left_wa', 0)
                
                # 如果stats中没有详细数据，尝试从原始结果中获取
                if left_wt == 0 and hasattr(self, 'ripple_results') and self.ripple_results:
                    profile_results = self.ripple_results.get('profile', {})
                    left_avg = profile_results.get('Left_Average', {})
