    def evaluate_ripple_quality(self):
        """基于Wt、Wq、Wa数值评价齿面质量"""
        if not self.ripple_results:
            return 'unknown'
            
        # 收集所有可用的参数值
        wt_values = []
        wq_values = []
        wa_values = []
        
        # 从profile数据获取
        profile_results = self.ripple_results.get('profile', {})
        for side in ['Left_Average', 'Right_Average']:
            if side in profile_results:
                data = profile_results[side]
                wt_values.append(data.get('ripple_value', 0))
                wq_values.append(data.get('rms_value', 0))
                wa_values.append(data.get('wa_value', 0))
        
        # 从flank数据获取
        flank_results = self.ripple_results.get('flank', {})
        for side in ['Left_Average', 'Right_Average']:
            if side in flank_results:
                data = flank_results[side]
                wt_values.append(data.get('ripple_value', 0))
                wq_values.append(data.get('rms_value', 0))
                wa_values.append(data.get('wa_value', 0))
        
        if not wt_values:
            return 'unknown'
        
        # 计算最大值进行评价
        max_wt = max(wt_values)
        max_wq = max(wq_values)
        max_wa = max(wa_values)
        
        # 质量评价标准
        if max_wt <= 10 and max_wq <= 3 and max_wa <= 2:
            return 'excellent'
        elif max_wt <= 20 and max_wq <= 6 and max_wa <= 4:
            return 'good'
        elif max_wt <= 30 and max_wq <= 9 and max_wa <= 6:
            return 'acceptable'
        else:
            return 'poor'
    
