            self.gear_data['accuracy_grade'] = new_grade
            self.gear_data['精度等级'] = new_grade

            # 重新计算公差值
            self.recalculate_tolerances_with_new_grade(new_grade)

            # 清空分析结果，提示重新分析
            self.clear_analysis_results()
            QMessageBox.information(self, "精度等级已更新", 
                                  f"精度等级已更新为 {new_grade} 级。\n"
                                  "请重新进行偏差分析以应用新的公差设置。")
            
            # 刷新表格显示
            self.refresh_deviation_table()
    
