    def get_evaluation_range_indices(self, data_type, side_key, data_length=None):
        """获取评价范围的索引"""
        try:
            if data_type == "齿形数据":
                # 齿形评价范围
                start_measure = self.gear_data.get('齿形起测点展长', {}).get(side_key, 0.0)
                end_measure = self.gear_data.get('齿形终测点展长', {}).get(side_key, 0.0)
                start_eval = self.gear_data.get('齿形起评点展长', {}).get(side_key, start_measure)
                end_eval = self.gear_data.get('齿形终评点展长', {}).get(side_key, end_measure)
            else:
                # 齿向评价范围
                start_measure = self.gear_data.get('齿向起测点', {}).get(side_key, 0.0)
                end_measure = self.gear_data.get('齿向终测点', {}).get(side_key, 0.0)
                start_eval = self.gear_data.get('齿向起评点', {}).get(side_key, start_measure)
                end_eval = self.gear_data.get('齿向终评点', {}).get(side_key, end_measure)
            
            # 确保范围有效
            if end_measure <= start_measure:
                end_measure = start_measure + 20.0  # 默认20mm范围
            if end_eval <= start_eval:
                end_eval = start_eval + (end_measure - start_measure) * 0.8  # 80%范围
            
            # 计算评价范围在数据中的索引位置
            total_range = end_measure - start_measure
            if total_range <= 0:
                total_range = 20.0  # 默认20mm
            
            # 使用实际数据长度或默认值
            if data_length is None:
                data_length = 1000  # 默认数据长度
            
            start_idx = max(0, int((start_eval - start_measure) / total_range * data_length))
            end_idx = min(data_length - 1, int((end_eval - start_measure) / total_range * data_length))
            
            # 确保索引有效
            if end_idx <= start_idx:
                start_idx = 0
                end_idx = data_length - 1
            
            return start_idx, end_idx
            
        except Exception as e:
            logger.error(f"获取评价范围索引失败: {str(e)}")
            return 0, data_length - 1 if data_length else 999  # 返回全范围

