    def init_diagnosis_table(self):
        """初始化诊断表格，显示示例内容"""
        # 添加示例诊断数据
        example_data = [
            ("1×齿轮频率", "---", "不平衡、偏心"),
            ("2×齿轮频率", "---", "热变形、装配误差"),
            ("齿数×频率", "---", "齿轮啮合误差"),
            ("高阶谐波", "---", "加工质量问题"),
        ]
        
        self.diagnosis_table.setRowCount(len(example_data))
        
        for row, (order, magnitude, cause) in enumerate(example_data):
            # 阶次
            order_item = QTableWidgetItem(order)
            order_item.setFlags(order_item.flags() & ~Qt.ItemIsEditable)
            order_item.setForeground(Qt.gray)
            self.diagnosis_table.setItem(row, 0, order_item)
            
            # 幅值
            mag_item = QTableWidgetItem(magnitude)
            mag_item.setFlags(mag_item.flags() & ~Qt.ItemIsEditable)
            mag_item.setForeground(Qt.gray)
            self.diagnosis_table.setItem(row, 1, mag_item)
            
            # 可能原因
            cause_item = QTableWidgetItem(cause)
            cause_item.setFlags(cause_item.flags() & ~Qt.ItemIsEditable)
            cause_item.setForeground(Qt.gray)
            self.diagnosis_table.setItem(row, 2, cause_item)

    def start_ripple_analysis(self, force_reanalysis=False):
        """开始Ripple分析"""
        # 确保UI已初始化（简化界面后ripple_figure可能为None，不影响分析）
        if not hasattr(self, 'ripple_figure') or self.ripple_figure is None:
            if hasattr(self, '_page_config') and 'ripple' in self._page_config and not self._page_config['ripple']['loaded']:
                self._load_page('ripple')

        if (not self.profile_data and not self.flank_data) or not self.gear_data:
            QMessageBox.warning(self, "警告", "没有可用的齿形、齿向或基本数据")
            return
            
        # 如果不是强制重分析，且已有结果，则不重复分析
        if self.ripple_results and not force_reanalysis:
            self.display_ripple_results()
            return

        # 使用默认设置或上次的设置
        if not hasattr(self, 'ripple_settings'):
            self.ripple_settings = {
                'cutoff_wavelength': 0.8,  # 截止波长 (mm)
                'highpass_cutoff': 0.01,  # 高通截止频率 (周期/mm)
                'lowpass_cutoff': 1.0,    # 低通截止频率 (周期/mm)
                'filter_order': 4,        # 滤波器阶数
                'min_order': 1,           # 最小阶次
                'max_order': 100,         # 最大阶次
                'threshold': 0.005        # 阈值 (0.5%)
            }

        # 禁用按钮
        if hasattr(self, 'analyze_ripple_btn'):
            self.analyze_ripple_btn.setEnabled(False)
        if hasattr(self, 'export_ripple_btn'):
            self.export_ripple_btn.setEnabled(False)

        # 显示进度条
        self.progress_bar.setVisible(True)
        self.progress_label.setVisible(True)
        self.progress_label.setText("正在分析Ripple...")

        # 使用处理后的数据进行分析
        profile_data_to_use = getattr(self, 'processed_profile_data', self.profile_data)
        flank_data_to_use = getattr(self, 'processed_flank_data', self.flank_data)
        
        logger.info(f"使用处理后的数据进行波纹度分析: 齿形数据{len(profile_data_to_use.get('left', {}))}个齿, 齿向数据{len(flank_data_to_use.get('left', {}))}个齿")

        # 启动分析线程
        self.ripple_thread = RippleAnalysisThread(
        profile_data_to_use, flank_data_to_use, self.gear_data, self.ripple_settings, self
        )
        self.ripple_thread.finished.connect(self.on_ripple_analysis_complete)
        self.ripple_thread.progress.connect(self.on_progress_update)
        self.ripple_thread.error.connect(self.on_ripple_analysis_error)
        self.ripple_thread.start()

    def show_ripple_settings(self):
        """显示Ripple分析设置对话框"""
        dialog = RippleAnalysisDialog(self)
        if dialog.exec_() == QDialog.Accepted:
            settings = dialog.get_settings()
            if settings:
                self.ripple_settings = settings
                logger.info(f"更新Ripple分析设置: {settings}")

    def on_ripple_analysis_complete(self, results):
        """Ripple分析完成"""
        self.ripple_results = results
        self.display_ripple_results()
        if hasattr(self, 'export_ripple_btn') and self.export_ripple_btn:
            self.export_ripple_btn.setEnabled(True)
        if hasattr(self, 'order_spectrum_btn') and self.order_spectrum_btn:
            self.order_spectrum_btn.setEnabled(True)
        if hasattr(self, 'analyze_ripple_btn') and self.analyze_ripple_btn:
            self.analyze_ripple_btn.setEnabled(True)
        if hasattr(self, 'process_view_btn') and self.process_view_btn:
            self.process_view_btn.setEnabled(True)

        # 隐藏进度条
        self.progress_bar.setVisible(False)
        self.progress_label.setVisible(False)

        self.status_bar.showMessage("Ripple分析完成", 5000)
        if self.deviation_results:
            self.html_report_action.setEnabled(True)
            self.pdf_report_action.setEnabled(True)
            self.klingelnberg_report_action.setEnabled(True)
            self.rotation_waviness_report_action.setEnabled(True)

    def on_ripple_analysis_error(self, error_msg):
        """Ripple分析错误处理"""
        # 重新启用按钮
        if hasattr(self, 'analyze_ripple_btn') and self.analyze_ripple_btn:
            self.analyze_ripple_btn.setEnabled(True)

        # 隐藏进度条
        self.progress_bar.setVisible(False)
        self.progress_label.setVisible(False)

        # 显示错误信息
        QMessageBox.critical(self, "Ripple分析错误", error_msg)
        self.status_bar.showMessage(f"Ripple分析失败: {error_msg}", 5000)

    def display_ripple_results(self):
        """显示Ripple分析结果（基于平均曲线分析）"""
        if not self.ripple_results:
            return

        # 更新统计信息（适应新的平均曲线分析结构）
        stats = self.ripple_results['stats']
        
        # 齿形统计信息
        profile_text = "齿形波纹度: "
        if stats['profile']['left_analyzed'] or stats['profile']['right_analyzed']:
            # 获取左右齿面的波纹度参数
            left_wt = stats['profile'].get('left_ripple', 0)
            right_wt = stats['profile'].get('right_ripple', 0)
            left_wq = stats['profile'].get('left_rms', 0)
            right_wq = stats['profile'].get('right_rms', 0)
            left_wa = stats['profile'].get('left_avg', 0)
            right_wa = stats['profile'].get('right_avg', 0)
            
            # 计算平均值
            avg_wt = (left_wt + right_wt) / 2 if (left_wt > 0 and right_wt > 0) else max(left_wt, right_wt)
            avg_wq = (left_wq + right_wq) / 2 if (left_wq > 0 and right_wq > 0) else max(left_wq, right_wq)
            avg_wa = (left_wa + right_wa) / 2 if (left_wa > 0 and right_wa > 0) else max(left_wa, right_wa)
            
            profile_text += f"Wt-{avg_wt:.1f}μm | Wq-{avg_wq:.1f}μm | Wa-{avg_wa:.1f}μm"
            
            # 添加一致性信息
            if stats['profile']['left_analyzed'] and stats['profile']['right_analyzed']:
                profile_text += f" | 一致性: L-{stats['profile']['left_consistency']} R-{stats['profile']['right_consistency']}"
        else:
            profile_text += "未分析"

        # 齿向统计信息
        flank_text = "\n齿向波纹度: "
        if stats['flank']['left_analyzed'] or stats['flank']['right_analyzed']:
            # 获取左右齿面的波纹度参数
            left_wt = stats['flank'].get('left_ripple', 0)
            right_wt = stats['flank'].get('right_ripple', 0)
            left_wq = stats['flank'].get('left_rms', 0)
            right_wq = stats['flank'].get('right_rms', 0)
            left_wa = stats['flank'].get('left_avg', 0)
            right_wa = stats['flank'].get('right_avg', 0)
            
            # 计算平均值
            avg_wt = (left_wt + right_wt) / 2 if (left_wt > 0 and right_wt > 0) else max(left_wt, right_wt)
            avg_wq = (left_wq + right_wq) / 2 if (left_wq > 0 and right_wq > 0) else max(left_wq, right_wq)
            avg_wa = (left_wa + right_wa) / 2 if (left_wa > 0 and right_wa > 0) else max(left_wa, right_wa)
            
            flank_text += f"Wt-{avg_wt:.1f}μm | Wq-{avg_wq:.1f}μm | Wa-{avg_wa:.1f}μm"
            
            # 添加一致性信息
            if stats['flank']['left_analyzed'] and stats['flank']['right_analyzed']:
                flank_text += f" | 一致性: L-{stats['flank']['left_consistency']} R-{stats['flank']['right_consistency']}"
        else:
            flank_text += "未分析"

        # 总体质量评估
        overall_text = f"\n\n总体质量等级: {stats.get('overall_quality', '未知')}"
        
        # 分析方法信息
        method_text = f"\n分析方法: 平均曲线Ripple分析 (符合齿轮分析标准)"

        stats_text = profile_text + flank_text + overall_text + method_text
        # 检查ripple_stats_label属性是否存在
        if hasattr(self, 'ripple_stats_label'):
            self.ripple_stats_label.setText(stats_text)

        # 更新参数说明区域
        if hasattr(self, 'update_ripple_parameters_display'):
            self.update_ripple_parameters_display()

        # 显示阶次分析图表
        self.plot_order_analysis()

        # 显示诊断信息
        self.display_diagnosis()

    def plot_order_analysis(self):
        """绘制专业阶次分析图表（四个区域格式）"""
        logger.info("开始绘制专业阶次分析图表")
        
        # 检查ripple_figure属性是否存在且不为None
        if not hasattr(self, 'ripple_figure') or self.ripple_figure is None:
            logger.warning("ripple_figure属性不存在或为None，跳过图表绘制")
            return
            
        # 清空图表
        self.ripple_figure.clear()

        # 检查是否有Ripple分析结果
        if not self.ripple_results:
            logger.warning("没有Ripple分析结果")
            ax = self.ripple_figure.add_subplot(111)
            ax.text(0.5, 0.5, "请先进行Ripple分析", ha='center', va='center', transform=ax.transAxes,
                   fontsize=14, color='gray')
            ax.set_title("阶次分析")
            ax.axis('off')
            if hasattr(self, 'ripple_canvas'):
                self.ripple_canvas.draw()
            return

        # 检查阶次分析数据是否存在
        order_analysis = self.ripple_results.get('order_analysis', {})
        
        if not order_analysis:
            logger.warning("阶次分析数据为空")
            ax = self.ripple_figure.add_subplot(111)
            ax.text(0.5, 0.5, "无可用的阶次分析数据", ha='center', va='center', transform=ax.transAxes,
                   fontsize=14, color='orange')
            ax.set_title("阶次分析")
            ax.axis('off')
            if hasattr(self, 'ripple_canvas'):
                self.ripple_canvas.draw()
            return

        # 使用专业布局 - 类似PDF格式
        self._plot_professional_window_order_spectrum(order_analysis)
        logger.info("专业阶次分析图表绘制完成")

