    def refresh_order_analysis_report(self):
        """刷新阶次分析报表"""
        try:
            # 检查是否有Ripple分析结果
            if not hasattr(self, 'ripple_results') or not self.ripple_results:
                self.show_no_data_message()
                return
            
            # 检查阶次分析数据是否存在
            order_analysis = self.ripple_results.get('order_analysis', {})
            if not order_analysis:
                self.show_no_data_message()
                return
            
            # 获取选择的阶次范围
            selected_order = self.order_combo.currentText()
            max_orders = self._get_max_orders_from_selection(selected_order)
            
            # 获取滤波设置
            filter_params = self.get_current_filter_params()
            
            # 生成图表（应用滤波）
            self._create_order_analysis_chart(max_orders, filter_params)
            
            # 更新主要阶次表格
            self._update_order_table(order_analysis, max_orders)
            
            # 更新统计信息
            self._update_stats_label(order_analysis, max_orders)
            
        except Exception as e:
            logger.error(f"刷新阶次分析报表失败: {e}")
            self.show_error_message(str(e))
    
