    def get_current_filter_params(self):
        """获取当前滤波参数"""
        if not hasattr(self, 'current_filter_params'):
            # 默认滤波参数
            self.current_filter_params = {
                'filter_type': '无滤波',
                'window_type': '汉宁窗',
                'overlap_ratio': 50.0,
                'zero_padding': 2,
                'enable_preview': True
            }
        return self.current_filter_params
    
    def apply_filter_to_data(self, data, filter_params):
        """对数据应用滤波器"""
        try:
            if filter_params['filter_type'] == '无滤波':
                return data
            
            import numpy as np
            from scipy import signal
            
            # 检查数据长度是否足够
            if len(data) < 20:
                logger.warning(f"数据长度太短({len(data)})，无法应用滤波器，返回原始数据")
                return data
            
            # 获取采样频率（假设数据是等间距的）
            fs = 1.0  # 标准化频率
            
            if filter_params['filter_type'] == '低通滤波':
                # 低通滤波
                if 'lowpass_freq' not in filter_params or 'lowpass_order' not in filter_params:
                    logger.warning("低通滤波参数不完整，使用默认值")
                    cutoff = 0.5  # 默认截止频率
                    order = 4      # 默认阶数
                else:
                    cutoff = filter_params['lowpass_freq'] / fs
                    order = filter_params['lowpass_order']
                # 确保截止频率在有效范围内
                cutoff = max(0.001, min(0.999, cutoff))
                b, a = signal.butter(order, cutoff, 'low')
                filtered_data = signal.filtfilt(b, a, data)
                
            elif filter_params['filter_type'] == '高通滤波':
                # 高通滤波
                if 'highpass_freq' not in filter_params or 'highpass_order' not in filter_params:
                    logger.warning("高通滤波参数不完整，使用默认值")
                    cutoff = 0.1  # 默认截止频率
                    order = 4      # 默认阶数
                else:
                    cutoff = filter_params['highpass_freq'] / fs
                    order = filter_params['highpass_order']
                # 确保截止频率在有效范围内
                cutoff = max(0.001, min(0.999, cutoff))
                b, a = signal.butter(order, cutoff, 'high')
                filtered_data = signal.filtfilt(b, a, data)
                
            elif filter_params['filter_type'] == '带通滤波':
                # 带通滤波
                if 'bandpass_low' not in filter_params or 'bandpass_high' not in filter_params or 'bandpass_order' not in filter_params:
                    logger.warning("带通滤波参数不完整，使用默认值")
                    low = 0.1   # 默认低频截止
                    high = 0.9  # 默认高频截止
                    order = 4   # 默认阶数
                else:
                    low = filter_params['bandpass_low'] / fs
                    high = filter_params['bandpass_high'] / fs
                    order = filter_params['bandpass_order']
                # 确保截止频率在有效范围内
                low = max(0.001, min(0.499, low))
                high = max(0.501, min(0.999, high))
                if low >= high:
                    # 如果低频截止大于等于高频截止，调整频率
                    low = 0.1
                    high = 0.9
                b, a = signal.butter(order, [low, high], 'band')
                filtered_data = signal.filtfilt(b, a, data)
                
            elif filter_params['filter_type'] == '截止波长滤波':
                # 截止波长滤波
                if 'wavelength_cutoff' not in filter_params or 'wavelength_unit' not in filter_params or 'wavelength_strength' not in filter_params:
                    logger.warning("截止波长滤波参数不完整，使用默认值")
                    cutoff_wavelength = 0.8  # 默认截止波长(mm)
                    unit = 'mm'
                    strength = 3
                else:
                    cutoff_wavelength = filter_params['wavelength_cutoff']
                    unit = filter_params['wavelength_unit']
                    strength = filter_params['wavelength_strength']
                
                # 单位转换
                if unit == 'μm':
                    cutoff_wavelength = cutoff_wavelength / 1000.0  # 转换为mm
                elif unit == 'm':
                    cutoff_wavelength = cutoff_wavelength * 1000.0  # 转换为mm
                
                # 计算截止频率（基于波长）
                # 假设数据采样间隔为1mm，则截止频率 = 1 / 截止波长
                cutoff_freq = 1.0 / cutoff_wavelength
                cutoff_freq = max(0.001, min(0.999, cutoff_freq))  # 限制在有效范围内
                
                # 使用Butterworth低通滤波器
                order = min(strength, 8)  # 限制阶数
                b, a = signal.butter(order, cutoff_freq, 'low')
                filtered_data = signal.filtfilt(b, a, data)
                
            elif filter_params['filter_type'] == '自定义滤波':
                # 自定义滤波（需要用户提供代码）
                custom_code = filter_params['custom_filter']
                if custom_code.strip():
                    # 这里可以执行自定义滤波代码
                    # 为了安全，这里只是示例
                    filtered_data = data  # 暂时返回原始数据
                    logger.warning("自定义滤波功能需要进一步实现")
                else:
                    filtered_data = data
            else:
                filtered_data = data
            
            return filtered_data
            
        except Exception as e:
            logger.error(f"应用滤波器失败: {e}")
            return data  # 返回原始数据
    
    def apply_window_function(self, data, window_type):
        """应用窗函数"""
        try:
            import numpy as np
            from scipy import signal
            
            if window_type == '矩形窗':
                window = np.ones(len(data))
            elif window_type == '汉宁窗':
                window = signal.windows.hann(len(data))
            elif window_type == '汉明窗':
                window = signal.windows.hamming(len(data))
            elif window_type == '布莱克曼窗':
                window = signal.windows.blackman(len(data))
            elif window_type == '凯撒窗':
                window = signal.windows.kaiser(len(data), beta=8.6)
            else:
                window = np.ones(len(data))
            
            return data * window
            
        except Exception as e:
            logger.error(f"应用窗函数失败: {e}")
            return data
    
    def update_filter_status(self, filter_params):
        """更新滤波状态显示"""
        try:
            if hasattr(self, 'filter_status_label'):
                filter_type = filter_params.get('filter_type', '无滤波')
                window_type = filter_params.get('window_type', '汉宁窗')
                
                status_text = f"滤波状态: {filter_type} | 窗函数: {window_type}"
                
                # 根据滤波类型设置颜色
                if filter_type == '无滤波':
                    color = '#e74c3c'  # 红色
                elif filter_type == '低通滤波':
                    color = '#3498db'  # 蓝色
                elif filter_type == '高通滤波':
                    color = '#2ecc71'  # 绿色
                elif filter_type == '带通滤波':
                    color = '#9b59b6'  # 紫色
                else:
                    color = '#f39c12'  # 橙色
                
                self.filter_status_label.setText(status_text)
                self.filter_status_label.setStyleSheet(f"color: {color}; font-weight: bold;")
                
        except Exception as e:
            logger.error(f"更新滤波状态失败: {e}")
    

    
    def _get_max_orders_from_selection(self, selection):
        """从选择中获取最大阶次数"""
        if "50阶次" in selection:
            return 50
        elif "200阶次" in selection:
            return 200
        elif "500阶次" in selection:
            return 500
        else:  # 全部阶次
            return 1000  # 设置一个较大的值
    
    def _create_order_analysis_chart(self, max_orders, filter_params=None):
        """创建阶次分析图表"""
        try:
            # 清空图表
            self.fig.clear()
            
            # 检查数据
            if not hasattr(self, 'ripple_results') or not self.ripple_results:
                self.show_no_data_message()
                return
            
            order_analysis = self.ripple_results.get('order_analysis', {})
            if not order_analysis:
                self.show_no_data_message()
                return
            
            # 如果没有提供滤波参数，使用默认参数
            if filter_params is None:
                filter_params = self.get_current_filter_params()
            
            # 创建2x2子图布局
            gs = self.fig.add_gridspec(2, 2, hspace=0.3, wspace=0.3)
            
            section_titles = ["右齿面齿形", "左齿面齿形", "右齿面齿向", "左齿面齿向"]
            section_keys = ["profile_right", "profile_left", "flank_right", "flank_left"]
            colors = ['#3498db', '#e74c3c', '#2ecc71', '#9b59b6']
            
            for i, (title, key, color) in enumerate(zip(section_titles, section_keys, colors)):
                ax = self.fig.add_subplot(gs[i // 2, i % 2])
                
                # 获取数据
                data = self._get_section_data(order_analysis, i)
                if data is not None and len(data) > 0:
                    # 应用窗函数
                    data = self.apply_window_function(data, filter_params['window_type'])
                    
                    # 应用滤波器
                    data = self.apply_filter_to_data(data, filter_params)
                    
                    # 限制阶次范围
                    data = data[:max_orders]
                    orders = list(range(1, len(data) + 1))
                    
                    # 绘制柱状图
                    bars = ax.bar(orders, data, width=0.6, color=color, alpha=0.7, 
                                 edgecolor='#2c3e50', linewidth=0.5)
                    
                    # 标记主要阶次（前3个最大值）
                    if len(data) > 0:
                        max_vals = sorted([(j+1, val) for j, val in enumerate(data) if val > 0], 
                                        key=lambda x: x[1], reverse=True)[:3]
                        for order, value in max_vals:
                            ax.bar(order, value, width=0.6, color='#f39c12', alpha=0.8)
                    
                    ax.set_xlabel('阶次', fontsize=10)
                    ax.set_ylabel('振幅', fontsize=10)
                    ax.set_title(f'{title}', fontsize=12, fontweight='bold')
                    ax.grid(True, alpha=0.3)
                    
                    # 设置x轴范围
                    ax.set_xlim(0.5, len(data) + 0.5)
                    
                else:
                    ax.text(0.5, 0.5, "无数据", ha='center', va='center',
                           transform=ax.transAxes, fontsize=12, color='gray')
                    ax.set_title(f'{title}', fontsize=12, fontweight='bold')
                    ax.axis('off')
            
            self.canvas.draw()
            
        except Exception as e:
            logger.error(f"创建阶次分析图表失败: {e}")
            self.show_error_message(str(e))
    
    def _update_order_table(self, order_analysis, max_orders):
        """更新主要阶次表格"""
        try:
            # 收集所有主要阶次数据
            all_dominant_orders = []
            
            section_titles = ["右齿面齿形", "左齿面齿形", "右齿面齿向", "左齿面齿向"]
            
            for i, title in enumerate(section_titles):
                data = self._get_section_data(order_analysis, i)
                if data is not None and len(data) > 0:
                    # 限制阶次范围
                    data = data[:max_orders]
                    
                    # 找到主要阶次（超过平均值的阶次）
                    valid_data = [val for val in data if val is not None and val > 0]
                    if valid_data:
                        mean_amplitude = np.mean(valid_data)
                        std_amplitude = np.std(valid_data)
                        threshold = mean_amplitude + 0.5 * std_amplitude
                        
                        dominant_orders = [(j+1, val) for j, val in enumerate(data) 
                                         if val is not None and val > threshold]
                        dominant_orders.sort(key=lambda x: x[1], reverse=True)
                        
                        # 添加到总列表
                        for order, amplitude in dominant_orders[:10]:  # 每个区域最多10个
                            percentage = (amplitude / max(valid_data)) * 100 if valid_data else 0
                            quality = self._get_order_quality_grade(amplitude)
                            all_dominant_orders.append({
                                'section': title,
                                'order': order,
                                'amplitude': amplitude,
                                'percentage': percentage,
                                'quality': quality
                            })
            
            # 按振幅排序，取前10个
            all_dominant_orders.sort(key=lambda x: x['amplitude'], reverse=True)
            top_10_orders = all_dominant_orders[:10]
            
            # 更新表格
            self.order_table.setRowCount(len(top_10_orders))
            
            for row, order_data in enumerate(top_10_orders):
                self.order_table.setItem(row, 0, QTableWidgetItem(order_data['section']))
                self.order_table.setItem(row, 1, QTableWidgetItem(str(order_data['order'])))
                self.order_table.setItem(row, 2, QTableWidgetItem(f"{order_data['amplitude']:.3f}"))
                self.order_table.setItem(row, 3, QTableWidgetItem(f"{order_data['percentage']:.1f}"))
                
                # 质量等级单元格
                quality_item = QTableWidgetItem(order_data['quality'])
                quality_item.setBackground(self._get_quality_color(order_data['quality']))
                self.order_table.setItem(row, 4, quality_item)
            
        except Exception as e:
            logger.error(f"更新阶次表格失败: {e}")
    
    def _get_order_quality_grade(self, amplitude):
        """获取阶次分析的质量等级"""
        if amplitude < 0.1:
            return "优秀"
        elif amplitude < 0.3:
            return "良好"
        elif amplitude < 0.5:
            return "一般"
        else:
            return "需要关注"
    
    def _get_quality_color(self, quality):
        """获取质量等级颜色"""
        from PyQt5.QtGui import QColor
        if quality == "优秀":
            return QColor(46, 204, 113)  # 绿色
        elif quality == "良好":
            return QColor(52, 152, 219)  # 蓝色
        elif quality == "一般":
            return QColor(243, 156, 18)  # 橙色
        else:
            return QColor(231, 76, 60)   # 红色
    
    def _update_stats_label(self, order_analysis, max_orders):
        """更新统计信息标签"""
        try:
            total_orders = 0
            total_amplitude = 0
            dominant_count = 0
            
            for i in range(4):
                data = self._get_section_data(order_analysis, i)
                if data is not None and len(data) > 0:
                    data = data[:max_orders]
                    valid_data = [val for val in data if val is not None and val > 0]
                    
                    if valid_data:
                        total_orders += len(valid_data)
                        total_amplitude += sum(valid_data)
                        
                        # 计算主要阶次数量
                        mean_amplitude = np.mean(valid_data)
                        std_amplitude = np.std(valid_data)
                        threshold = mean_amplitude + 0.5 * std_amplitude
                        dominant_count += len([val for val in data if val is not None and val > threshold])
            
            avg_amplitude = total_amplitude / total_orders if total_orders > 0 else 0
            stats_text = f"分析阶次: {max_orders} | 总阶次数: {total_orders} | 平均振幅: {avg_amplitude:.3f} | 主要阶次: {dominant_count}个"
            self.stats_label.setText(stats_text)
            
        except Exception as e:
            logger.error(f"更新统计信息失败: {e}")
            self.stats_label.setText("统计信息更新失败")
    
    def show_no_data_message(self):
        """显示无数据消息"""
        self.fig.clear()
        ax = self.fig.add_subplot(111)
        ax.text(0.5, 0.5, "请先进行Ripple分析\n然后查看专业阶次分析", 
               ha='center', va='center', transform=ax.transAxes,
               fontsize=14, color='gray')
        ax.set_title("阶次分析")
        ax.axis('off')
        self.canvas.draw()
        
        # 清空表格
        self.order_table.setRowCount(0)
        self.stats_label.setText("无可用数据")
    
    def show_error_message(self, error_msg):
        """显示错误消息"""
        self.fig.clear()
        ax = self.fig.add_subplot(111)
        ax.text(0.5, 0.5, f"生成报表时发生错误:\n{error_msg}", 
               ha='center', va='center', transform=ax.transAxes,
               fontsize=12, color='red')
        ax.axis('off')
        self.canvas.draw()
        
        self.stats_label.setText("报表生成失败")
    
    def export_order_analysis_report(self):
        """导出阶次分析报表"""
        try:
            from PyQt5.QtWidgets import QFileDialog
            import datetime
            
            # 获取当前时间
            current_time = datetime.datetime.now().strftime('%Y%m%d_%H%M%S')
            
            # 选择保存路径
            file_path, _ = QFileDialog.getSaveFileName(
                self, "导出阶次分析报表", 
                f"阶次分析报表_{current_time}.png",
                "PNG图片 (*.png);;JPEG图片 (*.jpg);;PDF文档 (*.pdf)"
            )
            
            if file_path:
                # 保存图表
                self.fig.savefig(file_path)
                
                # 显示成功消息
                from PyQt5.QtWidgets import QMessageBox
                QMessageBox.information(self, "导出成功", f"报表已成功导出到:\n{file_path}")
                
        except Exception as e:
            logger.error(f"导出报表失败: {e}")
            from PyQt5.QtWidgets import QMessageBox
            QMessageBox.warning(self, "导出失败", f"导出报表时发生错误:\n{str(e)}")

    def create_order_analysis_chart_in_page(self, canvas, fig):
        """在页面中创建阶次分析图表"""
        from PyQt5.QtWidgets import QMdiSubWindow
        from matplotlib.backends.backend_qt5agg import FigureCanvasQTAgg as FigureCanvas
        from matplotlib.figure import Figure
        import datetime
        import os
        
        # 清空图表
        fig.clear()
        
        # 检查是否有Ripple分析结果
        if not hasattr(self, 'ripple_results') or not self.ripple_results:
            # 创建提示内容
            ax = fig.add_subplot(111)
            ax.text(0.5, 0.5, "请先进行Ripple分析\n然后查看专业阶次分析", 
                   ha='center', va='center', transform=ax.transAxes,
                   fontsize=14, color='gray')
            ax.set_title("阶次分析")
            ax.axis('off')
            canvas.draw()
            return
        
        # 检查阶次分析数据是否存在
        order_analysis = self.ripple_results.get('order_analysis', {})
        if not order_analysis:
            # 创建提示内容
            ax = fig.add_subplot(111)
            ax.text(0.5, 0.5, "无可用的阶次分析数据\n请先完成Ripple分析", 
                   ha='center', va='center', transform=ax.transAxes,
                   fontsize=14, color='orange')
            ax.set_title("阶次分析")
            ax.axis('off')
            canvas.draw()
            return
        
        # 创建专业阶次分析图表
        self._create_professional_order_analysis_chart_in_page(canvas, fig, order_analysis)

    def refresh_order_analysis_page(self, page):
        """刷新页面中的阶次分析"""
        # 获取页面中的画布
        scroll_area = page.findChild(QScrollArea)
        if scroll_area:
            chart_container = scroll_area.widget()
            if chart_container:
                canvas = chart_container.findChild(FigureCanvas)
                if canvas:
                    fig = canvas.figure
                    self.create_order_analysis_chart_in_page(canvas, fig)

    def _create_professional_order_analysis_chart_in_page(self, canvas, fig, order_analysis):
        """在页面中创建全新的专业阶次分析报表"""
        import datetime
        import os
        import numpy as np

        try:
            # 清空图表
            fig.clear()
            
            # 创建网格布局：头部信息 + 4个分析区域 + 统计表格 + 诊断报告
            gs = fig.add_gridspec(8, 2, height_ratios=[0.3, 1.2, 1.2, 1.2, 1.2, 0.8, 0.6, 0.4], 
                                 width_ratios=[1, 0.3], hspace=0.4, wspace=0.1)

            # ==================== 头部信息区域 ====================
            ax_header = fig.add_subplot(gs[0, :])
            ax_header.axis('off')
            
            # 获取基本信息
            current_time = datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S')
            file_name = os.path.basename(self.current_file) if self.current_file else "未知文件"
            
            # 创建专业标题
            ax_header.text(0.02, 0.8, "专业阶次分析报告", fontsize=16, fontweight='bold', 
                          color='#2c3e50', transform=ax_header.transAxes)
            ax_header.text(0.02, 0.5, f"文件: {file_name}", fontsize=10, 
                          color='#34495e', transform=ax_header.transAxes)
            ax_header.text(0.02, 0.2, f"分析时间: {current_time}", fontsize=9, 
                          color='#7f8c8d', transform=ax_header.transAxes)
            ax_header.text(0.6, 0.5, "深度阶次分析", fontsize=12, fontweight='bold',
                          color='#e74c3c', transform=ax_header.transAxes)
            ax_header.text(0.6, 0.2, "200阶次频谱分析", fontsize=9,
                          color='#27ae60', transform=ax_header.transAxes)
            
            # 添加分析参数信息
            if hasattr(self, 'gear_data') and self.gear_data:
                module = self.gear_data.get('module', 'N/A')
                teeth = self.gear_data.get('teeth', 'N/A')
                ax_header.text(0.8, 0.5, f"模数: {module}mm", fontsize=8, 
                              color='#34495e', transform=ax_header.transAxes)
                ax_header.text(0.8, 0.2, f"齿数: {teeth}", fontsize=8, 
                              color='#34495e', transform=ax_header.transAxes)

            # ==================== 四个分析区域 ====================
            section_titles = ["右齿面齿形", "左齿面齿形", "右齿面齿向", "左齿面齿向"]
            section_keys = ["profile_right", "profile_left", "flank_right", "flank_left"]
            colors = ['#3498db', '#e74c3c', '#2ecc71', '#9b59b6']
            
            # 存储分析结果
            analysis_results = []
            
            for i, (title, key, color) in enumerate(zip(section_titles, section_keys, colors)):
                # 创建子图
                ax = fig.add_subplot(gs[i + 1, 0])
                ax.axis('off')
                
                # 区域标题
                ax.text(0.02, 0.95, title, fontsize=11, fontweight='bold',
                        color=color, transform=ax.transAxes, va='top')
                
                # 创建内部绘图区域
                inner_ax = ax.inset_axes([0.05, 0.15, 0.92, 0.75])
                
                # 获取数据
                data = self._get_section_data(order_analysis, i)
                
                if data is not None and len(data) > 0:
                    # 数据处理
                    data = [self._safe_cast_to_float(val) for val in data]
                    valid_data = [val for val in data if val is not None and val > 0]
                    
                    if valid_data:
                        # 计算统计信息
                        max_amplitude = max(valid_data)
                        mean_amplitude = np.mean(valid_data)
                        std_amplitude = np.std(valid_data)
                        
                        # 找到主要阶次（超过平均值的阶次）
                        threshold = mean_amplitude + 0.5 * std_amplitude
                        dominant_orders = [(j+1, val) for j, val in enumerate(data) 
                                         if val is not None and val > threshold]
                        dominant_orders.sort(key=lambda x: x[1], reverse=True)
                        
                        # 绘制阶次谱
                        orders = list(range(1, len(data) + 1))
                        bars = inner_ax.bar(orders, data, width=0.6, color=color,
                                           alpha=0.7, edgecolor='#2c3e50', linewidth=0.5)
                        
                        # 标记主要阶次
                        for order, amplitude in dominant_orders[:5]:  # 标记前5个主要阶次
                            if order <= len(data):
                                inner_ax.bar(order, data[order-1], width=0.6, 
                                           color='#f39c12', alpha=0.8, edgecolor='#e67e22')
                        
                        # 设置图表属性
                        inner_ax.set_xlabel('阶次', fontsize=9)
                        inner_ax.set_ylabel('振幅', fontsize=9)
                        inner_ax.set_title(f'{title} 阶次谱', fontsize=10, fontweight='bold')
                        inner_ax.grid(True, alpha=0.3)
                        
                        # 添加统计信息
                        stats_text = f"最大振幅: {max_amplitude:.3f}\n平均振幅: {mean_amplitude:.3f}\n主要阶次: {len(dominant_orders)}个"
                        ax.text(0.98, 0.1, stats_text, fontsize=8, ha='right', va='bottom',
                               transform=ax.transAxes, bbox=dict(boxstyle="round,pad=0.3", 
                               facecolor='white', alpha=0.8))
                        
                        # 存储分析结果
                        analysis_results.append({
                            'title': title,
                            'max_amplitude': max_amplitude,
                            'mean_amplitude': mean_amplitude,
                            'dominant_orders': dominant_orders[:10],
                            'total_orders': len(valid_data)
                        })
                    else:
                        inner_ax.text(0.5, 0.5, "无有效数据", ha='center', va='center',
                                      transform=inner_ax.transAxes, fontsize=10, color='gray')
                        inner_ax.set_title(f'{title} 阶次谱', fontsize=10, fontweight='bold')
                        analysis_results.append({
                            'title': title,
                            'max_amplitude': 0,
                            'mean_amplitude': 0,
                            'dominant_orders': [],
                            'total_orders': 0
                        })
                else:
                    inner_ax.text(0.5, 0.5, "无数据", ha='center', va='center',
                                  transform=inner_ax.transAxes, fontsize=10, color='gray')
                    inner_ax.set_title(f'{title} 阶次谱', fontsize=10, fontweight='bold')
                    analysis_results.append({
                        'title': title,
                        'max_amplitude': 0,
                        'mean_amplitude': 0,
                        'dominant_orders': [],
                        'total_orders': 0
                    })

            # ==================== 统计表格区域 ====================
            ax_table = fig.add_subplot(gs[5, :])
            ax_table.axis('off')
            
            # 创建统计表格
            table_data = [['分析项目', '最大振幅', '平均振幅', '主要阶次数', '主要阶次列表']]
            
            for result in analysis_results:
                dominant_orders_str = ', '.join([f"{order}({amp:.2f})" for order, amp in result['dominant_orders'][:5]])
                table_data.append([
                    result['title'],
                    f"{result['max_amplitude']:.3f}",
                    f"{result['mean_amplitude']:.3f}",
                    str(len(result['dominant_orders'])),
                    dominant_orders_str
                ])
            
            # 绘制表格
            table = ax_table.table(cellText=table_data[1:], colLabels=table_data[0],
                                  cellLoc='center', loc='center',
                                  colWidths=[0.25, 0.15, 0.15, 0.15, 0.3])
            
            # 设置表格样式
            table.auto_set_font_size(False)
            table.set_fontsize(8)
            table.scale(1, 2)
            
            # 设置表头样式
            for i in range(len(table_data[0])):
                table[(0, i)].set_facecolor('#34495e')
                table[(0, i)].set_text_props(weight='bold', color='white')
            
            # 设置数据行样式
            for i in range(1, len(table_data)):
                for j in range(len(table_data[0])):
                    if i % 2 == 0:
                        table[(i, j)].set_facecolor('#ecf0f1')
                    else:
                        table[(i, j)].set_facecolor('#ffffff')

            # ==================== 诊断报告区域 ====================
            ax_diagnosis = fig.add_subplot(gs[6, :])
            ax_diagnosis.axis('off')
            
            # 生成诊断报告
            diagnosis_text = self._generate_order_analysis_diagnosis(analysis_results)
            
            ax_diagnosis.text(0.02, 0.9, "诊断报告", fontsize=12, fontweight='bold',
                             color='#2c3e50', transform=ax_diagnosis.transAxes)
            
            # 分行显示诊断内容
            lines = diagnosis_text.split('\n')
            for i, line in enumerate(lines):
                if line.strip():
                    ax_diagnosis.text(0.02, 0.8 - i * 0.08, line, fontsize=9,
                                     color='#34495e', transform=ax_diagnosis.transAxes)

            # ==================== 总结区域 ====================
            ax_summary = fig.add_subplot(gs[7, :])
            ax_summary.axis('off')
            
            # 计算总体统计
            total_max_amplitude = max([r['max_amplitude'] for r in analysis_results])
            total_mean_amplitude = np.mean([r['mean_amplitude'] for r in analysis_results])
            total_dominant_orders = sum([len(r['dominant_orders']) for r in analysis_results])
            
            summary_text = f"总体分析结果: 最大振幅 {total_max_amplitude:.3f}, 平均振幅 {total_mean_amplitude:.3f}, 总主要阶次 {total_dominant_orders}个"
            ax_summary.text(0.02, 0.5, summary_text, fontsize=10, fontweight='bold',
                           color='#e74c3c', transform=ax_summary.transAxes)

            canvas.draw()
            logger.info("全新专业阶次分析报表生成完成")
            
        except Exception as e:
            logger.error(f"创建专业阶次分析报表失败: {e}")
            # 创建错误提示
            ax = fig.add_subplot(111)
            ax.text(0.5, 0.5, f"生成报表时发生错误:\n{str(e)}", 
                   ha='center', va='center', transform=ax.transAxes,
                   fontsize=12, color='red')
            ax.axis('off')
            canvas.draw()
    
    def _generate_order_analysis_diagnosis(self, analysis_results):
        """生成阶次分析诊断报告"""
        try:
            diagnosis_lines = []
            
            # 分析总体情况
            total_max_amplitude = max([r['max_amplitude'] for r in analysis_results])
            total_mean_amplitude = np.mean([r['mean_amplitude'] for r in analysis_results])
            total_dominant_orders = sum([len(r['dominant_orders']) for r in analysis_results])
            
            diagnosis_lines.append("=== 阶次分析诊断报告 ===")
            diagnosis_lines.append(f"总体分析: 最大振幅 {total_max_amplitude:.3f}, 平均振幅 {total_mean_amplitude:.3f}")
            diagnosis_lines.append(f"主要阶次总数: {total_dominant_orders}个")
            
            # 分析各区域情况
            for result in analysis_results:
                if result['max_amplitude'] > 0:
                    diagnosis_lines.append(f"\n{result['title']}:")
                    diagnosis_lines.append(f"  最大振幅: {result['max_amplitude']:.3f}")
                    diagnosis_lines.append(f"  平均振幅: {result['mean_amplitude']:.3f}")
                    diagnosis_lines.append(f"  主要阶次: {len(result['dominant_orders'])}个")
                    
                    if result['dominant_orders']:
                        top_orders = [f"{order}({amp:.2f})" for order, amp in result['dominant_orders'][:3]]
                        diagnosis_lines.append(f"  前3个主要阶次: {', '.join(top_orders)}")
                    
                    # 判断质量等级
                    if result['max_amplitude'] < 0.1:
                        diagnosis_lines.append("  质量评估: 优秀")
                    elif result['max_amplitude'] < 0.3:
                        diagnosis_lines.append("  质量评估: 良好")
                    elif result['max_amplitude'] < 0.5:
                        diagnosis_lines.append("  质量评估: 一般")
                    else:
                        diagnosis_lines.append("  质量评估: 需要关注")
                else:
                    diagnosis_lines.append(f"\n{result['title']}: 无有效数据")
            
            # 总体质量评估
            diagnosis_lines.append(f"\n=== 总体质量评估 ===")
            if total_max_amplitude < 0.2:
                diagnosis_lines.append("整体质量: 优秀 - 阶次分布均匀，主要阶次较少")
            elif total_max_amplitude < 0.4:
                diagnosis_lines.append("整体质量: 良好 - 阶次分布合理，主要阶次适中")
            elif total_max_amplitude < 0.6:
                diagnosis_lines.append("整体质量: 一般 - 存在较多主要阶次，需要关注")
            else:
                diagnosis_lines.append("整体质量: 需要改进 - 主要阶次过多，建议优化")
            
            return '\n'.join(diagnosis_lines)
            
        except Exception as e:
            logger.error(f"生成诊断报告失败: {e}")
            return "诊断报告生成失败"

            # 添加表格标题
            ax_table.text(0.5, 0.98, '阶次分析统计摘要',
                          ha='center', va='top',
                          transform=ax_table.transAxes,
                          fontsize=7,
                          fontweight='bold',
                          bbox=dict(facecolor='none', edgecolor='gray', pad=5.0))

        except Exception as e:
            # 错误处理
            ax = fig.add_subplot(111)
            ax.text(0.5, 0.6, f"创建阶次分析图表时出错",
                    ha='center', va='center', transform=ax.transAxes,
                    fontsize=12, fontweight='bold', color='#e74c3c')
            ax.text(0.5, 0.4, f"错误详情: {str(e)}",
                    ha='center', va='center', transform=ax.transAxes,
                    fontsize=10, color='#e74c3c')
            ax.set_title("阶次分析错误", fontsize=14, fontweight='bold', color='#c0392b')
            ax.axis('off')

        # 绘制图表
        canvas.draw()

