    def _plot_professional_window_order_spectrum(self, order_analysis):
        """在窗体中绘制专业阶次谱（仿PDF格式）"""
        try:
            # 设置更大的图表尺寸以改善显示效果
            self.ripple_figure.set_size_inches(30, 40)  # 增加图表尺寸
            
            # 使用GridSpec创建复杂布局（6行1列）
            # 行高比例：[头部信息, 图表区域1, 图表区域2, 图表区域3, 图表区域4, 表格区域]
            # 增大图表区域的高度比例，减小表格区域
            gs = self.ripple_figure.add_gridspec(6, 1, height_ratios=[0.4, 1.6, 1.6, 1.6, 1.6, 1.0], hspace=0.6)
            
            # 头部信息区域
            ax_header = self.ripple_figure.add_subplot(gs[0, 0])
            ax_header.axis('off')
            
            # 获取文件基本信息
            current_time = datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S')
            file_name = os.path.basename(self.current_file) if self.current_file else "未知文件"
            
            # 头部标题（简化版）- 增大字体
            ax_header.text(0.02, 0.8, "阶次谱分析 (Order Spectrum)", fontsize=11, fontweight='bold', 
                          color='red', transform=ax_header.transAxes)
            ax_header.text(0.98, 0.8, current_time, fontsize=9, ha='right', 
                          transform=ax_header.transAxes)
            ax_header.text(0.02, 0.4, f"文件: {file_name}", fontsize=9, 
                          transform=ax_header.transAxes)
            ax_header.text(0.02, 0.1, "评价方式: 高阶次分析", fontsize=9, 
                          transform=ax_header.transAxes)
            
            # 四个阶次谱图表区域
            section_titles = ["Profile right", "Profile left", "Helix right", "Helix left"]
            
            for i, title in enumerate(section_titles):
                ax = self.ripple_figure.add_subplot(gs[i+1, 0])
                ax.axis('off')
                
                # 绘制区域标题 - 增大字体
                ax.text(0.02, 0.95, title, fontsize=9, fontweight='bold', 
                       transform=ax.transAxes, va='top')
                
                # 创建内部绘图区域（增大尺寸以改善显示效果）
                # [x, y, width, height] - 扩大绘图区域
                inner_ax = ax.inset_axes([0.08, 0.15, 1.70, 1.75])
                
                # 获取数据并绘制
                data = self._get_section_data(order_analysis, i)
                
                if data is not None and len(data) > 0:
                    # 绘制阶次谱柱状图
                    orders = list(range(1, len(data) + 1))
                    
                    # 绘制柱状图
                    bars = inner_ax.bar(orders, data, width=0.8, color='blue', 
                                      edgecolor='darkblue', alpha=0.8)
                    
                    # 智能标签（避免重叠）
                    max_val = max(data)
                    if max_val > 0:
                        # 只显示最大的2个值
                        indexed_data = [(j+1, val) for j, val in enumerate(data)]
                        indexed_data.sort(key=lambda x: x[1], reverse=True)
                        
                        for j, (order, val) in enumerate(indexed_data[:2]):
                            if val > max_val * 0.1:
                                label_height = val + max_val * (0.08 + j * 0.06)
                                inner_ax.text(order, label_height, f'{val:.3f}', 
                                            ha='center', va='bottom', fontsize=10,
                                            bbox=dict(boxstyle='round,pad=0.3', facecolor='white', 
                                                    alpha=0.9, edgecolor='gray', linewidth=0.5))
                    
                    # 设置图表样式 - 改善显示效果
                    inner_ax.set_xlim(0.5, min(200, len(orders)) + 0.5)
                    inner_ax.set_ylim(0, max_val * 1.4 if max_val > 0 else 1)
                    inner_ax.set_xticks(orders[:min(50, len(orders))])
                    inner_ax.set_xticklabels([str(x) for x in orders[:min(50, len(orders))]], fontsize=8)
                    inner_ax.grid(True, alpha=0.3, linewidth=0.8)
                    inner_ax.spines['top'].set_visible(False)
                    inner_ax.spines['right'].set_visible(False)
                    inner_ax.tick_params(axis='y', labelsize=10)
                    inner_ax.tick_params(axis='x', labelsize=10)
                    # 添加坐标轴标签
                    inner_ax.set_xlabel('阶次', fontsize=8, fontweight='bold')
                    inner_ax.set_ylabel('幅值', fontsize=8, fontweight='bold')
                    
                    # 右侧参数信息
                    max_idx = data.index(max_val) + 1
                    info_text = f"ap={max_val:.3f}\nlo={max_idx}\nhu={max_val:.4f}"
                else:
                    # 无数据时显示占位符 - 增大字体
                    inner_ax.text(0.5, 0.5, "无数据", ha='center', va='center', 
                                 transform=inner_ax.transAxes, fontsize=9, color='gray', 
                                 bbox=dict(boxstyle='round,pad=0.3', facecolor='lightgray', alpha=0.3))
                    inner_ax.set_xlim(0, 10)
                    inner_ax.set_ylim(0, 1)
                    inner_ax.spines['top'].set_visible(False)
                    inner_ax.spines['right'].set_visible(False)
                    inner_ax.grid(True, alpha=0.3, linewidth=0.8)
                    # 添加坐标轴标签
                    inner_ax.set_xlabel('阶次', fontsize=8, fontweight='bold')
                    inner_ax.set_ylabel('幅值', fontsize=8, fontweight='bold')
                    info_text = "ap=0.000\nlo=0\nhu=0.0000"
                
                # 显示参数信息 - 增大字体和改善样式
                ax.text(0.82, 0.5, info_text, fontsize=9, ha='left', va='center', 
                       transform=ax.transAxes, 
                       bbox=dict(boxstyle='round,pad=0.5', facecolor='lightyellow', 
                               alpha=0.9, edgecolor='orange', linewidth=1.0))
            
            # 底部数据表格区域
            ax_table = self.ripple_figure.add_subplot(gs[5, 0])
            self._create_window_order_table(ax_table, order_analysis)
            
            # 调整布局 - 使用更安全的方法避免tight_layout警告
            try:
                self.ripple_figure.tight_layout(pad=1.0, h_pad=1.0, w_pad=1.0)
            except Exception as e:
                logger.warning(f"tight_layout失败，使用手动调整: {e}")
                # 手动调整子图间距
                self.ripple_figure.subplots_adjust(left=0.2, right=1.95, top=1.95, bottom=0.2, hspace=0.6, wspace=0.6)
            self.ripple_canvas.draw()
            
        except Exception as e:
            logger.exception(f"绘制专业窗体阶次谱失败: {str(e)}")
            # 显示错误信息 - 增大字体和改善样式
            self.ripple_figure.clear()
            ax = self.ripple_figure.add_subplot(111)
            ax.text(0.5, 0.5, f"绘制失败: {str(e)}", ha='center', va='center', 
                   transform=ax.transAxes, fontsize=11, color='red', fontweight='bold',
                   bbox=dict(boxstyle='round,pad=0.5', facecolor='white', 
                           alpha=0.9, edgecolor='red', linewidth=2))
            ax.axis('off')
            self.ripple_canvas.draw()

    def _create_window_order_table(self, ax, order_analysis):
        """为窗体创建阶次数据表格"""
        ax.axis('off')
        
        try:
            # 获取四个区域的数据
            profile_right_data = self._get_section_data(order_analysis, 0)  # Profile right
            profile_left_data = self._get_section_data(order_analysis, 1)   # Profile left
            helix_right_data = self._get_section_data(order_analysis, 2)    # Helix right
            helix_left_data = self._get_section_data(order_analysis, 3)     # Helix left
            
            # 填充数据到200列
            def pad_data(data, length=200):
                if not isinstance(data, list):
                    data = list(data) if data is not None else []
                if len(data) < length:
                    data.extend([0.0] * (length - len(data)))
                return data[:length]
            
            profile_right_data = pad_data(profile_right_data)
            profile_left_data = pad_data(profile_left_data)
            helix_right_data = pad_data(helix_right_data)
            helix_left_data = pad_data(helix_left_data)
            
            # 创建表格数据
            table_data = [
                ["Profile\nleft"] + [f"{val:.3f}" for val in profile_left_data],
                ["Profile\nright"] + [f"{val:.3f}" for val in profile_right_data],
                ["Helix\nright"] + [f"{val:.3f}" for val in helix_right_data],
                ["Helix\nleft"] + [f"{val:.3f}" for val in helix_left_data]
            ]
            
            # 表头（1-50阶）
            headers = ["区域"] + [f"{i}" for i in range(1, 51)]
            
            # 确保表格数据列数与表头匹配
            max_cols = len(headers)
            for i in range(len(table_data)):
                if len(table_data[i]) < max_cols:
                    table_data[i].extend([""] * (max_cols - len(table_data[i])))
                elif len(table_data[i]) > max_cols:
                    table_data[i] = table_data[i][:max_cols]
            
            # 创建表格
            table = ax.table(cellText=table_data, colLabels=headers,
                           cellLoc='center', loc='center',
                           bbox=[0, 0, 1, 1])
            
            # 设置表格样式 - 改善显示效果
            table.auto_set_font_size(False)
            table.set_fontsize(8)  # 增大字体
            table.scale(2, 4.0)     # 增大行高
            
            # 设置表头样式
            for i in range(len(headers)):
                cell = table[(0, i)]
                cell.set_facecolor('#d0d0d0')
                cell.set_text_props(weight='bold', fontsize=11)
                cell.set_height(0.4)    # 增大行高
                cell.set_edgecolor('black')
                cell.set_linewidth(0.8)  # 增大边框
            
            # 设置数据行样式
            for row_idx in range(1, len(table_data) + 1):
                for col_idx in range(len(headers)):
                    cell = table[(row_idx, col_idx)]
                    if col_idx == 0:  # 行标题
                        cell.set_facecolor('#f0f0f0')
                        cell.set_text_props(weight='bold', fontsize=10)
                    else:  # 数据单元格
                        cell.set_facecolor('white')
                        cell.set_text_props(fontsize=9)
                    cell.set_height(0.3)   # 增大行高
                    cell.set_edgecolor('black')
                    cell.set_linewidth(0.5)
                    
        except Exception as e:
            logger.exception(f"创建窗体表格时出错: {str(e)}")
            ax.text(0.5, 0.5, f"表格创建失败: {str(e)}", ha='center', va='center', 
                   transform=ax.transAxes, fontsize=9, color='red', fontweight='bold',
                   bbox=dict(boxstyle='round,pad=0.5', facecolor='white', 
                           alpha=0.9, edgecolor='red', linewidth=2))

    def _plot_single_order_analysis(self, ax, analysis, title):
        """绘制单个阶次分析图表"""
        # 检查数据完整性并设置默认值
        if not analysis or not isinstance(analysis, dict):
            logger.error(f"阶次分析数据无效: {title}, 数据类型: {type(analysis)}")
            ax.text(0.5, 0.5, f"无可用数据\n数据类型: {type(analysis)}", ha='center', va='center', transform=ax.transAxes)
            ax.set_title(title)
            return
            
        # 详细记录数据状态
        logger.info(f"绘制阶次分析图表: {title}")
        logger.info(f"分析数据包含键: {list(analysis.keys())}")
        
        orders = analysis.get('orders', [])
        amplitudes = analysis.get('amplitudes', [])  # 使用amplitudes而不是order_magnitudes
        dominant_orders = analysis.get('dominant_orders', [])  # 使用dominant_orders而不是top_orders
        teeth = analysis.get('teeth', 0)

        # 详细的数据验证
        logger.info(f"Orders数据: 类型={type(orders)}, 长度={len(orders) if hasattr(orders, '__len__') else 'N/A'}")
        logger.info(f"Amplitudes数据: 类型={type(amplitudes)}, 长度={len(amplitudes) if hasattr(amplitudes, '__len__') else 'N/A'}")
        logger.info(f"Dominant_orders数据: 类型={type(dominant_orders)}, 长度={len(dominant_orders) if hasattr(dominant_orders, '__len__') else 'N/A'}")
        logger.info(f"齿数: {teeth}")

        # 检查数据是否为空或无效
        # 检查数组是否为空或长度为0
        if orders is None or amplitudes is None or len(orders) == 0 or len(amplitudes) == 0:
            logger.error(f"阶次分析数据为空: orders={bool(orders)}, amplitudes={bool(amplitudes)}")
            ax.text(0.5, 0.5, f"数据为空\norders: {bool(orders)}\namplitudes: {bool(amplitudes)}", 
                   ha='center', va='center', transform=ax.transAxes)
            ax.set_title(title)
            return

        # 确保数据长度一致
        try:
            orders = np.array(orders)
            amplitudes = np.array(amplitudes)
            
            min_len = min(len(orders), len(amplitudes))
            if min_len == 0:
                logger.error(f"数据长度为零: orders={len(orders)}, amplitudes={len(amplitudes)}")
                ax.text(0.5, 0.5, "数据长度为零", ha='center', va='center', transform=ax.transAxes)
                ax.set_title(title)
                return
                
            orders = orders[:min_len]
            amplitudes = amplitudes[:min_len]
            
            logger.info(f"使用数据长度: {min_len}, 数据范围: orders[{orders[0]}-{orders[-1]}], amplitudes[{amplitudes.min():.6f}-{amplitudes.max():.6f}]")
            
        except Exception as e:
            logger.error(f"数据转换错误: {str(e)}")
            ax.text(0.5, 0.5, f"数据转换错误: {str(e)}", ha='center', va='center', transform=ax.transAxes)
            ax.set_title(title)
            return

        # 绘制阶次谱 - 使用专业样式
        bars = ax.bar(orders, amplitudes, width=0.4, color='lightblue', 
                     edgecolor='darkblue', alpha=0.8, linewidth=0.5)

        # 标记主要阶次（使用不同颜色）
        if len(dominant_orders) > 0:
            for order in dominant_orders:
                if order in orders:  # 确保order在数据范围内
                    order_idx = np.where(orders == order)[0]
                    if len(order_idx) > 0:
                        bars[order_idx[0]].set_color('red')
                        bars[order_idx[0]].set_alpha(0.9)
                        # 在柱子上方添加数值标签
                        mag = amplitudes[order_idx[0]]
                        ax.text(order, mag + max(amplitudes) * 0.02, f'{mag:.3f}', 
                               ha='center', va='bottom', fontsize=8, fontweight='bold')

        # 标记齿数相关阶次
        if teeth > 0 and len(orders) > 0:
            if teeth >= min(orders) and teeth <= max(orders):
                ax.axvline(x=teeth, color='green', linestyle='--', alpha=0.7, linewidth=2)
                ax.text(teeth, max(amplitudes) * 0.9, f"齿数阶\n({teeth}阶)",
                        ha='center', va='top', color='green', fontsize=9, 
                        bbox=dict(boxstyle='round,pad=0.3', facecolor='lightgreen', alpha=0.7))

        # 设置专业样式
        ax.set_title(title, fontsize=9, fontweight='bold', pad=15)
        ax.set_xlabel("阶次", fontsize=8)
        ax.set_ylabel("幅值", fontsize=8)
        ax.grid(True, linestyle='-', alpha=0.3, linewidth=0.5)
        ax.set_axisbelow(True)
        
        # 设置x轴刻度
        if len(orders) > 0:
            max_order = min(66, max(orders))  # 限制显示前15个阶次
            ax.set_xlim(0.5, max_order + 0.5)
            ax.set_xticks(range(1, int(max_order) + 1))
        
        # 美化y轴
        ax.yaxis.set_major_formatter(plt.FuncFormatter(lambda x, p: f'{x:.2f}'))

    def display_diagnosis(self):
        """显示诊断信息"""
        if not self.ripple_results or 'order_analysis' not in self.ripple_results:
            return

        # 清空表格
        if not hasattr(self, 'diagnosis_table') or self.diagnosis_table is None:
            logger.warning("diagnosis_table属性不存在或为None，跳过表格清空")
            return
        self.diagnosis_table.setRowCount(0)

        # 检查阶次分析数据是否存在
        order_analysis = self.ripple_results.get('order_analysis', {})
        if not order_analysis:
            return

        # 添加齿形诊断
        if 'profile' in order_analysis and order_analysis['profile']:
            analysis = order_analysis['profile']
            self._add_diagnosis_rows(analysis, "齿形")

        # 添加齿向诊断
        if 'flank' in order_analysis and order_analysis['flank']:
            analysis = order_analysis['flank']
            self._add_diagnosis_rows(analysis, "齿向")

    def _add_diagnosis_rows(self, analysis, data_type):
        """添加诊断行到表格"""
        # 检查数据完整性
        if not analysis or not isinstance(analysis, dict):
            return
            
        diagnostics = analysis.get('diagnostics', [])
        if not diagnostics:
            return
            
        for diag in diagnostics:
            # 检查诊断项的完整性
            if not isinstance(diag, dict) or 'order' not in diag or 'magnitude' not in diag or 'diagnosis' not in diag:
                continue
                
            row = self.diagnosis_table.rowCount()
            self.diagnosis_table.insertRow(row)

            # 阶次
            order_item = QTableWidgetItem(f"{diag['order']}阶 ({data_type})")
            self.diagnosis_table.setItem(row, 0, order_item)

            # 幅值
            mag_item = QTableWidgetItem(f"{diag['magnitude'] * 100:.1f}%")
            self.diagnosis_table.setItem(row, 1, mag_item)

            # 诊断信息
            diagnosis_list = diag.get('diagnosis', [])
            if isinstance(diagnosis_list, list):
                diagnosis_text = "\n".join(diagnosis_list)
            else:
                diagnosis_text = str(diagnosis_list)
            diagnosis_item = QTableWidgetItem(diagnosis_text)
            self.diagnosis_table.setItem(row, 2, diagnosis_item)

    def export_ripple_report(self):
        """导出Ripple分析报告"""
        if not self.ripple_results or not self.current_file:
            QMessageBox.warning(self, "警告", "没有可导出的Ripple数据")
            return

        output_path, _ = QFileDialog.getSaveFileName(
            self, "保存Ripple分析报告",
            os.path.splitext(self.current_file)[0] + "_Ripple报告.pdf",
            "PDF文件 (*.pdf)"
        )

        if not output_path:
            return

        try:
            # 🔧 基于测试程序的成功方案配置PDF生成
            import matplotlib
            import matplotlib.pyplot as plt
            
            # 临时切换后端
            original_backend = matplotlib.get_backend()
            matplotlib.use('Agg')  # 使用非交互式后端
            plt.ioff()  # 关闭交互模式
            
            # 完整的PDF参数配置 - 基于测试程序的成功配置
            matplotlib.rcParams.update({
                'figure.facecolor': 'white',
                'axes.facecolor': 'white',
                'savefig.facecolor': 'white',
                'savefig.edgecolor': 'none',
                'patch.facecolor': 'white',
                'text.color': 'black',
                'axes.labelcolor': 'black',
                'xtick.color': 'black',
                'ytick.color': 'black',
                'axes.edgecolor': 'black',
                'pdf.fonttype': 42,  # TrueType字体
                'ps.fonttype': 42,
                'font.sans-serif': ['SimHei', 'Arial Unicode MS', 'DejaVu Sans'],
                'axes.unicode_minus': False,
                #'figure.dpi': 100,
                # 'savefig.dpi': 100  # 注释掉这行，避免dpi参数错误
            })
            
            # 创建PDF文件
            with PdfPages(output_path) as pdf:
                # 1. 封面页
                fig = self.create_ripple_report_cover()
                pdf.savefig(fig, bbox_inches='tight', facecolor='white', edgecolor='none')
                plt.close(fig)

                # 2. 基本信息页
                fig = self.create_ripple_info_page()
                pdf.savefig(fig, bbox_inches='tight', facecolor='white', edgecolor='none')
                plt.close(fig)

                # 3. 统计信息页
                fig = self.create_ripple_stats_page()
                pdf.savefig(fig, bbox_inches='tight', facecolor='white', edgecolor='none')
                plt.close(fig)

                # 4. 阶次谱专业页（使用柱状图+公差线的新版）
                fig = self.create_professional_order_spectrum()
                pdf.savefig(fig, bbox_inches='tight', facecolor='white', edgecolor='none')
                plt.close(fig)

                # 5. 诊断建议页
                fig = self.create_diagnosis_page()
                pdf.savefig(fig, bbox_inches='tight', facecolor='white', edgecolor='none')
                plt.close(fig)

                # 6. 详细数据页
                fig = self.create_ripple_detail_page()
                pdf.savefig(fig, bbox_inches='tight', facecolor='white', edgecolor='none')
                plt.close(fig)

            # 🔧 恢复原始后端设置
            matplotlib.use(original_backend)
            plt.ion()  # 恢复交互模式

            # 创建自定义消息框
            msg_box = QMessageBox(self)
            msg_box.setWindowTitle("导出成功")
            msg_box.setIcon(QMessageBox.Information)
            msg_box.setText(f"Ripple分析报告已成功导出到:\n{output_path}")

            # 添加按钮
            open_file_btn = msg_box.addButton("打开文件", QMessageBox.ActionRole)
            open_folder_btn = msg_box.addButton("打开文件夹位置", QMessageBox.ActionRole)
            close_btn = msg_box.addButton("关闭", QMessageBox.RejectRole)

            # 显示消息框
            msg_box.exec_()

            # 处理按钮点击
            clicked_btn = msg_box.clickedButton()
            if clicked_btn == open_file_btn:
                self.open_file(output_path)
            elif clicked_btn == open_folder_btn:
                self.open_folder(output_path)

            logger.info(f"Ripple报告导出成功: {output_path}")
            
            # 🚀 新增：自动打开Ripple报告
            try:
                logger.info("正在自动打开Ripple报告...")
                self.open_file(output_path)
                logger.info("Ripple报告自动打开成功")
            except Exception as e:
                logger.warning(f"自动打开Ripple报告失败: {str(e)}")

        except Exception as e:
            QMessageBox.critical(self, "导出失败", f"无法导出Ripple分析报告:\n{str(e)}")
            logger.error(f"Ripple报告导出失败: {str(e)}")

