    def calculate_flankenlinie_parameters(self, data_points, data_type):
        """计算齿向（Flankenlinie）参数，支持915个数据点"""
        try:
            if not data_points:
                return None
            
            # 确定数据点数
            point_count = len(data_points)
            expected_points = 915 if data_type == "齿向" else 480
            
            logger.info(f"计算{data_type}参数: {point_count}个数据点 (期望: {expected_points}个点)")
            
            # 基本统计参数
            mean_value = sum(data_points) / len(data_points)
            max_value = max(data_points)
            min_value = min(data_points)
            range_value = max_value - min_value
            
            # 计算标准差
            variance = sum((x - mean_value) ** 2 for x in data_points) / len(data_points)
            std_deviation = variance ** 0.5
            
            # 计算RMS值
            rms_value = (sum(x ** 2 for x in data_points) / len(data_points)) ** 0.5
            
            # 对于915个数据点，计算更详细的参数
            if point_count == 915:
                # 分段分析（每段约100个点）
                segment_size = 100
                segments = [data_points[i:i+segment_size] for i in range(0, point_count, segment_size)]
                
                segment_means = []
                segment_stds = []
                
                for i, segment in enumerate(segments):
                    if segment:
                        seg_mean = sum(segment) / len(segment)
                        seg_variance = sum((x - seg_mean) ** 2 for x in segment) / len(segment)
                        seg_std = seg_variance ** 0.5
                        segment_means.append(seg_mean)
                        segment_stds.append(seg_std)
                
                # 计算段间变化
                segment_variation = max(segment_means) - min(segment_means) if segment_means else 0
                
                logger.info(f"915点{data_type}分段分析: {len(segments)}段, 段间变化: {segment_variation:.3f}")
            
            # 返回计算结果
            result = {
                'mean': mean_value,
                'max': max_value,
                'min': min_value,
                'range': range_value,
                'std_deviation': std_deviation,
                'rms': rms_value,
                'point_count': point_count,
                'expected_points': expected_points
            }
            
            # 添加915点特殊参数
            if point_count == 915:
                result.update({
                    'segment_count': len(segments) if 'segments' in locals() else 0,
                    'segment_variation': segment_variation if 'segment_variation' in locals() else 0
                })
            
            return result
            
        except Exception as e:
            logger.error(f"计算{data_type}参数错误: {str(e)}")
            return None

    def process_flankenlinie_data(self, data_points, gear_number, flank_side):
        """处理齿向（Flankenlinie）数据，支持915个点"""
        try:
            if not data_points:
                logger.warning(f"齿向数据为空: 齿号{gear_number} {flank_side}面")
                return None
            
            point_count = len(data_points)
            logger.info(f"处理齿向数据: 齿号{gear_number} {flank_side}面, {point_count}个点")
            
            # 计算基本参数
            params = self.calculate_flankenlinie_parameters(data_points, "齿向")
            if not params:
                return None
            
            # 计算ISO 1328偏差参数（针对915个点优化）
            if point_count == 915:
                # 使用915个点计算更精确的偏差
                deviation_params = self.calculate_iso1328_deviations_915(data_points)
            else:
                # 使用标准方法计算偏差
                deviation_params = self.calculate_iso1328_deviations(data_points)
            
            # 合并结果
            result = {
                'gear_number': gear_number,
                'flank_side': flank_side,
                'data_type': '齿向',
                'point_count': point_count,
                'basic_params': params,
                'deviation_params': deviation_params
            }
            
            logger.info(f"齿向数据处理完成: 齿号{gear_number} {flank_side}面, 偏差参数: {deviation_params}")
            return result
            
        except Exception as e:
            logger.error(f"处理齿向数据错误 (齿号{gear_number} {flank_side}面): {str(e)}")
            return None

    def calculate_iso1328_deviations_915(self, data_points):
        """使用915个数据点计算ISO 1328偏差参数"""
        try:
            if len(data_points) != 915:
                logger.warning(f"数据点数不匹配: 期望915个点，实际{len(data_points)}个点")
                return self.calculate_iso1328_deviations(data_points)
            
            logger.info("使用915个数据点计算ISO 1328偏差参数")
            
            # 分段计算（每段约100个点，共9段）
            segment_size = 100
            segments = [data_points[i:i+segment_size] for i in range(0, 915, segment_size)]
            
            # 计算每段的统计参数
            segment_stats = []
            for i, segment in enumerate(segments):
                if segment:
                    seg_mean = sum(segment) / len(segment)
                    seg_max = max(segment)
                    seg_min = min(segment)
                    seg_range = seg_max - seg_min
                    segment_stats.append({
                        'segment': i + 1,
                        'mean': seg_mean,
                        'max': seg_max,
                        'min': seg_min,
                        'range': seg_range
                    })
            
            # 计算总体偏差参数
            total_max = max(data_points)
            total_min = min(data_points)
            total_range = total_max - total_min
            
            # 计算F_beta（总偏差）
            F_beta = total_range
            
            # 计算fH_beta（单齿偏差）
            fH_beta = max(seg['range'] for seg in segment_stats)
            
            # 计算ff_beta（齿形偏差）
            # 使用相邻段的差异来计算
            ff_beta = 0
            for i in range(len(segment_stats) - 1):
                diff = abs(segment_stats[i]['mean'] - segment_stats[i+1]['mean'])
                ff_beta = max(ff_beta, diff)
            
            result = {
                'F_beta': F_beta,
                'fH_beta': fH_beta,
                'ff_beta': ff_beta,
                'segment_count': len(segments),
                'total_points': 915
            }
            
            logger.info(f"915点偏差计算结果: Fβ={F_beta:.3f}, fHβ={fH_beta:.3f}, ffβ={ff_beta:.3f}")
            return result
            
        except Exception as e:
            logger.error(f"915点偏差计算错误: {str(e)}")
            return None

